INSERT INTO `t_operation_log` VALUES (1728, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"黑色沙漠服务端优化**\\n\\n**项目前言**\\n\\n本项目是5月15号部署完黑色沙漠局域网的时候，游戏延迟明显操作卡顿，主线任务bug很多，给爷整烦了，爷干脆来了一个延迟的优化，目前第一阶段优化已经完成，功能对比市面上其他一键端较为完善，客户端编写花费时间较后端少，因为黑沙客户端比较多，有些拿来改改就行，比如2100、795、661、602等版本 。而2016 server数据中心版上手很容易，在学习完了狂神大大的视频后，趁热做的一个练手项目，可能会有很多bug，敬请原谅~~\\n\\n**项目预览**\\n\\n- 优化前：延迟在200ms浮动\\n- ​![0u2.jpg](http://ws.aqi125.cn/articles/63c32e91c1b5c3f8bdeb8faaacceb722.jpg)                                                              \\n- ![0u1.jpg](http://ws.aqi125.cn/articles/33feae1b9c4aac1eb0913e5153c2f0b4.jpg)\\n- 优化后：经过硬件，服务端综合优化后基本稳定在30ms左右\\n- ​![0u.jpg](https://ws.aqi125.cn/articles/bc82c383ff37c5afa171c9a43788e036.jpg)\\n- 综合起来看这样\\n- ![01.jpg](https://ws.aqi125.cn/articles/b875a757569bbdcfcac476b8cf5619e8.jpg)\\n\\n**项目描述**\\n\\n整体优化分为两个模块：一个是­­­硬件优化，一个是服务端环境及代码优化。\\n\\n**一.** 硬件优化模块：服务器原型机2H4G（单通道）加装内存条，组成2H12G（双通道）。在安装完后通过实际测试延迟仅仅降到了100ms左右，在高数据并发复杂环境下依然会卡顿操作不流畅，开始了服务端环境整合和动态加载的代码优化（工作量偏大）。\\n\\n- ![02.jpg](https://ws.aqi125.cn/articles/d1007544ba7580a1ec1911ab80cb8c35.jpg)\\n\\n**二**.服务端优化模块：服务端优化分三个子项目\\n\\n1.服务端环境优化: Windows7升至Windows server 2016 **Datacenter edition** （升级前数据库及数据文件压缩打包避免损坏）\\n\\n2.数据库简化：robo3t简化到MongoDBCompass官方工具避免数据库多次查询。\\n\\n3.代码优化：gameserver\\\\bing\\\\configs\\\\godata.properties随便找一个编码软件打开，geo.dynamic.load=true（动态加载）改为false（静态加载）地图加载程度改为——geo.terrrain.lod_level =0 geo.conllision.lod_level=0。ok服务端优化完成基本稳定在30ms了。\\n\\n**硬件**\\n\\n加个内存条这不有手就行。\\n\\n**服务端（升级系统也是有手就行。）**\\n\\n| **名称** | **技术点**                                 |\\n| -------- | ------------------------------------------ |\\n| 系统     | Windows server 2016 **Datacenter edition** |\\n| 数据库   | robo3t+MongoDBCompass                      |\\n| 端口     | 27017                                      |\\n| 代码     | godata.properties ， jwt                   |\\n| 其他     | Tcp/ip，服务器连接开放                     |\\n\\n**关于开源**\\n\\n代码部分已上传GitHub，欢迎给个star~ ，有能力的朋友，可以请我喝一杯奶茶。\\n\\n**关于黑色沙漠2260第三改**\\n\\n现在陆陆续续有朋友加入了这个服务端的Organizations，给这个服务端提供了很大的帮助，同时也给了很棒的建议，在此十分感谢他们。\\n\\n**关于我**\\n\\n由于我目前要做一个前后端分离的博客，后面可能没很大的精力投入这个服务端开发了，更新迭代的速度也会变慢。敬请原谅。如果有什么bug或者建议，可以及时联系我。\\n\\nqq:2316364297\\n\\n**参考项目**\\n\\n游戏屋2260版\\n\\n**十分感谢上面这些学习项目，感谢！！\",\"articleCover\":\"http://ws.aqi125.cn/articles/ce2c679ebaefd4c082c84e37eaa05d78.jpeg\",\"articleTitle\":\"2023-03-13\",\"categoryName\":\"linux游戏服务器部署\",\"isFeatured\":0,\"isTop\":0,\"status\":1,\"tagNames\":[\"黑色沙漠\"],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '110.184.180.10', '中国|四川省|成都市|电信', '2023-03-13 21:55:23', NULL);
INSERT INTO `t_operation_log` VALUES (1729, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# 服务器要求\\n\\n介绍一下rust服务器的部署流程以及踩的一些坑，给需要部署的朋友以借鉴。\\n内存：4G能满足5-10个人同时进行游戏，内存越大，支持的人数越多。推荐8G以上。\\n硬盘：40G以上,服务端有6G左右。\\n网络：8M~20M上行带宽，Rust服务器懂得都懂，最好弄高防御的服务器或者配置网络防御能力。\\n\\n# 一 服务器环境配置\\n\\n## 1. 根目录\\n\\n```language\\ncd\\n```\\n\\n## 2. 更新\\n\\n```language\\nyum check-update\\nyum update\\n```\\n\\n# 二 服务器安装依赖\\n\\n## 2.1. Cenos\\n\\n```language\\nyum install epel-release\\nyum install curl wget tar bzip2 gzip unzip python3 binutils bc jq tmux glibc.i686 libstdc++ libstdc++.i686 zlib-devel\\n```\\n\\n## 2.2. Ubuntu\\n\\n```language\\nsudo dpkg --add-architecture i386; sudo apt update; sudo apt install curl wget file tar bzip2 gzip unzip bsdmainutils python util-linux ca-certificates binutils bc jq tmux netcat lib32gcc1 lib32stdc++6 libsdl2-2.0-0:i386 steamcmd lib32z1\\n```\\n\\n## 2.3. 添加服务器-——————进入服务器\\n\\n```language\\nadduser rustserver      su - rustserver \\n```\\n\\n# 三 镜像\\n\\n## 3.1.下载 linuxgsm.sh ps国内镜像\\n\\n```language\\nwget -O cn-start.sh https://gitee.com/DefiedParty/LinuxGSM/raw/master/cn-start.sh && chmod +x cn-start.sh && bash cn-start.sh rustserver\\n```\\n\\n## 3.2. 镜像下载好后初始化rustservr\\n\\n```language\\nbash linuxgsm.sh rustserver\\n```\\n\\n## 3.3.安装服务器 大概4个G \\n\\n```language\\n./rustserver install\\n```\\n\\n# 四 rust服务器参数配置\\n\\n## 4.1.路径\\n\\n```language\\nnano /home/rustserver/serverfiles/server/rustserver/cfg/server.cfg\\n```\\n\\n## 4.2.进入rustserver文件夹\\n\\n```language\\ncd /home/rustserver/lgsm/config-lgsm/rustserver\\n```\\n\\n## 4.3.列表\\n\\n```language\\nls\\n```\\n\\n## 4.4.打开rustserver.cfg\\n\\n```language\\ncat rustserver.cfg\\n```\\n\\n## 4.5.覆盖\\n\\n```language\\ncp _default.cfg  rustserver.cfg\\n```\\n\\n## 4.6. 打开 rustserver.cfg\\n\\n```language\\nnano rustserver.cfg（ctrl+o保存 ctrl+v退出 ）\\n```\\n\\n# 五 安装oxide\\n\\n```language\\n./rustserver mods-install\\nrustoxide\\n```\\n\\n# 六 服务器基础操作\\n\\n## 6.1.进入         6.2.启动   \\t 6.3.停止 \\t 6.4.更新 \\t\\n\\n```language\\nsu - rustserver  ./rustserver start ./rustserver stop  ./rustserver update \\n```\\n\\n## 6.5.查看  6.6重启 6.7.运行时查看服务器的实时控制台并允许您输入命令\\n\\n```language\\n  ./rustserver ./rustserver restartdetails ./rustserver console\\n```\\n\\n# 七 Oxide操作\\n\\n## 7.1.更新oxide最新版本\\n\\n```language\\n./rustserver mods-update\\n```\\n\\n## 7.2.oxide插件存放目录\\n\\n```language\\ncd serverfiles/oxide/plugins\\n```\\n\\n## 7.3.退出控制台\\n\\n```language\\nCTRL+b d\\n./rustserver stop\\n```\\n\\n# 八 进入游戏\\n\\n```language\\nconnect 你的ip加端口号\\n```\\n![v2c01bbb1e094b37d0b04916c1b370ca66_1440w.jpg](https://ws.aqi125.cn/articles/59542fe2f3e7a54619deb569754064cd.jpg)\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/58727c4b325ec745599cbc08b1cf8efe.jpeg\",\"articleTitle\":\"2023-03-13\",\"categoryName\":\"linux游戏服务器部署\",\"id\":138,\"isFeatured\":0,\"isTop\":0,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '110.184.180.10', '中国|四川省|成都市|电信', '2023-03-13 21:56:44', NULL);
INSERT INTO `t_operation_log` VALUES (1730, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# 服务器要求\\n\\n介绍一下rust服务器的部署流程以及踩的一些坑，给需要部署的朋友以借鉴。\\n内存：4G能满足5-10个人同时进行游戏，内存越大，支持的人数越多。推荐8G以上。\\n硬盘：40G以上,服务端有6G左右。\\n网络：8M~20M上行带宽，Rust服务器懂得都懂，最好弄高防御的服务器或者配置网络防御能力。\\n\\n# 一 服务器环境配置\\n\\n## 1. 根目录\\n\\n```language\\ncd\\n```\\n\\n## 2. 更新\\n\\n```language\\nyum check-update\\nyum update\\n```\\n\\n# 二 服务器安装依赖\\n\\n## 2.1. Cenos\\n\\n```language\\nyum install epel-release\\nyum install curl wget tar bzip2 gzip unzip python3 binutils bc jq tmux glibc.i686 libstdc++ libstdc++.i686 zlib-devel\\n```\\n\\n## 2.2. Ubuntu\\n\\n```language\\nsudo dpkg --add-architecture i386; sudo apt update; sudo apt install curl wget file tar bzip2 gzip unzip bsdmainutils python util-linux ca-certificates binutils bc jq tmux netcat lib32gcc1 lib32stdc++6 libsdl2-2.0-0:i386 steamcmd lib32z1\\n```\\n\\n## 2.3. 添加服务器-——————进入服务器\\n\\n```language\\nadduser rustserver      su - rustserver \\n```\\n\\n# 三 镜像\\n\\n## 3.1.下载 linuxgsm.sh ps国内镜像\\n\\n```language\\nwget -O cn-start.sh https://gitee.com/DefiedParty/LinuxGSM/raw/master/cn-start.sh && chmod +x cn-start.sh && bash cn-start.sh rustserver\\n```\\n\\n## 3.2. 镜像下载好后初始化rustservr\\n\\n```language\\nbash linuxgsm.sh rustserver\\n```\\n\\n## 3.3.安装服务器 大概4个G \\n\\n```language\\n./rustserver install\\n```\\n\\n# 四 rust服务器参数配置\\n\\n## 4.1.路径\\n\\n```language\\nnano /home/rustserver/serverfiles/server/rustserver/cfg/server.cfg\\n```\\n\\n## 4.2.进入rustserver文件夹\\n\\n```language\\ncd /home/rustserver/lgsm/config-lgsm/rustserver\\n```\\n\\n## 4.3.列表\\n\\n```language\\nls\\n```\\n\\n## 4.4.打开rustserver.cfg\\n\\n```language\\ncat rustserver.cfg\\n```\\n\\n## 4.5.覆盖\\n\\n```language\\ncp _default.cfg  rustserver.cfg\\n```\\n\\n## 4.6. 打开 rustserver.cfg\\n\\n```language\\nnano rustserver.cfg（ctrl+o保存 ctrl+v退出 ）\\n```\\n\\n# 五 安装oxide\\n\\n```language\\n./rustserver mods-install\\nrustoxide\\n```\\n\\n# 六 服务器基础操作\\n\\n## 6.1.进入         6.2.启动   \\t 6.3.停止 \\t 6.4.更新 \\t\\n\\n```language\\nsu - rustserver  ./rustserver start ./rustserver stop  ./rustserver update \\n```\\n\\n## 6.5.查看  6.6重启 6.7.运行时查看服务器的实时控制台并允许您输入命令\\n\\n```language\\n  ./rustserver ./rustserver restartdetails ./rustserver console\\n```\\n\\n# 七 Oxide操作\\n\\n## 7.1.更新oxide最新版本\\n\\n```language\\n./rustserver mods-update\\n```\\n\\n## 7.2.oxide插件存放目录\\n\\n```language\\ncd serverfiles/oxide/plugins\\n```\\n\\n## 7.3.退出控制台\\n\\n```language\\nCTRL+b d\\n./rustserver stop\\n```\\n\\n# 八 进入游戏\\n\\n```language\\nconnect 你的ip加端口号\\n```\\n![v2c01bbb1e094b37d0b04916c1b370ca66_1440w.jpg](https://ws.aqi125.cn/articles/59542fe2f3e7a54619deb569754064cd.jpg)\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/58727c4b325ec745599cbc08b1cf8efe.jpeg\",\"articleTitle\":\"2023-03-13\",\"categoryName\":\"linux游戏服务器部署\",\"id\":138,\"isFeatured\":0,\"isTop\":0,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '110.184.180.10', '中国|四川省|成都市|电信', '2023-03-13 22:01:09', NULL);
INSERT INTO `t_operation_log` VALUES (1731, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# *黑色沙漠服务端优化*\\n\\n## **项目前言**\\n\\n本项目是5月15号部署完黑色沙漠局域网的时候，游戏延迟明显操作卡顿，主线任务bug很多，给爷整烦了，爷干脆来了一个延迟的优化，目前第一阶段优化已经完成，功能对比市面上其他一键端较为完善，客户端编写花费时间较后端少，因为黑沙客户端比较多，有些拿来改改就行，比如2100、795、661、602等版本 。而2016 server数据中心版上手很容易，在学习完了狂神大大的视频后，趁热做的一个练手项目，可能会有很多bug，敬请原谅~~\\n\\n**项目预览**\\n\\n- 优化前：延迟在200ms浮动\\n- ​![0u2.jpg](http://ws.aqi125.cn/articles/63c32e91c1b5c3f8bdeb8faaacceb722.jpg)                                                              \\n- ![0u1.jpg](http://ws.aqi125.cn/articles/33feae1b9c4aac1eb0913e5153c2f0b4.jpg)\\n- 优化后：经过硬件，服务端综合优化后基本稳定在30ms左右\\n- ​![0u.jpg](https://ws.aqi125.cn/articles/bc82c383ff37c5afa171c9a43788e036.jpg)\\n- 综合起来看这样\\n- ![01.jpg](https://ws.aqi125.cn/articles/b875a757569bbdcfcac476b8cf5619e8.jpg)\\n\\n**项目描述**\\n\\n整体优化分为两个模块：一个是­­­硬件优化，一个是服务端环境及代码优化。\\n\\n**一.** 硬件优化模块：服务器原型机2H4G（单通道）加装内存条，组成2H12G（双通道）。在安装完后通过实际测试延迟仅仅降到了100ms左右，在高数据并发复杂环境下依然会卡顿操作不流畅，开始了服务端环境整合和动态加载的代码优化（工作量偏大）。\\n\\n- ![02.jpg](https://ws.aqi125.cn/articles/d1007544ba7580a1ec1911ab80cb8c35.jpg)\\n\\n**二**.服务端优化模块：服务端优化分三个子项目\\n\\n1.服务端环境优化: Windows7升至Windows server 2016 **Datacenter edition** （升级前数据库及数据文件压缩打包避免损坏）\\n\\n2.数据库简化：robo3t简化到MongoDBCompass官方工具避免数据库多次查询。\\n\\n3.代码优化：gameserver\\\\bing\\\\configs\\\\godata.properties随便找一个编码软件打开，geo.dynamic.load=true（动态加载）改为false（静态加载）地图加载程度改为——geo.terrrain.lod_level =0 geo.conllision.lod_level=0。ok服务端优化完成基本稳定在30ms了。\\n\\n**硬件**\\n\\n加个内存条这不有手就行。\\n\\n**服务端（升级系统也是有手就行。）**\\n\\n| **名称** | **技术点**                                 |\\n| -------- | ------------------------------------------ |\\n| 系统     | Windows server 2016 **Datacenter edition** |\\n| 数据库   | robo3t+MongoDBCompass                      |\\n| 端口     | 27017                                      |\\n| 代码     | godata.properties ， jwt                   |\\n| 其他     | Tcp/ip，服务器连接开放                     |\\n\\n**关于开源**\\n\\n代码部分已上传GitHub，欢迎给个star~ ，有能力的朋友，可以请我喝一杯奶茶。\\n\\n**关于黑色沙漠2260第三改**\\n\\n现在陆陆续续有朋友加入了这个服务端的Organizations，给这个服务端提供了很大的帮助，同时也给了很棒的建议，在此十分感谢他们。\\n\\n**关于我**\\n\\n由于我目前要做一个前后端分离的博客，后面可能没很大的精力投入这个服务端开发了，更新迭代的速度也会变慢。敬请原谅。如果有什么bug或者建议，可以及时联系我。\\n\\nqq:2316364297\\n\\n**参考项目**\\n\\n游戏屋2260版\\n\\n**十分感谢上面这些学习项目，感谢！！\",\"articleCover\":\"http://ws.aqi125.cn/articles/ce2c679ebaefd4c082c84e37eaa05d78.jpeg\",\"articleTitle\":\"2023-03-13\",\"categoryName\":\"linux游戏服务器部署\",\"id\":139,\"isFeatured\":0,\"isTop\":0,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '110.184.180.10', '中国|四川省|成都市|电信', '2023-03-13 22:01:40', NULL);
INSERT INTO `t_operation_log` VALUES (1732, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# 黑色沙漠服务端优化\\n\\n## **项目前言**\\n\\n本项目是5月15号部署完黑色沙漠局域网的时候，游戏延迟明显操作卡顿，主线任务bug很多，给爷整烦了，爷干脆来了一个延迟的优化，目前第一阶段优化已经完成，功能对比市面上其他一键端较为完善，客户端编写花费时间较后端少，因为黑沙客户端比较多，有些拿来改改就行，比如2100、795、661、602等版本 。而2016 server数据中心版上手很容易，在学习完了狂神大大的视频后，趁热做的一个练手项目，可能会有很多bug，敬请原谅~~\\n\\n## **项目预览**\\n\\n- 优化前：延迟在200ms浮动\\n- ​![0u2.jpg](http://ws.aqi125.cn/articles/63c32e91c1b5c3f8bdeb8faaacceb722.jpg)                                                              \\n- ![0u1.jpg](http://ws.aqi125.cn/articles/33feae1b9c4aac1eb0913e5153c2f0b4.jpg)        \\n- 优化后：经过硬件，服务端综合优化后基本稳定在30ms左右\\n- ​![0u.jpg](https://ws.aqi125.cn/articles/bc82c383ff37c5afa171c9a43788e036.jpg)  \\n- 综合起来看这样\\n- ![01.jpg](https://ws.aqi125.cn/articles/b875a757569bbdcfcac476b8cf5619e8.jpg)\\n\\n## **项目描述**\\n\\n整体优化分为两个模块：一个是­­­硬件优化，一个是服务端环境及代码优化。\\n\\n# 一. 硬件优化模块：\\n\\n服务器原型机2H4G（单通道）加装内存条，组成2H12G（双通道）。在安装完后通过实际测试延迟仅仅降到了100ms左右，在高数据并发复杂环境下依然会卡顿操作不流畅，开始了服务端环境整合和动态加载的代码优化（工作量偏大）。\\n\\n- ![02.jpg](https://ws.aqi125.cn/articles/d1007544ba7580a1ec1911ab80cb8c35.jpg)\\n\\n# **二**.服务端优化模块：\\n\\n服务端优化分三个子项目\\n\\n## 1.服务端环境优化:\\n\\n Windows7升至Windows server 2016 **Datacenter edition** （升级前数据库及数据文件压缩打包避免损坏）\\n\\n## 2.数据库简化：\\n\\nrobo3t简化到MongoDBCompass官方工具避免数据库多次查询。\\n\\n## 3.代码优化：\\n\\ngameserver\\\\bing\\\\configs\\\\godata.properties随便找一个编码软件打开，geo.dynamic.load=true（动态加载）改为false（静态加载）地图加载程度改为——geo.terrrain.lod_level =0 geo.conllision.lod_level=0。ok服务端优化完成基本稳定在30ms了。\\n\\n### **硬件**\\n\\n加个内存条这不有手就行。\\n\\n### **服务端（升级系统也是有手就行。）**\\n\\n| **名称** | **技术点**                                 |\\n| -------- | ------------------------------------------ |\\n| 系统     | Windows server 2016 **Datacenter edition** |\\n| 数据库   | robo3t+MongoDBCompass                      |\\n| 端口     | 27017                                      |\\n| 代码     | godata.properties ， jwt                   |\\n| 其他     | Tcp/ip，服务器连接开放                     |\\n\\n### **关于开源**\\n\\n代码部分已上传GitHub，欢迎给个star~ ，有能力的朋友，可以请我喝一杯奶茶。\\n\\n### **关于黑色沙漠2260第三改**\\n\\n现在陆陆续续有朋友加入了这个服务端的Organizations，给这个服务端提供了很大的帮助，同时也给了很棒的建议，在此十分感谢他们。\\n\\n### **关于我**\\n\\n由于我目前要做一个前后端分离的博客，后面可能没很大的精力投入这个服务端开发了，更新迭代的速度也会变慢。敬请原谅。如果有什么bug或者建议，可以及时联系我。\\n\\nqq:2316364297\\n\\n### **参考项目**\\n\\n游戏屋2260版\\n\\n### **十分感谢上面这些学习项目，感谢！！\",\"articleCover\":\"http://ws.aqi125.cn/articles/ce2c679ebaefd4c082c84e37eaa05d78.jpeg\",\"articleTitle\":\"2023-03-13\",\"categoryName\":\"linux游戏服务器部署\",\"id\":139,\"isFeatured\":0,\"isTop\":0,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '110.184.180.10', '中国|四川省|成都市|电信', '2023-03-13 22:08:20', NULL);
INSERT INTO `t_operation_log` VALUES (1733, '文章模块', '上传', '/admin/articles/images', 'com.aurora.controller.ArticleController.saveArticleImages', '上传文章图片', 'file', 'POST', '{\"code\":20000,\"data\":\"http://ws.aqi125.cn/articles/e951a9b164bd1124d28e874eabb6d079.jpg\",\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '110.184.180.10', '中国|四川省|成都市|电信', '2023-03-13 22:15:57', NULL);
INSERT INTO `t_operation_log` VALUES (1734, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# Linux下架设部署left4dead2服务器\\n\\n## 更新\\n\\n```\\nyum update\\ny\\n```\\n\\n## 安装screen \\n\\n```\\nyum install screen\\n```\\n\\n## 在root根目录下创建一个Steam文件夹：\\n\\n```\\nmkdir ~/Steam \\n```\\n\\n## 进入Steam文件夹：\\n\\n```\\ncd ~/Steam\\n```\\n\\n## 下载并解压SteamCMD\\n\\n```\\nwget https://steamcdn-a.akamaihd.net/client/installer/steamcmd_linux.tar.gz\\ntar -xzvf steamcmd_linux.tar.gz\\n```\\n\\n## 运行SteamCMD安装脚本\\n\\n```\\n./steamcmd.sh\\n```\\n\\n## 输入指令匿名登录即可：\\n\\n```\\nlogin anonymous \\n```\\n\\n## 下载求生之路2的服务端：\\n\\n```\\napp_update 222860 validate\\n```\\n\\n## 退出\\n\\n```\\nquit\\n```\\n\\n## 试运行服务器\\n\\n```\\ncd ~/Steam/steamapps/common/\\\"Left 4 Dead 2 Dedicated Server\\\"/\\n```\\n\\nNote：tab键可以补全代码，善用tab键可以提升速度并有效减少错误。\\n\\n## 然后建立一个托盘并进入(coop可替换成自己想要的名称)：\\n\\n```\\nscreen -S coop \\n./srcds_run -game left4dead2 -condebug -insecure +port 27015 +map c2m1_highway +exec server.cfg -tickrate 100 \\n./srcds_run -game left4dead2（启动）\\n-condebug -insecure +port 27015（端口） \\n+map c2m1_highway（地图章节） \\n+exec server.cfg（加载模式） -tickrate 100 （tick设置）\\n```\\n\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/e951a9b164bd1124d28e874eabb6d079.jpg\",\"articleTitle\":\"2023-03-13\",\"categoryName\":\"linux游戏服务器部署\",\"isFeatured\":0,\"isTop\":0,\"status\":1,\"tagNames\":[\"left4dead2\",\"求生之路2\"],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '110.184.180.10', '中国|四川省|成都市|电信', '2023-03-13 22:15:59', NULL);
INSERT INTO `t_operation_log` VALUES (1735, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# Linux下架设部署left4dead2服务器\\n\\n## 更新\\n\\n```yaml\\nyum update\\ny\\n```\\n\\n## 安装screen \\n\\n```yaml\\nyum install screen\\n```\\n\\n## 在root根目录下创建一个Steam文件夹：\\n\\n```yaml\\nmkdir ~/Steam \\n```\\n\\n## 进入Steam文件夹：\\n\\n```yaml\\ncd ~/Steam\\n```\\n\\n## 下载并解压SteamCMD\\n\\n```yaml\\nwget https://steamcdn-a.akamaihd.net/client/installer/steamcmd_linux.tar.gz\\ntar -xzvf steamcmd_linux.tar.gz\\n```\\n\\n## 运行SteamCMD安装脚本\\n\\n```yaml\\n./steamcmd.sh\\n```\\n\\n## 输入指令匿名登录即可：\\n\\n```yaml\\nlogin anonymous \\n```\\n\\n## 下载求生之路2的服务端：\\n\\n```yaml\\napp_update 222860 validate\\n```\\n\\n## 退出\\n\\n```yaml\\nquit\\n```\\n\\n## 试运行服务器\\n\\n```yaml\\ncd ~/Steam/steamapps/common/\\\"Left 4 Dead 2 Dedicated Server\\\"/\\n```\\n\\nNote：tab键可以补全代码，善用tab键可以提升速度并有效减少错误。\\n\\n## 然后建立一个托盘并进入(coop可替换成自己想要的名称)：\\n\\n```yaml\\nscreen -S coop \\n./srcds_run -game left4dead2 -condebug -insecure +port 27015 +map c2m1_highway +exec server.cfg -tickrate 100 \\n./srcds_run -game left4dead2（启动）\\n-condebug -insecure +port 27015（端口） \\n+map c2m1_highway（地图章节） \\n+exec server.cfg（加载模式） -tickrate 100 （tick设置）\\n```\\n\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/e951a9b164bd1124d28e874eabb6d079.jpg\",\"articleTitle\":\"2023-03-13\",\"categoryName\":\"linux游戏服务器部署\",\"id\":140,\"isFeatured\":0,\"isTop\":0,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '110.184.180.10', '中国|四川省|成都市|电信', '2023-03-13 22:18:41', NULL);
INSERT INTO `t_operation_log` VALUES (1736, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# Linux下架设部署left4dead2服务器\\n\\n## 更新\\n\\n```yaml\\nyum update\\ny\\n```\\n\\n## 安装screen \\n\\n```yaml\\nyum install screen\\n```\\n\\n## 在root根目录下创建一个Steam文件夹：\\n\\n```yaml\\nmkdir ~/Steam \\n```\\n\\n## 进入Steam文件夹：\\n\\n```yaml\\ncd ~/Steam\\n```\\n\\n## 下载并解压SteamCMD\\n\\n```yaml\\nwget https://steamcdn-a.akamaihd.net/client/installer/steamcmd_linux.tar.gz\\ntar -xzvf steamcmd_linux.tar.gz\\n```\\n\\n## 运行SteamCMD安装脚本\\n\\n```yaml\\n./steamcmd.sh\\n```\\n\\n## 输入指令匿名登录即可：\\n\\n```yaml\\nlogin anonymous \\n```\\n\\n## 下载求生之路2的服务端：\\n\\n```yaml\\napp_update 222860 validate\\n```\\n\\n## 退出\\n\\n```yaml\\nquit\\n```\\n\\n## 试运行服务器\\n\\n```yaml\\ncd ~/Steam/steamapps/common/\\\"Left 4 Dead 2 Dedicated Server\\\"/\\n```\\n\\nNote：tab键可以补全代码，善用tab键可以提升速度并有效减少错误。\\n\\n## 然后建立一个托盘并进入(coop可替换成自己想要的名称)：\\n\\n```yaml\\nscreen -S coop \\n./srcds_run -game left4dead2 -condebug -insecure +port 27015 +map c2m1_highway +exec server.cfg -tickrate 100 \\n./srcds_run -game left4dead2（启动）\\n-condebug -insecure +port 27015（端口） \\n+map c2m1_highway（地图章节） \\n+exec server.cfg（加载模式） -tickrate 100 （tick设置）\\n```\\n\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/e951a9b164bd1124d28e874eabb6d079.jpg\",\"articleTitle\":\"2022-04-30\",\"categoryName\":\"linux游戏服务器部署\",\"id\":140,\"isFeatured\":0,\"isTop\":0,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '110.184.180.10', '中国|四川省|成都市|电信', '2023-03-13 22:21:28', NULL);
INSERT INTO `t_operation_log` VALUES (1737, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# Linux下架设部署left4dead2服务器\\n\\n## 更新\\n\\n```yaml\\nyum update\\ny\\n```\\n\\n## 安装screen \\n\\n```yaml\\nyum install screen\\n```\\n\\n## 在root根目录下创建一个Steam文件夹：\\n\\n```yaml\\nmkdir ~/Steam \\n```\\n\\n## 进入Steam文件夹：\\n\\n```yaml\\ncd ~/Steam\\n```\\n\\n## 下载并解压SteamCMD\\n\\n```yaml\\nwget https://steamcdn-a.akamaihd.net/client/installer/steamcmd_linux.tar.gz\\ntar -xzvf steamcmd_linux.tar.gz\\n```\\n\\n## 运行SteamCMD安装脚本\\n\\n```yaml\\n./steamcmd.sh\\n```\\n\\n## 输入指令匿名登录即可：\\n\\n```yaml\\nlogin anonymous \\n```\\n\\n## 下载求生之路2的服务端：\\n\\n```yaml\\napp_update 222860 validate\\n```\\n\\n## 退出\\n\\n```yaml\\nquit\\n```\\n\\n## 试运行服务器\\n\\n```yaml\\ncd ~/Steam/steamapps/common/\\\"Left 4 Dead 2 Dedicated Server\\\"/\\n```\\n\\nNote：tab键可以补全代码，善用tab键可以提升速度并有效减少错误。\\n\\n## 然后建立一个托盘并进入(coop可替换成自己想要的名称)：\\n\\n```yaml\\nscreen -S coop \\n./srcds_run -game left4dead2 -condebug -insecure +port 27015 +map c2m1_highway +exec server.cfg -tickrate 100 \\n./srcds_run -game left4dead2（启动）\\n-condebug -insecure +port 27015（端口） \\n+map c2m1_highway（地图章节） \\n+exec server.cfg（加载模式） -tickrate 100 （tick设置）\\n```\\n\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/e951a9b164bd1124d28e874eabb6d079.jpg\",\"articleTitle\":\"left4dead2\",\"categoryName\":\"linux游戏服务器部署\",\"id\":140,\"isFeatured\":0,\"isTop\":0,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '110.184.180.10', '中国|四川省|成都市|电信', '2023-03-13 22:22:44', NULL);
INSERT INTO `t_operation_log` VALUES (1738, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# 黑色沙漠服务端优化\\n\\n## **项目前言**\\n\\n本项目是5月15号部署完黑色沙漠局域网的时候，游戏延迟明显操作卡顿，主线任务bug很多，给爷整烦了，爷干脆来了一个延迟的优化，目前第一阶段优化已经完成，功能对比市面上其他一键端较为完善，客户端编写花费时间较后端少，因为黑沙客户端比较多，有些拿来改改就行，比如2100、795、661、602等版本 。而2016 server数据中心版上手很容易，在学习完了狂神大大的视频后，趁热做的一个练手项目，可能会有很多bug，敬请原谅~~\\n\\n## **项目预览**\\n\\n- 优化前：延迟在200ms浮动\\n- ​![0u2.jpg](http://ws.aqi125.cn/articles/63c32e91c1b5c3f8bdeb8faaacceb722.jpg)                                                              \\n- ![0u1.jpg](http://ws.aqi125.cn/articles/33feae1b9c4aac1eb0913e5153c2f0b4.jpg)        \\n- 优化后：经过硬件，服务端综合优化后基本稳定在30ms左右\\n- ​![0u.jpg](https://ws.aqi125.cn/articles/bc82c383ff37c5afa171c9a43788e036.jpg)  \\n- 综合起来看这样\\n- ![01.jpg](https://ws.aqi125.cn/articles/b875a757569bbdcfcac476b8cf5619e8.jpg)\\n\\n## **项目描述**\\n\\n整体优化分为两个模块：一个是­­­硬件优化，一个是服务端环境及代码优化。\\n\\n# 一. 硬件优化模块：\\n\\n服务器原型机2H4G（单通道）加装内存条，组成2H12G（双通道）。在安装完后通过实际测试延迟仅仅降到了100ms左右，在高数据并发复杂环境下依然会卡顿操作不流畅，开始了服务端环境整合和动态加载的代码优化（工作量偏大）。\\n\\n- ![02.jpg](https://ws.aqi125.cn/articles/d1007544ba7580a1ec1911ab80cb8c35.jpg)\\n\\n# **二**.服务端优化模块：\\n\\n服务端优化分三个子项目\\n\\n## 1.服务端环境优化:\\n\\n Windows7升至Windows server 2016 **Datacenter edition** （升级前数据库及数据文件压缩打包避免损坏）\\n\\n## 2.数据库简化：\\n\\nrobo3t简化到MongoDBCompass官方工具避免数据库多次查询。\\n\\n## 3.代码优化：\\n\\ngameserver\\\\bing\\\\configs\\\\godata.properties随便找一个编码软件打开，geo.dynamic.load=true（动态加载）改为false（静态加载）地图加载程度改为——geo.terrrain.lod_level =0 geo.conllision.lod_level=0。ok服务端优化完成基本稳定在30ms了。\\n\\n### **硬件**\\n\\n加个内存条这不有手就行。\\n\\n### **服务端（升级系统也是有手就行。）**\\n\\n| **名称** | **技术点**                                 |\\n| -------- | ------------------------------------------ |\\n| 系统     | Windows server 2016 **Datacenter edition** |\\n| 数据库   | robo3t+MongoDBCompass                      |\\n| 端口     | 27017                                      |\\n| 代码     | godata.properties ， jwt                   |\\n| 其他     | Tcp/ip，服务器连接开放                     |\\n\\n### **关于开源**\\n\\n代码部分已上传GitHub，欢迎给个star~ ，有能力的朋友，可以请我喝一杯奶茶。\\n\\n### **关于黑色沙漠2260第三改**\\n\\n现在陆陆续续有朋友加入了这个服务端的Organizations，给这个服务端提供了很大的帮助，同时也给了很棒的建议，在此十分感谢他们。\\n\\n### **关于我**\\n\\n由于我目前要做一个前后端分离的博客，后面可能没很大的精力投入这个服务端开发了，更新迭代的速度也会变慢。敬请原谅。如果有什么bug或者建议，可以及时联系我。\\n\\nqq:2316364297\\n\\n### **参考项目**\\n\\n游戏屋2260版\\n\\n### **十分感谢上面这些学习项目，感谢！！\",\"articleCover\":\"http://ws.aqi125.cn/articles/ce2c679ebaefd4c082c84e37eaa05d78.jpeg\",\"articleTitle\":\"黑色沙漠\",\"categoryName\":\"linux游戏服务器部署\",\"id\":139,\"isFeatured\":0,\"isTop\":0,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '110.184.180.10', '中国|四川省|成都市|电信', '2023-03-13 22:22:56', NULL);
INSERT INTO `t_operation_log` VALUES (1739, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# 服务器要求\\n\\n介绍一下rust服务器的部署流程以及踩的一些坑，给需要部署的朋友以借鉴。\\n内存：4G能满足5-10个人同时进行游戏，内存越大，支持的人数越多。推荐8G以上。\\n硬盘：40G以上,服务端有6G左右。\\n网络：8M~20M上行带宽，Rust服务器懂得都懂，最好弄高防御的服务器或者配置网络防御能力。\\n\\n# 一 服务器环境配置\\n\\n## 1. 根目录\\n\\n```language\\ncd\\n```\\n\\n## 2. 更新\\n\\n```language\\nyum check-update\\nyum update\\n```\\n\\n# 二 服务器安装依赖\\n\\n## 2.1. Cenos\\n\\n```language\\nyum install epel-release\\nyum install curl wget tar bzip2 gzip unzip python3 binutils bc jq tmux glibc.i686 libstdc++ libstdc++.i686 zlib-devel\\n```\\n\\n## 2.2. Ubuntu\\n\\n```language\\nsudo dpkg --add-architecture i386; sudo apt update; sudo apt install curl wget file tar bzip2 gzip unzip bsdmainutils python util-linux ca-certificates binutils bc jq tmux netcat lib32gcc1 lib32stdc++6 libsdl2-2.0-0:i386 steamcmd lib32z1\\n```\\n\\n## 2.3. 添加服务器-——————进入服务器\\n\\n```language\\nadduser rustserver      su - rustserver \\n```\\n\\n# 三 镜像\\n\\n## 3.1.下载 linuxgsm.sh ps国内镜像\\n\\n```language\\nwget -O cn-start.sh https://gitee.com/DefiedParty/LinuxGSM/raw/master/cn-start.sh && chmod +x cn-start.sh && bash cn-start.sh rustserver\\n```\\n\\n## 3.2. 镜像下载好后初始化rustservr\\n\\n```language\\nbash linuxgsm.sh rustserver\\n```\\n\\n## 3.3.安装服务器 大概4个G \\n\\n```language\\n./rustserver install\\n```\\n\\n# 四 rust服务器参数配置\\n\\n## 4.1.路径\\n\\n```language\\nnano /home/rustserver/serverfiles/server/rustserver/cfg/server.cfg\\n```\\n\\n## 4.2.进入rustserver文件夹\\n\\n```language\\ncd /home/rustserver/lgsm/config-lgsm/rustserver\\n```\\n\\n## 4.3.列表\\n\\n```language\\nls\\n```\\n\\n## 4.4.打开rustserver.cfg\\n\\n```language\\ncat rustserver.cfg\\n```\\n\\n## 4.5.覆盖\\n\\n```language\\ncp _default.cfg  rustserver.cfg\\n```\\n\\n## 4.6. 打开 rustserver.cfg\\n\\n```language\\nnano rustserver.cfg（ctrl+o保存 ctrl+v退出 ）\\n```\\n\\n# 五 安装oxide\\n\\n```language\\n./rustserver mods-install\\nrustoxide\\n```\\n\\n# 六 服务器基础操作\\n\\n## 6.1.进入         6.2.启动   \\t 6.3.停止 \\t 6.4.更新 \\t\\n\\n```language\\nsu - rustserver  ./rustserver start ./rustserver stop  ./rustserver update \\n```\\n\\n## 6.5.查看  6.6重启 6.7.运行时查看服务器的实时控制台并允许您输入命令\\n\\n```language\\n  ./rustserver ./rustserver restartdetails ./rustserver console\\n```\\n\\n# 七 Oxide操作\\n\\n## 7.1.更新oxide最新版本\\n\\n```language\\n./rustserver mods-update\\n```\\n\\n## 7.2.oxide插件存放目录\\n\\n```language\\ncd serverfiles/oxide/plugins\\n```\\n\\n## 7.3.退出控制台\\n\\n```language\\nCTRL+b d\\n./rustserver stop\\n```\\n\\n# 八 进入游戏\\n\\n```language\\nconnect 你的ip加端口号\\n```\\n![v2c01bbb1e094b37d0b04916c1b370ca66_1440w.jpg](https://ws.aqi125.cn/articles/59542fe2f3e7a54619deb569754064cd.jpg)\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/58727c4b325ec745599cbc08b1cf8efe.jpeg\",\"articleTitle\":\"RUST\",\"categoryName\":\"linux游戏服务器部署\",\"id\":138,\"isFeatured\":0,\"isTop\":0,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '110.184.180.10', '中国|四川省|成都市|电信', '2023-03-13 22:23:10', NULL);
INSERT INTO `t_operation_log` VALUES (1740, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"## 部署过程中遇到的问题\\n\\n首先docker基本命令\\n\\n进入Centos命令行\\n\\n```dockerfile\\n1.首先切换到 root：su -root\\n2.进入 /bin 目录：cd /bin\\n3.执行命令：systemctl stop firewalld.service（关闭防火墙)\\nsystemctl disable firewalld.service（关闭防火墙自动启动）\\ndocker 命令\\ndocker ps 显示容器\\ndocker ps -a 列出所有的容器\\n#查看本地所有的镜像\\ndocker images\\ndocker rmi #镜像id  删除指定镜像\\ndocker restart  重新启动容器\\ndocker kill +id 杀死指定容器\\ndocker rm -f  删除指定容器\\n```\\n\\n## 安装minio遇到的问题\\n\\n通过这个报错信息，得知最近minio 升级，一些启动信息和之前不一样了。\\n\\t\\t日志报差错\\n\\t\\n\\n```日志\\n\\tWARNING: MINIO_ACCESS_KEY and MINIO_SECRET_KEY are deprecated.\\n\\t\\tPlease use MINIO_ROOT_USER and MINIO_ROOT_PASSWORD\\n\\t\\tWARNING: Detected Linux kernel version older than 4.0.0 release,\\n\\t\\tthere are some known potential performance problems\\n\\t\\twith this kernel version. MinIO recommends a minimum of 4.x. x\\n\\t\\tlinux kernel version for best performance\\n```\\n\\n### \\t\\t#安装镜像\\n\\n​\\t\\t\\n\\n```dockerfile\\ndocker run \\\\\\n\\t\\t--name minio \\\\\\n\\t\\t-p 9000:9000 \\\\\\n\\t\\t-p 9090:9090 \\\\\\n\\t\\t-d --restart=always \\\\\\n\\t\\t-e \\\"MINIO_ROOT_USER=admin\\\" \\\\\\n\\t\\t-e \\\"MINIO_ROOT_PASSWORD=admin123\\\" \\\\\\n\\t\\t-v /home/data:/data \\\\\\n\\t\\t-v /home/config:/root/.minio \\\\\\n\\t\\tminio/minio server /data --console-address \\\":9090\\\" --address \\\":9000\\\"‘\\n```\\n\\n#### \\t\\t日志\\n\\n```dockerfile\\ndocker logs minio\\n```\\n\\n#### \\t\\t再次报错版本太新了\\n\\n```\\nWARNING: Detected Linux kernel version older than 4.0.0 release, there are some known potential performance\\n\\t\\tproblems with this kernel version. MinIO recommends a minimum of 4.x.x linux kernel version for best performance\\n\\t\\tFormatting 1st pool, 1 set(s), 1 drives per set.\\n\\t\\tWARNING: Host local has more than 0 drives of set. A host failure will result in data becoming unavailable.\\n```\\n\\n\\n\\n### \\t\\t下载稳定版本\\n\\n​\\t\\t\\n\\n```dockerfile\\ndocker run -d -p 9000:9000 -p 9001:9001 --name minio --restart=always -e \\\"MINIO_ROOT_USER=密码\\\" -e \\\"MINIO_ROOT_PASSWORD=密码\\\" -v /minio/data:/data -v /minio/config:/root/.minio -v /etc/localtime:/etc/localtime minio/minio server /data --console-address \\\":9001\\\"\\n```\\n\\n## 导入Vue遇到的问题\\n\\n### 生成admin后台页面遇到的问题\\n\\n​\\t\\t缺少vue-echarts的使用\\n​\\t\\t解决方法\\n​\\t\\t\\n\\n```nginx\\nnpm install echarts vue-echarts\\n```\\n\\n### 生成blog前端页面遇到的问题\\n\\n​\\t\\t本机nodejs版本过高\\n​\\t\\t解决方法：\\n​\\t\\tnodejs降为node-v17.4.0-x64   对应npm版本为：8.3.1\\n​\\t\\tvue-cli的版本为：5.0.6\\n​\\t\\n\\n```nginx\\nvue卸载：npm uninstall vue-cli -g（3.0以下版本卸载）\\nnpm uninstall -g @vue/cli（3.0以上版本卸载）\\nvue安装：npm install -g @vue/cli （安装的是最新版）\\nnpm install vue-cli@2.9.6 （指定版本安装【指定版本为3.0以下版本】，其中2.9.6为版本号）\\nnpm install -g @vue/cli@5.0.6（指定版本安装【指定版本为3.0以上版本】，其中5.0.6为版本号）\\nvue版本查看：vue -V\\n```\\n\\n\\n## 前端页面遇到的问题上传图片加载失败\\n\\n![image20230223225305778.png](https://ws.aqi125.cn/articles/e8f5895c7a5010a9ee2b5cd89bee78c8.png)\\n\\n### 原因minio未配置https\\n\\n### 解决方法\\n```nginx\\n   server {\\n   listen  443 ssl;\\n    server_name 二级域名n;\\n\\n    ssl on;\\n    ssl_certificate /etc/nginx/cert/二级域名_bundle.pem; \\n    ssl_certificate_key /etc/nginx/cert/二级域名.key; \\n    ssl_session_timeout 5m;\\n    ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n    ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n    ssl_prefer_server_ciphers on;\\n\\n    location / {\\n        proxy_pass http://服务器ip:9000/aurora/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n\\n}\\n server {\\n    listen 80;\\n    server_name 二级域名;\\n    location / {\\n        proxy_pass http://服务器ip:9000/aurora/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n}\\n\\nserver {\\n    listen 9000;\\n    server_name 二级域名;\\n    location / {\\n        proxy_pass http://服务器ip:9000/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n}\\n}\\n```\\n## 前端页面遇到的问题上传好的图片回调加载失败\\n\\n![image20230223230053802.png](https://ws.aqi125.cn/articles/651c28e2d60914b845ec7616ee6dd4f7.png)\\n原因如下\\n\\n可以很清晰的看到http和https对不上\\n![image20230223230133757.png](https://ws.aqi125.cn/articles/b21afabcb05ce840ceb5c0a719aa057b.png)\\n\\n### 解决办法admin页面上传图片的时候直接在http后面加s\\n\\n![image20230223230505082.png](https://ws.aqi125.cn/articles/60b20926da1d814f712b111668f8ee3f.png)\\n\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/8e911b7de439f0ef5197740ce20ae4fc.jpg\",\"articleTitle\":\"blog部署\",\"categoryName\":\"blog部署\",\"id\":137,\"isFeatured\":0,\"isTop\":0,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '110.184.180.10', '中国|四川省|成都市|电信', '2023-03-13 22:23:54', NULL);
