INSERT INTO `t_operation_log` VALUES (1773, 'aurora信息', '修改', '/admin/website/config', 'com.aurora.controller.AuroraInfoController.updateWebsiteConfig', '更新网站配置', '[{\"alipayQRCode\":\"https://static.linhaojun.top/config/da4c6d8c13f66a8dd6716ddb48d73299.jpg\",\"author\":\"七七\",\"authorAvatar\":\"http://ws.aqi125.cn/config/6d93c4e2a2690ce5f742f42f8d80e365.jpg\",\"authorIntro\":\"一个疯狂的coder\",\"beianNumber\":\"豫ICP备2021007034号-1\",\"csdn\":\"\",\"englishName\":\"七七\",\"gitee\":\"https://gitee.com/aqily\",\"github\":\"https://github.com/linhaojun857\",\"isCommentReview\":0,\"isEmailNotice\":1,\"isReward\":1,\"juejin\":\"\",\"logo\":\"http://ws.aqi125.cn/config/6d93c4e2a2690ce5f742f42f8d80e365.jpg\",\"multiLanguage\":1,\"name\":\"aqi的小窝\",\"notice\":\"代码已经开源，如果你感觉还行就给一个star吧。。。\",\"qq\":\"\",\"qqLogin\":1,\"stackoverflow\":\"\",\"touristAvatar\":\"https://static.linhaojun.top/config/2af2e2db20740e712f0a011a6f8c9af5.jpg\",\"twitter\":\"\",\"userAvatar\":\"https://static.linhaojun.top/config/0af1901da1e64dfb99bb61db21e716c4.jpeg\",\"weChat\":\"\",\"websiteCreateTime\":\"2021-03-25\",\"weiXinQRCode\":\"https://static.linhaojun.top/config/ed47edae605f74306f751c6fba9f14bd.png\",\"weibo\":\"\",\"zhihu\":\"\"}]', 'PUT', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1, '演示账号', '110.184.181.186', '中国|四川省|成都市|电信', '2023-04-01 19:49:53', NULL);
