INSERT INTO `t_operation_log` VALUES (1808, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"前端配置Nginx完成后\\n\\n进到nginx使用./nginx -s reload重新读取配置文件，发现报\\n\\n```yaml\\n[root@aqi nginx]# cd conf/\\n[root@aqi conf]# cd ../sbin/\\n[root@aqi sbin]# ./nginx -s reload\\n   nginx: [error] open() \\\"/usr/local/nginx/logs/nginx.pid\\\" failed (2: No such file or directory)\\n```\\n\\n解决方法：\\n\\n```yaml\\n[root@aqi sbin]# /usr/local/nginx/sbin/nginx -c /usr/local/nginx/conf/nginx.conf\\n```\\n\\n理由：\\n　　使用nginx -c的参数指定nginx.conf文件的位置\\n部署完的图\\n![xcx.png](https://ws.aqi125.cn/articles/c1eb421e08842e0a272a300bfe9783bf.png)\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/c1eb421e08842e0a272a300bfe9783bf.png\",\"articleTitle\":\"小程序部署遇到的错误\",\"categoryName\":\"小程序\",\"id\":144,\"isFeatured\":1,\"isTop\":0,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '175.152.177.87', '中国|四川省|成都市|联通', '2023-06-29 00:37:55', NULL);
INSERT INTO `t_operation_log` VALUES (1809, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"## 前端配置Nginx完成后\\n\\n进到nginx使用./nginx -s reload重新读取配置文件，发现报\\n\\n```yaml\\n[root@aqi nginx]# cd conf/\\n[root@aqi conf]# cd ../sbin/\\n[root@aqi sbin]# ./nginx -s reload\\n   nginx: [error] open() \\\"/usr/local/nginx/logs/nginx.pid\\\" failed (2: No such file or directory)\\n```\\n\\n## 解决方法：\\n\\n```yaml\\n[root@aqi sbin]# /usr/local/nginx/sbin/nginx -c /usr/local/nginx/conf/nginx.conf\\n```\\n\\n## 理由：\\n\\n　　使用nginx -c的参数指定nginx.conf文件的位置\\n\\n## 部署完的图\\n![xcx.png](https://ws.aqi125.cn/articles/c1eb421e08842e0a272a300bfe9783bf.png)\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/c1eb421e08842e0a272a300bfe9783bf.png\",\"articleTitle\":\"小程序部署遇到的错误\",\"categoryName\":\"小程序\",\"id\":144,\"isFeatured\":1,\"isTop\":0,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '175.152.177.87', '中国|四川省|成都市|联通', '2023-06-29 00:39:42', NULL);
