INSERT INTO `t_operation_log` VALUES (1813, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"自建分布式文件存储MinIO容器化部署\\r\\n\\r\\n容器化MinIO账号密码忘记/丢失      \\r\\n\\r\\n保存容器内图片，文档，头像等数据重新设置密码复盘、\\r\\n\\r\\n第一步先看数据 找我们的后台账号后台密码\\r\\n\\r\\n```\\r\\ncd /data  #移动到存储目录\\r\\nll -a  #显示隐藏文件夹\\r\\n很明显没有我们想要的数据\\r\\ncd /minio/ #进入minio\\r\\ncd data/.minio.sys/config/\\r\\nls\\r\\nvim config.json #一样没我们旧的access_key账号和secretKey就用不了重新注册一个就好了\\r\\n```\\r\\n\\r\\n\\r\\n\\r\\n![](C:\\\\Users\\\\23163\\\\Pictures\\\\Screenshots\\\\MinIO\\\\微信图片_20230703184233.png)\\r\\n\\r\\n![](C:\\\\Users\\\\23163\\\\Pictures\\\\Screenshots\\\\MinIO\\\\微信图片_20230703184334.png)\\r\\n\\r\\n```\\r\\n#下面进daocker拷贝数据\\r\\ndocker ps -a\\r\\ndocker exec -it minio /bin/bash \\r\\ncd /data\\r\\nls\\r\\n\\r\\n```\\r\\n\\r\\n![](C:\\\\Users\\\\23163\\\\Pictures\\\\Screenshots\\\\MinIO\\\\微信图片_20230703190657.png)\\r\\n\\r\\n![](C:\\\\Users\\\\23163\\\\Pictures\\\\Screenshots\\\\MinIO\\\\微信图片_20230703190704.png)\\r\\n\\r\\n```\\r\\n准备cp数据\\r\\n#将容器中的文件拷贝出来 记住目录先不要粘贴操作\\r\\ndocker cp -a 容器id:/data/aurora /home/tom\\r\\n#删除容器\\r\\ndocker rm -f 容器名/容器ID\\r\\n#然后重新启动容器\\r\\ndocker run -d -p 9000:9000 -p 9001:9001 --name minio --restart=always -e \\\"MINIO_ROOT_USER=密码\\\" -e \\\"MINIO_ROOT_PASSWORD=密码\\\" -v /minio/data:/data -v /minio/config:/root/.minio -v /etc/localtime:/etc/localtime minio/minio server /data --console-address \\\":9001\\\"\\r\\n#将容器中的文件拷贝回去 数据恢复完成\\r\\ndocker cp -a /home/tom  容器ID:/data/aurora\\r\\n#这会儿minio后台账号密码就可以登录了，但是旧的accessKey和secretKey就用不了注册一个新的就好。\\r\\n```\\r\\n\\r\\n![](C:\\\\Users\\\\23163\\\\Pictures\\\\Screenshots\\\\MinIO\\\\微信图片_20230703192640.png)\\r\\n\\r\\n![](C:\\\\Users\\\\23163\\\\Pictures\\\\Screenshots\\\\MinIO\\\\微信图片_20230703192836.png)\",\"articleTitle\":\"MinIO容器化账号密码丢失数据无损重建账号密码\",\"id\":145,\"isFeatured\":0,\"isTop\":0,\"status\":3,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '171.221.218.100', '中国|四川省|成都市|电信', '2023-07-03 19:33:39', NULL);
