INSERT INTO `t_operation_log` VALUES (1821, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"自建分布式文件存储MinIO容器化部署\\n\\n容器化MinIO账号密码忘记/丢失      \\n\\n保存容器内图片，文档，头像等数据重新设置密码复盘、\\n\\n## 一，先看数据 找我们的后台账号后台密码\\n\\n```\\ncd /data  #移动到存储目录\\nll -a  #显示隐藏文件夹\\n很明显没有我们想要的数据\\ncd /minio/ #进入minio\\ncd data/.minio.sys/config/\\nls\\nvim config.json #一样没我们的minio账号和密码\\n```\\n\\n\\n![微信图片_20230703184233.png](https://ws.aqi125.cn/articles/2568d8a4b3ec25a615d4c8a672bf5fb7.png)\\n\\n![微信图片_20230703184334.png](https://ws.aqi125.cn/articles/f3fdbf6425639f7a56911de3d5bc090d.png)\\n\\n## 二，进docker\\n\\n```\\n#下面进daocker拷贝数据\\ndocker ps -a\\ndocker exec -it minio /bin/bash \\ncd /data\\nls\\n\\n```\\n\\n![微信图片_20230703190657.png](https://ws.aqi125.cn/articles/7f3ead4a5e6ac7cdc138d96d171f609a.png)\\n![微信图片_20230703190704.png](https://ws.aqi125.cn/articles/6fcc153a8b86dff896b7eaea8fe67e76.png)\\n\\n## 三，数据恢复与注册新账号和密码还有新accessKey和secretKey\\n\\n```\\n准备cp数据\\n#将容器中的文件拷贝出来 记住目录先不要粘贴操作\\ndocker cp -a 容器id:/data/aurora /home/tom\\n#删除容器\\ndocker rm -f 容器名/容器ID\\n#然后重新启动容器\\ndocker run -d -p 9000:9000 -p 9001:9001 --name minio --restart=always -e \\\"MINIO_ROOT_USER=密码\\\" -e \\\"MINIO_ROOT_PASSWORD=密码\\\" -v /minio/data:/data -v /minio/config:/root/.minio -v /etc/localtime:/etc/localtime minio/minio server /data --console-address \\\":9001\\\"\\n#将容器中的文件拷贝回去 数据恢复完成\\ndocker cp -a /home/tom  容器ID:/data/aurora\\n#这会儿minio后台账号密码就可以登录了，但是旧的accessKey和secretKey用不了，就重新注册一个新的就好。\\n客户端accessKey和secretKey也换成新。\\n```\\n\\n![微信图片_20230703192640.png](https://ws.aqi125.cn/articles/2f293c46e36aedcffb0379f43b08ea58.png)\\n\\n![微信图片_20230703192836.png](https://ws.aqi125.cn/articles/917ec0e48b391aaf1c246a89156682a2.png)\\n\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/9346d9f4ad2d94dd82e6436465cc5865.jpg\",\"articleTitle\":\"MinIO容器化账号密码丢失数据无损重建账号密码\",\"categoryName\":\"分布式文件存储\",\"isFeatured\":1,\"isTop\":0,\"status\":1,\"tagNames\":[\"MinIO容器化\"],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '171.221.218.100', '中国|四川省|成都市|电信', '2023-07-03 19:44:03', NULL);
INSERT INTO `t_operation_log` VALUES (1822, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"自建分布式文件存储MinIO容器化部署\\n\\n容器化MinIO账号密码忘记/丢失      \\n\\n保存容器内图片，文档，头像等数据重新设置密码复盘、\\n\\n## 一，先看数据 找我们的后台账号后台密码\\n\\n```yaml\\ncd /data  #移动到存储目录\\nll -a  #显示隐藏文件夹\\n很明显没有我们想要的数据\\ncd /minio/ #进入minio\\ncd data/.minio.sys/config/\\nls\\nvim config.json #一样没我们的minio账号和密码\\n```\\n\\n![微信图片_20230703184233.png](https://ws.aqi125.cn/articles/2568d8a4b3ec25a615d4c8a672bf5fb7.png)\\n\\n![微信图片_20230703184334.png](https://ws.aqi125.cn/articles/f3fdbf6425639f7a56911de3d5bc090d.png)\\n\\n## 二，进docker\\n\\n```yaml\\n#下面进daocker拷贝数据\\ndocker ps -a\\ndocker exec -it minio /bin/bash \\ncd /data\\nls\\n\\n```\\n\\n![微信图片_20230703190657.png](https://ws.aqi125.cn/articles/7f3ead4a5e6ac7cdc138d96d171f609a.png)\\n![微信图片_20230703190704.png](https://ws.aqi125.cn/articles/6fcc153a8b86dff896b7eaea8fe67e76.png)\\n\\n## 三，数据恢复与注册新账号和密码还有新accessKey和secretKey\\n\\n```yaml\\n准备cp数据\\n#将容器中的文件拷贝出来 记住目录先不要粘贴操作\\ndocker cp -a 容器id:/data/aurora /home/tom\\n#删除容器\\ndocker rm -f 容器名/容器ID\\n#然后重新启动容器\\ndocker run -d -p 9000:9000 -p 9001:9001 --name minio --restart=always -e \\\"MINIO_ROOT_USER=密码\\\" -e \\\"MINIO_ROOT_PASSWORD=密码\\\" -v /minio/data:/data -v /minio/config:/root/.minio -v /etc/localtime:/etc/localtime minio/minio server /data --console-address \\\":9001\\\"\\n#将容器中的文件拷贝回去 数据恢复完成\\ndocker cp -a /home/tom  容器ID:/data/aurora\\n#这会儿minio后台账号密码就可以登录了，但是旧的accessKey和secretKey用不了，就重新注册一个新的就好。\\n客户端accessKey和secretKey也换成新。\\n```\\n\\n![微信图片_20230703192640.png](https://ws.aqi125.cn/articles/2f293c46e36aedcffb0379f43b08ea58.png)\\n\\n![微信图片_20230703192836.png](https://ws.aqi125.cn/articles/917ec0e48b391aaf1c246a89156682a2.png)\\n\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/9346d9f4ad2d94dd82e6436465cc5865.jpg\",\"articleTitle\":\"MinIO容器化账号密码丢失数据无损重建账号密码\",\"categoryName\":\"分布式文件存储\",\"id\":146,\"isFeatured\":1,\"isTop\":0,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '171.221.218.100', '中国|四川省|成都市|电信', '2023-07-03 19:47:15', NULL);
