INSERT INTO `t_operation_log` VALUES (1830, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"## 被勒索删库。\\n\\n昨天测试微服务的时候进库看了看，经典mysql 3306连不上，然后进docker mysql 并设置远程访问，一通操作下来Navicat 远程连接mysql 成功！然后不出意料的BTC ！![微信图片_20230721133137.png](https://ws.aqi125.cn/articles/2982888a7d2ac169f9e3495572af73f9.png)  然后还好这是测试库，而且本地有同步。兄弟萌mysql远程连接密码别设root了 。开始处理遗留问题，从删库开始\\n\\n## 一：改mysql端口\\n\\n### 1.查看所有容器列表（包含 正在运行 和 已停止的）\\n\\n```yaml\\ndocker ps -a\\n```\\n\\n### 2.删除一个容器\\n\\n```yaml\\ndocker rm -f 容器名/容器ID\\n```\\n\\n### 3.创建容器并配置\\n\\n```yaml\\ndocker run --name mysql --restart=always -p 端口号:端口号 -e MYSQL_ROOT_PASSWORD=密码这次设复杂点 -d mysql \\n```\\n\\n### 4.进容器\\n\\n```yaml\\ndocker exec -it mysql bash\\n```\\n\\n### 5.cd 到/etc/mysql文件夹，修改 my.cnf \\n\\n```yaml\\ncd /etc/mysql  \\nvim my.cnf (打不开 安装 vim 命令)\\n```\\n\\n### 6.安装 vim 命令并修改端口号\\n\\n```yaml\\napt-get update \\napt-get install vim\\n或\\nyum update\\nyum install vim\\n\\nvim /etc/mysql/my.cnf\\n```\\n\\n![1690029108930.jpg](https://ws.aqi125.cn/articles/908f38e8b4f2d462f3ab41b1db24f69f.jpg)\\n\\n### 7.改好重启容器\\n\\n```yaml\\ndocker restart mysql-test\\n```\\n\\n### 8.登录mysql查看端口\\n\\n```yaml\\nshow global variables like \'port\';\\n```\\n\\n## 二：然后开始动mysql 做限制ip登录并限制链接次数\\n\\n### 1.连接到mysql 的容器\\n\\n```yaml\\ndocker exec -it mysql bash\\n```\\n\\n### 2.登录mysql\\n\\n```yaml\\nmysql -h localhost -u root -p\\n```\\n\\n### 3.配置密码并限制ip登录\\n\\n```mysql\\nCREATE USER \'用户名\'@\'IP地址\' IDENTIFIED BY \'密码\'; \\nGRANT ALL ON *.* TO \'用户名\'@\'IP地址\'; \\nALTER USER \'用户名\'@\'IP地址\' IDENTIFIED WITH mysql_native_password BY \'密码\';\\n```\\n\\n### 4.Connection-Control插件安装\\n\\n```mysql\\nINSTALL PLUGIN CONNECTION_CONTROL SONAME \'connection_control.so\';\\nINSTALL PLUGIN CONNECTION_CONTROL_FAILED_LOGIN_ATTEMPTS SONAME \'connection_control.so\';\\n```\\n\\n\\n\\n### 5.为防止彩虹表暴力破解限制登录次数\\n\\n```mysql\\n# 最多连续4次错误登录\\nSET GLOBAL connection_control_failed_connections_threshold = 3;\\n# 休眠5000毫秒后再次尝试建立连接\\nSET GLOBAL connection_control_min_connection_delay = 5000;\\n\\n```\\n\\n#### 6.刷新权限\\n\\n```mysql\\nFLUSH PRIVILEGES;\\n```\\n![1690031246997.png](https://ws.aqi125.cn/articles/aeffb41f12888c79e742fce2e53c2d62.png)\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/aeffb41f12888c79e742fce2e53c2d62.png\",\"articleTitle\":\"被勒索删库了，root密码太简单\",\"categoryName\":\"Docker mysql\",\"id\":147,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '119.4.21.107', '中国|四川省|成都市|联通', '2023-07-22 21:08:51', NULL);
INSERT INTO `t_operation_log` VALUES (1831, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"## 被勒索删库。\\n\\n昨天测试微服务的时候进库看了看，经典mysql 3306连不上，然后进docker mysql 并设置远程访问，一通操作下来Navicat 远程连接mysql 成功！然后不出意料的BTC ！![微信图片_20230721133137.png](https://ws.aqi125.cn/articles/2982888a7d2ac169f9e3495572af73f9.png)  然后还好这是测试库，而且本地有同步。兄弟萌mysql远程连接密码别设root了 。开始处理遗留问题，从删库开始\\n\\n## 一：改mysql端口\\n\\n### 1.查看所有容器列表（包含 正在运行 和 已停止的）\\n\\n```yaml\\ndocker ps -a\\n```\\n\\n### 2.删除一个容器\\n\\n```yaml\\ndocker rm -f 容器名/容器ID\\n```\\n\\n### 3.创建容器并配置\\n\\n```yaml\\ndocker run --name mysql --restart=always -p 端口号:端口号 -e MYSQL_ROOT_PASSWORD=密码这次设复杂点 -d mysql \\n```\\n\\n### 4.进容器\\n\\n```yaml\\ndocker exec -it mysql bash\\n```\\n\\n### 5.cd 到/etc/mysql文件夹，修改 my.cnf \\n\\n```yaml\\ncd /etc/mysql  \\nvim my.cnf (打不开 安装 vim 命令)\\n```\\n\\n### 6.安装 vim 命令并修改端口号\\n\\n```yaml\\napt-get update \\napt-get install vim\\n或\\nyum update\\nyum install vim\\n\\nvim /etc/mysql/my.cnf\\n```\\n\\n![1690029108930.jpg](https://ws.aqi125.cn/articles/908f38e8b4f2d462f3ab41b1db24f69f.jpg)\\n\\n### 7.改好重启容器\\n\\n```yaml\\ndocker restart mysql-test\\n```\\n\\n### 8.登录mysql查看端口\\n\\n```yaml\\nshow global variables like \'port\';\\n```\\n\\n## 二：然后开始动mysql 做限制ip登录并限制链接次数\\n\\n### 1.连接到mysql 的容器\\n\\n```yaml\\ndocker exec -it mysql bash\\n```\\n\\n### 2.登录mysql\\n\\n```yaml\\nmysql -h localhost -u root -p\\n```\\n\\n### 3.配置密码并限制ip登录\\n\\n```mysql\\nCREATE USER \'用户名\'@\'IP地址\' IDENTIFIED BY \'密码\'; \\nGRANT ALL ON *.* TO \'用户名\'@\'IP地址\'; \\nALTER USER \'用户名\'@\'IP地址\' IDENTIFIED WITH mysql_native_password BY \'密码\';\\n```\\n\\n### 4.Connection-Control插件安装\\n\\n```mysql\\nINSTALL PLUGIN CONNECTION_CONTROL SONAME \'connection_control.so\';\\nINSTALL PLUGIN CONNECTION_CONTROL_FAILED_LOGIN_ATTEMPTS SONAME \'connection_control.so\';\\n```\\n\\n\\n\\n### 5.为防止彩虹表暴力破解限制登录次数\\n\\n```mysql\\n# 最多连续4次错误登录\\nSET GLOBAL connection_control_failed_connections_threshold = 3;\\n# 休眠5000毫秒后再次尝试建立连接\\nSET GLOBAL connection_control_min_connection_delay = 5000;\\n\\n```\\n\\n### 6.刷新权限\\n\\n```mysql\\nFLUSH PRIVILEGES;\\n```\\n![1690031246997.png](https://ws.aqi125.cn/articles/aeffb41f12888c79e742fce2e53c2d62.png)\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/aeffb41f12888c79e742fce2e53c2d62.png\",\"articleTitle\":\"被勒索删库了，root密码太简单\",\"categoryName\":\"Docker mysql\",\"id\":147,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '119.4.21.107', '中国|四川省|成都市|联通', '2023-07-22 21:09:52', NULL);
