INSERT INTO `t_operation_log` VALUES (1841, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"## 中间件\\n\\n中间件是什么？英文名称为Middleware，是一种应用于分布式系统的基础软件。从纵向层次来看，中间件位于各类应用/服务与操作系统/数据库系统以及其他系统软件之间，主要解决分布式环境下数据传输、数据访问、应用调度、系统构建和系统集成、流程管理等问题，是分布式环境下支撑应用开发、运行和集成的平台，能够实现系统之间的互联互通，帮助用户高效开发应用软件。\\n\\n## Nacos\\n\\nNacos是阿里的一个开源产品，它是针对微服务架构中的服务发现、配置管理、服务治理的综合型解决方案。\\n\\n这两天搞中间件踩的坑不少先说Nacos，要解决什么问题？\\n\\nNacos配置中心持久化到外部数据库中\\n\\n```yaml\\n#本机环境\\n#Windows11专业版\\n#Nacos:1.4.1 /对应下载地址 有Windows/liunx看需要下载\\nhttps://github.com/alibaba/nacos/releases/tag/1.4.1\\n#Mysql:8.0.32\\n```\\n\\n## 配置mysql数据库\\n\\n### 1.mysql安装完毕后，创建nacos数据库nacos_config，数据库sql文件：\\n\\n```html\\nhttps://github.com/alibaba/nacos/blob/1.4.1/config/src/main/resources/META-INF/nacos-db.sql\\n```\\n\\n### 2.修改在conf目录下的application.properties文件\\n\\n修改完成后重启 nacos，以后所有数据都会持久化到mysql中，进conf文件夹下\\n\\n修改application.properties文件改成这样：\\n\\n```sql\\n# db mysql\\n \\ndb.driver-class-name=com.mysql.cj.jdbc.Driver  \\n\\nspring.datasource.platform=mysql\\n\\n### Count of DB:\\ndb.num=1\\n\\n### Connect URL of DB:我这里不是nacos_config \\ndb.url.0=jdbc:mysql://192.168.124.4:3306/aqi_nacos?characterEncoding=utf8&connectTimeout=1000&socketTimeout=3000&autoReconnect=true&useUnicode=true&useSSL=false&serverTimezone=UTC\\ndb.user.0=root\\ndb.password.0=root\\n```\\n\\n![1690458641307.png](https://ws.aqi125.cn/articles/8dd2952efa466f7944f192b20afe616b.png)\\n\\n### 3.在bin目录下创建run.bat文件\\n\\n```c++\\nstartup.cmd -m standalone\\n```\\n\\n### 4.启动单击run.bat出现该界面成功\\n\\n![db4691f1024ad61c0ee77326d762e3f.png](https://ws.aqi125.cn/articles/d2da8ac91f8b121aa9a7380d3aacdd7b.png)\\n\\n![1690459626600.png](http://ws.aqi125.cn/articles/7ef9df26c8e5d30354f47b1684d54171.png)\\n\\n搞定收工，下面开始整另外一个中间件。\\n\\n\",\"articleCover\":\"\",\"articleTitle\":\"Nacos配置文件持久化到外部数据库\",\"isTop\":0,\"status\":3,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '175.152.152.195', '中国|四川省|成都市|联通', '2023-07-27 20:10:36', NULL);
INSERT INTO `t_operation_log` VALUES (1842, '文章模块', '上传', '/admin/articles/images', 'com.aurora.controller.ArticleController.saveArticleImages', '上传文章图片', 'file', 'POST', '{\"code\":20000,\"data\":\"http://ws.aqi125.cn/articles/5297e045738ebb26907ee74bb166d016.jpg\",\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '175.152.152.195', '中国|四川省|成都市|联通', '2023-07-27 20:13:20', NULL);
INSERT INTO `t_operation_log` VALUES (1843, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"## 中间件\\n\\n中间件是什么？英文名称为Middleware，是一种应用于分布式系统的基础软件。从纵向层次来看，中间件位于各类应用/服务与操作系统/数据库系统以及其他系统软件之间，主要解决分布式环境下数据传输、数据访问、应用调度、系统构建和系统集成、流程管理等问题，是分布式环境下支撑应用开发、运行和集成的平台，能够实现系统之间的互联互通，帮助用户高效开发应用软件。\\n\\n## Nacos\\n\\nNacos是阿里的一个开源产品，它是针对微服务架构中的服务发现、配置管理、服务治理的综合型解决方案。\\n\\n这两天搞中间件踩的坑不少先说Nacos，要解决什么问题？\\n\\nNacos配置中心持久化到外部数据库中\\n\\n```yaml\\n#本机环境\\n#Windows11专业版\\n#Nacos:1.4.1 /对应下载地址 有Windows/liunx看需要下载\\nhttps://github.com/alibaba/nacos/releases/tag/1.4.1\\n#Mysql:8.0.32\\n```\\n\\n## 配置mysql数据库\\n\\n### 1.mysql安装完毕后，创建nacos数据库nacos_config，数据库sql文件：\\n\\n```html\\nhttps://github.com/alibaba/nacos/blob/1.4.1/config/src/main/resources/META-INF/nacos-db.sql\\n```\\n\\n### 2.修改在conf目录下的application.properties文件\\n\\n修改完成后重启 nacos，以后所有数据都会持久化到mysql中，进conf文件夹下\\n\\n修改application.properties文件改成这样：\\n\\n```sql\\n# db mysql\\n \\ndb.driver-class-name=com.mysql.cj.jdbc.Driver  \\n\\nspring.datasource.platform=mysql\\n\\n### Count of DB:\\ndb.num=1\\n\\n### Connect URL of DB:我这里不是nacos_config \\ndb.url.0=jdbc:mysql://192.168.124.4:3306/aqi_nacos?characterEncoding=utf8&connectTimeout=1000&socketTimeout=3000&autoReconnect=true&useUnicode=true&useSSL=false&serverTimezone=UTC\\ndb.user.0=root\\ndb.password.0=root\\n```\\n\\n![1690458641307.png](https://ws.aqi125.cn/articles/8dd2952efa466f7944f192b20afe616b.png)\\n\\n### 3.在bin目录下创建run.bat文件\\n\\n```c++\\nstartup.cmd -m standalone\\n```\\n\\n### 4.启动单击run.bat出现该界面成功\\n\\n![db4691f1024ad61c0ee77326d762e3f.png](https://ws.aqi125.cn/articles/d2da8ac91f8b121aa9a7380d3aacdd7b.png)\\n\\n![1690459626600.png](http://ws.aqi125.cn/articles/7ef9df26c8e5d30354f47b1684d54171.png)\\n\\n搞定收工，下面开始整另外一个中间件。\\n\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/5297e045738ebb26907ee74bb166d016.jpg\",\"articleTitle\":\"Nacos配置文件持久化到外部数据库\",\"categoryName\":\"中间件\",\"id\":148,\"isFeatured\":1,\"isTop\":0,\"status\":3,\"tagNames\":[\"Nacos\"],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '175.152.152.195', '中国|四川省|成都市|联通', '2023-07-27 20:13:24', NULL);
INSERT INTO `t_operation_log` VALUES (1844, '文章模块', '修改', '/admin/articles/topAndFeatured', 'com.aurora.controller.ArticleController.updateArticleTopAndFeatured', '修改文章是否置顶和推荐', '[{\"id\":148,\"isFeatured\":1,\"isTop\":1}]', 'PUT', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '175.152.152.195', '中国|四川省|成都市|联通', '2023-07-27 20:14:04', NULL);
INSERT INTO `t_operation_log` VALUES (1845, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# 写在前面\\n\\n# 是对原花未眠博客  Aurora 由原有jdk8全面升级到jdk11 及安装minio存储的补充\\n\\n# 一.jdk升级很简单谁都会直接上代码看问题:\\n\\n```java\\nClosing non transactional SqlSession [org.apache.ibatis.session.defaults.DefaultSqlSession@6137f51c]\\n2023-04-08 19:05:57.419 ERROR 7908 --- [nio-8080-exec-2] o.a.c.c.C.[.[.[/].[dispatcherServlet]    : Servlet.service() for servlet [dispatcherServlet] in context with path [] threw exception [Filter execution threw an exception] with root cause\\n\\njava.lang.ClassNotFoundException: javax.xml.bind.DatatypeConverter\\n\\tat java.base/jdk.internal.loader.BuiltinClassLoader.loadClass(BuiltinClassLoader.java:581) ~[na:na]\\n\\tat java.base/jdk.internal.loader.ClassLoaders$AppClassLoader.loadClass(ClassLoaders.java:178) ~[na:na]\\n\\tat java.base/java.lang.ClassLoader.loadClass(ClassLoader.java:521) ~[na:na]\\n```\\n\\n解决方法如下\\n\\n1.是回退，回退不符合我们需求\\n\\n2.是pom.xml添加依赖\\n\\n```xml\\n<dependency>\\n   <groupId>javax.xml.bind</groupId>\\n    <artifactId>jaxb-api</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>com.sun.xml.bind</groupId>\\n    <artifactId>jaxb-impl</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>com.sun.xml.bind</groupId>\\n    <artifactId>jaxb-core</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>javax.activation</groupId>\\n    <artifactId>activation</artifactId>\\n    <version>1.1.1</version>\\n</dependency>\\n```\\n\\n# 二.minio安装有详细步骤在12小节 在配置nginx的时候minio部分配置如下:\\n\\n```xml\\nserver {\\n\\n        listen  443 ssl;\\n        server_name ws.你的域名;\\n    \\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/ws.你的域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/ws.你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n    \\n        location / {\\n            proxy_pass http://你的IP:9000/aurora/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n    \\n    }\\n\\n\\nserver {\\n        listen       80;\\n        server_name  你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n\\n    }\\n\\nserver {\\n        listen       80;\\n        server_name  admin.你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n\\n    }\\t\\n    server {\\n    listen 80;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/aurora/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n\\n}\\n\\nserver {\\n    listen 9000;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n```\\n\\n# 三.以下是原安装详情及补充：\\n\\n## 1.服务器要求：\\n\\n> 下面的建议不包含minio的内存占用，如需使用minio，请参考步骤12\\n\\n1. 核心数和内存大小有两种方案：\\n   - 2核4G（使用ES搜索策略）\\n   - 2核2G（使用MySQL搜素策略）\\n\\n2. 带宽大小有两种方案：\\n   - 使用oss对带宽没有要求（本人亲测：1M带宽+oss 访问速度很快）\\n   - 使用minio需要大一点的带宽（小带宽也可以，但需要使用cdn加速）\\n\\n## 2.docker的安装：\\n\\n> 以下命令基于CentOS环境。\\n\\n1. 下载工具\\n\\n   ```shell\\n   yum install -y yum-utils\\n   ```\\n\\n2. 设置镜像的仓库\\n\\n   ```shell\\n   yum-config-manager \\\\\\n       --add-repo \\\\\\n       https://mirrors.aliyun.com/docker-ce/linux/centos/docker-ce.repo  #配置阿里云的镜像\\n   ```\\n\\n3. 更新yum软件包索引\\n\\n   ```shell\\n   yum makecache fast\\n   ```\\n\\n4. 安装docker相关配置\\n\\n   ```shell\\n   yum install docker-ce docker-ce-cli containerd.io\\n   ```\\n\\n5. 启动docker\\n\\n   ```shell\\n   systemctl start docker\\n   # 查看当前版本号，是否启动成功\\n   docker version\\n   # 设置开机自启动\\n   systemctl enable docker\\n   ```\\n\\n****\\n\\n## 3.安装mysql：\\n\\n### 方式1: 无挂载模式\\n\\n> 这种方式直接运行mysql之后，所有关于mysql的内容都在容器中，后续如果需要修改mysql的内容，需要手动进入容器内进行操作。且在宿主机上无备份，一旦容器被删除，数据也会被删除。\\n\\n```shell\\ndocker pull mysql //下载MySQL镜像\\ndocker run --name mysql --restart=always -p 3306:3306 -e MYSQL_ROOT_PASSWORD=你的密码 -d mysql //启动MySQL\\n```\\n\\n### 方式2: 数据卷挂载模式\\n\\n> 和**无挂载模式相对**，通过数据卷挂载的方式运行容器，将容器内的部分重要文件映射到宿主机上。直接操作宿主机对应的映射文件就能和容器内作同步，方便操作的同时还能保证容器内的数据在宿主机上有一个备份。\\n>\\n> 下面的命令分别对mysql的日志文件、配置文件、数据文件进行了映射，你也可以自己修改。\\n\\n```shell\\ndocker run -d -p 3306:3306 --restart=always -v /auroras/mysql/log:/var/log/mysql -v /auroras/mysql/data:/var/lib/mysql -v /auroras/mysql/conf:/etc/mysql/conf.d  -e MYSQL_ROOT_PASSWORD=你的密码  --name mysql mysql\\n```\\n\\n****\\n\\n## 4.安装redis：\\n\\n```shell\\ndocker pull redis //下载Redis镜像\\ndocker run --name redis  --restart=always -p 6379:6379 -d redis --requirepass \\\"你的密码\\\" //启动Redis\\n```\\n\\n## 5.安装rabbitmq：\\n\\n```shell\\ndocker pull rabbitmq:management //下载RabbitMQ镜像\\ndocker run --name rabbit --restart=always -p 15672:15672 -p 5672:5672  -d  rabbitmq:management   //启动RabbitMQ,默认guest用户，密码也是guest。\\n```\\n\\n## 6.安装elasticsearch：\\n\\n```shell\\ndocker pull elasticsearch:7.9.2\\n```\\n\\n```shell\\nmkdir -p  /home/elasticsearch/data/ \\nmkdir -p  /home/elasticsearch/config/\\n```\\n\\n1. 编写配置文件\\n\\n   ```shell\\n   echo \'http.host: 0.0.0.0\\n   http.cors.enabled: true\\n   http.cors.allow-origin: \\\"*\\\" \'>>/home/elasticsearch/config/elasticsearch.yml\\n   ```\\n\\n2. 修改文件夹权限\\n\\n   ```shell\\n   chmod -R 777 /home/elasticsearch/\\n   ls -l # 查看文件权限\\n   ```\\n\\n3. 启动elasticseach镜像\\n\\n   ```shell\\n   docker run --name elasticsearch -p 9200:9200 \\\\\\n    -p 9300:9300 \\\\\\n    -e \\\"discovery.type=single-node\\\" \\\\\\n    -e ES_JAVA_OPTS=\\\"-Xms64m -Xmx128m\\\" \\\\\\n     -v /home/elasticsearch/config/elasticsearch.yml:/usr/shellare/elasticsearch/config/elasticsearch.yml \\\\\\n    -v /home/elasticsearch/data:/usr/shellare/elasticsearch/data \\\\\\n    -v /home/elasticsearch/plugins:/usr/shellare/elasticsearch/plugins \\\\\\n    -d elasticsearch:7.9.2\\n   ```\\n\\n>接下来我们就是拿浏览器访问啦。\\n>在浏览器上输入：服务器IP地址:9200\\n>可能出现的问题：\\n\\n### 1. 启动成功，但是访问失败的话，查看一下安全组中映射端口是否已经打开。如果是本地虚拟机，可能与防火墙相关（我用的云服务器，没有测试，如果有问题，还是需要大家自行去百度||谷歌一下）。\\n\\n### 2. -e ES_JAVA_OPTS=\\\"-Xms64m -Xmx128m\\\"：配置内存大小出现了问题。\\n\\n### 3. 最后就还有可能是配置文件中出现了问题。\\n\\n   ```shell\\necho \'http.host: 0.0.0.0\\nhttp.cors.enabled: true\\nhttp.cors.allow-origin: \\\"*\\\" \'>>/home/elasticsearch/config/elasticsearch.yml\\n   ```\\n\\n   >`http.host: 0.0.0.0` 在冒号后面有一个空格的，这里的配置文件是`yml`格式,所以一定要严格按照`yml`格式来书写。\\n   >安装ik分词器\\n   >进入已经启动成功的elasticsearch容器。\\n\\n```shell\\ndocker exec -it elasticsearch /bin/bash\\n```\\n\\n```shell\\n./bin/elasticsearch-plugin install https://github.com/medcl/elasticsearch-analysis-ik/releases/download/v7.9.2/elasticsearch-analysis-ik-7.9.2.zip\\n```\\n\\n>ps: `安装的ik分词器的版本一定要与elasticsearch的版本保持一致`\\n>下载过程中如果遇到选择，直接输入 y回车就可以了。\\n>下载完成之后，退出去，重新启动elasticsearch容器。\\n\\n```shell\\ndocker restart elasticsearch\\n```\\n\\n>测试ik分词器是否安装成功\\n>安装完成后，我们再来进行测试遍，看看有什么样的变化。\\n>postman post请求分词测试：`http://服务器IP地址:9200/_analyze`\\n\\n```json\\n{\\n\\t\\\"tokenizer\\\":\\\"ik_smart\\\",\\n\\t\\\"text\\\":\\\"我爱技术\\\"\\n}\\n```\\n\\n结果\\n\\n```shell\\n{\\n    \\\"tokens\\\": [\\n        {\\n            \\\"token\\\": \\\"我\\\",\\n            \\\"start_offset\\\": 0,\\n            \\\"end_offset\\\": 1,\\n            \\\"type\\\": \\\"CN_CHAR\\\",\\n            \\\"position\\\": 0\\n        },\\n        {\\n            \\\"token\\\": \\\"爱\\\",\\n            \\\"start_offset\\\": 1,\\n            \\\"end_offset\\\": 2,\\n            \\\"type\\\": \\\"CN_CHAR\\\",\\n            \\\"position\\\": 1\\n        },\\n        {\\n            \\\"token\\\": \\\"技术\\\",\\n            \\\"start_offset\\\": 2,\\n            \\\"end_offset\\\": 4,\\n            \\\"type\\\": \\\"CN_WORD\\\",\\n            \\\"position\\\": 2\\n        }\\n    ]\\n}\\n```\\n\\n## 7.安装MaxWell：\\n\\n```sh\\ndocker pull zendesk/maxwell //下载MaxWell镜像\\ndocker run --name maxwell --restart=always  -d  zendesk/maxwell bin/maxwell  --user=\'root\' --password=\'你的密码\'  --host=\'你的IP\'  --producer=rabbitmq --rabbitmq_user=\'guest\' --rabbitmq_pass=\'guest\' --rabbitmq_host=\'你的IP\' --rabbitmq_port=\'5672\' --rabbitmq_exchange=\'maxwell_exchange\'  --rabbitmq_exchange_type=\'fanout\' --rabbitmq_exchange_durable=\'true\' --filter=\'exclude: *.*, include: aurora.t_article.article_title = *, include: aurora.t_article.article_content = *, include: aurora.t_article.is_delete = *, include: aurora.t_article.status = *\' //运行MaxWell\\n```\\n\\n注意：上述命令中aurora为数据库名称。\\n\\n****\\n\\n## 8.填写aurora-springboot中的yml文件：\\n\\n>此处省略，操作比较简单，就是配置一些简单的ip+端口+用户名+密码，前提是服务器上对应的端口已经打开\\n>阿里云oss具体情况详见百度\\n>QQ互联具体情况详见百度\\n>这里就不赘述了\\n\\n## 9.打包运行后端项目：\\n\\n### 1. 使用idea右侧Maven的package命令\\n\\n### 2. 在服务器的/usr/local/下面创建名为docker的文件夹\\n\\n### 3. 将打包好的jar包传到服务器上面的/usr/local/docker下面\\n\\n### 4. 编写Dockerfile,同时将编写好的Dockerfile传输到服务器的/usr/local/docker下面\\n\\n```dockerfile\\nFROM openjdk:8\\nVOLUME /tmp\\nADD aurora-springboot-0.0.1.jar blog.jar\\nENTRYPOINT [\\\"java\\\",\\\"-Djava.security.egd=file:/dev/./urandom\\\",\\\"-jar\\\",\\\"/blog.jar\\\"]\\n```\\n\\n> 注意：Dockerfile文件只需要上传到指定目录下即可，不需要手动执行其他操作。\\n\\n### 5. 编写aurora-start.sh,同时将编写好的aurora-start.sh上传到服务器的/usr/local/docker下面\\n\\n```shell\\nSOURCE_PATH=/usr/local/docker\\nSERVER_NAME=aurora-springboot-0.0.1.jar\\nTAG=latest\\nSERVER_PORT=8080\\nCID=$(docker ps | grep \\\"$SERVER_NAME\\\" | awk \'{print $1}\')\\nIID=$(docker images | grep \\\"$SERVER_NAME\\\" | awk \'{print $3}\')\\nif [ -n \\\"$CID\\\" ]; then\\n  echo \\\"存在容器$SERVER_NAME,CID-$CID\\\"\\n  docker stop $CID\\n  echo \\\"成功停止容器$SERVER_NAME,CID-$CID\\\"\\n  docker rm $CID\\n  echo \\\"成功删除容器$SERVER_NAME,CID-$CID\\\"\\nfi\\nif [ -n \\\"$IID\\\" ]; then\\n  echo \\\"存在镜像$SERVER_NAME:$TAG,IID=$IID\\\"\\n  docker rmi $IID\\n  echo \\\"成功删除镜像$SERVER_NAME:$TAG,IID=$IID\\\"\\nfi\\necho \\\"开始构建镜像$SERVER_NAME:$TAG\\\"\\ncd $SOURCE_PATH\\ndocker build -t $SERVER_NAME:$TAG .\\necho \\\"成功构建镜像$SERVER_NAME:$TAG\\\"\\ndocker run --restart=always --name aurora-springboot-0.0.1.jar -d -p 8080:8080 aurora-springboot-0.0.1.jar:latest\\necho \\\"成功创建并运行容器$SERVER_NAME\\\"\\n```\\n\\n**注意事项：sh文件需要用notepad++转为Unix格式**\\n\\n具体操作：点开notepad++中的编辑 ---> 文档格式转换 --->转为Unix \\n\\n### 6. cd到/usr/local/docker下面 ，执行如下命令打包docker镜像文件\\n\\n```shell\\nsh aurora-start.sh\\n```\\n\\n### 7. 启动容器\\n\\n```sh\\ndocker run  --name aurora-springboot-0.0.1.jar -d -p 8080:8080 aurora-springboot-0.0.1.jar:latest\\n```\\n\\n### 8. 这样后端项目就可以在服务器上跑起来了\\n\\n### 9. 访问测试(浏览器上访问)\\n\\n   ```shell\\nip:8080\\n   ```\\n\\n****\\n\\n## 10.打包运行前端项目：\\n\\n### 1. aurora-blog项目中，更改src/config/config.ts\\n\\n   ```typescript\\n  captcha: {\\n    TENCENT_CAPTCHA: \'你自己的天御验证码\'\\n  },\\n  qqLogin: {\\n    QQ_APP_ID: \'你自己的APP_ID\',\\n    QQ_REDIRECT_URI: \'https://你的前台域名/oauth/login/qq\'\\n  },\\n   ```\\n\\n### 2. aurora-blog项目中，更改public/index.html\\n\\n   ```html\\n<script\\n      src=\\\"http://connect.qq.com/qc_jssdk.js\\\"\\n      data-appid=\\\"你自己的APP_ID\\\"\\n      data-redirecturi=\\\"https://你的前台域名/oauth/login/qq\\\"></script>\\n   ```\\n\\n### 3. 如果你的网站没有打算使用https,将aurora-blog/public/index.html和aurora-admin/public/index.html中下面这一行代码给注释掉\\n\\n   ```html\\n<meta http-equiv=\\\"Content-Security-Policy\\\" content=\\\"upgrade-insecure-requests\\\" />\\n   ```\\n\\n### 4. 分别到aurora-blog和aurora-admin下面执行如下命令 (推荐关闭vscode的Eslint,本项目没有遵循Eslint的规范)\\n\\n如果下列命令执行报错，可以尝试替换版本\\n参考版本：npm版本为：8.3.1    vue-cli的版本为：5.0.6\\n\\n   ```shell\\nnpm install\\nnpm run build\\n   ```\\n\\n### 5. 在服务器的/usr/local/下面创建名为vue的文件夹，\\n\\n### 6. 将打包好的前台代码重命名为blog, 并传输到服务器的/usr/local/vue下面\\n\\n### 7. 将打包好的后台代码重命名为admin, 并传输到服务器的/usr/local/vue下面\\n\\n## 11.安装并启动nginx：\\n\\n### 方式1: http\\n\\n1. 拉取nginx镜像\\n\\n   ```shell\\n   docker pull nginx\\n   ```\\n\\n2. 在/usr/local/nginx下创建nginx.conf文件，格式如下\\n\\n   ```shell\\n   events {\\n       worker_connections  1024;\\n   }\\n   \\n   http {\\n       include       mime.types;\\n       default_type  application/octet-stream;\\n       sendfile        on;\\n       keepalive_timeout  65;\\n   \\n       client_max_body_size     50m;\\n       client_body_buffer_size  10m; \\n       client_header_timeout    1m;\\n       client_body_timeout      1m;\\n   \\n       gzip on;\\n       gzip_min_length  1k;\\n       gzip_buffers     4 16k;\\n       gzip_comp_level  4;\\n       gzip_types text/plain application/javascript application/x-javascript text/css application/xml text/javascript application/x-httpd-php image/jpeg image/gif image/png;\\n       gzip_vary on;\\n   \\n   server {\\n           listen       80;\\n           server_name  前台域名;\\n        \\n           location / {\\t\\t\\n               root   /usr/local/vue/blog;\\n               index  index.html index.htm; \\n               try_files $uri $uri/ /index.html;\\t\\n           }\\n   \\t\\t\\t\\n   \\tlocation ^~ /api/ {\\t\\t\\n               proxy_pass http://服务器ip:8080/;\\n   \\t       proxy_set_header   Host             $host;\\n               proxy_set_header   X-Real-IP        $remote_addr;\\t\\t\\t\\t\\t\\t\\n               proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n           }\\n   \\t\\t\\n       }\\n   \\t\\n   server {\\n           listen       80;\\n           server_name  后台子域名;\\n        \\n           location / {\\t\\t\\n               root   /usr/local/vue/admin;\\n               index  index.html index.htm; \\n               try_files $uri $uri/ /index.html;\\t\\n           }\\n   \\t\\t\\t\\n   \\tlocation ^~ /api/ {\\t\\t\\n               proxy_pass http://你的ip:8080/;\\n   \\t    proxy_set_header   Host             $host;\\n               proxy_set_header   X-Real-IP        $remote_addr;\\t\\t\\t\\t\\t\\t\\n               proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n           }\\n   \\t\\t\\n       }\\n    }\\n   ```\\n\\n3. 启动nginx\\n\\n   ```shell\\n   docker run --name nginx --restart=always -p 80:80 -d -v /usr/local/nginx/nginx.conf:/etc/nginx/nginx.conf -v /usr/local/vue:/usr/local/vue nginx \\n   ```\\n\\n### 方式2: https\\n\\n拉取nginx镜像\\n\\n```shell\\ndocker pull nginx\\n```\\n\\n修改配置文件(在原版的基础上加上minio存储-全站https)\\n\\n```shell\\nevents {\\n    worker_connections  1024;\\n}\\n\\nhttp {\\n    include       mime.types;\\n    default_type  application/octet-stream;\\n    sendfile        on;\\n    keepalive_timeout  65;\\n\\n    client_max_body_size     50m;\\n    client_body_buffer_size  10m; \\t  \\n    client_header_timeout    1m;\\n    client_body_timeout      1m;\\n\\n    gzip on;\\n    gzip_min_length  1k;\\n    gzip_buffers     4 16k;\\n    gzip_comp_level  4;\\n    gzip_types text/plain application/javascript application/x-javascript text/css application/xml text/javascript application/x-httpd-php image/jpeg image/gif image/png;\\n    gzip_vary on;\\n\\t\\nserver {\\n\\n        listen  443 ssl;\\n        server_name  你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/你的域名_bundle.pem; \\n\\t   ssl_certificate_key /etc/nginx/cert/你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n       location / {\\n            root   /usr/local/vue/blog;\\n            index  index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\t\\t\\n        location ^~ /api/ {\\n            proxy_pass http://你的IP:8080/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n\\n    }\\n\\nserver {\\n\\n        listen  443 ssl;\\n        server_name admin.你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/admin.你的域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/admin.你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n       location / {\\n            root   /usr/local/vue/admin;\\n            index  index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\t\\t\\n        location ^~ /api/ {\\n            proxy_pass http://你的IP:8080/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n\\t\\n    }\\nserver {\\n\\n        listen  443 ssl;\\n        server_name ws.你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/ws.你的域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/ws.你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n        location / {\\n            proxy_pass http://你的IP:9000/aurora/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n\\t\\n    }\\n\\n\\nserver {\\n        listen       80;\\n        server_name  你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n    }\\n\\t\\nserver {\\n        listen       80;\\n        server_name  admin.你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n    }\\t\\n    server {\\n    listen 80;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/aurora/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n}\\n\\nserver {\\n    listen 9000;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n}\\n}\\n```\\n\\n启动nginx\\n\\n```shell\\ndocker run --name nginx --restart=always -p 443:443 -p 80:80 -d -v /usr/local/nginx/nginx.conf:/etc/nginx/nginx.conf -v /usr/local/nginx/cert:/etc/nginx/cert -v /usr/local/vue:/usr/local/vue --privileged=true nginx\\n```\\n\\n## 12.安装并启动minio：\\n\\n```dockerfile\\ndocker run -d -p 9000:9000 -p 9001:9001 --name minio --restart=always -e \\\"MINIO_ROOT_USER=你的用户名\\\" -e \\\"MINIO_ROOT_PASSWORD=你的密码\\\" -v /minio/data:/data -v /minio/config:/root/.minio -v /etc/localtime:/etc/localtime minio/minio server /data --console-address \\\":9001\\\"\\n```\",\"articleCover\":\"http://ws.aqi125.cn/articles/854cb4178a8fa828a3bc7d1e694d37de.jpg\",\"articleTitle\":\"Blog部署教程补充\",\"categoryName\":\"blog部署\",\"id\":142,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '175.152.152.195', '中国|四川省|成都市|联通', '2023-07-27 20:14:24', NULL);
INSERT INTO `t_operation_log` VALUES (1846, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"## 部署过程中遇到的问题\\n\\n首先docker基本命令\\n\\n进入Centos命令行\\n\\n```dockerfile\\n1.首先切换到 root：su -root\\n2.进入 /bin 目录：cd /bin\\n3.执行命令：systemctl stop firewalld.service（关闭防火墙)\\nsystemctl disable firewalld.service（关闭防火墙自动启动）\\ndocker 命令\\ndocker ps 显示容器\\ndocker ps -a 列出所有的容器\\n#查看本地所有的镜像\\ndocker images\\ndocker rmi #镜像id  删除指定镜像\\ndocker restart  重新启动容器\\ndocker kill +id 杀死指定容器\\ndocker rm -f  删除指定容器\\n```\\n\\n## 安装minio遇到的问题\\n\\n通过这个报错信息，得知最近minio 升级，一些启动信息和之前不一样了。\\n\\t\\t日志报差错\\n\\t\\n\\n```日志\\n\\tWARNING: MINIO_ACCESS_KEY and MINIO_SECRET_KEY are deprecated.\\n\\t\\tPlease use MINIO_ROOT_USER and MINIO_ROOT_PASSWORD\\n\\t\\tWARNING: Detected Linux kernel version older than 4.0.0 release,\\n\\t\\tthere are some known potential performance problems\\n\\t\\twith this kernel version. MinIO recommends a minimum of 4.x. x\\n\\t\\tlinux kernel version for best performance\\n```\\n\\n### \\t\\t#安装镜像\\n\\n​\\t\\t\\n\\n```dockerfile\\ndocker run \\\\\\n\\t\\t--name minio \\\\\\n\\t\\t-p 9000:9000 \\\\\\n\\t\\t-p 9090:9090 \\\\\\n\\t\\t-d --restart=always \\\\\\n\\t\\t-e \\\"MINIO_ROOT_USER=admin\\\" \\\\\\n\\t\\t-e \\\"MINIO_ROOT_PASSWORD=admin123\\\" \\\\\\n\\t\\t-v /home/data:/data \\\\\\n\\t\\t-v /home/config:/root/.minio \\\\\\n\\t\\tminio/minio server /data --console-address \\\":9090\\\" --address \\\":9000\\\"‘\\n```\\n\\n#### \\t\\t日志\\n\\n```dockerfile\\ndocker logs minio\\n```\\n\\n#### \\t\\t再次报错版本太新了\\n\\n```\\nWARNING: Detected Linux kernel version older than 4.0.0 release, there are some known potential performance\\n\\t\\tproblems with this kernel version. MinIO recommends a minimum of 4.x.x linux kernel version for best performance\\n\\t\\tFormatting 1st pool, 1 set(s), 1 drives per set.\\n\\t\\tWARNING: Host local has more than 0 drives of set. A host failure will result in data becoming unavailable.\\n```\\n\\n\\n\\n### \\t\\t下载稳定版本\\n\\n​\\t\\t\\n\\n```dockerfile\\ndocker run -d -p 9000:9000 -p 9001:9001 --name minio --restart=always -e \\\"MINIO_ROOT_USER=密码\\\" -e \\\"MINIO_ROOT_PASSWORD=密码\\\" -v /minio/data:/data -v /minio/config:/root/.minio -v /etc/localtime:/etc/localtime minio/minio server /data --console-address \\\":9001\\\"\\n```\\n\\n## 导入Vue遇到的问题\\n\\n### 生成admin后台页面遇到的问题\\n\\n​\\t\\t缺少vue-echarts的使用\\n​\\t\\t解决方法\\n​\\t\\t\\n\\n```nginx\\nnpm install echarts vue-echarts\\n```\\n\\n### 生成blog前端页面遇到的问题\\n\\n​\\t\\t本机nodejs版本过高\\n​\\t\\t解决方法：\\n​\\t\\tnodejs降为node-v17.4.0-x64   对应npm版本为：8.3.1\\n​\\t\\tvue-cli的版本为：5.0.6\\n​\\t\\n\\n```nginx\\nvue卸载：npm uninstall vue-cli -g（3.0以下版本卸载）\\nnpm uninstall -g @vue/cli（3.0以上版本卸载）\\nvue安装：npm install -g @vue/cli （安装的是最新版）\\nnpm install vue-cli@2.9.6 （指定版本安装【指定版本为3.0以下版本】，其中2.9.6为版本号）\\nnpm install -g @vue/cli@5.0.6（指定版本安装【指定版本为3.0以上版本】，其中5.0.6为版本号）\\nvue版本查看：vue -V\\n```\\n\\n\\n## 前端页面遇到的问题上传图片加载失败\\n\\n![image20230223225305778.png](https://ws.aqi125.cn/articles/e8f5895c7a5010a9ee2b5cd89bee78c8.png)\\n\\n### 原因minio未配置https\\n\\n### 解决方法\\n```nginx\\n   server {\\n   listen  443 ssl;\\n    server_name 二级域名n;\\n\\n    ssl on;\\n    ssl_certificate /etc/nginx/cert/二级域名_bundle.pem; \\n    ssl_certificate_key /etc/nginx/cert/二级域名.key; \\n    ssl_session_timeout 5m;\\n    ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n    ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n    ssl_prefer_server_ciphers on;\\n\\n    location / {\\n        proxy_pass http://服务器ip:9000/aurora/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n\\n}\\n server {\\n    listen 80;\\n    server_name 二级域名;\\n    location / {\\n        proxy_pass http://服务器ip:9000/aurora/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n}\\n\\nserver {\\n    listen 9000;\\n    server_name 二级域名;\\n    location / {\\n        proxy_pass http://服务器ip:9000/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n}\\n}\\n```\\n## 前端页面遇到的问题上传好的图片回调加载失败\\n\\n![image20230223230053802.png](https://ws.aqi125.cn/articles/651c28e2d60914b845ec7616ee6dd4f7.png)\\n原因如下\\n\\n可以很清晰的看到http和https对不上\\n![image20230223230133757.png](https://ws.aqi125.cn/articles/b21afabcb05ce840ceb5c0a719aa057b.png)\\n\\n### 解决办法admin页面上传图片的时候直接在http后面加s\\n\\n![image20230223230505082.png](https://ws.aqi125.cn/articles/60b20926da1d814f712b111668f8ee3f.png)\\n\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/8e911b7de439f0ef5197740ce20ae4fc.jpg\",\"articleTitle\":\"blog部署\",\"categoryName\":\"blog部署\",\"id\":137,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '175.152.152.195', '中国|四川省|成都市|联通', '2023-07-27 20:14:48', NULL);
INSERT INTO `t_operation_log` VALUES (1847, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"## 中间件\\n\\n中间件是什么？英文名称为Middleware，是一种应用于分布式系统的基础软件。从纵向层次来看，中间件位于各类应用/服务与操作系统/数据库系统以及其他系统软件之间，主要解决分布式环境下数据传输、数据访问、应用调度、系统构建和系统集成、流程管理等问题，是分布式环境下支撑应用开发、运行和集成的平台，能够实现系统之间的互联互通，帮助用户高效开发应用软件。\\n\\n## Nacos\\n\\nNacos是阿里的一个开源产品，它是针对微服务架构中的服务发现、配置管理、服务治理的综合型解决方案。\\n\\n这两天搞中间件踩的坑不少先说Nacos，要解决什么问题？\\n\\nNacos配置中心持久化到外部数据库中\\n\\n```yaml\\n#本机环境\\n#Windows11专业版\\n#Nacos:1.4.1 /对应下载地址 有Windows/liunx看需要下载\\nhttps://github.com/alibaba/nacos/releases/tag/1.4.1\\n#Mysql:8.0.32\\n```\\n\\n## 配置mysql数据库\\n\\n### 1.mysql安装完毕后，创建nacos数据库nacos_config，数据库sql文件：\\n\\n```html\\nhttps://github.com/alibaba/nacos/blob/1.4.1/config/src/main/resources/META-INF/nacos-db.sql\\n```\\n\\n### 2.修改在conf目录下的application.properties文件\\n\\n修改完成后重启 nacos，以后所有数据都会持久化到mysql中，进conf文件夹下\\n\\n修改application.properties文件改成这样：\\n\\n```sql\\n# db mysql\\n \\ndb.driver-class-name=com.mysql.cj.jdbc.Driver  \\n\\nspring.datasource.platform=mysql\\n\\n### Count of DB:\\ndb.num=1\\n\\n### Connect URL of DB:我这里不是nacos_config \\ndb.url.0=jdbc:mysql://192.168.124.4:3306/aqi_nacos?characterEncoding=utf8&connectTimeout=1000&socketTimeout=3000&autoReconnect=true&useUnicode=true&useSSL=false&serverTimezone=UTC\\ndb.user.0=root\\ndb.password.0=root\\n```\\n\\n![1690458641307.png](https://ws.aqi125.cn/articles/8dd2952efa466f7944f192b20afe616b.png)\\n\\n### 3.在bin目录下创建run.bat文件\\n\\n```c++\\nstartup.cmd -m standalone\\n```\\n\\n### 4.启动单击run.bat出现该界面成功\\n\\n![db4691f1024ad61c0ee77326d762e3f.png](https://ws.aqi125.cn/articles/d2da8ac91f8b121aa9a7380d3aacdd7b.png)\\n\\n![1690459626600.png](http://ws.aqi125.cn/articles/7ef9df26c8e5d30354f47b1684d54171.png)\\n\\n搞定收工，下面开始整另外一个中间件。\\n\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/5297e045738ebb26907ee74bb166d016.jpg\",\"articleTitle\":\"Nacos配置文件持久化到外部数据库\",\"categoryName\":\"中间件\",\"id\":148,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '175.152.152.195', '中国|四川省|成都市|联通', '2023-07-27 20:16:35', NULL);
