INSERT INTO `t_operation_log` VALUES (1852, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"## 中间件\\n\\n中间件是什么？英文名称为Middleware，是一种应用于分布式系统的基础软件。从纵向层次来看，中间件位于各类应用/服务与操作系统/数据库系统以及其他系统软件之间，主要解决分布式环境下数据传输、数据访问、应用调度、系统构建和系统集成、流程管理等问题，是分布式环境下支撑应用开发、运行和集成的平台，能够实现系统之间的互联互通，帮助用户高效开发应用软件。\\n\\n## Nacos\\n\\nNacos是阿里的一个开源产品，它是针对微服务架构中的服务发现、配置管理、服务治理的综合型解决方案。\\n\\n这两天搞中间件踩的坑不少先说Nacos，要解决什么问题？\\n\\nNacos配置中心持久化到外部数据库中\\n\\n```yaml\\n#本机环境\\n#Windows11专业版\\n#Nacos:1.4.1 /对应下载地址 有Windows/liunx看需要下载\\nhttps://github.com/alibaba/nacos/releases/tag/1.4.1\\n#Mysql:8.0.32\\n```\\n\\n## 配置mysql数据库\\n\\n### 1.mysql安装完毕后，创建nacos数据库nacos_config，数据库sql文件：\\n\\n```html\\nhttps://github.com/alibaba/nacos/blob/1.4.1/config/src/main/resources/META-INF/nacos-db.sql\\n```\\n\\n### 2.修改在conf目录下的application.properties文件\\n\\n修改完成后重启 nacos，以后所有数据都会持久化到mysql中，进conf文件夹下\\n\\n修改application.properties文件改成这样：\\n\\n```sql\\n# db mysql\\n \\nspring.datasource.platform=mysql\\n\\n### Count of DB:\\n db.num=1\\n\\n### Connect URL of DB:我这里不是nacos_config \\ndb.url.0=jdbc:mysql://192.168.124.4:3306/aqi_nacos?characterEncoding=utf8&connectTimeout=1000&socketTimeout=3000&autoReconnect=true&useUnicode=true&useSSL=false&serverTimezone=UTC\\n db.user.0=root\\n db.password.0=root\\n```\\n\\n![1690458641307.png](https://ws.aqi125.cn/articles/8dd2952efa466f7944f192b20afe616b.png)\\n\\n### 3.在bin目录下创建run.bat文件\\n\\n```c++\\nstartup.cmd -m standalone\\n```\\n\\n### 4.启动单击run.bat出现该界面成功\\n\\n![db4691f1024ad61c0ee77326d762e3f.png](https://ws.aqi125.cn/articles/d2da8ac91f8b121aa9a7380d3aacdd7b.png)\\n\\n![1690459626600.png](http://ws.aqi125.cn/articles/7ef9df26c8e5d30354f47b1684d54171.png)\\n\\n搞定收工，下面开始整另外一个中间件。\\n\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/5297e045738ebb26907ee74bb166d016.jpg\",\"articleTitle\":\"Nacos配置文件持久化到外部数据库\",\"categoryName\":\"中间件\",\"id\":148,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '175.152.152.195', '中国|四川省|成都市|联通', '2023-07-27 21:30:11', NULL);
INSERT INTO `t_operation_log` VALUES (1853, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"## 中间件\\n\\n中间件是什么？英文名称为Middleware，是一种应用于分布式系统的基础软件。从纵向层次来看，中间件位于各类应用/服务与操作系统/数据库系统以及其他系统软件之间，主要解决分布式环境下数据传输、数据访问、应用调度、系统构建和系统集成、流程管理等问题，是分布式环境下支撑应用开发、运行和集成的平台，能够实现系统之间的互联互通，帮助用户高效开发应用软件。\\n\\n## Nacos\\n\\nNacos是阿里的一个开源产品，它是针对微服务架构中的服务发现、配置管理、服务治理的综合型解决方案。\\n\\n这两天搞中间件踩的坑不少先说Nacos，要解决什么问题？\\n\\nNacos配置中心持久化到外部数据库中\\n\\n```yaml\\n#本机环境\\n#Windows11专业版\\n#Nacos:1.4.1 /对应下载地址 有Windows/liunx看需要下载\\nhttps://github.com/alibaba/nacos/releases/tag/1.4.1\\n#Mysql:8.0.32\\n```\\n\\n## 配置mysql数据库\\n\\n### 1.mysql安装完毕后，创建nacos数据库nacos_config，数据库sql文件：\\n\\n```html\\nhttps://github.com/alibaba/nacos/blob/1.4.1/config/src/main/resources/META-INF/nacos-db.sql\\n```\\n\\n### 2.修改在conf目录下的application.properties文件\\n\\n修改完成后重启 nacos，以后所有数据都会持久化到mysql中，进conf文件夹下\\n\\n修改application.properties文件改成这样：\\n\\n```sql\\n# db mysql\\n \\nspring.datasource.platform=mysql\\n\\n### Count of DB:\\n db.num=1\\n\\n### Connect URL of DB:我这里不是nacos_config \\ndb.url.0=jdbc:mysql://192.168.124.4:3306/aqi_nacos?characterEncoding=utf8&connectTimeout=1000&socketTimeout=3000&autoReconnect=true&useUnicode=true&useSSL=false&serverTimezone=UTC\\n db.user.0=root\\n db.password.0=root\\n```\\n\\n![1690458641307.png](https://ws.aqi125.cn/articles/8dd2952efa466f7944f192b20afe616b.png)\\n\\n### 3.在bin目录下创建run.bat文件\\n\\n```c++\\nstartup.cmd -m standalone\\n```\\n\\n### 4.启动单击run.bat出现该界面成功\\n\\n![db4691f1024ad61c0ee77326d762e3f.png](https://ws.aqi125.cn/articles/d2da8ac91f8b121aa9a7380d3aacdd7b.png)\\n\\n![1690459626600.png](http://ws.aqi125.cn/articles/7ef9df26c8e5d30354f47b1684d54171.png)\\n\\n搞定收工，下面开始整另外一个中间件。\\n\\n\",\"articleCover\":\"http://ws.aqi125.cn/articles/5297e045738ebb26907ee74bb166d016.jpg\",\"articleTitle\":\"Nacos配置文件持久化到外部数据库\",\"categoryName\":\"中间件\",\"id\":148,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '175.152.152.195', '中国|四川省|成都市|联通', '2023-07-27 21:34:26', NULL);
