INSERT INTO `t_operation_log` VALUES (1858, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"## 中间件\\n\\n中间件是什么？英文名称为Middleware，是一种应用于分布式系统的基础软件。从纵向层次来看，中间件位于各类应用/服务与操作系统/数据库系统以及其他系统软件之间，主要解决分布式环境下数据传输、数据访问、应用调度、系统构建和系统集成、流程管理等问题，是分布式环境下支撑应用开发、运行和集成的平台，能够实现系统之间的互联互通，帮助用户高效开发应用软件。\\n\\n## Sentinel\\n\\n什么是Sentinel，Sentinel官网是这样描述的Sentinel 是面向分布式、多语言异构化服务架构的流量治理组件，主要以流量为切入点，从流量控制、流量路由、熔断降级、系统自适应保护等多个维度来帮助用户保障微服务的稳定性。\\n\\n这两天在搞中间件，搭建Sentinel进行服务熔断，降级，监控等操作时一切按照教程操作发现Sentinel控制台没有对应的数据显示。首先有一点可以确定不是懒加载导致的问题，本地开发机上服务多次测试依然没有。可以确定问题所在了，拉回本地，或者做隧道。穿透也比较简单向日葵，这里主要测试用。就不搞隧道了。\\n\\n![1690469733787.png](https://ws.aqi125.cn/articles/d488dd6016e0e26f4a08d32b76fe0aeb.png)\\n![1690469733787.png](https://ws.aqi125.cn/articles/d488dd6016e0e26f4a08d32b76fe0aeb.png)\\n\\n首先我的环境——,Sentinel服务端是搭建在百度智能云轻量服务器上的，测试的微服务是在我本地开发机上，中间件服务都运行在了轻量服务器上。\\n\\n![3335208bdbe6a9091ca0612c5bf914a.png](https://ws.aqi125.cn/articles/8d7de3b14729680616c5c0bd4ba13ded.png)\\n\\n本地docker怎么部署Sentinel就不写了比较简单，网上随便一搜一个博文就可以了。\",\"articleCover\":\"http://ws.aqi125.cn/articles/b591f83cf4c15c4945ad0a117e1a61c7.jpg\",\"articleTitle\":\"Sentinel控制台没有对应的数据显示\",\"categoryName\":\"中间件\",\"isFeatured\":1,\"isTop\":0,\"status\":1,\"tagNames\":[\"Sentinel\"],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '175.152.152.195', '中国|四川省|成都市|联通', '2023-07-27 23:05:36', NULL);
