INSERT INTO `t_operation_log` VALUES (1995, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"### Docker Firefox 容器搭建指南\\n\\n#### 简介\\n\\nMozilla Firefox 是一个由 Mozilla 基金会及其子公司 Mozilla Corporation 开发的免费开源网页浏览器。Docker Firefox 实现了一个用于 Firefox 的 Docker 容器，搭建完毕后，我们可以通过任意网页浏览器（无需客户端安装或配置）或使用任何 VNC 客户端来访问该应用程序的图形用户界面。\\n\\n#### 安装 Docker Firefox\\n\\n1. **SSH 登录 Linux 服务器**\\n   确保系统已经安装好 Docker 和 Docker Compose。\\n\\n2. **创建项目文件夹**\\n   推荐在 `/home` 目录下创建项目文件夹。\\n\\n   ```sh\\n   cd /home\\n   mkdir firefox\\n   cd firefox\\n   ```\\n\\n\\n3. **创建 `docker-compose.yml` 文件**\\n\\n   ```sh\\n   touch docker-compose.yml\\n   ```\\n\\n\\n4. **编辑 `docker-compose.yml` 文件**\\n   使用文本编辑器（如 `vi`）打开并编辑 `docker-compose.yml` 文件。\\n\\n   ```sh\\n   vi docker-compose.yml\\n   ```\\n\\n\\n   按 `i` 切换到编辑模式，将以下内容粘贴进去：\\n\\n   ```yaml\\n   version: \\\"3.7\\\"\\n\\n   services:\\n     firefox:\\n       image: jlesage/firefox\\n       container_name: firefox\\n       environment:\\n         - PUID=1000  # 替换为你的QNAP用户ID\\n         - PGID=1000  # 替换为你的QNAP组ID\\n         - TZ=Asia/Shanghai  # 设置时区，可根据需要更改\\n         - VNC_PASSWORD=123456  # 设置VNC访问密码\\n         - VNC_IDLE_TIMEOUT=3600  # 设置VNC空闲超时时间为1小时\\n       volumes:\\n         - ./config:/config\\n         - ./fonts:/usr/share/fonts\\n       ports:\\n         - 5800:5800\\n       shm_size: \\\"2gb\\\"  # 共享内存大小设置\\n       restart: unless-stopped  # 设置容器重启策略\\n   ```\\n\\n\\n   完成后按 `Esc` 键，然后输入 `:wq` 保存并退出。\\n\\n   你也可以使用 FinalShell 的可视化编辑功能，双击打开 `/home/firefox/docker-compose.yml`，直接将上述内容粘贴进去。\\n\\n5. **启动 Docker 容器**\\n\\n   ```sh\\n   docker-compose up -d\\n   ```\\n\\n\\n   等待一会儿，打开本地浏览器输入 `IP:5800` 即可开始访问搭建好的 Docker Firefox。\\n\\n#### 使用 Docker Firefox\\n\\n1. **初始设置**\\n   打开 `IP:5800` 后，进行一系列 Firefox 的初始设置。\\n\\n2. **测试速度**\\n   打开 YouTube 测试速度，通常速度很快，具体取决于服务器的带宽。\\n\\n3. **地区特定内容**\\n   由于服务器位于新加坡，打开某些网站时可能会收到新加坡规定的 Cookie 提醒。\\n\\n4. **工具栏功能**\\n   Docker Firefox 在窗口左侧提供了一个小工具栏，可以访问剪贴板、设置窗口大小和质量等。\\n\\n5. **用户体验**\\n   使用 Docker Firefox 访问网页非常流畅，观看视频的体验取决于本地/代理网络与主机服务器之间的通信质量。距离较近时，体验会更好。\\n   ![1730992994271.jpg](https://ws.aqi125.cn/articles/21d0c818a08722630541bd2b49fb410e.jpg)\\n\\n6. **状态记忆**\\n   Docker Firefox 会记忆当前状态。在新浏览器中访问 `IP:5800` 或在当前浏览器断开访问后再连接，Firefox 不会重新启动。\\n\\n#### 总结\\n\\nDocker Firefox 是一个非常实用的工具，适合搭建个人私有的网页浏览器，或者将某些页面分享给他人。无论是日常浏览还是特定任务，Docker Firefox 都能提供流畅且稳定的体验。\\n\\n#### 链接\\n\\n- GitHub：[https://github.com/jlesage/docker-firefox](https://github.com/jlesage/docker-firefox)\\n\\n希望这篇指南对你有所帮助！如果有任何问题或建议，请随时联系。\",\"articleCover\":\"https://ws.aqi125.cn/articles/5297e045738ebb26907ee74bb166d016.jpg\",\"articleTitle\":\"Docker Firefox搭建指南\",\"categoryName\":\"Docker Firefox搭建指南\",\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[\"网页版 Firefox\"],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.127.79', '中国|河南省|南阳市|移动', '2024-11-08 00:48:30', NULL);
INSERT INTO `t_operation_log` VALUES (1996, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"#  **Docker Firefox 容器搭建指南**\\n\\n#### **简介**\\n\\nMozilla Firefox 是一个由 Mozilla 基金会及其子公司 Mozilla Corporation 开发的免费开源网页浏览器。Docker Firefox 实现了一个用于 Firefox 的 Docker 容器，搭建完毕后，我们可以通过任意网页浏览器（无需客户端安装或配置）或使用任何 VNC 客户端来访问该应用程序的图形用户界面。\\n\\n# **安装 Docker Firefox**\\n\\n## 1. **SSH 登录 Linux 服务器**\\n   确保系统已经安装好 Docker 和 Docker Compose。\\n\\n## 2. **创建项目文件夹**\\n   推荐在 `/home` 目录下创建项目文件夹。\\n\\n   ```sh\\n   cd /home\\n   mkdir firefox\\n   cd firefox\\n   ```\\n\\n\\n## 3. **创建 `docker-compose.yml` 文件**\\n\\n   ```sh\\n   touch docker-compose.yml\\n   ```\\n\\n\\n## 4. **编辑 `docker-compose.yml` 文件**\\n   使用文本编辑器（如 `vi`）打开并编辑 `docker-compose.yml` 文件。\\n\\n   ```sh\\n   vi docker-compose.yml\\n   ```\\n\\n\\n   按 `i` 切换到编辑模式，将以下内容粘贴进去：\\n\\n   ```yaml\\n   version: \\\"3.7\\\"\\n\\n   services:\\n     firefox:\\n       image: jlesage/firefox\\n       container_name: firefox\\n       environment:\\n         - PUID=1000  # 替换为你的QNAP用户ID\\n         - PGID=1000  # 替换为你的QNAP组ID\\n         - TZ=Asia/Shanghai  # 设置时区，可根据需要更改\\n         - VNC_PASSWORD=123456  # 设置VNC访问密码\\n         - VNC_IDLE_TIMEOUT=3600  # 设置VNC空闲超时时间为1小时\\n       volumes:\\n         - ./config:/config\\n         - ./fonts:/usr/share/fonts\\n       ports:\\n         - 5800:5800\\n       shm_size: \\\"2gb\\\"  # 共享内存大小设置\\n       restart: unless-stopped  # 设置容器重启策略\\n   ```\\n\\n\\n   完成后按 `Esc` 键，然后输入 `:wq` 保存并退出。\\n\\n   你也可以使用 FinalShell 的可视化编辑功能，双击打开 `/home/firefox/docker-compose.yml`，直接将上述内容粘贴进去。\\n\\n## 5. **启动 Docker 容器**\\n\\n   ```sh\\n   docker-compose up -d\\n   ```\\n\\n\\n   等待一会儿，打开本地浏览器输入 `IP:5800` 即可开始访问搭建好的 Docker Firefox。\\n\\n#  **使用 Docker Firefox**\\n\\n## 1. **初始设置**\\n   打开 `IP:5800` 后，进行一系列 Firefox 的初始设置。\\n\\n## 2. **测试速度**\\n   打开 YouTube 测试速度，通常速度很快，具体取决于服务器的带宽。\\n\\n## 3. **地区特定内容**\\n   由于服务器位于新加坡，打开某些网站时可能会收到新加坡规定的 Cookie 提醒。\\n\\n## 4. **工具栏功能**\\n   Docker Firefox 在窗口左侧提供了一个小工具栏，可以访问剪贴板、设置窗口大小和质量等。\\n\\n## 5. **用户体验**\\n   使用 Docker Firefox 访问网页非常流畅，观看视频的体验取决于本地/代理网络与主机服务器之间的通信质量。距离较近时，体验会更好。\\n   ![1730992994271.jpg](https://ws.aqi125.cn/articles/21d0c818a08722630541bd2b49fb410e.jpg)\\n\\n## 6. **状态记忆**\\n   Docker Firefox 会记忆当前状态。在新浏览器中访问 `IP:5800` 或在当前浏览器断开访问后再连接，Firefox 不会重新启动。\\n\\n#### **总结**\\n\\nDocker Firefox 是一个非常实用的工具，适合搭建个人私有的网页浏览器，或者将某些页面分享给他人。无论是日常浏览还是特定任务，Docker Firefox 都能提供流畅且稳定的体验。\\n\\n#### **链接**\\n\\n- GitHub：[https://github.com/jlesage/docker-firefox](https://github.com/jlesage/docker-firefox)\\n\\n希望这篇指南对你有所帮助！如果有任何问题或建议，请随时联系。\",\"articleCover\":\"https://ws.aqi125.cn/articles/5297e045738ebb26907ee74bb166d016.jpg\",\"articleTitle\":\"Docker Firefox搭建指南\",\"categoryName\":\"Docker Firefox搭建指南\",\"id\":159,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.127.79', '中国|河南省|南阳市|移动', '2024-11-08 00:54:47', NULL);
INSERT INTO `t_operation_log` VALUES (1997, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"#  Aurora 博客 Nginx 优化配置\\n\\n#### 目的\\n### 1. **统一公共配置**：将公共的代理头设置和其他常用配置提取到一个单独的块中，以减少重复代码。\\n### 2. **简化和标准化配置**：确保每个 `server` 块的结构一致，便于维护。\\n### 3. **增加注释**：增加必要的注释，以便其他开发者更容易理解配置文件。\\n\\n##  **1. 启动 Minio 容器**\\n\\n```sh\\ndocker run -d -p 9000:9000 -p 9001:9001 --name minio --restart=always \\\\\\n-e \\\"MINIO_ROOT_USER=你的用户名\\\" \\\\\\n-e \\\"MINIO_ROOT_PASSWORD=你的密码\\\" \\\\\\n-v /minio/data:/data \\\\\\n-v /minio/config:/root/.minio \\\\\\n-v /etc/localtime:/etc/localtime \\\\\\nminio/minio server /data --console-address \\\":9001\\\"\\n```\\n\\n\\n## **2. 配置 Nginx 路由转发（基于 HTTPS 且有 SSL 证书）**\\n\\n```nginx\\nevents {\\n    worker_connections  1024;\\n}\\n\\nhttp {\\n    include       mime.types;\\n    default_type  application/octet-stream;\\n    sendfile        on;\\n    keepalive_timeout  65;\\n\\n    client_max_body_size     50m;\\n    client_body_buffer_size  10m; \\t  \\n    client_header_timeout    1m;\\n    client_body_timeout      1m;\\n\\n    gzip on;\\n    gzip_min_length  1k;\\n    gzip_buffers     4 16k;\\n    gzip_comp_level  4;\\n    gzip_types text/plain application/javascript application/x-javascript text/css application/xml text/javascript application/x-httpd-php image/jpeg image/gif image/png;\\n    gzip_vary on;\\n\\n    # 公共 SSL 配置\\n    map $scheme $ssl_flag {\\n        default off;\\n        https on;\\n    }\\n\\n    ssl_session_timeout 5m;\\n    ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n    ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n    ssl_prefer_server_ciphers on;\\n\\n    # 公共代理头设置\\n    proxy_set_header Host $host;\\n    proxy_set_header X-Real-IP $remote_addr;\\n    proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n    proxy_set_header X-Forwarded-Proto $scheme;\\n\\n    # 公共 HTTP 到 HTTPS 重定向\\n    server {\\n        listen       80;\\n        server_name  主站域名 管理后台二级域名 Minio域名;\\n        return 301 https://$host$request_uri;\\n    }\\n\\n    # 主站配置\\n    server {\\n        listen  443 ssl;\\n        server_name  主站域名;\\n\\n        ssl_certificate /etc/nginx/cert/主站域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/主站域名.key; \\n\\n        location / {\\n            root   /usr/local/vue/blog;\\n            index  index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\n        location ^~ /api/ {\\n            proxy_pass http://你的IP:8080/;\\n        }\\n    }\\n\\n    # 管理后台配置\\n    server {\\n        listen  443 ssl;\\n        server_name 管理后台二级域名;\\n\\n        ssl_certificate /etc/nginx/cert/管理后台二级域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/管理后台二级域名.key; \\n\\n        location / {\\n            root   /usr/local/vue/admin;\\n            index  index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\n        location ^~ /api/ {\\n            proxy_pass http://你的IP:8080/;\\n        }\\n    }\\n\\n    # Minio 服务配置\\n    server {\\n        listen  443 ssl;\\n        server_name Minio域名;\\n\\n        ssl_certificate /etc/nginx/cert/Minio域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/Minio域名.key; \\n\\n        location / {\\n            proxy_pass http://你的IP:9000/;\\n        }\\n    }\\n\\n    # Minio 服务的非 SSL 配置\\n    server {\\n        listen 9000;\\n        server_name Minio域名;\\n\\n        location / {\\n            proxy_pass http://你的IP:9000/;\\n        }\\n    } \\n}\\n```\\n\\n\\n## **说明**\\n\\n### 1. **公共配置提取**：\\n   - **SSL 配置**：定义了 SSL 会话超时时间、加密套件、协议版本等。\\n   - **代理头设置**：设置了常见的代理头，如 `Host`、`X-Real-IP`、`X-Forwarded-For` 和 `X-Forwarded-Proto`。\\n\\n### 2. **HTTP 到 HTTPS 重定向**：\\n   - 将所有 HTTP 请求重定向到 HTTPS，确保安全访问。\\n\\n### 3. **主站配置**：\\n   - 监听 443 端口，使用 SSL 证书。\\n   - 静态文件根目录设置为 `/usr/local/vue/blog`。\\n   - API 请求代理到后端服务。\\n\\n### 4. **管理后台配置**：\\n   - 监听 443 端口，使用 SSL 证书。\\n   - 静态文件根目录设置为 `/usr/local/vue/admin`。\\n   - API 请求代理到后端服务。\\n\\n### 5. **Minio 服务配置**：\\n   - 监听 443 端口，使用 SSL 证书。\\n   - 请求代理到 Minio 服务。\\n   - 非 SSL 配置监听 9000 端口，请求代理到 Minio 服务。\\n\\n**通过以上配置，可以实现 Aurora 博客的 Nginx 优化，确保各个服务的高效和安全运行。**\",\"articleCover\":\"https://ws.aqi125.cn/articles/26f792a8dec37ca514f6f65f06f7ed46.jpg\",\"articleTitle\":\"Nginx 优化配置\",\"categoryName\":\"Nginx 优化配置\",\"id\":158,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.127.79', '中国|河南省|南阳市|移动', '2024-11-08 00:58:14', NULL);
INSERT INTO `t_operation_log` VALUES (1998, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"#  Aurora 博客 Nginx 优化配置\\n### **目的:**\\n 1. **统一公共配置**：将公共的代理头设置和其他常用配置提取到一个单独的块中，以减少重复代码。\\n 2. **简化和标准化配置**：确保每个 `server` 块的结构一致，便于维护。\\n 3. **增加注释**：增加必要的注释，以便其他开发者更容易理解配置文件。\\n\\n##  **1. 启动 Minio 容器**\\n\\n```sh\\ndocker run -d -p 9000:9000 -p 9001:9001 --name minio --restart=always \\\\\\n-e \\\"MINIO_ROOT_USER=你的用户名\\\" \\\\\\n-e \\\"MINIO_ROOT_PASSWORD=你的密码\\\" \\\\\\n-v /minio/data:/data \\\\\\n-v /minio/config:/root/.minio \\\\\\n-v /etc/localtime:/etc/localtime \\\\\\nminio/minio server /data --console-address \\\":9001\\\"\\n```\\n\\n\\n## **2. 配置 Nginx 路由转发（基于 HTTPS 且有 SSL 证书）**\\n\\n```nginx\\nevents {\\n    worker_connections  1024;\\n}\\n\\nhttp {\\n    include       mime.types;\\n    default_type  application/octet-stream;\\n    sendfile        on;\\n    keepalive_timeout  65;\\n\\n    client_max_body_size     50m;\\n    client_body_buffer_size  10m; \\t  \\n    client_header_timeout    1m;\\n    client_body_timeout      1m;\\n\\n    gzip on;\\n    gzip_min_length  1k;\\n    gzip_buffers     4 16k;\\n    gzip_comp_level  4;\\n    gzip_types text/plain application/javascript application/x-javascript text/css application/xml text/javascript application/x-httpd-php image/jpeg image/gif image/png;\\n    gzip_vary on;\\n\\n    # 公共 SSL 配置\\n    map $scheme $ssl_flag {\\n        default off;\\n        https on;\\n    }\\n\\n    ssl_session_timeout 5m;\\n    ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n    ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n    ssl_prefer_server_ciphers on;\\n\\n    # 公共代理头设置\\n    proxy_set_header Host $host;\\n    proxy_set_header X-Real-IP $remote_addr;\\n    proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n    proxy_set_header X-Forwarded-Proto $scheme;\\n\\n    # 公共 HTTP 到 HTTPS 重定向\\n    server {\\n        listen       80;\\n        server_name  主站域名 管理后台二级域名 Minio域名;\\n        return 301 https://$host$request_uri;\\n    }\\n\\n    # 主站配置\\n    server {\\n        listen  443 ssl;\\n        server_name  主站域名;\\n\\n        ssl_certificate /etc/nginx/cert/主站域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/主站域名.key; \\n\\n        location / {\\n            root   /usr/local/vue/blog;\\n            index  index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\n        location ^~ /api/ {\\n            proxy_pass http://你的IP:8080/;\\n        }\\n    }\\n\\n    # 管理后台配置\\n    server {\\n        listen  443 ssl;\\n        server_name 管理后台二级域名;\\n\\n        ssl_certificate /etc/nginx/cert/管理后台二级域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/管理后台二级域名.key; \\n\\n        location / {\\n            root   /usr/local/vue/admin;\\n            index  index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\n        location ^~ /api/ {\\n            proxy_pass http://你的IP:8080/;\\n        }\\n    }\\n\\n    # Minio 服务配置\\n    server {\\n        listen  443 ssl;\\n        server_name Minio域名;\\n\\n        ssl_certificate /etc/nginx/cert/Minio域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/Minio域名.key; \\n\\n        location / {\\n            proxy_pass http://你的IP:9000/;\\n        }\\n    }\\n\\n    # Minio 服务的非 SSL 配置\\n    server {\\n        listen 9000;\\n        server_name Minio域名;\\n\\n        location / {\\n            proxy_pass http://你的IP:9000/;\\n        }\\n    } \\n}\\n```\\n\\n\\n## **说明**\\n\\n### 1. **公共配置提取**：\\n   - **SSL 配置**：定义了 SSL 会话超时时间、加密套件、协议版本等。\\n   - **代理头设置**：设置了常见的代理头，如 `Host`、`X-Real-IP`、`X-Forwarded-For` 和 `X-Forwarded-Proto`。\\n\\n### 2. **HTTP 到 HTTPS 重定向**：\\n   - 将所有 HTTP 请求重定向到 HTTPS，确保安全访问。\\n\\n### 3. **主站配置**：\\n   - 监听 443 端口，使用 SSL 证书。\\n   - 静态文件根目录设置为 `/usr/local/vue/blog`。\\n   - API 请求代理到后端服务。\\n\\n### 4. **管理后台配置**：\\n   - 监听 443 端口，使用 SSL 证书。\\n   - 静态文件根目录设置为 `/usr/local/vue/admin`。\\n   - API 请求代理到后端服务。\\n\\n### 5. **Minio 服务配置**：\\n   - 监听 443 端口，使用 SSL 证书。\\n   - 请求代理到 Minio 服务。\\n   - 非 SSL 配置监听 9000 端口，请求代理到 Minio 服务。\\n\\n**通过以上配置，可以实现 Aurora 博客的 Nginx 优化，确保各个服务的高效和安全运行。**\",\"articleCover\":\"https://ws.aqi125.cn/articles/26f792a8dec37ca514f6f65f06f7ed46.jpg\",\"articleTitle\":\"Nginx 优化配置\",\"categoryName\":\"Nginx 优化配置\",\"id\":158,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.127.79', '中国|河南省|南阳市|移动', '2024-11-08 00:59:50', NULL);
