INSERT INTO `t_operation_log` VALUES (2021, '文章模块', '导出', '/admin/articles/export', 'com.aurora.controller.ArticleController.exportArticles', '导出文章', '[[160,159,158,151,150,148,142,149,147,146]]', 'POST', '{\"code\":20000,\"data\":[\"https://ws.aqi125.cn/markdown/Blog部署教程补充.md\",\"https://ws.aqi125.cn/markdown/MinIO容器化账号密码丢失数据无损重建账号密码.md\",\"https://ws.aqi125.cn/markdown/被勒索删库了，root密码太简单.md\",\"https://ws.aqi125.cn/markdown/Nacos配置文件持久化到外部数据库.md\",\"https://ws.aqi125.cn/markdown/Sentinel控制台没有对应的数据显示.md\",\"https://ws.aqi125.cn/markdown/Ubuntu23.04开发环境基本初始化.md\",\"https://ws.aqi125.cn/markdown/Kubernetes.md\",\"https://ws.aqi125.cn/markdown/Nginx 优化配置.md\",\"https://ws.aqi125.cn/markdown/Docker Firefox搭建指南.md\",\"https://ws.aqi125.cn/markdown/Docker DeskTop安装kubernetes时一直停留在Starting处理方案.md\"],\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.127.8', '中国|河南省|南阳市|移动', '2024-11-27 23:34:54', NULL);
INSERT INTO `t_operation_log` VALUES (2022, '文章模块', '上传', '/admin/articles/images', 'com.aurora.controller.ArticleController.saveArticleImages', '上传文章图片', 'file', 'POST', '{\"code\":20000,\"data\":\"https://ws.aqi125.cn/articles/d6113889d13b73c4d659d6a92b59b07d.png\",\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.127.8', '中国|河南省|南阳市|移动', '2024-11-28 23:09:01', NULL);
INSERT INTO `t_operation_log` VALUES (2023, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"#  **Docker Firefox 容器搭建指南**\\n\\n#### **简介**\\n\\nMozilla Firefox 是一个由 Mozilla 基金会及其子公司 Mozilla Corporation 开发的免费开源网页浏览器。Docker Firefox 实现了一个用于 Firefox 的 Docker 容器，搭建完毕后，我们可以通过任意网页浏览器（无需客户端安装或配置）或使用任何 VNC 客户端来访问该应用程序的图形用户界面。\\n\\n# **安装 Docker Firefox**\\n\\n## 1. **SSH 登录 Linux 服务器**\\n   确保系统已经安装好 Docker 和 Docker Compose。\\n\\n## 2. **创建项目文件夹**\\n   推荐在 `/home` 目录下创建项目文件夹。\\n\\n   ```sh\\n   cd /home\\n   mkdir firefox\\n   cd firefox\\n   ```\\n\\n\\n## 3. **创建 `docker-compose.yml` 文件**\\n\\n   ```sh\\n   touch docker-compose.yml\\n   ```\\n\\n\\n## 4. **编辑 `docker-compose.yml` 文件**\\n   使用文本编辑器（如 `vi`）打开并编辑 `docker-compose.yml` 文件。\\n\\n   ```sh\\n   vi docker-compose.yml\\n   ```\\n\\n\\n   按 `i` 切换到编辑模式，将以下内容粘贴进去：\\n\\n   ```yaml\\n   version: \\\"3.7\\\"\\n\\n   services:\\n     firefox:\\n       image: jlesage/firefox\\n       container_name: firefox\\n       environment:\\n         - PUID=1000  # 替换为你的QNAP用户ID\\n         - PGID=1000  # 替换为你的QNAP组ID\\n         - TZ=Asia/Shanghai  # 设置时区，可根据需要更改\\n         - VNC_PASSWORD=123456  # 设置VNC访问密码\\n         - VNC_IDLE_TIMEOUT=3600  # 设置VNC空闲超时时间为1小时\\n       volumes:\\n         - ./config:/config\\n         - ./fonts:/usr/share/fonts\\n       ports:\\n         - 5800:5800\\n       shm_size: \\\"2gb\\\"  # 共享内存大小设置\\n       restart: unless-stopped  # 设置容器重启策略\\n   ```\\n\\n\\n   完成后按 `Esc` 键，然后输入 `:wq` 保存并退出。\\n\\n   你也可以使用 FinalShell 的可视化编辑功能，双击打开 `/home/firefox/docker-compose.yml`，直接将上述内容粘贴进去。\\n\\n## 5. **启动 Docker 容器**\\n\\n   ```sh\\n   docker-compose up -d\\n   ```\\n\\n\\n   等待一会儿，打开本地浏览器输入 `IP:5800` 即可开始访问搭建好的 Docker Firefox。\\n\\n#  **使用 Docker Firefox**\\n\\n## 1. **初始设置**\\n   打开 `IP:5800` 后，进行一系列 Firefox 的初始设置。\\n\\n## 2. **测试速度**\\n   打开 YouTube 测试速度，通常速度很快，具体取决于服务器的带宽。\\n\\n## 3. **地区特定内容**\\n   由于服务器位于新加坡，打开某些网站时可能会收到新加坡规定的 Cookie 提醒。\\n\\n## 4. **工具栏功能**\\n   Docker Firefox 在窗口左侧提供了一个小工具栏，可以访问剪贴板、设置窗口大小和质量等。\\n\\n## 5. **用户体验**\\n   使用 Docker Firefox 访问网页非常流畅，观看视频的体验取决于本地/代理网络与主机服务器之间的通信质量。距离较近时，体验会更好。\\n   ![1730992994271.jpg](https://ws.aqi125.cn/articles/21d0c818a08722630541bd2b49fb410e.jpg)\\n\\n## 6. **状态记忆**\\n   Docker Firefox 会记忆当前状态。在新浏览器中访问 `IP:5800` 或在当前浏览器断开访问后再连接，Firefox 不会重新启动。\\n\\n## 7. **中文汉化**\\n最近在使用jlesage/firefox镜像创建容器的时候，发现远程管理家里网络的时候中文会出现乱码，导致整个体验非常的不好，网上查找资料说在windows上面把宋体和微软雅黑字体复制到/usr/share/fonts目录下就可以解决。我试了不行，目录不对我的目录是/home/firefox/fonts\\t下上传MSYH.TTC\\n![image.png](https://ws.aqi125.cn/articles/d6113889d13b73c4d659d6a92b59b07d.png)\\n[这是百度云链接](https://pan.baidu.com/s/1kl3lXHPHklDLCaH_6j0LUQ?pwd=h21f)提取码h21f\\n#### **总结**\\n\\nDocker Firefox 是一个非常实用的工具，适合搭建个人私有的网页浏览器，或者将某些页面分享给他人。无论是日常浏览还是特定任务，Docker Firefox 都能提供流畅且稳定的体验。\\n\\n#### **链接**\\n\\n- GitHub：[https://github.com/jlesage/docker-firefox](https://github.com/jlesage/docker-firefox)\\n\\n希望这篇指南对你有所帮助！如果有任何问题或建议，请随时联系。\",\"articleCover\":\"https://ws.aqi125.cn/articles/5297e045738ebb26907ee74bb166d016.jpg\",\"articleTitle\":\"Docker Firefox搭建指南\",\"categoryName\":\"Docker Firefox搭建指南\",\"id\":159,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.127.8', '中国|河南省|南阳市|移动', '2024-11-28 23:11:56', NULL);
INSERT INTO `t_operation_log` VALUES (2024, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"#  **Docker Firefox 容器搭建指南**\\n\\n#### **简介**\\n\\nMozilla Firefox 是一个由 Mozilla 基金会及其子公司 Mozilla Corporation 开发的免费开源网页浏览器。Docker Firefox 实现了一个用于 Firefox 的 Docker 容器，搭建完毕后，我们可以通过任意网页浏览器（无需客户端安装或配置）或使用任何 VNC 客户端来访问该应用程序的图形用户界面。\\n\\n# **安装 Docker Firefox**\\n\\n## 1. **SSH 登录 Linux 服务器**\\n   确保系统已经安装好 Docker 和 Docker Compose。\\n\\n## 2. **创建项目文件夹**\\n   推荐在 `/home` 目录下创建项目文件夹。\\n\\n   ```sh\\n   cd /home\\n   mkdir firefox\\n   cd firefox\\n   ```\\n\\n\\n## 3. **创建 `docker-compose.yml` 文件**\\n\\n   ```sh\\n   touch docker-compose.yml\\n   ```\\n\\n\\n## 4. **编辑 `docker-compose.yml` 文件**\\n   使用文本编辑器（如 `vi`）打开并编辑 `docker-compose.yml` 文件。\\n\\n   ```sh\\n   vi docker-compose.yml\\n   ```\\n\\n\\n   按 `i` 切换到编辑模式，将以下内容粘贴进去：\\n\\n   ```yaml\\n   version: \\\"3.7\\\"\\n\\n   services:\\n     firefox:\\n       image: jlesage/firefox\\n       container_name: firefox\\n       environment:\\n         - PUID=1000  # 替换为你的QNAP用户ID\\n         - PGID=1000  # 替换为你的QNAP组ID\\n         - TZ=Asia/Shanghai  # 设置时区，可根据需要更改\\n         - VNC_PASSWORD=123456  # 设置VNC访问密码\\n         - VNC_IDLE_TIMEOUT=3600  # 设置VNC空闲超时时间为1小时\\n       volumes:\\n         - ./config:/config\\n         - ./fonts:/usr/share/fonts\\n       ports:\\n         - 5800:5800\\n       shm_size: \\\"2gb\\\"  # 共享内存大小设置\\n       restart: unless-stopped  # 设置容器重启策略\\n   ```\\n\\n\\n   完成后按 `Esc` 键，然后输入 `:wq` 保存并退出。\\n\\n   你也可以使用 FinalShell 的可视化编辑功能，双击打开 `/home/firefox/docker-compose.yml`，直接将上述内容粘贴进去。\\n\\n## 5. **启动 Docker 容器**\\n\\n   ```sh\\n   docker-compose up -d\\n   ```\\n\\n\\n   等待一会儿，打开本地浏览器输入 `IP:5800` 即可开始访问搭建好的 Docker Firefox。\\n\\n#  **使用 Docker Firefox**\\n\\n## 1. **初始设置**\\n   打开 `IP:5800` 后，进行一系列 Firefox 的初始设置。\\n\\n## 2. **测试速度**\\n   打开 YouTube 测试速度，通常速度很快，具体取决于服务器的带宽。\\n\\n## 3. **地区特定内容**\\n   由于服务器位于新加坡，打开某些网站时可能会收到新加坡规定的 Cookie 提醒。\\n\\n## 4. **工具栏功能**\\n   Docker Firefox 在窗口左侧提供了一个小工具栏，可以访问剪贴板、设置窗口大小和质量等。\\n\\n## 5. **用户体验**\\n   使用 Docker Firefox 访问网页非常流畅，观看视频的体验取决于本地/代理网络与主机服务器之间的通信质量。距离较近时，体验会更好。\\n   ![1730992994271.jpg](https://ws.aqi125.cn/articles/21d0c818a08722630541bd2b49fb410e.jpg)\\n\\n## 6. **状态记忆**\\n   Docker Firefox 会记忆当前状态。在新浏览器中访问 `IP:5800` 或在当前浏览器断开访问后再连接，Firefox 不会重新启动。\\n\\n## 7. **中文汉化**\\n最近在使用jlesage/firefox镜像创建容器的时候，发现远程管理家里网络的时候中文会出现乱码，导致整个体验非常的不好，网上查找资料说在windows上面把宋体和微软雅黑字体复制到/usr/share/fonts目录下就可以解决。我试了不行，目录不对我的目录是/home/firefox/fonts\\t下上传MSYH.TTC\\n![image.png](https://ws.aqi125.cn/articles/d6113889d13b73c4d659d6a92b59b07d.png)\\n[这是百度云链接](https://pan.baidu.com/s/1kl3lXHPHklDLCaH_6j0LUQ?pwd=h21f)提取码**h21f**\\n#### **总结**\\n\\nDocker Firefox 是一个非常实用的工具，适合搭建个人私有的网页浏览器，或者将某些页面分享给他人。无论是日常浏览还是特定任务，Docker Firefox 都能提供流畅且稳定的体验。\\n\\n#### **链接**\\n\\n- GitHub：[https://github.com/jlesage/docker-firefox](https://github.com/jlesage/docker-firefox)\\n\\n希望这篇指南对你有所帮助！如果有任何问题或建议，请随时联系。\",\"articleCover\":\"https://ws.aqi125.cn/articles/5297e045738ebb26907ee74bb166d016.jpg\",\"articleTitle\":\"Docker Firefox搭建指南\",\"categoryName\":\"Docker Firefox搭建指南\",\"id\":159,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.127.8', '中国|河南省|南阳市|移动', '2024-11-28 23:13:49', NULL);
INSERT INTO `t_operation_log` VALUES (2025, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"### 读完这篇文章你能收获到\\n\\n- Docker Desktop 安装 K8S 失败处理方案\\n- Docker 配置镜像加速器\\n- 数字签名的限制解除\\n\\n### 一、安装 Docker Desktop 和 Kubernetes\\n\\n#### 1. 步骤\\n1. **安装 Docker Desktop for Windows**：\\n   - 下载并安装 [Docker Desktop for Windows](https://www.docker.com/products/docker-desktop)。\\n2. **启用 Kubernetes**：\\n   - 打开 Docker Desktop。\\n   - 点击左上角的 Docker 图标，选择 **Settings**。\\n   - 在 **Kubernetes** 选项卡中，勾选 **Enable Kubernetes**。\\n   - 点击右下角的 **Apply & Restart**，Docker Desktop 会自动下载所需的 Kubernetes 组件。\\n\\n#### 2. 现象\\n- 安装过程中，Kubernetes 一直停留在 **Starting** 状态。\\n- 重启或重新安装 Docker Desktop 无效。\\n- ![image.png](https://ws.aqi125.cn/articles/96a83a58602ced27e282ad8366b6014b.png)\\n\\n#### 3. 根因\\n- 镜像源无法下载，导致 Kubernetes 组件下载失败。\\n\\n### 二、配置镜像加速器\\n\\n#### 1. 添加阿里云和 1Panel 镜像加速\\n1. **修改镜像源**：\\n   - 打开 Docker Desktop。\\n   - 点击左上角的 Docker 图标，选择 **Settings**。\\n   - 在 **Docker Engine** 选项卡中，编辑 JSON 配置文件，添加国内镜像地址：\\n     ```json\\n     {\\n       \\\"builder\\\": {\\n         \\\"gc\\\": {\\n           \\\"defaultKeepStorage\\\": \\\"20GB\\\",\\n           \\\"enabled\\\": true\\n         }\\n       },\\n       \\\"experimental\\\": false,\\n       \\\"features\\\": {\\n         \\\"buildkit\\\": true\\n       },\\n       \\\"registry-mirrors\\\": [\\n         \\\"https://你自己的阿里云镜像.mirror.aliyuncs.com\\\",\\n         \\\"https://docker.1panelproxy.com\\\",\\n         \\\"https://dockerhub1.beget.com\\\",\\n         \\\"https://noohub.ru\\\"\\n       ]\\n     }\\n     ```\\n![image.png](https://ws.aqi125.cn/articles/d335cde2c3081fda6871307358bbc787.png)\\n   - 设置完成后，点击 **Apply & Restart**。\\n\\n#### 2. 添加阿里云镜像加速\\n1. **登录阿里云容器 Hub 服务控制台**：\\n   - 访问 [阿里云容器镜像服务](https://cr.console.aliyun.com/)。\\n   - 创建或选择一个镜像加速器实例，获取镜像加速器地址。\\n\\n#### 3. 配置镜像加速器\\n- 将获取到的镜像加速器地址添加到 Docker Desktop 的配置中，如上所示。\\n\\n### 三、下载 k8s-for-docker-desktop\\n\\n1. **选择 Kubernetes 版本**：\\n   - 访问 [k8s-for-docker-desktop GitHub 仓库](https://github.com/AliyunContainerService/k8s-for-docker-desktop)。\\n   - 选择合适的 Kubernetes 版本，例如 v1.30.2。\\n  - ![image.png](https://ws.aqi125.cn/articles/35fba7766e4e3a5aad604476fcf43e0d.png)\\n    - 下载对应的压缩包并解压到指定目录，例如 `E:\\\\k8s-for-docker-desktop-1.30.2`。\\n\\n2. **解除数字签名限制**：\\n   - 打开 PowerShell 以管理员身份运行。\\n   - 切换到解压后的目录：\\n     ```powershell\\n     cd E:\\\\k8s-for-docker-desktop-1.30.2\\n     ```\\n  - ![image.png](https://ws.aqi125.cn/articles/4a8959477de471bb1c01b7fe3d947d24.png)\\n   - 临时更改执行策略：\\n     ```powershell\\n     Set-ExecutionPolicy -Scope Process -ExecutionPolicy Bypass\\n     ```\\n\\n   - 运行 `load_images.ps1` 脚本：\\n     ```powershell\\n     .\\\\load_images.ps1\\n     ```\\n  - ![image.png](https://ws.aqi125.cn/articles/af116e92515f467b83fb61bd2b7b5a35.png)\\n\\n### 四、大功告成\\n\\n1. **重启 Docker Desktop**：\\n   - 右键点击任务栏上的 Docker 图标，选择 **Restart Docker Desktop**。\\n2. **等待启动**：\\n   - 等待一段时间，直到 Kubernetes 启动成功。\\n  - ![image.png](https://ws.aqi125.cn/articles/44f436873570c6dbb45b9fd10813db7e.png)\\n\\n### 总结\\n通过以上步骤，你可以成功安装并配置 Docker Desktop 和 Kubernetes，解决镜像下载失败的问题，并解除数字签名限制。希望这些步骤对你有所帮助。如果有任何问题或建议，请随时反馈。\\n### 文章参考阿里云  https://developer.aliyun.com/article/989502\",\"articleCover\":\"https://ws.aqi125.cn/articles/9bfa2953bc860b33841b3debb0a03675.jpg\",\"articleTitle\":\"Docker DeskTop安装kubernetes Helm Ingress-Nginx\",\"categoryName\":\"DockerDeskTop安装k8s\",\"id\":160,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.127.8', '中国|河南省|南阳市|移动', '2024-11-28 23:20:46', NULL);
