INSERT INTO `t_operation_log` VALUES (2047, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"\\n# jenkins+docker自动化部署\\n使用docker安装jenkins, 这里使用90端口外放, 截止2025/12/07 这个镜像版本比较高(jdk21)。默认docker环境centos源已经配置好换了国内源。\\n## 安装Jenkins\\n\\n### 创建Jenkins持久化目录\\n\\n```language\\nmkdir -p /root/docker/jenkins\\n```\\n### 运行部署容器\\n```language\\n docker run -d \\\\\\n  -u root \\\\\\n  --name aqi_jenkins \\\\\\n  -p 90:8080 \\\\\\n  -v /root/docker/jenkins:/var/jenkins_home \\\\\\n  -v /var/run/docker.sock:/var/run/docker.sock \\\\\\n  -v /usr/bin/docker:/usr/bin/docker \\\\\\n  jenkins/jenkins:2.540-slim-jdk21\\n```\\n**Jenkins登录流程直接跳过我认为你会。**\\n## 安装多版本TencentKona JDK\\n安装jdk11/17/21(这边我的项目是对腾讯云服务器做了专项优化所以选择TencentKona，你也可以选择Oracle，阿里Dragonwell等等如果你们公司做了高可用做了多云服务商聚合容灾请自行适配相应的JDK。) \\n```language\\n# 先进容器\\ndocker exec -it aqi_jenkins /bin/bash\\n# 然后cd到 /usr/local/目录\\ncd /usr/local/\\n# 更新包管理器并安装 wget 和 tar\\napt-get update -y && apt-get install -y wget tar\\n\\n# 下载 TencentKona JDK 11/17/21 压缩包\\nwget https://github.com/Tencent/TencentKona-11/releases/download/kona11.0.29/TencentKona-11.0.29.b1-jdk_linux-x86_64.tar.gz\\nwget https://github.com/Tencent/TencentKona-17/releases/download/TencentKona-17.0.17/TencentKona-17.0.17.b1-jdk_linux-x86_64.tar.gz\\nwget https://github.com/Tencent/TencentKona-21/releases/download/TencentKona-21.0.9/TencentKona-21.0.9.b1-jdk_linux-x86_64.tar.gz\\n\\n# 解压缩 JDK 压缩包\\ntar -xzf TencentKona-11.0.29.b1-jdk_linux-x86_64.tar.gz\\ntar -xzf TencentKona-17.0.17.b1-jdk_linux-x86_64.tar.gz\\ntar -xzf TencentKona-21.0.9.b1-jdk_linux-x86_64.tar.gz\\nls  \\n# 如下图\\n![e780a975d7990d1377fc22fa52f1bfb6.png] \\n(https://ws.aqi125.cn/articles/516952904b48a516e1cca52dd33999f7.png)\\n```\\n\",\"articleCover\":\"https://ws.aqi125.cn/articles/6d93c4e2a2690ce5f742f42f8d80e365.jpg\",\"articleTitle\":\"jenkins+docker自动化部署 多jdk配置\",\"categoryName\":\"jenkins+docker自动化部署多jdk配置\",\"id\":162,\"isFeatured\":1,\"isTop\":1,\"status\":3,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.95', '中国|河南省|南阳市|移动', '2025-12-07 22:51:15', NULL);
