INSERT INTO `t_operation_log` VALUES (2064, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"\\n# jenkins+docker自动化部署\\n**使用docker安装jenkins, 这里使用90端口外放, 截止2025/12/07 这个镜像版本比较高(jdk21)。默认docker环境centos源已经配置好换了国内源。**\\n## 安装Jenkins\\n\\n### 创建Jenkins持久化目录\\n\\n```language\\nmkdir -p /root/docker/jenkins\\n```\\n### 运行部署容器\\n```language\\n docker run -d \\\\\\n  -u root \\\\\\n  --name aqi_jenkins \\\\\\n  -p 90:8080 \\\\\\n  -v /root/docker/jenkins:/var/jenkins_home \\\\\\n  -v /var/run/docker.sock:/var/run/docker.sock \\\\\\n  -v /usr/bin/docker:/usr/bin/docker \\\\\\n  jenkins/jenkins:2.540-slim-jdk21\\n```\\n**Jenkins登录流程直接跳过我认为你会。**\\n## 安装多版本TencentKona JDK\\n安装jdk11/17/21(这边我的项目是对腾讯云服务器做了专项优化所以选择TencentKona，你也可以选择Oracle，阿里Dragonwell等等如果你们公司做了高可用做了多云服务商聚合容灾请自行适配相应的JDK。) \\n```language\\n# 先进容器\\ndocker exec -it aqi_jenkins /bin/bash\\n# 然后cd到 /usr/local/目录\\ncd /usr/local/\\n# 更新包管理器并安装 wget 和 tar\\napt-get update -y && apt-get install -y wget tar\\n\\n# 下载 TencentKona JDK 11/17/21 压缩包\\nwget https://github.com/Tencent/TencentKona-11/releases/download/kona11.0.29/TencentKona-11.0.29.b1-jdk_linux-x86_64.tar.gz\\nwget https://github.com/Tencent/TencentKona-17/releases/download/TencentKona-17.0.17/TencentKona-17.0.17.b1-jdk_linux-x86_64.tar.gz\\nwget https://github.com/Tencent/TencentKona-21/releases/download/TencentKona-21.0.9/TencentKona-21.0.9.b1-jdk_linux-x86_64.tar.gz\\n\\n# 解压缩 JDK 压缩包\\ntar -xzf TencentKona-11.0.29.b1-jdk_linux-x86_64.tar.gz\\ntar -xzf TencentKona-17.0.17.b1-jdk_linux-x86_64.tar.gz\\ntar -xzf TencentKona-21.0.9.b1-jdk_linux-x86_64.tar.gz\\nls  \\n# 如下图\\n```\\n![e780a975d7990d1377fc22fa52f1bfb6.png](https://ws.aqi125.cn/articles/516952904b48a516e1cca52dd33999f7.png)\\n## 配置jdk和Maven\\n系统管理 -> 全局工具配置\\n![image.png](https://ws.aqi125.cn/articles/c97fe622404dae2c70abc7add309c5fa.png)\\n### 配置上一步解压好的jdk地址 (/usr/local/目录)\\n![49663658bfcb05d452f357be3839a107.png](https://ws.aqi125.cn/articles/e9c24b672cbc02b62fdaf886b4a7a62e.png)\\n### 配置maven, 我这边是双版本\\n![ba893ac31bce24e79d1706b1c725db16.png](https://ws.aqi125.cn/articles/b04aef44a5004d7613d948f657afad2b.png)\\n### 下边就是系统管理-> 系统配置-> 工具位置工具列表（这个位置也可以配置一下）\\n![9f37830501f6f50436292c68e3b73b03.png](https://ws.aqi125.cn/articles/95044ea925676a62798526df12aaa32e.png)\\n## 你的多个jdk的新老项目就可以愉快的cicd了![cc349c04121512589f9eb0281e9c1a05.jpg](https://ws.aqi125.cn/articles/be98ee2d549521bc2e94851364cf7787.jpg)\\n![14fb054b59e1c4a9a458a3866c308602.jpg](https://ws.aqi125.cn/articles/13cc5cad08635d2eb417ff7d18565f55.jpg)\",\"articleCover\":\"https://ws.aqi125.cn/articles/6d93c4e2a2690ce5f742f42f8d80e365.jpg\",\"articleTitle\":\"jenkins+docker自动化部署 多jdk配置\",\"categoryName\":\"jenkins部署多jdk配置\",\"id\":162,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.95', '中国|河南省|南阳市|移动', '2025-12-07 23:33:22', NULL);
INSERT INTO `t_operation_log` VALUES (2065, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"\\n# jenkins+docker自动化部署\\n**使用docker安装jenkins, 这里使用90端口外放, 截止2025/12/07 这个镜像版本比较高(jdk21)。默认docker环境centos源已经配置好换了国内源。**\\n## 安装Jenkins\\n\\n### 创建Jenkins持久化目录\\n\\n```language\\nmkdir -p /root/docker/jenkins\\n```\\n### 运行部署容器\\n```language\\n docker run -d \\\\\\n  -u root \\\\\\n  --name aqi_jenkins \\\\\\n  -p 90:8080 \\\\\\n  -v /root/docker/jenkins:/var/jenkins_home \\\\\\n  -v /var/run/docker.sock:/var/run/docker.sock \\\\\\n  -v /usr/bin/docker:/usr/bin/docker \\\\\\n  jenkins/jenkins:2.540-slim-jdk21\\n```\\n**Jenkins登录流程直接跳过我认为你会。**\\n## 安装多版本TencentKona JDK\\n安装jdk11/17/21(这边我的项目是对腾讯云服务器做了专项优化所以选择TencentKona，你也可以选择Oracle，阿里Dragonwell等等如果你们公司做了高可用做了多云服务商聚合容灾请自行适配相应的JDK。) \\n```language\\n# 先进容器\\ndocker exec -it aqi_jenkins /bin/bash\\n# 然后cd到 /usr/local/目录\\ncd /usr/local/\\n# 更新包管理器并安装 wget 和 tar\\napt-get update -y && apt-get install -y wget tar\\n\\n# 下载 TencentKona JDK 11/17/21 压缩包\\nwget https://github.com/Tencent/TencentKona-11/releases/download/kona11.0.29/TencentKona-11.0.29.b1-jdk_linux-x86_64.tar.gz\\nwget https://github.com/Tencent/TencentKona-17/releases/download/TencentKona-17.0.17/TencentKona-17.0.17.b1-jdk_linux-x86_64.tar.gz\\nwget https://github.com/Tencent/TencentKona-21/releases/download/TencentKona-21.0.9/TencentKona-21.0.9.b1-jdk_linux-x86_64.tar.gz\\n\\n# 解压缩 JDK 压缩包\\ntar -xzf TencentKona-11.0.29.b1-jdk_linux-x86_64.tar.gz\\ntar -xzf TencentKona-17.0.17.b1-jdk_linux-x86_64.tar.gz\\ntar -xzf TencentKona-21.0.9.b1-jdk_linux-x86_64.tar.gz\\nls  \\n# 如下图\\n```\\n![e780a975d7990d1377fc22fa52f1bfb6.png](https://ws.aqi125.cn/articles/516952904b48a516e1cca52dd33999f7.png)\\n## 配置jdk和Maven\\n系统管理 -> 全局工具配置\\n![image.png](https://ws.aqi125.cn/articles/c97fe622404dae2c70abc7add309c5fa.png)\\n### 配置上一步解压好的jdk地址 (/usr/local/目录)\\n![49663658bfcb05d452f357be3839a107.png](https://ws.aqi125.cn/articles/e9c24b672cbc02b62fdaf886b4a7a62e.png)\\n### 配置maven, 我这边是双版本\\n![ba893ac31bce24e79d1706b1c725db16.png](https://ws.aqi125.cn/articles/b04aef44a5004d7613d948f657afad2b.png)\\n### 下边就是系统管理-> 系统配置-> 工具位置工具列表（这个位置也可以配置一下）\\n![9f37830501f6f50436292c68e3b73b03.png](https://ws.aqi125.cn/articles/95044ea925676a62798526df12aaa32e.png)\\n## 你的多个jdk的新老项目就可以愉快的cicd了。\\n![cc349c04121512589f9eb0281e9c1a05.jpg](https://ws.aqi125.cn/articles/be98ee2d549521bc2e94851364cf7787.jpg)\\n![14fb054b59e1c4a9a458a3866c308602.jpg](https://ws.aqi125.cn/articles/13cc5cad08635d2eb417ff7d18565f55.jpg)\",\"articleCover\":\"https://ws.aqi125.cn/articles/6d93c4e2a2690ce5f742f42f8d80e365.jpg\",\"articleTitle\":\"jenkins+docker自动化部署 多jdk配置\",\"categoryName\":\"jenkins部署多jdk配置\",\"id\":162,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.95', '中国|河南省|南阳市|移动', '2025-12-07 23:34:20', NULL);
INSERT INTO `t_operation_log` VALUES (2066, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# 基于 Docker 的 Jenkins 自动化部署配置指南\\n\\n本文介绍如何使用 Docker 部署 Jenkins 并配置多版本 TencentKona JDK，实现多版本 Java 项目的自动化构建与部署。\\n\\n## 环境说明\\n- **Jenkins 版本**: 2.540-slim-jdk21（截至 2025/12/07 的较新版本）\\n- **映射端口**: 90（外部）→ 8080（容器内部）\\n- **前提条件**: Docker 环境已配置国内镜像源\\n\\n---\\n\\n## 一、Jenkins 容器部署\\n\\n### 1.1 创建持久化数据目录\\n```bash\\nmkdir -p /root/docker/jenkins\\n```\\n\\n### 1.2 启动 Jenkins 容器\\n```bash\\ndocker run -d \\\\\\n  -u root \\\\\\n  --name aqi_jenkins \\\\\\n  -p 90:8080 \\\\\\n  -v /root/docker/jenkins:/var/jenkins_home \\\\\\n  -v /var/run/docker.sock:/var/run/docker.sock \\\\\\n  -v /usr/bin/docker:/usr/bin/docker \\\\\\n  jenkins/jenkins:2.540-slim-jdk21\\n```\\n\\n**参数说明**:\\n- `-u root`：以 root 用户运行，避免权限问题\\n- `-p 90:8080`：将容器 8080 端口映射到主机 90 端口\\n- `-v /root/docker/jenkins:/var/jenkins_home`：数据持久化\\n- `-v /var/run/docker.sock:/var/run/docker.sock`：允许容器内使用宿主机 Docker\\n- `-v /usr/bin/docker:/usr/bin/docker`：映射 Docker 命令行工具\\n\\n> **提示**：初始登录流程已省略，请按 Jenkins 标准流程完成初次设置。\\n\\n---\\n\\n## 二、多版本 TencentKona JDK 安装\\n\\n### 2.1 进入容器并准备环境\\n```bash\\n# 进入 Jenkins 容器\\ndocker exec -it aqi_jenkins /bin/bash\\n\\n# 切换到安装目录\\ncd /usr/local/\\n\\n# 更新包管理工具并安装必要软件\\napt-get update -y && apt-get install -y wget tar\\n```\\n\\n### 2.2 下载并解压 TencentKona JDK\\n```bash\\n# 下载 JDK 11/17/21 版本\\nwget https://github.com/Tencent/TencentKona-11/releases/download/kona11.0.29/TencentKona-11.0.29.b1-jdk_linux-x86_64.tar.gz\\nwget https://github.com/Tencent/TencentKona-17/releases/download/TencentKona-17.0.17/TencentKona-17.0.17.b1-jdk_linux-x86_64.tar.gz\\nwget https://github.com/Tencent/TencentKona-21/releases/download/TencentKona-21.0.9/TencentKona-21.0.9.b1-jdk_linux-x86_64.tar.gz\\n\\n# 解压所有 JDK 包\\ntar -xzf TencentKona-11.0.29.b1-jdk_linux-x86_64.tar.gz\\ntar -xzf TencentKona-17.0.17.b1-jdk_linux-x86_64.tar.gz\\ntar -xzf TencentKona-21.0.9.b1-jdk_linux-x86_64.tar.gz\\n\\n# 验证解压结果\\nls\\n```\\n\\n**执行结果示例**：\\n```\\nTencentKona-11.0.29.b1-jdk   TencentKona-17.0.17.b1-jdk   TencentKona-21.0.9.b1-jdk\\n```\\n\\n> **注意**：本文示例选用 TencentKona JDK 以适配腾讯云环境优化。如公司采用多云架构，请根据实际需求选择相应 JDK（如 Oracle JDK、阿里 Dragonwell 等）。\\n\\n---\\n\\n## 三、Jenkins 全局工具配置\\n\\n### 3.1 配置多版本 JDK\\n1. 访问 Jenkins：`http://服务器IP:90`\\n2. 进入 **系统管理** → **全局工具配置**\\n   \\n   ![全局工具配置入口](https://ws.aqi125.cn/articles/c97fe622404dae2c70abc7add309c5fa.png)\\n\\n3. 添加 JDK 安装：\\n   - **JDK 11**: `/usr/local/TencentKona-11.0.29.b1-jdk`\\n   - **JDK 17**: `/usr/local/TencentKona-17.0.17.b1-jdk`\\n   - **JDK 21**: `/usr/local/TencentKona-21.0.9.b1-jdk`\\n\\n   ![JDK 配置示例](https://ws.aqi125.cn/articles/e9c24b672cbc02b62fdaf886b4a7a62e.png)\\n\\n### 3.2 配置多版本 Maven\\n根据项目需求配置相应版本的 Maven：\\n\\n![Maven 多版本配置](https://ws.aqi125.cn/articles/b04aef44a5004d7613d948f657afad2b.png)\\n\\n### 3.3 （可选）系统工具位置配置\\n进入 **系统管理** → **系统配置** → **工具位置**，可统一管理所有工具路径：\\n\\n![工具位置统一配置](https://ws.aqi125.cn/articles/95044ea925676a62798526df12aaa32e.png)\\n\\n---\\n\\n## 四、项目构建配置示例\\n\\n完成上述配置后，即可在 Jenkins 任务中按需选择不同 JDK 版本进行构建：\\n\\n- **JDK 11 项目构建示例**：\\n  ![JDK11 项目构建](https://ws.aqi125.cn/articles/be98ee2d549521bc2e94851364cf7787.jpg)\\n\\n- **JDK 17/21 项目构建示例**：\\n  ![JDK17/21 项目构建](https://ws.aqi125.cn/articles/13cc5cad08635d2eb417ff7d18565f55.jpg)\\n\\n---\\n\\n## 最佳实践建议\\n\\n1. **版本管理**：定期检查并更新 JDK 和 Jenkins 版本，确保安全性和稳定性\\n2. **备份策略**：定期备份 `/root/docker/jenkins` 目录\\n3. **权限控制**：生产环境中建议使用非 root 用户运行 Jenkins\\n4. **网络优化**：如构建速度慢，可在容器内配置 Maven 国内镜像源\\n5. **资源监控**：监控容器资源使用情况，及时调整分配\\n\\n---\\n\\n## 故障排除\\n\\n- **权限问题**：如遇 Docker 命令执行权限问题，检查 `/var/run/docker.sock` 权限\\n- **构建失败**：确认 JDK 路径配置正确，路径末尾不要包含 `/`\\n- **网络问题**：如无法下载依赖，检查容器内网络配置\\n\\n通过以上配置，即可实现支持多版本 JDK 项目的自动化构建与部署流水线。\",\"articleCover\":\"https://ws.aqi125.cn/articles/6d93c4e2a2690ce5f742f42f8d80e365.jpg\",\"articleTitle\":\"jenkins+docker自动化部署 多jdk配置\",\"categoryName\":\"jenkins部署多jdk配置\",\"id\":162,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.95', '中国|河南省|南阳市|移动', '2025-12-07 23:39:04', NULL);
INSERT INTO `t_operation_log` VALUES (2067, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# 基于 Docker 的 Jenkins 自动化部署配置指南\\n\\n本文介绍如何使用 Docker 部署 Jenkins 并配置多版本 TencentKona JDK，实现多版本 Java 项目的自动化构建与部署。\\n\\n## 环境说明\\n- **Jenkins 版本**: 2.540-slim-jdk21（截至 2025/12/07 的较新版本）\\n- **映射端口**: 90（外部）→ 8080（容器内部）\\n- **前提条件**: Docker 环境已配置国内镜像源\\n\\n---\\n\\n## 一、Jenkins 容器部署\\n\\n### 1.1 创建持久化数据目录\\n```bash\\nmkdir -p /root/docker/jenkins\\n```\\n\\n### 1.2 启动 Jenkins 容器\\n```bash\\ndocker run -d \\\\\\n  -u root \\\\\\n  --name aqi_jenkins \\\\\\n  -p 90:8080 \\\\\\n  -v /root/docker/jenkins:/var/jenkins_home \\\\\\n  -v /var/run/docker.sock:/var/run/docker.sock \\\\\\n  -v /usr/bin/docker:/usr/bin/docker \\\\\\n  jenkins/jenkins:2.540-slim-jdk21\\n```\\n\\n**参数说明**:\\n- `-u root`：以 root 用户运行，避免权限问题\\n- `-p 90:8080`：将容器 8080 端口映射到主机 90 端口\\n- `-v /root/docker/jenkins:/var/jenkins_home`：数据持久化\\n- `-v /var/run/docker.sock:/var/run/docker.sock`：允许容器内使用宿主机 Docker\\n- `-v /usr/bin/docker:/usr/bin/docker`：映射 Docker 命令行工具\\n\\n> **提示**：初始登录流程已省略，请按 Jenkins 标准流程完成初次设置。\\n\\n---\\n\\n## 二、多版本 TencentKona JDK 安装\\n\\n### 2.1 进入容器并准备环境\\n```bash\\n# 进入 Jenkins 容器\\ndocker exec -it aqi_jenkins /bin/bash\\n\\n# 切换到安装目录\\ncd /usr/local/\\n\\n# 更新包管理工具并安装必要软件\\napt-get update -y && apt-get install -y wget tar\\n```\\n\\n### 2.2 下载并解压 TencentKona JDK\\n```bash\\n# 下载 JDK 11/17/21 版本\\nwget https://github.com/Tencent/TencentKona-11/releases/download/kona11.0.29/TencentKona-11.0.29.b1-jdk_linux-x86_64.tar.gz\\nwget https://github.com/Tencent/TencentKona-17/releases/download/TencentKona-17.0.17/TencentKona-17.0.17.b1-jdk_linux-x86_64.tar.gz\\nwget https://github.com/Tencent/TencentKona-21/releases/download/TencentKona-21.0.9/TencentKona-21.0.9.b1-jdk_linux-x86_64.tar.gz\\n\\n# 解压所有 JDK 包\\ntar -xzf TencentKona-11.0.29.b1-jdk_linux-x86_64.tar.gz\\ntar -xzf TencentKona-17.0.17.b1-jdk_linux-x86_64.tar.gz\\ntar -xzf TencentKona-21.0.9.b1-jdk_linux-x86_64.tar.gz\\n\\n# 验证解压结果\\nls\\n```\\n\\n**执行结果示例**：\\n```\\nTencentKona-11.0.29.b1-jdk   TencentKona-17.0.17.b1-jdk   TencentKona-21.0.9.b1-jdk\\n```\\n\\n> **注意**：本文示例选用 TencentKona JDK 以适配腾讯云环境优化。如公司采用多云架构，请根据实际需求选择相应 JDK（如 Oracle JDK、阿里 Dragonwell 等）。\\n\\n---\\n\\n## 三、Jenkins 全局工具配置\\n\\n### 3.1 配置多版本 JDK\\n1. 访问 Jenkins：`http://服务器IP:90`\\n2. 进入 **系统管理** → **全局工具配置**\\n   \\n   ![全局工具配置入口](https://ws.aqi125.cn/articles/c97fe622404dae2c70abc7add309c5fa.png)\\n\\n3. 添加 JDK 安装：\\n   - **JDK 11**: `/usr/local/TencentKona-11.0.29.b1-jdk`\\n   - **JDK 17**: `/usr/local/TencentKona-17.0.17.b1-jdk`\\n   - **JDK 21**: `/usr/local/TencentKona-21.0.9.b1-jdk`\\n\\n   ![JDK 配置示例](https://ws.aqi125.cn/articles/e9c24b672cbc02b62fdaf886b4a7a62e.png)\\n\\n### 3.2 配置多版本 Maven\\n根据项目需求配置相应版本的 Maven：\\n\\n![Maven 多版本配置](https://ws.aqi125.cn/articles/b04aef44a5004d7613d948f657afad2b.png)\\n\\n### 3.3 （可选）系统工具位置配置\\n进入 **系统管理** → **系统配置** → **工具位置**，可统一管理所有工具路径：\\n\\n![工具位置统一配置](https://ws.aqi125.cn/articles/95044ea925676a62798526df12aaa32e.png)\\n\\n---\\n\\n## 四、项目构建配置示例\\n\\n完成上述配置后，即可在 Jenkins 任务中按需选择不同 JDK 版本进行构建：\\n\\n- **JDK 11 项目构建示例**：\\n  ![JDK11 项目构建](https://ws.aqi125.cn/articles/be98ee2d549521bc2e94851364cf7787.jpg)\\n\\n- **JDK 17/21 项目构建示例**：\\n  ![JDK17/21 项目构建](https://ws.aqi125.cn/articles/13cc5cad08635d2eb417ff7d18565f55.jpg)\\n\\n---\\n\\n## 最佳实践建议\\n\\n1. **版本管理**：定期检查并更新 JDK 和 Jenkins 版本，确保安全性和稳定性\\n2. **备份策略**：定期备份 `/root/docker/jenkins` 目录\\n3. **权限控制**：生产环境中建议使用非 root 用户运行 Jenkins\\n4. **网络优化**：如构建速度慢，可在容器内配置 Maven 国内镜像源\\n5. **资源监控**：监控容器资源使用情况，及时调整分配\\n\\n---\\n\\n## 故障排除\\n\\n- **权限问题**：如遇 Docker 命令执行权限问题，检查 `/var/run/docker.sock` 权限\\n- **构建失败**：确认 JDK 路径配置正确，路径末尾不要包含 `/`\\n- **网络问题**：如无法下载依赖，检查容器内网络配置\\n\\n通过以上配置，即可实现支持多版本 JDK 项目的自动化构建与部署流水线。\",\"articleCover\":\"https://ws.aqi125.cn/articles/6d93c4e2a2690ce5f742f42f8d80e365.jpg\",\"articleTitle\":\"jenkins+docker自动化部署 多jdk配置\",\"categoryName\":\"jenkins部署多jdk配置\",\"id\":162,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.95', '中国|河南省|南阳市|移动', '2025-12-08 03:56:59', NULL);
INSERT INTO `t_operation_log` VALUES (2068, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# 写在前面\\n\\n# 是对原花未眠博客  Aurora 由原有jdk8全面升级到jdk17 spring boot版本升级至2.7.18 elasticsearch升级至7.17.12 及安装minio存储的补充\\n\\n# 一.jdk升级很简单谁都会直接上代码看问题:\\n\\n```java\\nClosing non transactional SqlSession [org.apache.ibatis.session.defaults.DefaultSqlSession@6137f51c]\\n2023-04-08 19:05:57.419 ERROR 7908 --- [nio-8080-exec-2] o.a.c.c.C.[.[.[/].[dispatcherServlet]    : Servlet.service() for servlet [dispatcherServlet] in context with path [] threw exception [Filter execution threw an exception] with root cause\\n\\njava.lang.ClassNotFoundException: javax.xml.bind.DatatypeConverter\\n\\tat java.base/jdk.internal.loader.BuiltinClassLoader.loadClass(BuiltinClassLoader.java:581) ~[na:na]\\n\\tat java.base/jdk.internal.loader.ClassLoaders$AppClassLoader.loadClass(ClassLoaders.java:178) ~[na:na]\\n\\tat java.base/java.lang.ClassLoader.loadClass(ClassLoader.java:521) ~[na:na]\\n```\\n\\n解决方法如下\\n\\n1.是回退，回退不符合我们需求\\n\\n2.是pom.xml添加依赖\\n\\n```xml\\n<dependency>\\n   <groupId>javax.xml.bind</groupId>\\n    <artifactId>jaxb-api</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>com.sun.xml.bind</groupId>\\n    <artifactId>jaxb-impl</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>com.sun.xml.bind</groupId>\\n    <artifactId>jaxb-core</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>javax.activation</groupId>\\n    <artifactId>activation</artifactId>\\n    <version>1.1.1</version>\\n</dependency>\\n```\\n\\n# 二.minio安装有详细步骤在12小节 在配置nginx的时候minio部分配置如下:\\n\\n```xml\\nserver {\\n\\n        listen  443 ssl;\\n        server_name ws.你的域名;\\n    \\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/ws.你的域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/ws.你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n    \\n        location / {\\n            proxy_pass http://你的IP:9000/aurora/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n    \\n    }\\n\\n\\nserver {\\n        listen       80;\\n        server_name  你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n\\n    }\\n\\nserver {\\n        listen       80;\\n        server_name  admin.你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n\\n    }\\t\\n    server {\\n    listen 80;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/aurora/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n\\n}\\n\\nserver {\\n    listen 9000;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n```\\n\\n# 三.以下是原安装详情及补充：\\n\\n## 1.服务器要求：\\n\\n> 下面的建议不包含minio的内存占用，如需使用minio，请参考步骤12\\n\\n1. 核心数和内存大小有两种方案：\\n   - 2核4G（使用ES搜索策略）\\n   - 2核2G（使用MySQL搜素策略）\\n\\n2. 带宽大小有两种方案：\\n   - 使用oss对带宽没有要求（本人亲测：1M带宽+oss 访问速度很快）\\n   - 使用minio需要大一点的带宽（小带宽也可以，但需要使用cdn加速）\\n\\n## 2.docker的安装：\\n\\n> 以下命令基于CentOS环境。\\n\\n1. 下载工具\\n\\n   ```shell\\n   yum install -y yum-utils\\n   ```\\n\\n2. 设置镜像的仓库\\n\\n   ```shell\\n   yum-config-manager \\\\\\n       --add-repo \\\\\\n       https://mirrors.aliyun.com/docker-ce/linux/centos/docker-ce.repo  #配置阿里云的镜像\\n   ```\\n\\n3. 更新yum软件包索引\\n\\n   ```shell\\n   yum makecache fast\\n   ```\\n\\n4. 安装docker相关配置\\n\\n   ```shell\\n   yum install docker-ce docker-ce-cli containerd.io\\n   ```\\n\\n5. 启动docker\\n\\n   ```shell\\n   systemctl start docker\\n   # 查看当前版本号，是否启动成功\\n   docker version\\n   # 设置开机自启动\\n   systemctl enable docker\\n   ```\\n\\n****\\n\\n## 3.安装mysql：\\n\\n### 方式1: 无挂载模式\\n\\n> 这种方式直接运行mysql之后，所有关于mysql的内容都在容器中，后续如果需要修改mysql的内容，需要手动进入容器内进行操作。且在宿主机上无备份，一旦容器被删除，数据也会被删除。\\n\\n```shell\\ndocker pull mysql //下载MySQL镜像\\ndocker run --name mysql --restart=always -p 3306:3306 -e MYSQL_ROOT_PASSWORD=你的密码 -d mysql //启动MySQL\\n```\\n\\n### 方式2: 数据卷挂载模式\\n\\n> 和**无挂载模式相对**，通过数据卷挂载的方式运行容器，将容器内的部分重要文件映射到宿主机上。直接操作宿主机对应的映射文件就能和容器内作同步，方便操作的同时还能保证容器内的数据在宿主机上有一个备份。\\n>\\n> 下面的命令分别对mysql的日志文件、配置文件、数据文件进行了映射，你也可以自己修改。\\n\\n```shell\\ndocker run -d -p 3306:3306 --restart=always -v /auroras/mysql/log:/var/log/mysql -v /auroras/mysql/data:/var/lib/mysql -v /auroras/mysql/conf:/etc/mysql/conf.d  -e MYSQL_ROOT_PASSWORD=你的密码  --name mysql mysql\\n```\\n\\n****\\n\\n## 4.安装redis：\\n\\n```shell\\ndocker pull redis //下载Redis镜像\\ndocker run --name redis  --restart=always -p 6379:6379 -d redis --requirepass \\\"你的密码\\\" //启动Redis\\n```\\n\\n## 5.安装rabbitmq：\\n\\n```shell\\ndocker pull rabbitmq:management //下载RabbitMQ镜像\\ndocker run --name rabbit --restart=always -p 15672:15672 -p 5672:5672  -d  rabbitmq:management   //启动RabbitMQ,默认guest用户，密码也是guest。\\n```\\n\\n## 6.安装elasticsearch：\\n\\n```shell\\ndocker pull elasticsearch:7.17.12\\n```\\n\\n```shell\\nmkdir -p  /home/elasticsearch/data/ \\nmkdir -p  /home/elasticsearch/config/\\n```\\n\\n1. 编写配置文件\\n\\n   ```shell\\n   echo \'http.host: 0.0.0.0\\n   http.cors.enabled: true\\n   http.cors.allow-origin: \\\"*\\\" \'>>/home/elasticsearch/config/elasticsearch.yml\\n   ```\\n\\n2. 修改文件夹权限\\n\\n   ```shell\\n   chmod -R 777 /home/elasticsearch/\\n   ls -l # 查看文件权限\\n   ```\\n\\n3. 启动elasticseach镜像\\n\\n   ```shell\\n   docker run --name elasticsearch -p 9200:9200 \\\\\\n    -p 9300:9300 \\\\\\n    -e \\\"discovery.type=single-node\\\" \\\\\\n    -e ES_JAVA_OPTS=\\\"-Xms64m -Xmx128m\\\" \\\\\\n     -v /home/elasticsearch/config/elasticsearch.yml:/usr/shellare/elasticsearch/config/elasticsearch.yml \\\\\\n    -v /home/elasticsearch/data:/usr/shellare/elasticsearch/data \\\\\\n    -v /home/elasticsearch/plugins:/usr/shellare/elasticsearch/plugins \\\\\\n    -d elasticsearch:7.17.12\\n   ```\\n\\n>接下来我们就是拿浏览器访问啦。\\n>在浏览器上输入：服务器IP地址:9200\\n>可能出现的问题：\\n\\n### 1. 启动成功，但是访问失败的话，查看一下安全组中映射端口是否已经打开。如果是本地虚拟机，可能与防火墙相关（我用的云服务器，没有测试，如果有问题，还是需要大家自行去百度||谷歌一下）。\\n\\n### 2. -e ES_JAVA_OPTS=\\\"-Xms64m -Xmx128m\\\"：配置内存大小出现了问题。\\n\\n### 3. 最后就还有可能是配置文件中出现了问题。\\n\\n   ```shell\\necho \'http.host: 0.0.0.0\\nhttp.cors.enabled: true\\nhttp.cors.allow-origin: \\\"*\\\" \'>>/home/elasticsearch/config/elasticsearch.yml\\n   ```\\n\\n   >`http.host: 0.0.0.0` 在冒号后面有一个空格的，这里的配置文件是`yml`格式,所以一定要严格按照`yml`格式来书写。\\n   >安装ik分词器\\n   >进入已经启动成功的elasticsearch容器。\\n\\n```shell\\ndocker exec -it elasticsearch /bin/bash\\n```\\n\\n```shell\\n./bin/elasticsearch-plugin install https://github.com/medcl/elasticsearch-analysis-ik/releases/download/v7.9.2/elasticsearch-analysis-ik-7.9.2.zip\\n```\\n\\n>ps: `安装的ik分词器的版本一定要与elasticsearch的版本保持一致`\\n>下载过程中如果遇到选择，直接输入 y回车就可以了。\\n>下载完成之后，退出去，重新启动elasticsearch容器。\\n\\n```shell\\ndocker restart elasticsearch\\n```\\n\\n>测试ik分词器是否安装成功\\n>安装完成后，我们再来进行测试遍，看看有什么样的变化。\\n>postman post请求分词测试：`http://服务器IP地址:9200/_analyze`\\n\\n```json\\n{\\n\\t\\\"tokenizer\\\":\\\"ik_smart\\\",\\n\\t\\\"text\\\":\\\"我爱技术\\\"\\n}\\n```\\n\\n结果\\n\\n```shell\\n{\\n    \\\"tokens\\\": [\\n        {\\n            \\\"token\\\": \\\"我\\\",\\n            \\\"start_offset\\\": 0,\\n            \\\"end_offset\\\": 1,\\n            \\\"type\\\": \\\"CN_CHAR\\\",\\n            \\\"position\\\": 0\\n        },\\n        {\\n            \\\"token\\\": \\\"爱\\\",\\n            \\\"start_offset\\\": 1,\\n            \\\"end_offset\\\": 2,\\n            \\\"type\\\": \\\"CN_CHAR\\\",\\n            \\\"position\\\": 1\\n        },\\n        {\\n            \\\"token\\\": \\\"技术\\\",\\n            \\\"start_offset\\\": 2,\\n            \\\"end_offset\\\": 4,\\n            \\\"type\\\": \\\"CN_WORD\\\",\\n            \\\"position\\\": 2\\n        }\\n    ]\\n}\\n```\\n\\n## 7.安装MaxWell：\\n\\n```sh\\ndocker pull zendesk/maxwell //下载MaxWell镜像\\ndocker run --name maxwell --restart=always  -d  zendesk/maxwell bin/maxwell  --user=\'root\' --password=\'你的密码\'  --host=\'你的IP\'  --producer=rabbitmq --rabbitmq_user=\'guest\' --rabbitmq_pass=\'guest\' --rabbitmq_host=\'你的IP\' --rabbitmq_port=\'5672\' --rabbitmq_exchange=\'maxwell_exchange\'  --rabbitmq_exchange_type=\'fanout\' --rabbitmq_exchange_durable=\'true\' --filter=\'exclude: *.*, include: aurora.t_article.article_title = *, include: aurora.t_article.article_content = *, include: aurora.t_article.is_delete = *, include: aurora.t_article.status = *\' //运行MaxWell\\n```\\n\\n注意：上述命令中aurora为数据库名称。\\n\\n****\\n\\n## 8.填写aurora-springboot中的yml文件：\\n\\n>此处省略，操作比较简单，就是配置一些简单的ip+端口+用户名+密码，前提是服务器上对应的端口已经打开\\n>阿里云oss具体情况详见百度\\n>QQ互联具体情况详见百度\\n>这里就不赘述了\\n\\n## 9.打包运行后端项目：\\n\\n### 1. 使用idea右侧Maven的package命令\\n\\n### 2. 在服务器的/usr/local/下面创建名为docker的文件夹\\n\\n### 3. 将打包好的jar包传到服务器上面的/usr/local/docker下面\\n\\n### 4. 编写Dockerfile,同时将编写好的Dockerfile传输到服务器的/usr/local/docker下面\\n\\n```dockerfile\\nFROM openjdk:17-jdk-slim-buster\\nVOLUME /tmp\\nADD aurora-springboot-0.0.1.jar blog.jar\\nENTRYPOINT [\\\"java\\\",\\\"-Djava.security.egd=file:/dev/./urandom\\\",\\\"-jar\\\",\\\"/blog.jar\\\"]\\n```\\n\\n> 注意：Dockerfile文件只需要上传到指定目录下即可，不需要手动执行其他操作。\\n\\n### 5. 编写aurora-start.sh,同时将编写好的aurora-start.sh上传到服务器的/usr/local/docker下面\\n\\n```shell\\nSOURCE_PATH=/usr/local/docker\\nSERVER_NAME=aurora-springboot-0.0.1.jar\\nTAG=latest\\nSERVER_PORT=8080\\nCID=$(docker ps | grep \\\"$SERVER_NAME\\\" | awk \'{print $1}\')\\nIID=$(docker images | grep \\\"$SERVER_NAME\\\" | awk \'{print $3}\')\\nif [ -n \\\"$CID\\\" ]; then\\n  echo \\\"存在容器$SERVER_NAME,CID-$CID\\\"\\n  docker stop $CID\\n  echo \\\"成功停止容器$SERVER_NAME,CID-$CID\\\"\\n  docker rm $CID\\n  echo \\\"成功删除容器$SERVER_NAME,CID-$CID\\\"\\nfi\\nif [ -n \\\"$IID\\\" ]; then\\n  echo \\\"存在镜像$SERVER_NAME:$TAG,IID=$IID\\\"\\n  docker rmi $IID\\n  echo \\\"成功删除镜像$SERVER_NAME:$TAG,IID=$IID\\\"\\nfi\\necho \\\"开始构建镜像$SERVER_NAME:$TAG\\\"\\ncd $SOURCE_PATH\\ndocker build -t $SERVER_NAME:$TAG .\\necho \\\"成功构建镜像$SERVER_NAME:$TAG\\\"\\ndocker run --restart=always --name aurora-springboot-0.0.1.jar -d -p 8080:8080 aurora-springboot-0.0.1.jar:latest\\necho \\\"成功创建并运行容器$SERVER_NAME\\\"\\n```\\n\\n**注意事项：sh文件需要用notepad++转为Unix格式**\\n\\n具体操作：点开notepad++中的编辑 ---> 文档格式转换 --->转为Unix \\n\\n### 6. cd到/usr/local/docker下面 ，执行如下命令打包docker镜像文件\\n\\n```shell\\nsh aurora-start.sh\\n```\\n\\n### 7. 启动容器\\n\\n```sh\\ndocker run  --name aurora-springboot-0.0.1.jar -d -p 8080:8080 aurora-springboot-0.0.1.jar:latest\\n```\\n\\n### 8. 这样后端项目就可以在服务器上跑起来了\\n\\n### 9. 访问测试(浏览器上访问)\\n\\n   ```shell\\nip:8080\\n   ```\\n\\n****\\n\\n## 10.打包运行前端项目：\\n\\n### 1. aurora-blog项目中，更改src/config/config.ts\\n\\n   ```typescript\\n  captcha: {\\n    TENCENT_CAPTCHA: \'你自己的天御验证码\'\\n  },\\n  qqLogin: {\\n    QQ_APP_ID: \'你自己的APP_ID\',\\n    QQ_REDIRECT_URI: \'https://你的前台域名/oauth/login/qq\'\\n  },\\n   ```\\n\\n### 2. aurora-blog项目中，更改public/index.html\\n\\n   ```html\\n<script\\n      src=\\\"http://connect.qq.com/qc_jssdk.js\\\"\\n      data-appid=\\\"你自己的APP_ID\\\"\\n      data-redirecturi=\\\"https://你的前台域名/oauth/login/qq\\\"></script>\\n   ```\\n\\n### 3. 如果你的网站没有打算使用https,将aurora-blog/public/index.html和aurora-admin/public/index.html中下面这一行代码给注释掉\\n\\n   ```html\\n<meta http-equiv=\\\"Content-Security-Policy\\\" content=\\\"upgrade-insecure-requests\\\" />\\n   ```\\n\\n### 4. 分别到aurora-blog和aurora-admin下面执行如下命令 (推荐关闭vscode的Eslint,本项目没有遵循Eslint的规范)\\n\\n如果下列命令执行报错，可以尝试替换版本\\n参考版本：npm版本为：8.3.1    vue-cli的版本为：5.0.6\\n\\n   ```shell\\nnpm install\\nnpm run build\\n   ```\\n\\n### 5. 在服务器的/usr/local/下面创建名为vue的文件夹，\\n\\n### 6. 将打包好的前台代码重命名为blog, 并传输到服务器的/usr/local/vue下面\\n\\n### 7. 将打包好的后台代码重命名为admin, 并传输到服务器的/usr/local/vue下面\\n\\n## 11.安装并启动nginx：\\n\\n### 方式1: http\\n\\n1. 拉取nginx镜像\\n\\n   ```shell\\n   docker pull nginx\\n   ```\\n\\n2. 在/usr/local/nginx下创建nginx.conf文件，格式如下\\n\\n   ```shell\\n   events {\\n       worker_connections  1024;\\n   }\\n   \\n   http {\\n       include       mime.types;\\n       default_type  application/octet-stream;\\n       sendfile        on;\\n       keepalive_timeout  65;\\n   \\n       client_max_body_size     50m;\\n       client_body_buffer_size  10m; \\n       client_header_timeout    1m;\\n       client_body_timeout      1m;\\n   \\n       gzip on;\\n       gzip_min_length  1k;\\n       gzip_buffers     4 16k;\\n       gzip_comp_level  4;\\n       gzip_types text/plain application/javascript application/x-javascript text/css application/xml text/javascript application/x-httpd-php image/jpeg image/gif image/png;\\n       gzip_vary on;\\n   \\n   server {\\n           listen       80;\\n           server_name  前台域名;\\n        \\n           location / {\\t\\t\\n               root   /usr/local/vue/blog;\\n               index  index.html index.htm; \\n               try_files $uri $uri/ /index.html;\\t\\n           }\\n   \\t\\t\\t\\n   \\tlocation ^~ /api/ {\\t\\t\\n               proxy_pass http://服务器ip:8080/;\\n   \\t       proxy_set_header   Host             $host;\\n               proxy_set_header   X-Real-IP        $remote_addr;\\t\\t\\t\\t\\t\\t\\n               proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n           }\\n   \\t\\t\\n       }\\n   \\t\\n   server {\\n           listen       80;\\n           server_name  后台子域名;\\n        \\n           location / {\\t\\t\\n               root   /usr/local/vue/admin;\\n               index  index.html index.htm; \\n               try_files $uri $uri/ /index.html;\\t\\n           }\\n   \\t\\t\\t\\n   \\tlocation ^~ /api/ {\\t\\t\\n               proxy_pass http://你的ip:8080/;\\n   \\t    proxy_set_header   Host             $host;\\n               proxy_set_header   X-Real-IP        $remote_addr;\\t\\t\\t\\t\\t\\t\\n               proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n           }\\n   \\t\\t\\n       }\\n    }\\n   ```\\n\\n3. 启动nginx\\n\\n   ```shell\\n   docker run --name nginx --restart=always -p 80:80 -d -v /usr/local/nginx/nginx.conf:/etc/nginx/nginx.conf -v /usr/local/vue:/usr/local/vue nginx \\n   ```\\n\\n### 方式2: https\\n\\n拉取nginx镜像\\n\\n```shell\\ndocker pull nginx\\n```\\n\\n修改配置文件(在原版的基础上加上minio存储-全站https)\\n\\n```shell\\nevents {\\n    worker_connections  1024;\\n}\\n\\nhttp {\\n    include       mime.types;\\n    default_type  application/octet-stream;\\n    sendfile        on;\\n    keepalive_timeout  65;\\n\\n    client_max_body_size     50m;\\n    client_body_buffer_size  10m; \\t  \\n    client_header_timeout    1m;\\n    client_body_timeout      1m;\\n\\n    gzip on;\\n    gzip_min_length  1k;\\n    gzip_buffers     4 16k;\\n    gzip_comp_level  4;\\n    gzip_types text/plain application/javascript application/x-javascript text/css application/xml text/javascript application/x-httpd-php image/jpeg image/gif image/png;\\n    gzip_vary on;\\n\\t\\nserver {\\n\\n        listen  443 ssl;\\n        server_name  你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/你的域名_bundle.pem; \\n\\t   ssl_certificate_key /etc/nginx/cert/你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n       location / {\\n            root   /usr/local/vue/blog;\\n            index  index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\t\\t\\n        location ^~ /api/ {\\n            proxy_pass http://你的IP:8080/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n\\n    }\\n\\nserver {\\n\\n        listen  443 ssl;\\n        server_name admin.你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/admin.你的域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/admin.你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n       location / {\\n            root   /usr/local/vue/admin;\\n            index  index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\t\\t\\n        location ^~ /api/ {\\n            proxy_pass http://你的IP:8080/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n\\t\\n    }\\nserver {\\n\\n        listen  443 ssl;\\n        server_name ws.你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/ws.你的域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/ws.你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n        location / {\\n            proxy_pass http://你的IP:9000/aurora/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n\\t\\n    }\\n\\n\\nserver {\\n        listen       80;\\n        server_name  你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n    }\\n\\t\\nserver {\\n        listen       80;\\n        server_name  admin.你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n    }\\t\\n    server {\\n    listen 80;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/aurora/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n}\\n\\nserver {\\n    listen 9000;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n}\\n}\\n```\\n\\n启动nginx\\n\\n```shell\\ndocker run --name nginx --restart=always -p 443:443 -p 80:80 -d -v /usr/local/nginx/nginx.conf:/etc/nginx/nginx.conf -v /usr/local/nginx/cert:/etc/nginx/cert -v /usr/local/vue:/usr/local/vue --privileged=true nginx\\n```\\n\\n## 12.安装并启动minio：\\n\\n```dockerfile\\ndocker run -d -p 9000:9000 -p 9001:9001 --name minio --restart=always -e \\\"MINIO_ROOT_USER=你的用户名\\\" -e \\\"MINIO_ROOT_PASSWORD=你的密码\\\" -v /minio/data:/data -v /minio/config:/root/.minio -v /etc/localtime:/etc/localtime minio/minio server /data --console-address \\\":9001\\\"\\n```\",\"articleCover\":\"http://ws.aqi125.cn/articles/854cb4178a8fa828a3bc7d1e694d37de.jpg\",\"articleTitle\":\"Blog部署教程补充\",\"categoryName\":\"blog部署\",\"id\":142,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.127.50', '中国|河南省|南阳市|移动', '2025-12-13 11:53:43', NULL);
INSERT INTO `t_operation_log` VALUES (2069, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# 写在前面\\n\\n# 是对原花未眠博客  Aurora 由原有jdk8全面升级到jdk17 spring boot版本升级至2.7.18 elasticsearch升级至7.17.12 及安装minio存储的补充\\n\\n# 一.jdk升级很简单谁都会直接上代码看问题:\\n\\n```java\\nClosing non transactional SqlSession [org.apache.ibatis.session.defaults.DefaultSqlSession@6137f51c]\\n2023-04-08 19:05:57.419 ERROR 7908 --- [nio-8080-exec-2] o.a.c.c.C.[.[.[/].[dispatcherServlet]    : Servlet.service() for servlet [dispatcherServlet] in context with path [] threw exception [Filter execution threw an exception] with root cause\\n\\njava.lang.ClassNotFoundException: javax.xml.bind.DatatypeConverter\\n\\tat java.base/jdk.internal.loader.BuiltinClassLoader.loadClass(BuiltinClassLoader.java:581) ~[na:na]\\n\\tat java.base/jdk.internal.loader.ClassLoaders$AppClassLoader.loadClass(ClassLoaders.java:178) ~[na:na]\\n\\tat java.base/java.lang.ClassLoader.loadClass(ClassLoader.java:521) ~[na:na]\\n```\\n\\n解决方法如下\\n\\n1.是回退，回退不符合我们需求\\n\\n2.是pom.xml添加依赖\\n\\n```xml\\n<dependency>\\n   <groupId>javax.xml.bind</groupId>\\n    <artifactId>jaxb-api</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>com.sun.xml.bind</groupId>\\n    <artifactId>jaxb-impl</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>com.sun.xml.bind</groupId>\\n    <artifactId>jaxb-core</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>javax.activation</groupId>\\n    <artifactId>activation</artifactId>\\n    <version>1.1.1</version>\\n</dependency>\\n```\\n\\n# 二.minio安装有详细步骤在12小节 在配置nginx的时候minio部分配置如下:\\n\\n```xml\\nserver {\\n\\n        listen  443 ssl;\\n        server_name ws.你的域名;\\n    \\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/ws.你的域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/ws.你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n    \\n        location / {\\n            proxy_pass http://你的IP:9000/aurora/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n    \\n    }\\n\\n\\nserver {\\n        listen       80;\\n        server_name  你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n\\n    }\\n\\nserver {\\n        listen       80;\\n        server_name  admin.你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n\\n    }\\t\\n    server {\\n    listen 80;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/aurora/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n\\n}\\n\\nserver {\\n    listen 9000;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n```\\n# 三.pom.xml 变更如下两个部分\\n```language\\n<properties>\\n        <java.version>17</java.version>\\n        <project.build.sourceEncoding>UTF-8</project.build.sourceEncoding>\\n        <project.reporting.outputEncoding>UTF-8</project.reporting.outputEncoding>\\n        <spring-boot.version>2.7.18</spring-boot.version>\\n        <elasticsearch.version>7.17.12</elasticsearch.version>\\n这是分割线------------------------------------------------------------------------\\n        <plugins>\\n            <plugin>\\n                <groupId>org.apache.maven.plugins</groupId>\\n                <artifactId>maven-compiler-plugin</artifactId>\\n                <version>3.9.0</version>\\n                <configuration>\\n                    <source>17</source>\\n                    <target>17</target>\\n                    <encoding>UTF-8</encoding>\\n                </configuration>\\n            </plugin>\\n```\\n\\n\\n# 四.以下是原安装详情及补充：\\n\\n## 1.服务器要求：\\n\\n> 下面的建议不包含minio的内存占用，如需使用minio，请参考步骤12\\n\\n1. 核心数和内存大小有两种方案：\\n   - 2核4G（使用ES搜索策略）\\n   - 2核2G（使用MySQL搜素策略）\\n\\n2. 带宽大小有两种方案：\\n   - 使用oss对带宽没有要求（本人亲测：1M带宽+oss 访问速度很快）\\n   - 使用minio需要大一点的带宽（小带宽也可以，但需要使用cdn加速）\\n\\n## 2.docker的安装：\\n\\n> 以下命令基于CentOS环境。\\n\\n1. 下载工具\\n\\n   ```shell\\n   yum install -y yum-utils\\n   ```\\n\\n2. 设置镜像的仓库\\n\\n   ```shell\\n   yum-config-manager \\\\\\n       --add-repo \\\\\\n       https://mirrors.aliyun.com/docker-ce/linux/centos/docker-ce.repo  #配置阿里云的镜像\\n   ```\\n\\n3. 更新yum软件包索引\\n\\n   ```shell\\n   yum makecache fast\\n   ```\\n\\n4. 安装docker相关配置\\n\\n   ```shell\\n   yum install docker-ce docker-ce-cli containerd.io\\n   ```\\n\\n5. 启动docker\\n\\n   ```shell\\n   systemctl start docker\\n   # 查看当前版本号，是否启动成功\\n   docker version\\n   # 设置开机自启动\\n   systemctl enable docker\\n   ```\\n\\n****\\n\\n## 3.安装mysql：\\n\\n### 方式1: 无挂载模式\\n\\n> 这种方式直接运行mysql之后，所有关于mysql的内容都在容器中，后续如果需要修改mysql的内容，需要手动进入容器内进行操作。且在宿主机上无备份，一旦容器被删除，数据也会被删除。\\n\\n```shell\\ndocker pull mysql //下载MySQL镜像\\ndocker run --name mysql --restart=always -p 3306:3306 -e MYSQL_ROOT_PASSWORD=你的密码 -d mysql //启动MySQL\\n```\\n\\n### 方式2: 数据卷挂载模式\\n\\n> 和**无挂载模式相对**，通过数据卷挂载的方式运行容器，将容器内的部分重要文件映射到宿主机上。直接操作宿主机对应的映射文件就能和容器内作同步，方便操作的同时还能保证容器内的数据在宿主机上有一个备份。\\n>\\n> 下面的命令分别对mysql的日志文件、配置文件、数据文件进行了映射，你也可以自己修改。\\n\\n```shell\\ndocker run -d -p 3306:3306 --restart=always -v /auroras/mysql/log:/var/log/mysql -v /auroras/mysql/data:/var/lib/mysql -v /auroras/mysql/conf:/etc/mysql/conf.d  -e MYSQL_ROOT_PASSWORD=你的密码  --name mysql mysql\\n```\\n\\n****\\n\\n## 4.安装redis：\\n\\n```shell\\ndocker pull redis //下载Redis镜像\\ndocker run --name redis  --restart=always -p 6379:6379 -d redis --requirepass \\\"你的密码\\\" //启动Redis\\n```\\n\\n## 5.安装rabbitmq：\\n\\n```shell\\ndocker pull rabbitmq:management //下载RabbitMQ镜像\\ndocker run --name rabbit --restart=always -p 15672:15672 -p 5672:5672  -d  rabbitmq:management   //启动RabbitMQ,默认guest用户，密码也是guest。\\n```\\n\\n## 6.安装elasticsearch：\\n\\n```shell\\ndocker pull elasticsearch:7.17.12\\n```\\n\\n```shell\\nmkdir -p  /home/elasticsearch/data/ \\nmkdir -p  /home/elasticsearch/config/\\n```\\n\\n1. 编写配置文件\\n\\n   ```shell\\n   echo \'http.host: 0.0.0.0\\n   http.cors.enabled: true\\n   http.cors.allow-origin: \\\"*\\\" \'>>/home/elasticsearch/config/elasticsearch.yml\\n   ```\\n\\n2. 修改文件夹权限\\n\\n   ```shell\\n   chmod -R 777 /home/elasticsearch/\\n   ls -l # 查看文件权限\\n   ```\\n\\n3. 启动elasticseach镜像\\n\\n   ```shell\\n   docker run --name elasticsearch -p 9200:9200 \\\\\\n    -p 9300:9300 \\\\\\n    -e \\\"discovery.type=single-node\\\" \\\\\\n    -e ES_JAVA_OPTS=\\\"-Xms64m -Xmx128m\\\" \\\\\\n     -v /home/elasticsearch/config/elasticsearch.yml:/usr/shellare/elasticsearch/config/elasticsearch.yml \\\\\\n    -v /home/elasticsearch/data:/usr/shellare/elasticsearch/data \\\\\\n    -v /home/elasticsearch/plugins:/usr/shellare/elasticsearch/plugins \\\\\\n    -d elasticsearch:7.17.12\\n   ```\\n\\n>接下来我们就是拿浏览器访问啦。\\n>在浏览器上输入：服务器IP地址:9200\\n>可能出现的问题：\\n\\n### 1. 启动成功，但是访问失败的话，查看一下安全组中映射端口是否已经打开。如果是本地虚拟机，可能与防火墙相关（我用的云服务器，没有测试，如果有问题，还是需要大家自行去百度||谷歌一下）。\\n\\n### 2. -e ES_JAVA_OPTS=\\\"-Xms64m -Xmx128m\\\"：配置内存大小出现了问题。\\n\\n### 3. 最后就还有可能是配置文件中出现了问题。\\n\\n   ```shell\\necho \'http.host: 0.0.0.0\\nhttp.cors.enabled: true\\nhttp.cors.allow-origin: \\\"*\\\" \'>>/home/elasticsearch/config/elasticsearch.yml\\n   ```\\n\\n   >`http.host: 0.0.0.0` 在冒号后面有一个空格的，这里的配置文件是`yml`格式,所以一定要严格按照`yml`格式来书写。\\n   >安装ik分词器\\n   >进入已经启动成功的elasticsearch容器。\\n\\n```shell\\ndocker exec -it elasticsearch /bin/bash\\n```\\n\\n```shell\\n./bin/elasticsearch-plugin install https://github.com/medcl/elasticsearch-analysis-ik/releases/download/v7.9.2/elasticsearch-analysis-ik-7.9.2.zip\\n```\\n\\n>ps: `安装的ik分词器的版本一定要与elasticsearch的版本保持一致`\\n>下载过程中如果遇到选择，直接输入 y回车就可以了。\\n>下载完成之后，退出去，重新启动elasticsearch容器。\\n\\n```shell\\ndocker restart elasticsearch\\n```\\n\\n>测试ik分词器是否安装成功\\n>安装完成后，我们再来进行测试遍，看看有什么样的变化。\\n>postman post请求分词测试：`http://服务器IP地址:9200/_analyze`\\n\\n```json\\n{\\n\\t\\\"tokenizer\\\":\\\"ik_smart\\\",\\n\\t\\\"text\\\":\\\"我爱技术\\\"\\n}\\n```\\n\\n结果\\n\\n```shell\\n{\\n    \\\"tokens\\\": [\\n        {\\n            \\\"token\\\": \\\"我\\\",\\n            \\\"start_offset\\\": 0,\\n            \\\"end_offset\\\": 1,\\n            \\\"type\\\": \\\"CN_CHAR\\\",\\n            \\\"position\\\": 0\\n        },\\n        {\\n            \\\"token\\\": \\\"爱\\\",\\n            \\\"start_offset\\\": 1,\\n            \\\"end_offset\\\": 2,\\n            \\\"type\\\": \\\"CN_CHAR\\\",\\n            \\\"position\\\": 1\\n        },\\n        {\\n            \\\"token\\\": \\\"技术\\\",\\n            \\\"start_offset\\\": 2,\\n            \\\"end_offset\\\": 4,\\n            \\\"type\\\": \\\"CN_WORD\\\",\\n            \\\"position\\\": 2\\n        }\\n    ]\\n}\\n```\\n\\n## 7.安装MaxWell：\\n\\n```sh\\ndocker pull zendesk/maxwell //下载MaxWell镜像\\ndocker run --name maxwell --restart=always  -d  zendesk/maxwell bin/maxwell  --user=\'root\' --password=\'你的密码\'  --host=\'你的IP\'  --producer=rabbitmq --rabbitmq_user=\'guest\' --rabbitmq_pass=\'guest\' --rabbitmq_host=\'你的IP\' --rabbitmq_port=\'5672\' --rabbitmq_exchange=\'maxwell_exchange\'  --rabbitmq_exchange_type=\'fanout\' --rabbitmq_exchange_durable=\'true\' --filter=\'exclude: *.*, include: aurora.t_article.article_title = *, include: aurora.t_article.article_content = *, include: aurora.t_article.is_delete = *, include: aurora.t_article.status = *\' //运行MaxWell\\n```\\n\\n注意：上述命令中aurora为数据库名称。\\n\\n****\\n\\n## 8.填写aurora-springboot中的yml文件：\\n\\n>此处省略，操作比较简单，就是配置一些简单的ip+端口+用户名+密码，前提是服务器上对应的端口已经打开\\n>阿里云oss具体情况详见百度\\n>QQ互联具体情况详见百度\\n>这里就不赘述了\\n\\n## 9.打包运行后端项目：\\n\\n### 1. 使用idea右侧Maven的package命令\\n\\n### 2. 在服务器的/usr/local/下面创建名为docker的文件夹\\n\\n### 3. 将打包好的jar包传到服务器上面的/usr/local/docker下面\\n\\n### 4. 编写Dockerfile,同时将编写好的Dockerfile传输到服务器的/usr/local/docker下面\\n\\n```dockerfile\\nFROM openjdk:17-jdk-slim-buster\\nVOLUME /tmp\\nADD aurora-springboot-0.0.1.jar blog.jar\\nENTRYPOINT [\\\"java\\\",\\\"-Djava.security.egd=file:/dev/./urandom\\\",\\\"-jar\\\",\\\"/blog.jar\\\"]\\n```\\n\\n> 注意：Dockerfile文件只需要上传到指定目录下即可，不需要手动执行其他操作。\\n\\n### 5. 编写aurora-start.sh,同时将编写好的aurora-start.sh上传到服务器的/usr/local/docker下面\\n\\n```shell\\nSOURCE_PATH=/usr/local/docker\\nSERVER_NAME=aurora-springboot-0.0.1.jar\\nTAG=latest\\nSERVER_PORT=8080\\nCID=$(docker ps | grep \\\"$SERVER_NAME\\\" | awk \'{print $1}\')\\nIID=$(docker images | grep \\\"$SERVER_NAME\\\" | awk \'{print $3}\')\\nif [ -n \\\"$CID\\\" ]; then\\n  echo \\\"存在容器$SERVER_NAME,CID-$CID\\\"\\n  docker stop $CID\\n  echo \\\"成功停止容器$SERVER_NAME,CID-$CID\\\"\\n  docker rm $CID\\n  echo \\\"成功删除容器$SERVER_NAME,CID-$CID\\\"\\nfi\\nif [ -n \\\"$IID\\\" ]; then\\n  echo \\\"存在镜像$SERVER_NAME:$TAG,IID=$IID\\\"\\n  docker rmi $IID\\n  echo \\\"成功删除镜像$SERVER_NAME:$TAG,IID=$IID\\\"\\nfi\\necho \\\"开始构建镜像$SERVER_NAME:$TAG\\\"\\ncd $SOURCE_PATH\\ndocker build -t $SERVER_NAME:$TAG .\\necho \\\"成功构建镜像$SERVER_NAME:$TAG\\\"\\ndocker run --restart=always --name aurora-springboot-0.0.1.jar -d -p 8080:8080 aurora-springboot-0.0.1.jar:latest\\necho \\\"成功创建并运行容器$SERVER_NAME\\\"\\n```\\n\\n**注意事项：sh文件需要用notepad++转为Unix格式**\\n\\n具体操作：点开notepad++中的编辑 ---> 文档格式转换 --->转为Unix \\n\\n### 6. cd到/usr/local/docker下面 ，执行如下命令打包docker镜像文件\\n\\n```shell\\nsh aurora-start.sh\\n```\\n\\n### 7. 启动容器\\n\\n```sh\\ndocker run  --name aurora-springboot-0.0.1.jar -d -p 8080:8080 aurora-springboot-0.0.1.jar:latest\\n```\\n\\n### 8. 这样后端项目就可以在服务器上跑起来了\\n\\n### 9. 访问测试(浏览器上访问)\\n\\n   ```shell\\nip:8080\\n   ```\\n\\n****\\n\\n## 10.打包运行前端项目：\\n\\n### 1. aurora-blog项目中，更改src/config/config.ts\\n\\n   ```typescript\\n  captcha: {\\n    TENCENT_CAPTCHA: \'你自己的天御验证码\'\\n  },\\n  qqLogin: {\\n    QQ_APP_ID: \'你自己的APP_ID\',\\n    QQ_REDIRECT_URI: \'https://你的前台域名/oauth/login/qq\'\\n  },\\n   ```\\n\\n### 2. aurora-blog项目中，更改public/index.html\\n\\n   ```html\\n<script\\n      src=\\\"http://connect.qq.com/qc_jssdk.js\\\"\\n      data-appid=\\\"你自己的APP_ID\\\"\\n      data-redirecturi=\\\"https://你的前台域名/oauth/login/qq\\\"></script>\\n   ```\\n\\n### 3. 如果你的网站没有打算使用https,将aurora-blog/public/index.html和aurora-admin/public/index.html中下面这一行代码给注释掉\\n\\n   ```html\\n<meta http-equiv=\\\"Content-Security-Policy\\\" content=\\\"upgrade-insecure-requests\\\" />\\n   ```\\n\\n### 4. 分别到aurora-blog和aurora-admin下面执行如下命令 (推荐关闭vscode的Eslint,本项目没有遵循Eslint的规范)\\n\\n如果下列命令执行报错，可以尝试替换版本\\n参考版本：npm版本为：8.3.1    vue-cli的版本为：5.0.6\\n\\n   ```shell\\nnpm install\\nnpm run build\\n   ```\\n\\n### 5. 在服务器的/usr/local/下面创建名为vue的文件夹，\\n\\n### 6. 将打包好的前台代码重命名为blog, 并传输到服务器的/usr/local/vue下面\\n\\n### 7. 将打包好的后台代码重命名为admin, 并传输到服务器的/usr/local/vue下面\\n\\n## 11.安装并启动nginx：\\n\\n### 方式1: http\\n\\n1. 拉取nginx镜像\\n\\n   ```shell\\n   docker pull nginx\\n   ```\\n\\n2. 在/usr/local/nginx下创建nginx.conf文件，格式如下\\n\\n   ```shell\\n   events {\\n       worker_connections  1024;\\n   }\\n   \\n   http {\\n       include       mime.types;\\n       default_type  application/octet-stream;\\n       sendfile        on;\\n       keepalive_timeout  65;\\n   \\n       client_max_body_size     50m;\\n       client_body_buffer_size  10m; \\n       client_header_timeout    1m;\\n       client_body_timeout      1m;\\n   \\n       gzip on;\\n       gzip_min_length  1k;\\n       gzip_buffers     4 16k;\\n       gzip_comp_level  4;\\n       gzip_types text/plain application/javascript application/x-javascript text/css application/xml text/javascript application/x-httpd-php image/jpeg image/gif image/png;\\n       gzip_vary on;\\n   \\n   server {\\n           listen       80;\\n           server_name  前台域名;\\n        \\n           location / {\\t\\t\\n               root   /usr/local/vue/blog;\\n               index  index.html index.htm; \\n               try_files $uri $uri/ /index.html;\\t\\n           }\\n   \\t\\t\\t\\n   \\tlocation ^~ /api/ {\\t\\t\\n               proxy_pass http://服务器ip:8080/;\\n   \\t       proxy_set_header   Host             $host;\\n               proxy_set_header   X-Real-IP        $remote_addr;\\t\\t\\t\\t\\t\\t\\n               proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n           }\\n   \\t\\t\\n       }\\n   \\t\\n   server {\\n           listen       80;\\n           server_name  后台子域名;\\n        \\n           location / {\\t\\t\\n               root   /usr/local/vue/admin;\\n               index  index.html index.htm; \\n               try_files $uri $uri/ /index.html;\\t\\n           }\\n   \\t\\t\\t\\n   \\tlocation ^~ /api/ {\\t\\t\\n               proxy_pass http://你的ip:8080/;\\n   \\t    proxy_set_header   Host             $host;\\n               proxy_set_header   X-Real-IP        $remote_addr;\\t\\t\\t\\t\\t\\t\\n               proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n           }\\n   \\t\\t\\n       }\\n    }\\n   ```\\n\\n3. 启动nginx\\n\\n   ```shell\\n   docker run --name nginx --restart=always -p 80:80 -d -v /usr/local/nginx/nginx.conf:/etc/nginx/nginx.conf -v /usr/local/vue:/usr/local/vue nginx \\n   ```\\n\\n### 方式2: https\\n\\n拉取nginx镜像\\n\\n```shell\\ndocker pull nginx\\n```\\n\\n修改配置文件(在原版的基础上加上minio存储-全站https)\\n\\n```shell\\nevents {\\n    worker_connections  1024;\\n}\\n\\nhttp {\\n    include       mime.types;\\n    default_type  application/octet-stream;\\n    sendfile        on;\\n    keepalive_timeout  65;\\n\\n    client_max_body_size     50m;\\n    client_body_buffer_size  10m; \\t  \\n    client_header_timeout    1m;\\n    client_body_timeout      1m;\\n\\n    gzip on;\\n    gzip_min_length  1k;\\n    gzip_buffers     4 16k;\\n    gzip_comp_level  4;\\n    gzip_types text/plain application/javascript application/x-javascript text/css application/xml text/javascript application/x-httpd-php image/jpeg image/gif image/png;\\n    gzip_vary on;\\n\\t\\nserver {\\n\\n        listen  443 ssl;\\n        server_name  你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/你的域名_bundle.pem; \\n\\t   ssl_certificate_key /etc/nginx/cert/你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n       location / {\\n            root   /usr/local/vue/blog;\\n            index  index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\t\\t\\n        location ^~ /api/ {\\n            proxy_pass http://你的IP:8080/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n\\n    }\\n\\nserver {\\n\\n        listen  443 ssl;\\n        server_name admin.你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/admin.你的域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/admin.你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n       location / {\\n            root   /usr/local/vue/admin;\\n            index  index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\t\\t\\n        location ^~ /api/ {\\n            proxy_pass http://你的IP:8080/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n\\t\\n    }\\nserver {\\n\\n        listen  443 ssl;\\n        server_name ws.你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/ws.你的域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/ws.你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n        location / {\\n            proxy_pass http://你的IP:9000/aurora/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n\\t\\n    }\\n\\n\\nserver {\\n        listen       80;\\n        server_name  你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n    }\\n\\t\\nserver {\\n        listen       80;\\n        server_name  admin.你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n    }\\t\\n    server {\\n    listen 80;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/aurora/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n}\\n\\nserver {\\n    listen 9000;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n}\\n}\\n```\\n\\n启动nginx\\n\\n```shell\\ndocker run --name nginx --restart=always -p 443:443 -p 80:80 -d -v /usr/local/nginx/nginx.conf:/etc/nginx/nginx.conf -v /usr/local/nginx/cert:/etc/nginx/cert -v /usr/local/vue:/usr/local/vue --privileged=true nginx\\n```\\n\\n## 12.安装并启动minio：\\n\\n```dockerfile\\ndocker run -d -p 9000:9000 -p 9001:9001 --name minio --restart=always -e \\\"MINIO_ROOT_USER=你的用户名\\\" -e \\\"MINIO_ROOT_PASSWORD=你的密码\\\" -v /minio/data:/data -v /minio/config:/root/.minio -v /etc/localtime:/etc/localtime minio/minio server /data --console-address \\\":9001\\\"\\n```\",\"articleCover\":\"http://ws.aqi125.cn/articles/854cb4178a8fa828a3bc7d1e694d37de.jpg\",\"articleTitle\":\"Blog部署教程补充\",\"categoryName\":\"blog部署\",\"id\":142,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.127.50', '中国|河南省|南阳市|移动', '2025-12-13 11:59:29', NULL);
INSERT INTO `t_operation_log` VALUES (2070, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# 写在前面\\n\\n# 是对原花未眠博客  Aurora 由原有jdk8全面升级到jdk17 spring boot版本升级至2.7.18 elasticsearch升级至7.17.12 及安装minio存储的补充\\n\\n# 一.jdk升级很简单谁都会直接上代码看问题:\\n\\n```java\\nClosing non transactional SqlSession [org.apache.ibatis.session.defaults.DefaultSqlSession@6137f51c]\\n2023-04-08 19:05:57.419 ERROR 7908 --- [nio-8080-exec-2] o.a.c.c.C.[.[.[/].[dispatcherServlet]    : Servlet.service() for servlet [dispatcherServlet] in context with path [] threw exception [Filter execution threw an exception] with root cause\\n\\njava.lang.ClassNotFoundException: javax.xml.bind.DatatypeConverter\\n\\tat java.base/jdk.internal.loader.BuiltinClassLoader.loadClass(BuiltinClassLoader.java:581) ~[na:na]\\n\\tat java.base/jdk.internal.loader.ClassLoaders$AppClassLoader.loadClass(ClassLoaders.java:178) ~[na:na]\\n\\tat java.base/java.lang.ClassLoader.loadClass(ClassLoader.java:521) ~[na:na]\\n```\\n\\n解决方法如下\\n\\n1.是回退，回退不符合我们需求\\n\\n2.是pom.xml添加依赖\\n\\n```xml\\n<dependency>\\n   <groupId>javax.xml.bind</groupId>\\n    <artifactId>jaxb-api</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>com.sun.xml.bind</groupId>\\n    <artifactId>jaxb-impl</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>com.sun.xml.bind</groupId>\\n    <artifactId>jaxb-core</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>javax.activation</groupId>\\n    <artifactId>activation</artifactId>\\n    <version>1.1.1</version>\\n</dependency>\\n```\\n\\n# 二.minio安装有详细步骤在12小节 在配置nginx的时候minio部分配置如下:\\n\\n```xml\\nserver {\\n\\n        listen  443 ssl;\\n        server_name ws.你的域名;\\n    \\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/ws.你的域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/ws.你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n    \\n        location / {\\n            proxy_pass http://你的IP:9000/aurora/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n    \\n    }\\n\\n\\nserver {\\n        listen       80;\\n        server_name  你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n\\n    }\\n\\nserver {\\n        listen       80;\\n        server_name  admin.你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n\\n    }\\t\\n    server {\\n    listen 80;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/aurora/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n\\n}\\n\\nserver {\\n    listen 9000;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n```\\n# 三.pom.xml 变更如下两个部分\\n```language\\n<properties>\\n        <java.version>17</java.version>\\n        <project.build.sourceEncoding>UTF-8</project.build.sourceEncoding>\\n        <project.reporting.outputEncoding>UTF-8</project.reporting.outputEncoding>\\n        <spring-boot.version>2.7.18</spring-boot.version>\\n        <elasticsearch.version>7.17.12</elasticsearch.version>\\n这是分割线------------------------------------------------------------------------\\n        <plugins>\\n            <plugin>\\n                <groupId>org.apache.maven.plugins</groupId>\\n                <artifactId>maven-compiler-plugin</artifactId>\\n                <version>3.9.0</version>\\n                <configuration>\\n                    <source>17</source>\\n                    <target>17</target>\\n                    <encoding>UTF-8</encoding>\\n                </configuration>\\n            </plugin>\\n```\\n\\n\\n# 四.以下是原安装详情及补充：\\n\\n## 1.服务器要求：\\n\\n> 下面的建议不包含minio的内存占用，如需使用minio，请参考步骤12\\n\\n1. 核心数和内存大小有两种方案：\\n   - 2核4G（使用ES搜索策略）\\n   - 2核2G（使用MySQL搜素策略）\\n\\n2. 带宽大小有两种方案：\\n   - 使用oss对带宽没有要求（本人亲测：1M带宽+oss 访问速度很快）\\n   - 使用minio需要大一点的带宽（小带宽也可以，但需要使用cdn加速）\\n\\n## 2.docker的安装：\\n\\n> 以下命令基于CentOS环境。\\n\\n1. 下载工具\\n\\n   ```shell\\n   yum install -y yum-utils\\n   ```\\n\\n2. 设置镜像的仓库\\n\\n   ```shell\\n   yum-config-manager \\\\\\n       --add-repo \\\\\\n       https://mirrors.aliyun.com/docker-ce/linux/centos/docker-ce.repo  #配置阿里云的镜像\\n   ```\\n\\n3. 更新yum软件包索引\\n\\n   ```shell\\n   yum makecache fast\\n   ```\\n\\n4. 安装docker相关配置\\n\\n   ```shell\\n   yum install docker-ce docker-ce-cli containerd.io\\n   ```\\n\\n5. 启动docker\\n\\n   ```shell\\n   systemctl start docker\\n   # 查看当前版本号，是否启动成功\\n   docker version\\n   # 设置开机自启动\\n   systemctl enable docker\\n   ```\\n\\n****\\n\\n## 3.安装mysql：\\n\\n### 方式1: 无挂载模式\\n\\n> 这种方式直接运行mysql之后，所有关于mysql的内容都在容器中，后续如果需要修改mysql的内容，需要手动进入容器内进行操作。且在宿主机上无备份，一旦容器被删除，数据也会被删除。\\n\\n```shell\\ndocker pull mysql //下载MySQL镜像\\ndocker run --name mysql --restart=always -p 3306:3306 -e MYSQL_ROOT_PASSWORD=你的密码 -d mysql //启动MySQL\\n```\\n\\n### 方式2: 数据卷挂载模式\\n\\n> 和**无挂载模式相对**，通过数据卷挂载的方式运行容器，将容器内的部分重要文件映射到宿主机上。直接操作宿主机对应的映射文件就能和容器内作同步，方便操作的同时还能保证容器内的数据在宿主机上有一个备份。\\n>\\n> 下面的命令分别对mysql的日志文件、配置文件、数据文件进行了映射，你也可以自己修改。\\n\\n```shell\\ndocker run -d -p 3306:3306 --restart=always -v /auroras/mysql/log:/var/log/mysql -v /auroras/mysql/data:/var/lib/mysql -v /auroras/mysql/conf:/etc/mysql/conf.d  -e MYSQL_ROOT_PASSWORD=你的密码  --name mysql mysql\\n```\\n\\n****\\n\\n## 4.安装redis：\\n\\n```shell\\ndocker pull redis //下载Redis镜像\\ndocker run --name redis  --restart=always -p 6379:6379 -d redis --requirepass \\\"你的密码\\\" //启动Redis\\n```\\n\\n## 5.安装rabbitmq：\\n\\n```shell\\ndocker pull rabbitmq:management //下载RabbitMQ镜像\\ndocker run --name rabbit --restart=always -p 15672:15672 -p 5672:5672  -d  rabbitmq:management   //启动RabbitMQ,默认guest用户，密码也是guest。\\n```\\n\\n## 6.安装elasticsearch：\\n\\n```shell\\ndocker pull elasticsearch:7.17.12\\n```\\n\\n```shell\\nmkdir -p  /home/elasticsearch/data/ \\nmkdir -p  /home/elasticsearch/config/\\n```\\n\\n1. 编写配置文件\\n\\n   ```shell\\n   echo \'http.host: 0.0.0.0\\n   http.cors.enabled: true\\n   http.cors.allow-origin: \\\"*\\\" \'>>/home/elasticsearch/config/elasticsearch.yml\\n   ```\\n\\n2. 修改文件夹权限\\n\\n   ```shell\\n   chmod -R 777 /home/elasticsearch/\\n   ls -l # 查看文件权限\\n   ```\\n\\n3. 启动elasticseach镜像\\n\\n   ```shell\\n   docker run --name elasticsearch -p 9200:9200 \\\\\\n    -p 9300:9300 \\\\\\n    -e \\\"discovery.type=single-node\\\" \\\\\\n    -e ES_JAVA_OPTS=\\\"-Xms64m -Xmx128m\\\" \\\\\\n     -v /home/elasticsearch/config/elasticsearch.yml:/usr/shellare/elasticsearch/config/elasticsearch.yml \\\\\\n    -v /home/elasticsearch/data:/usr/shellare/elasticsearch/data \\\\\\n    -v /home/elasticsearch/plugins:/usr/shellare/elasticsearch/plugins \\\\\\n    -d elasticsearch:7.17.12\\n   ```\\n\\n>接下来我们就是拿浏览器访问啦。\\n>在浏览器上输入：服务器IP地址:9200\\n>可能出现的问题：\\n\\n### 1. 启动成功，但是访问失败的话，查看一下安全组中映射端口是否已经打开。如果是本地虚拟机，可能与防火墙相关（我用的云服务器，没有测试，如果有问题，还是需要大家自行去百度||谷歌一下）。\\n\\n### 2. -e ES_JAVA_OPTS=\\\"-Xms64m -Xmx128m\\\"：配置内存大小出现了问题。\\n\\n### 3. 最后就还有可能是配置文件中出现了问题。\\n\\n   ```shell\\necho \'http.host: 0.0.0.0\\nhttp.cors.enabled: true\\nhttp.cors.allow-origin: \\\"*\\\" \'>>/home/elasticsearch/config/elasticsearch.yml\\n   ```\\n\\n   >`http.host: 0.0.0.0` 在冒号后面有一个空格的，这里的配置文件是`yml`格式,所以一定要严格按照`yml`格式来书写。\\n   >安装ik分词器\\n   >进入已经启动成功的elasticsearch容器。\\n\\n```shell\\ndocker exec -it elasticsearch /bin/bash\\n```\\n\\n```shell\\n./bin/elasticsearch-plugin install https://github.com/medcl/elasticsearch-analysis-ik/releases/download/v7.9.2/elasticsearch-analysis-ik-7.9.2.zip\\n```\\n\\n>ps: `安装的ik分词器的版本一定要与elasticsearch的版本保持一致`\\n>下载过程中如果遇到选择，直接输入 y回车就可以了。\\n>下载完成之后，退出去，重新启动elasticsearch容器。\\n\\n```shell\\ndocker restart elasticsearch\\n```\\n\\n>测试ik分词器是否安装成功\\n>安装完成后，我们再来进行测试遍，看看有什么样的变化。\\n>postman post请求分词测试：`http://服务器IP地址:9200/_analyze`\\n\\n```json\\n{\\n\\t\\\"tokenizer\\\":\\\"ik_smart\\\",\\n\\t\\\"text\\\":\\\"我爱技术\\\"\\n}\\n```\\n\\n结果\\n\\n```shell\\n{\\n    \\\"tokens\\\": [\\n        {\\n            \\\"token\\\": \\\"我\\\",\\n            \\\"start_offset\\\": 0,\\n            \\\"end_offset\\\": 1,\\n            \\\"type\\\": \\\"CN_CHAR\\\",\\n            \\\"position\\\": 0\\n        },\\n        {\\n            \\\"token\\\": \\\"爱\\\",\\n            \\\"start_offset\\\": 1,\\n            \\\"end_offset\\\": 2,\\n            \\\"type\\\": \\\"CN_CHAR\\\",\\n            \\\"position\\\": 1\\n        },\\n        {\\n            \\\"token\\\": \\\"技术\\\",\\n            \\\"start_offset\\\": 2,\\n            \\\"end_offset\\\": 4,\\n            \\\"type\\\": \\\"CN_WORD\\\",\\n            \\\"position\\\": 2\\n        }\\n    ]\\n}\\n```\\n\\n## 7.安装MaxWell：\\n\\n```sh\\ndocker pull zendesk/maxwell //下载MaxWell镜像\\ndocker run --name maxwell --restart=always  -d  zendesk/maxwell bin/maxwell  --user=\'root\' --password=\'你的密码\'  --host=\'你的IP\'  --producer=rabbitmq --rabbitmq_user=\'guest\' --rabbitmq_pass=\'guest\' --rabbitmq_host=\'你的IP\' --rabbitmq_port=\'5672\' --rabbitmq_exchange=\'maxwell_exchange\'  --rabbitmq_exchange_type=\'fanout\' --rabbitmq_exchange_durable=\'true\' --filter=\'exclude: *.*, include: aurora.t_article.article_title = *, include: aurora.t_article.article_content = *, include: aurora.t_article.is_delete = *, include: aurora.t_article.status = *\' //运行MaxWell\\n```\\n\\n注意：上述命令中aurora为数据库名称。\\n\\n****\\n\\n## 8.填写aurora-springboot中的yml文件：\\n\\n>此处省略，操作比较简单，就是配置一些简单的ip+端口+用户名+密码，前提是服务器上对应的端口已经打开\\n>阿里云oss具体情况详见百度\\n>QQ互联具体情况详见百度\\n>这里就不赘述了\\n\\n## 9.打包运行后端项目：\\n\\n### 1. 使用idea右侧Maven的package命令\\n\\n### 2. 在服务器的/usr/local/下面创建名为docker的文件夹\\n\\n### 3. 将打包好的jar包传到服务器上面的/usr/local/docker下面\\n\\n### 4. 编写Dockerfile,同时将编写好的Dockerfile传输到服务器的/usr/local/docker下面\\n\\n```dockerfile\\nFROM openjdk:17-jdk-slim-buster\\nVOLUME /tmp\\nADD aurora-springboot-0.0.1.jar blog.jar\\nENTRYPOINT [\\\"java\\\",\\\"-Djava.security.egd=file:/dev/./urandom\\\",\\\"-jar\\\",\\\"/blog.jar\\\"]\\n```\\n\\n> 注意：Dockerfile文件只需要上传到指定目录下即可，不需要手动执行其他操作。\\n\\n### 5. 编写aurora-start.sh,同时将编写好的aurora-start.sh上传到服务器的/usr/local/docker下面\\n\\n```shell\\nSOURCE_PATH=/usr/local/docker\\nSERVER_NAME=aurora-springboot-0.0.1.jar\\nTAG=latest\\nSERVER_PORT=8080\\nCID=$(docker ps | grep \\\"$SERVER_NAME\\\" | awk \'{print $1}\')\\nIID=$(docker images | grep \\\"$SERVER_NAME\\\" | awk \'{print $3}\')\\nif [ -n \\\"$CID\\\" ]; then\\n  echo \\\"存在容器$SERVER_NAME,CID-$CID\\\"\\n  docker stop $CID\\n  echo \\\"成功停止容器$SERVER_NAME,CID-$CID\\\"\\n  docker rm $CID\\n  echo \\\"成功删除容器$SERVER_NAME,CID-$CID\\\"\\nfi\\nif [ -n \\\"$IID\\\" ]; then\\n  echo \\\"存在镜像$SERVER_NAME:$TAG,IID=$IID\\\"\\n  docker rmi $IID\\n  echo \\\"成功删除镜像$SERVER_NAME:$TAG,IID=$IID\\\"\\nfi\\necho \\\"开始构建镜像$SERVER_NAME:$TAG\\\"\\ncd $SOURCE_PATH\\ndocker build -t $SERVER_NAME:$TAG .\\necho \\\"成功构建镜像$SERVER_NAME:$TAG\\\"\\ndocker run --restart=always --name aurora-springboot-0.0.1.jar -d -p 8080:8080 aurora-springboot-0.0.1.jar:latest\\necho \\\"成功创建并运行容器$SERVER_NAME\\\"\\n```\\n\\n**注意事项：sh文件需要用notepad++转为Unix格式**\\n\\n具体操作：点开notepad++中的编辑 ---> 文档格式转换 --->转为Unix \\n\\n### 6. cd到/usr/local/docker下面 ，执行如下命令打包docker镜像文件\\n\\n```shell\\nsh aurora-start.sh\\n```\\n\\n### 7. 启动容器\\n\\n```sh\\ndocker run  --name aurora-springboot-0.0.1.jar -d -p 8080:8080 aurora-springboot-0.0.1.jar:latest\\n```\\n\\n### 8. 这样后端项目就可以在服务器上跑起来了\\n\\n### 9. 访问测试(浏览器上访问)\\n\\n   ```shell\\nip:8080\\n   ```\\n\\n****\\n\\n## 10.打包运行前端项目：\\n\\n### 1. aurora-blog项目中，更改src/config/config.ts\\n\\n   ```typescript\\n  captcha: {\\n    TENCENT_CAPTCHA: \'你自己的天御验证码\'\\n  },\\n  qqLogin: {\\n    QQ_APP_ID: \'你自己的APP_ID\',\\n    QQ_REDIRECT_URI: \'https://你的前台域名/oauth/login/qq\'\\n  },\\n   ```\\n\\n### 2. aurora-blog项目中，更改public/index.html\\n\\n   ```html\\n<script\\n      src=\\\"http://connect.qq.com/qc_jssdk.js\\\"\\n      data-appid=\\\"你自己的APP_ID\\\"\\n      data-redirecturi=\\\"https://你的前台域名/oauth/login/qq\\\"></script>\\n   ```\\n\\n### 3. 如果你的网站没有打算使用https,将aurora-blog/public/index.html和aurora-admin/public/index.html中下面这一行代码给注释掉\\n\\n   ```html\\n<meta http-equiv=\\\"Content-Security-Policy\\\" content=\\\"upgrade-insecure-requests\\\" />\\n   ```\\n\\n### 4. 分别到aurora-blog和aurora-admin下面执行如下命令 (推荐关闭vscode的Eslint,本项目没有遵循Eslint的规范)\\n\\n如果下列命令执行报错，可以尝试替换版本\\n参考版本：npm版本为：8.3.1    vue-cli的版本为：5.0.6\\n\\n   ```shell\\nnpm install\\nnpm run build\\n   ```\\n\\n### 5. 在服务器的/usr/local/下面创建名为vue的文件夹，\\n\\n### 6. 将打包好的前台代码重命名为blog, 并传输到服务器的/usr/local/vue下面\\n\\n### 7. 将打包好的后台代码重命名为admin, 并传输到服务器的/usr/local/vue下面\\n\\n## 11.安装并启动nginx：\\n\\n### 方式1: http\\n\\n1. 拉取nginx镜像\\n\\n   ```shell\\n   docker pull nginx\\n   ```\\n\\n2. 在/usr/local/nginx下创建nginx.conf文件，格式如下\\n\\n   ```shell\\n   events {\\n       worker_connections  1024;\\n   }\\n   \\n   http {\\n       include       mime.types;\\n       default_type  application/octet-stream;\\n       sendfile        on;\\n       keepalive_timeout  65;\\n   \\n       client_max_body_size     50m;\\n       client_body_buffer_size  10m; \\n       client_header_timeout    1m;\\n       client_body_timeout      1m;\\n   \\n       gzip on;\\n       gzip_min_length  1k;\\n       gzip_buffers     4 16k;\\n       gzip_comp_level  4;\\n       gzip_types text/plain application/javascript application/x-javascript text/css application/xml text/javascript application/x-httpd-php image/jpeg image/gif image/png;\\n       gzip_vary on;\\n   \\n   server {\\n           listen       80;\\n           server_name  前台域名;\\n        \\n           location / {\\t\\t\\n               root   /usr/local/vue/blog;\\n               index  index.html index.htm; \\n               try_files $uri $uri/ /index.html;\\t\\n           }\\n   \\t\\t\\t\\n   \\tlocation ^~ /api/ {\\t\\t\\n               proxy_pass http://服务器ip:8080/;\\n   \\t       proxy_set_header   Host             $host;\\n               proxy_set_header   X-Real-IP        $remote_addr;\\t\\t\\t\\t\\t\\t\\n               proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n           }\\n   \\t\\t\\n       }\\n   \\t\\n   server {\\n           listen       80;\\n           server_name  后台子域名;\\n        \\n           location / {\\t\\t\\n               root   /usr/local/vue/admin;\\n               index  index.html index.htm; \\n               try_files $uri $uri/ /index.html;\\t\\n           }\\n   \\t\\t\\t\\n   \\tlocation ^~ /api/ {\\t\\t\\n               proxy_pass http://你的ip:8080/;\\n   \\t    proxy_set_header   Host             $host;\\n               proxy_set_header   X-Real-IP        $remote_addr;\\t\\t\\t\\t\\t\\t\\n               proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n           }\\n   \\t\\t\\n       }\\n    }\\n   ```\\n\\n3. 启动nginx\\n\\n   ```shell\\n   docker run --name nginx --restart=always -p 80:80 -d -v /usr/local/nginx/nginx.conf:/etc/nginx/nginx.conf -v /usr/local/vue:/usr/local/vue nginx \\n   ```\\n\\n### 方式2: https\\n\\n拉取nginx镜像\\n\\n```shell\\ndocker pull nginx\\n```\\n\\n修改配置文件(在原版的基础上加上minio存储-全站https)\\n\\n```shell\\nevents {\\n    worker_connections  1024;\\n}\\n\\nhttp {\\n    include       mime.types;\\n    default_type  application/octet-stream;\\n    sendfile        on;\\n    keepalive_timeout  65;\\n\\n    client_max_body_size     50m;\\n    client_body_buffer_size  10m; \\t  \\n    client_header_timeout    1m;\\n    client_body_timeout      1m;\\n\\n    gzip on;\\n    gzip_min_length  1k;\\n    gzip_buffers     4 16k;\\n    gzip_comp_level  4;\\n    gzip_types text/plain application/javascript application/x-javascript text/css application/xml text/javascript application/x-httpd-php image/jpeg image/gif image/png;\\n    gzip_vary on;\\n\\t\\nserver {\\n\\n        listen  443 ssl;\\n        server_name  你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/你的域名_bundle.pem; \\n\\t   ssl_certificate_key /etc/nginx/cert/你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n       location / {\\n            root   /usr/local/vue/blog;\\n            index  index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\t\\t\\n        location ^~ /api/ {\\n            proxy_pass http://你的IP:8080/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n\\n    }\\n\\nserver {\\n\\n        listen  443 ssl;\\n        server_name admin.你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/admin.你的域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/admin.你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n       location / {\\n            root   /usr/local/vue/admin;\\n            index  index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\t\\t\\n        location ^~ /api/ {\\n            proxy_pass http://你的IP:8080/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n\\t\\n    }\\nserver {\\n\\n        listen  443 ssl;\\n        server_name ws.你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/ws.你的域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/ws.你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n        location / {\\n            proxy_pass http://你的IP:9000/aurora/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n\\t\\n    }\\n\\n\\nserver {\\n        listen       80;\\n        server_name  你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n    }\\n\\t\\nserver {\\n        listen       80;\\n        server_name  admin.你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n    }\\t\\n    server {\\n    listen 80;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/aurora/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n}\\n\\nserver {\\n    listen 9000;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n}\\n}\\n```\\n\\n启动nginx\\n\\n```shell\\ndocker run --name nginx --restart=always -p 443:443 -p 80:80 -d -v /usr/local/nginx/nginx.conf:/etc/nginx/nginx.conf -v /usr/local/nginx/cert:/etc/nginx/cert -v /usr/local/vue:/usr/local/vue --privileged=true nginx\\n```\\n\\n## 12.安装并启动minio：\\n\\n```dockerfile\\ndocker run -d -p 9000:9000 -p 9001:9001 --name minio --restart=always -e \\\"MINIO_ROOT_USER=你的用户名\\\" -e \\\"MINIO_ROOT_PASSWORD=你的密码\\\" -v /minio/data:/data -v /minio/config:/root/.minio -v /etc/localtime:/etc/localtime minio/minio server /data --console-address \\\":9001\\\"\\n```\",\"articleCover\":\"http://ws.aqi125.cn/articles/854cb4178a8fa828a3bc7d1e694d37de.jpg\",\"articleTitle\":\"Blog部署教程补充\",\"categoryName\":\"blog部署\",\"id\":142,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.127.50', '中国|河南省|南阳市|移动', '2025-12-13 12:05:58', NULL);
INSERT INTO `t_operation_log` VALUES (2071, '文章模块', '导出', '/admin/articles/export', 'com.aurora.controller.ArticleController.exportArticles', '导出文章', '[[142]]', 'POST', '{\"code\":20000,\"data\":[\"https://ws.aqi125.cn/markdown/Blog部署教程补充.md\"],\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.127.50', '中国|河南省|南阳市|移动', '2025-12-13 12:06:16', NULL);
INSERT INTO `t_operation_log` VALUES (2072, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# 写在前面\\n\\n# 是对原花未眠博客  Aurora 由原有jdk8全面升级到jdk17 spring boot版本升级至2.7.18 elasticsearch升级至7.17.12 及安装minio存储的补充\\n\\n# 一.jdk升级很简单谁都会直接上代码看问题:\\n\\n```java\\nClosing non transactional SqlSession [org.apache.ibatis.session.defaults.DefaultSqlSession@6137f51c]\\n2023-04-08 19:05:57.419 ERROR 7908 --- [nio-8080-exec-2] o.a.c.c.C.[.[.[/].[dispatcherServlet]    : Servlet.service() for servlet [dispatcherServlet] in context with path [] threw exception [Filter execution threw an exception] with root cause\\n\\njava.lang.ClassNotFoundException: javax.xml.bind.DatatypeConverter\\n\\tat java.base/jdk.internal.loader.BuiltinClassLoader.loadClass(BuiltinClassLoader.java:581) ~[na:na]\\n\\tat java.base/jdk.internal.loader.ClassLoaders$AppClassLoader.loadClass(ClassLoaders.java:178) ~[na:na]\\n\\tat java.base/java.lang.ClassLoader.loadClass(ClassLoader.java:521) ~[na:na]\\n```\\n\\n解决方法如下\\n\\n1.是回退，回退不符合我们需求\\n\\n2.是pom.xml添加依赖\\n\\n```xml\\n<dependency>\\n   <groupId>javax.xml.bind</groupId>\\n    <artifactId>jaxb-api</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>com.sun.xml.bind</groupId>\\n    <artifactId>jaxb-impl</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>com.sun.xml.bind</groupId>\\n    <artifactId>jaxb-core</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>javax.activation</groupId>\\n    <artifactId>activation</artifactId>\\n    <version>1.1.1</version>\\n</dependency>\\n```\\n\\n# 二.minio安装有详细步骤在12小节 在配置nginx的时候minio部分配置如下:\\n\\n```xml\\nserver {\\n\\n        listen  443 ssl;\\n        server_name ws.你的域名;\\n    \\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/ws.你的域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/ws.你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n    \\n        location / {\\n            proxy_pass http://你的IP:9000/aurora/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n    \\n    }\\n\\n\\nserver {\\n        listen       80;\\n        server_name  你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n\\n    }\\n\\nserver {\\n        listen       80;\\n        server_name  admin.你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n\\n    }\\t\\n    server {\\n    listen 80;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/aurora/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n\\n}\\n\\nserver {\\n    listen 9000;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n```\\n# 三.pom.xml 变更如下两个部分\\n```language\\n<properties>\\n        <java.version>17</java.version>\\n        <project.build.sourceEncoding>UTF-8</project.build.sourceEncoding>\\n        <project.reporting.outputEncoding>UTF-8</project.reporting.outputEncoding>\\n        <spring-boot.version>2.7.18</spring-boot.version>\\n        <elasticsearch.version>7.17.12</elasticsearch.version>\\n这是分割线------------------------------------------------------------------------\\n        <plugins>\\n            <plugin>\\n                <groupId>org.apache.maven.plugins</groupId>\\n                <artifactId>maven-compiler-plugin</artifactId>\\n                <version>3.9.0</version>\\n                <configuration>\\n                    <source>17</source>\\n                    <target>17</target>\\n                    <encoding>UTF-8</encoding>\\n                </configuration>\\n            </plugin>\\n```\\n\\n\\n# 四.以下是原安装详情及补充：\\n\\n## 1.服务器要求：\\n\\n> 下面的建议不包含minio的内存占用，如需使用minio，请参考步骤12\\n\\n1. 核心数和内存大小有两种方案：\\n   - 2核4G（使用ES搜索策略）\\n   - 2核2G（使用MySQL搜素策略）\\n\\n2. 带宽大小有两种方案：\\n   - 使用oss对带宽没有要求（本人亲测：1M带宽+oss 访问速度很快）\\n   - 使用minio需要大一点的带宽（小带宽也可以，但需要使用cdn加速）\\n\\n## 2.docker的安装：\\n\\n> 以下命令基于CentOS环境。\\n\\n1. 下载工具\\n\\n   ```shell\\n   yum install -y yum-utils\\n   ```\\n\\n2. 设置镜像的仓库\\n\\n   ```shell\\n   yum-config-manager \\\\\\n       --add-repo \\\\\\n       https://mirrors.aliyun.com/docker-ce/linux/centos/docker-ce.repo  #配置阿里云的镜像\\n   ```\\n\\n3. 更新yum软件包索引\\n\\n   ```shell\\n   yum makecache fast\\n   ```\\n\\n4. 安装docker相关配置\\n\\n   ```shell\\n   yum install docker-ce docker-ce-cli containerd.io\\n   ```\\n\\n5. 启动docker\\n\\n   ```shell\\n   systemctl start docker\\n   # 查看当前版本号，是否启动成功\\n   docker version\\n   # 设置开机自启动\\n   systemctl enable docker\\n   ```\\n\\n****\\n\\n## 3.安装mysql：\\n\\n### 方式1: 无挂载模式\\n\\n> 这种方式直接运行mysql之后，所有关于mysql的内容都在容器中，后续如果需要修改mysql的内容，需要手动进入容器内进行操作。且在宿主机上无备份，一旦容器被删除，数据也会被删除。\\n\\n```shell\\ndocker pull mysql //下载MySQL镜像\\ndocker run --name mysql --restart=always -p 3306:3306 -e MYSQL_ROOT_PASSWORD=你的密码 -d mysql //启动MySQL\\n```\\n\\n### 方式2: 数据卷挂载模式\\n\\n> 和**无挂载模式相对**，通过数据卷挂载的方式运行容器，将容器内的部分重要文件映射到宿主机上。直接操作宿主机对应的映射文件就能和容器内作同步，方便操作的同时还能保证容器内的数据在宿主机上有一个备份。\\n>\\n> 下面的命令分别对mysql的日志文件、配置文件、数据文件进行了映射，你也可以自己修改。\\n\\n```shell\\ndocker run -d -p 3306:3306 --restart=always -v /auroras/mysql/log:/var/log/mysql -v /auroras/mysql/data:/var/lib/mysql -v /auroras/mysql/conf:/etc/mysql/conf.d  -e MYSQL_ROOT_PASSWORD=你的密码  --name mysql mysql\\n```\\n\\n****\\n\\n## 4.安装redis：\\n\\n```shell\\ndocker pull redis //下载Redis镜像\\ndocker run --name redis  --restart=always -p 6379:6379 -d redis --requirepass \\\"你的密码\\\" //启动Redis\\n```\\n\\n## 5.安装rabbitmq：\\n\\n```shell\\ndocker pull rabbitmq:management //下载RabbitMQ镜像\\ndocker run --name rabbit --restart=always -p 15672:15672 -p 5672:5672  -d  rabbitmq:management   //启动RabbitMQ,默认guest用户，密码也是guest。\\n```\\n\\n## 6.安装elasticsearch：\\n\\n```shell\\ndocker pull elasticsearch:7.17.12\\n```\\n\\n```shell\\nmkdir -p  /home/elasticsearch/data/ \\nmkdir -p  /home/elasticsearch/config/\\n```\\n\\n1. 编写配置文件\\n\\n   ```shell\\n   echo \'http.host: 0.0.0.0\\n   http.cors.enabled: true\\n   http.cors.allow-origin: \\\"*\\\" \'>>/home/elasticsearch/config/elasticsearch.yml\\n   ```\\n\\n2. 修改文件夹权限\\n\\n   ```shell\\n   chmod -R 777 /home/elasticsearch/\\n   ls -l # 查看文件权限\\n   ```\\n\\n3. 启动elasticseach镜像\\n\\n   ```shell\\n   docker run --name elasticsearch -p 9200:9200 \\\\\\n    -p 9300:9300 \\\\\\n    -e \\\"discovery.type=single-node\\\" \\\\\\n    -e ES_JAVA_OPTS=\\\"-Xms64m -Xmx128m\\\" \\\\\\n     -v /home/elasticsearch/config/elasticsearch.yml:/usr/shellare/elasticsearch/config/elasticsearch.yml \\\\\\n    -v /home/elasticsearch/data:/usr/shellare/elasticsearch/data \\\\\\n    -v /home/elasticsearch/plugins:/usr/shellare/elasticsearch/plugins \\\\\\n    -d elasticsearch:7.17.12\\n   ```\\n\\n>接下来我们就是拿浏览器访问啦。\\n>在浏览器上输入：服务器IP地址:9200\\n>可能出现的问题：\\n\\n### 1. 启动成功，但是访问失败的话，查看一下安全组中映射端口是否已经打开。如果是本地虚拟机，可能与防火墙相关（我用的云服务器，没有测试，如果有问题，还是需要大家自行去百度||谷歌一下）。\\n\\n### 2. -e ES_JAVA_OPTS=\\\"-Xms64m -Xmx128m\\\"：配置内存大小出现了问题。\\n\\n### 3. 最后就还有可能是配置文件中出现了问题。\\n\\n   ```shell\\necho \'http.host: 0.0.0.0\\nhttp.cors.enabled: true\\nhttp.cors.allow-origin: \\\"*\\\" \'>>/home/elasticsearch/config/elasticsearch.yml\\n   ```\\n\\n   >`http.host: 0.0.0.0` 在冒号后面有一个空格的，这里的配置文件是`yml`格式,所以一定要严格按照`yml`格式来书写。\\n   >安装ik分词器\\n   >进入已经启动成功的elasticsearch容器。\\n\\n```shell\\ndocker exec -it elasticsearch /bin/bash\\n```\\n\\n```shell\\n./bin/elasticsearch-plugin install https://github.com/medcl/elasticsearch-analysis-ik/releases/download/v7.9.2/elasticsearch-analysis-ik-7.9.2.zip\\n```\\n\\n>ps: `安装的ik分词器的版本一定要与elasticsearch的版本保持一致`\\n>下载过程中如果遇到选择，直接输入 y回车就可以了。\\n>下载完成之后，退出去，重新启动elasticsearch容器。\\n\\n```shell\\ndocker restart elasticsearch\\n```\\n\\n>测试ik分词器是否安装成功\\n>安装完成后，我们再来进行测试遍，看看有什么样的变化。\\n>postman post请求分词测试：`http://服务器IP地址:9200/_analyze`\\n\\n```json\\n{\\n\\t\\\"tokenizer\\\":\\\"ik_smart\\\",\\n\\t\\\"text\\\":\\\"我爱技术\\\"\\n}\\n```\\n\\n结果\\n\\n```shell\\n{\\n    \\\"tokens\\\": [\\n        {\\n            \\\"token\\\": \\\"我\\\",\\n            \\\"start_offset\\\": 0,\\n            \\\"end_offset\\\": 1,\\n            \\\"type\\\": \\\"CN_CHAR\\\",\\n            \\\"position\\\": 0\\n        },\\n        {\\n            \\\"token\\\": \\\"爱\\\",\\n            \\\"start_offset\\\": 1,\\n            \\\"end_offset\\\": 2,\\n            \\\"type\\\": \\\"CN_CHAR\\\",\\n            \\\"position\\\": 1\\n        },\\n        {\\n            \\\"token\\\": \\\"技术\\\",\\n            \\\"start_offset\\\": 2,\\n            \\\"end_offset\\\": 4,\\n            \\\"type\\\": \\\"CN_WORD\\\",\\n            \\\"position\\\": 2\\n        }\\n    ]\\n}\\n```\\n\\n## 7.安装MaxWell：\\n\\n```sh\\ndocker pull zendesk/maxwell //下载MaxWell镜像\\ndocker run --name maxwell --restart=always  -d  zendesk/maxwell bin/maxwell  --user=\'root\' --password=\'你的密码\'  --host=\'你的IP\'  --producer=rabbitmq --rabbitmq_user=\'guest\' --rabbitmq_pass=\'guest\' --rabbitmq_host=\'你的IP\' --rabbitmq_port=\'5672\' --rabbitmq_exchange=\'maxwell_exchange\'  --rabbitmq_exchange_type=\'fanout\' --rabbitmq_exchange_durable=\'true\' --filter=\'exclude: *.*, include: aurora.t_article.article_title = *, include: aurora.t_article.article_content = *, include: aurora.t_article.is_delete = *, include: aurora.t_article.status = *\' //运行MaxWell\\n```\\n\\n注意：上述命令中aurora为数据库名称。\\n\\n****\\n\\n## 8.填写aurora-springboot中的yml文件：\\n\\n>此处省略，操作比较简单，就是配置一些简单的ip+端口+用户名+密码，前提是服务器上对应的端口已经打开\\n>阿里云oss具体情况详见百度\\n>QQ互联具体情况详见百度\\n>这里就不赘述了\\n\\n## 9.打包运行后端项目：\\n\\n### 1. 使用idea右侧Maven的package命令\\n\\n### 2. 在服务器的/usr/local/下面创建名为docker的文件夹\\n\\n### 3. 将打包好的jar包传到服务器上面的/usr/local/docker下面\\n\\n### 4. 编写Dockerfile,同时将编写好的Dockerfile传输到服务器的/usr/local/docker下面\\n\\n```dockerfile\\nFROM openjdk:17-jdk-slim-buster\\nVOLUME /tmp\\nADD aurora-springboot-0.0.1.jar blog.jar\\nENTRYPOINT [\\\"java\\\",\\\"-Djava.security.egd=file:/dev/./urandom\\\",\\\"-jar\\\",\\\"/blog.jar\\\"]\\n```\\n\\n> 注意：Dockerfile文件只需要上传到指定目录下即可，不需要手动执行其他操作。\\n\\n### 5. 编写aurora-start.sh,同时将编写好的aurora-start.sh上传到服务器的/usr/local/docker下面\\n\\n```shell\\nSOURCE_PATH=/usr/local/docker\\nSERVER_NAME=aurora-springboot-0.0.1.jar\\nTAG=latest\\nSERVER_PORT=8080\\nCID=$(docker ps | grep \\\"$SERVER_NAME\\\" | awk \'{print $1}\')\\nIID=$(docker images | grep \\\"$SERVER_NAME\\\" | awk \'{print $3}\')\\nif [ -n \\\"$CID\\\" ]; then\\n  echo \\\"存在容器$SERVER_NAME,CID-$CID\\\"\\n  docker stop $CID\\n  echo \\\"成功停止容器$SERVER_NAME,CID-$CID\\\"\\n  docker rm $CID\\n  echo \\\"成功删除容器$SERVER_NAME,CID-$CID\\\"\\nfi\\nif [ -n \\\"$IID\\\" ]; then\\n  echo \\\"存在镜像$SERVER_NAME:$TAG,IID=$IID\\\"\\n  docker rmi $IID\\n  echo \\\"成功删除镜像$SERVER_NAME:$TAG,IID=$IID\\\"\\nfi\\necho \\\"开始构建镜像$SERVER_NAME:$TAG\\\"\\ncd $SOURCE_PATH\\ndocker build -t $SERVER_NAME:$TAG .\\necho \\\"成功构建镜像$SERVER_NAME:$TAG\\\"\\ndocker run --restart=always --name aurora-springboot-0.0.1.jar -d -p 8080:8080 aurora-springboot-0.0.1.jar:latest\\necho \\\"成功创建并运行容器$SERVER_NAME\\\"\\n```\\n\\n**注意事项：sh文件需要用notepad++转为Unix格式**\\n\\n具体操作：点开notepad++中的编辑 ---> 文档格式转换 --->转为Unix \\n\\n### 6. cd到/usr/local/docker下面 ，执行如下命令打包docker镜像文件\\n\\n```shell\\nsh aurora-start.sh\\n```\\n\\n### 7. 启动容器\\n\\n```sh\\ndocker run  --name aurora-springboot-0.0.1.jar -d -p 8080:8080 aurora-springboot-0.0.1.jar:latest\\n```\\n\\n### 8. 这样后端项目就可以在服务器上跑起来了\\n\\n### 9. 访问测试(浏览器上访问)\\n\\n   ```shell\\nip:8080\\n   ```\\n\\n****\\n\\n## 10.打包运行前端项目：\\n\\n### 1. aurora-blog项目中，更改src/config/config.ts\\n\\n   ```typescript\\n  captcha: {\\n    TENCENT_CAPTCHA: \'你自己的天御验证码\'\\n  },\\n  qqLogin: {\\n    QQ_APP_ID: \'你自己的APP_ID\',\\n    QQ_REDIRECT_URI: \'https://你的前台域名/oauth/login/qq\'\\n  },\\n   ```\\n\\n### 2. aurora-blog项目中，更改public/index.html\\n\\n   ```html\\n<script\\n      src=\\\"http://connect.qq.com/qc_jssdk.js\\\"\\n      data-appid=\\\"你自己的APP_ID\\\"\\n      data-redirecturi=\\\"https://你的前台域名/oauth/login/qq\\\"></script>\\n   ```\\n\\n### 3. 如果你的网站没有打算使用https,将aurora-blog/public/index.html和aurora-admin/public/index.html中下面这一行代码给注释掉\\n\\n   ```html\\n<meta http-equiv=\\\"Content-Security-Policy\\\" content=\\\"upgrade-insecure-requests\\\" />\\n   ```\\n\\n### 4. 分别到aurora-blog和aurora-admin下面执行如下命令 (推荐关闭vscode的Eslint,本项目没有遵循Eslint的规范)\\n\\n如果下列命令执行报错，可以尝试替换版本\\n参考版本：npm版本为：8.3.1    vue-cli的版本为：5.0.6\\n\\n   ```shell\\nnpm install\\nnpm run build\\n   ```\\n\\n### 5. 在服务器的/usr/local/下面创建名为vue的文件夹，\\n\\n### 6. 将打包好的前台代码重命名为blog, 并传输到服务器的/usr/local/vue下面\\n\\n### 7. 将打包好的后台代码重命名为admin, 并传输到服务器的/usr/local/vue下面\\n\\n## 11.安装并启动nginx：\\n\\n### 方式1: http\\n\\n1. 拉取nginx镜像\\n\\n   ```shell\\n   docker pull nginx\\n   ```\\n\\n2. 在/usr/local/nginx下创建nginx.conf文件，格式如下\\n\\n   ```shell\\n   events {\\n       worker_connections  1024;\\n   }\\n   \\n   http {\\n       include       mime.types;\\n       default_type  application/octet-stream;\\n       sendfile        on;\\n       keepalive_timeout  65;\\n   \\n       client_max_body_size     50m;\\n       client_body_buffer_size  10m; \\n       client_header_timeout    1m;\\n       client_body_timeout      1m;\\n   \\n       gzip on;\\n       gzip_min_length  1k;\\n       gzip_buffers     4 16k;\\n       gzip_comp_level  4;\\n       gzip_types text/plain application/javascript application/x-javascript text/css application/xml text/javascript application/x-httpd-php image/jpeg image/gif image/png;\\n       gzip_vary on;\\n   \\n   server {\\n           listen       80;\\n           server_name  前台域名;\\n        \\n           location / {\\t\\t\\n               root   /usr/local/vue/blog;\\n               index  index.html index.htm; \\n               try_files $uri $uri/ /index.html;\\t\\n           }\\n   \\t\\t\\t\\n   \\tlocation ^~ /api/ {\\t\\t\\n               proxy_pass http://服务器ip:8080/;\\n   \\t       proxy_set_header   Host             $host;\\n               proxy_set_header   X-Real-IP        $remote_addr;\\t\\t\\t\\t\\t\\t\\n               proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n           }\\n   \\t\\t\\n       }\\n   \\t\\n   server {\\n           listen       80;\\n           server_name  后台子域名;\\n        \\n           location / {\\t\\t\\n               root   /usr/local/vue/admin;\\n               index  index.html index.htm; \\n               try_files $uri $uri/ /index.html;\\t\\n           }\\n   \\t\\t\\t\\n   \\tlocation ^~ /api/ {\\t\\t\\n               proxy_pass http://你的ip:8080/;\\n   \\t    proxy_set_header   Host             $host;\\n               proxy_set_header   X-Real-IP        $remote_addr;\\t\\t\\t\\t\\t\\t\\n               proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n           }\\n   \\t\\t\\n       }\\n    }\\n   ```\\n\\n3. 启动nginx\\n\\n   ```shell\\n   docker run --name nginx --restart=always -p 80:80 -d -v /usr/local/nginx/nginx.conf:/etc/nginx/nginx.conf -v /usr/local/vue:/usr/local/vue nginx \\n   ```\\n\\n### 方式2: https\\n\\n拉取nginx镜像\\n\\n```shell\\ndocker pull nginx\\n```\\n\\n修改配置文件(在原版的基础上加上minio存储-全站https)\\n\\n```shell\\nevents {\\n    worker_connections  1024;\\n}\\n\\nhttp {\\n    include       mime.types;\\n    default_type  application/octet-stream;\\n    sendfile        on;\\n    keepalive_timeout  65;\\n\\n    client_max_body_size     50m;\\n    client_body_buffer_size  10m; \\t  \\n    client_header_timeout    1m;\\n    client_body_timeout      1m;\\n\\n    gzip on;\\n    gzip_min_length  1k;\\n    gzip_buffers     4 16k;\\n    gzip_comp_level  4;\\n    gzip_types text/plain application/javascript application/x-javascript text/css application/xml text/javascript application/x-httpd-php image/jpeg image/gif image/png;\\n    gzip_vary on;\\n\\t\\nserver {\\n\\n        listen  443 ssl;\\n        server_name  你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/你的域名_bundle.pem; \\n\\t   ssl_certificate_key /etc/nginx/cert/你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n       location / {\\n            root   /usr/local/vue/blog;\\n            index  index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\t\\t\\n        location ^~ /api/ {\\n            proxy_pass http://你的IP:8080/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n\\n    }\\n\\nserver {\\n\\n        listen  443 ssl;\\n        server_name admin.你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/admin.你的域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/admin.你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n       location / {\\n            root   /usr/local/vue/admin;\\n            index  index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\t\\t\\n        location ^~ /api/ {\\n            proxy_pass http://你的IP:8080/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n\\t\\n    }\\nserver {\\n\\n        listen  443 ssl;\\n        server_name ws.你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/ws.你的域名_bundle.pem; \\n        ssl_certificate_key /etc/nginx/cert/ws.你的域名.key; \\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n        location / {\\n            proxy_pass http://你的IP:9000/aurora/;\\n            proxy_set_header   Host             $host;\\n            proxy_set_header   X-Real-IP        $remote_addr;\\n            proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        }\\n\\t\\n    }\\n\\n\\nserver {\\n        listen       80;\\n        server_name  你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n    }\\n\\t\\nserver {\\n        listen       80;\\n        server_name  admin.你的域名;\\n        rewrite ^(.*)$\\thttps://$host$1\\tpermanent;\\n\\t\\t\\n    }\\t\\n    server {\\n    listen 80;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/aurora/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n}\\n\\nserver {\\n    listen 9000;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/;\\n        proxy_set_header   Host             $host;\\n        proxy_set_header   X-Real-IP        $remote_addr;\\n        proxy_set_header   X-Forwarded-For  $proxy_add_x_forwarded_for;\\n    }\\n}\\n}\\n```\\n\\n启动nginx\\n\\n```shell\\ndocker run --name nginx --restart=always -p 443:443 -p 80:80 -d -v /usr/local/nginx/nginx.conf:/etc/nginx/nginx.conf -v /usr/local/nginx/cert:/etc/nginx/cert -v /usr/local/vue:/usr/local/vue --privileged=true nginx\\n```\\n\\n## 12.安装并启动minio：\\n\\n```dockerfile\\ndocker run -d -p 9000:9000 -p 9001:9001 --name minio --restart=always -e \\\"MINIO_ROOT_USER=你的用户名\\\" -e \\\"MINIO_ROOT_PASSWORD=你的密码\\\" -v /minio/data:/data -v /minio/config:/root/.minio -v /etc/localtime:/etc/localtime minio/minio server /data --console-address \\\":9001\\\"\\n```\",\"articleCover\":\"http://ws.aqi125.cn/articles/854cb4178a8fa828a3bc7d1e694d37de.jpg\",\"articleTitle\":\"Blog部署教程补充\",\"categoryName\":\"blog部署\",\"id\":142,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.127.50', '中国|河南省|南阳市|移动', '2025-12-13 12:19:07', NULL);
INSERT INTO `t_operation_log` VALUES (2073, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleContent\":\"# 写在前面\\n\\n本文档是对原《花未眠博客（Aurora）》部署教程的**补充与更新指南**，旨在帮助用户完成从原有技术栈到新版本技术栈的平滑迁移。主要涵盖以下四大核心升级内容：\\n\\n1. **运行环境升级**：JDK 从 8 全面升级至 17\\n2. **应用框架升级**：Spring Boot 版本升级至 2.7.18\\n3. **搜索服务升级**：Elasticsearch 升级至 7.17.12\\n4. **存储服务新增**：集成 MinIO 对象存储\\n\\n文档将按照问题解决→环境部署→应用配置的顺序展开，并提供详细的配置示例与故障排查方法。\\n\\n---\\n\\n## 一、JDK 17 升级问题与解决方案\\n\\n### 1.1 问题现象\\n升级到 JDK 17 后，应用启动时可能出现以下错误：\\n\\n```java\\nClosing non transactional SqlSession [org.apache.ibatis.session.defaults.DefaultSqlSession@6137f51c]\\n2023-04-08 19:05:57.419 ERROR 7908 --- [nio-8080-exec-2] o.a.c.c.C.[.[.[/].[dispatcherServlet]    : Servlet.service() for servlet [dispatcherServlet] in context with path [] threw exception [Filter execution threw an exception] with root cause\\n\\njava.lang.ClassNotFoundException: javax.xml.bind.DatatypeConverter\\n\\tat java.base/jdk.internal.loader.BuiltinClassLoader.loadClass(BuiltinClassLoader.java:581) ~[na:na]\\n\\tat java.base/jdk.internal.loader.ClassLoaders$AppClassLoader.loadClass(ClassLoaders.java:178) ~[na:na]\\n\\tat java.base/java.lang.ClassLoader.loadClass(ClassLoader.java:521) ~[na:na]\\n```\\n\\n### 1.2 解决方案\\n由于 JDK 9+ 移除了 `javax.xml.bind` 等模块，需在项目中添加以下依赖：\\n\\n**方法一：添加兼容依赖（推荐）**\\n在项目的 `pom.xml` 中添加：\\n\\n```xml\\n<!-- 解决 JDK 9+ 中 javax.xml.bind 缺失问题 -->\\n<dependency>\\n    <groupId>javax.xml.bind</groupId>\\n    <artifactId>jaxb-api</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>com.sun.xml.bind</groupId>\\n    <artifactId>jaxb-impl</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>com.sun.xml.bind</groupId>\\n    <artifactId>jaxb-core</artifactId>\\n    <version>2.3.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>javax.activation</groupId>\\n    <artifactId>activation</artifactId>\\n    <version>1.1.1</version>\\n</dependency>\\n```\\n\\n**方法二：使用 Jakarta EE 替代方案**\\n对于新项目，建议迁移到 Jakarta EE API：\\n\\n```xml\\n<dependency>\\n    <groupId>jakarta.xml.bind</groupId>\\n    <artifactId>jakarta.xml.bind-api</artifactId>\\n    <version>4.0.0</version>\\n</dependency>\\n<dependency>\\n    <groupId>com.sun.xml.bind</groupId>\\n    <artifactId>jaxb-impl</artifactId>\\n    <version>4.0.0</version>\\n    <scope>runtime</scope>\\n</dependency>\\n```\\n\\n---\\n\\n## 二、项目配置更新\\n\\n### 2.1 POM 文件关键变更\\n\\n#### 2.1.1 属性配置更新\\n```xml\\n<properties>\\n    <java.version>17</java.version>\\n    <project.build.sourceEncoding>UTF-8</project.build.sourceEncoding>\\n    <project.reporting.outputEncoding>UTF-8</project.reporting.outputEncoding>\\n    <!-- 锁定 Spring Boot 版本 -->\\n    <spring-boot.version>2.7.18</spring-boot.version>\\n    <!-- 锁定 Elasticsearch 版本 -->\\n    <elasticsearch.version>7.17.12</elasticsearch.version>\\n</properties>\\n```\\n\\n#### 2.1.2 Maven 编译器插件配置\\n```xml\\n<build>\\n    <plugins>\\n        <plugin>\\n            <groupId>org.apache.maven.plugins</groupId>\\n            <artifactId>maven-compiler-plugin</artifactId>\\n            <version>3.9.0</version>\\n            <configuration>\\n                <source>17</source>\\n                <target>17</target>\\n                <encoding>UTF-8</encoding>\\n            </configuration>\\n        </plugin>\\n    </plugins>\\n</build>\\n```\\n\\n---\\n\\n## 三、服务部署与配置\\n\\n### 3.1 服务器资源规划\\n\\n| 组件方案 | 核心与内存 | 带宽要求 | 适用场景 |\\n|---------|-----------|----------|----------|\\n| **方案A (ES搜索)** | 2核4G | 1M（使用OSS） | 需要全文搜索功能 |\\n| **方案B (MySQL搜索)** | 2核2G | 1M（使用OSS） | 搜索需求简单 |\\n| **方案C (使用MinIO)** | 2核4G+ | 建议3M+或搭配CDN | 需要自建对象存储 |\\n\\n> **注意**：MinIO 会占用额外内存，如使用请相应增加内存配置。\\n\\n### 3.2 Docker 安装（CentOS）\\n\\n```bash\\n# 1. 安装必要工具\\nyum install -y yum-utils\\n\\n# 2. 配置阿里云Docker镜像仓库\\nyum-config-manager \\\\\\n    --add-repo \\\\\\n    https://mirrors.aliyun.com/docker-ce/linux/centos/docker-ce.repo\\n\\n# 3. 更新软件包索引并安装\\nyum makecache fast\\nyum install -y docker-ce docker-ce-cli containerd.io\\n\\n# 4. 启动并设置开机自启\\nsystemctl start docker\\nsystemctl enable docker\\n\\n# 5. 验证安装\\ndocker version\\n```\\n\\n### 3.3 MySQL 部署\\n\\n#### 方式一：简单模式（无数据持久化）\\n```bash\\ndocker pull mysql\\ndocker run --name mysql --restart=always -p 3306:3306 -e MYSQL_ROOT_PASSWORD=你的密码 -d mysql\\n```\\n\\n#### 方式二：数据卷挂载模式（推荐）\\n```bash\\n# 创建数据目录\\nmkdir -p /auroras/mysql/{data,conf,log}\\n\\n# 启动容器\\ndocker run -d \\\\\\n  --name mysql \\\\\\n  --restart=always \\\\\\n  -p 3306:3306 \\\\\\n  -v /auroras/mysql/data:/var/lib/mysql \\\\\\n  -v /auroras/mysql/conf:/etc/mysql/conf.d \\\\\\n  -v /auroras/mysql/log:/var/log/mysql \\\\\\n  -e MYSQL_ROOT_PASSWORD=你的密码 \\\\\\n  mysql:latest\\n```\\n\\n### 3.4 Redis 部署\\n```bash\\ndocker pull redis\\ndocker run --name redis --restart=always -p 6379:6379 -d redis --requirepass \\\"你的密码\\\"\\n```\\n\\n### 3.5 RabbitMQ 部署\\n```bash\\ndocker pull rabbitmq:management\\ndocker run --name rabbit --restart=always -p 15672:15672 -p 5672:5672 -d rabbitmq:management\\n```\\n\\n> 管理界面：http://服务器IP:15672，默认账号/密码：guest/guest\\n\\n### 3.6 Elasticsearch 7.17.12 部署\\n\\n#### 3.6.1 准备工作\\n```bash\\n# 创建数据目录\\nmkdir -p /home/elasticsearch/{data,config,plugins}\\n\\n# 配置 Elasticsearch\\necho \'http.host: 0.0.0.0\\nhttp.cors.enabled: true\\nhttp.cors.allow-origin: \\\"*\\\"\' > /home/elasticsearch/config/elasticsearch.yml\\n\\n# 设置目录权限\\nchmod -R 777 /home/elasticsearch/\\n```\\n\\n#### 3.6.2 启动 Elasticsearch\\n```bash\\ndocker run -d \\\\\\n  --name elasticsearch \\\\\\n  --restart=always \\\\\\n  -p 9200:9200 \\\\\\n  -p 9300:9300 \\\\\\n  -e \\\"discovery.type=single-node\\\" \\\\\\n  -e ES_JAVA_OPTS=\\\"-Xms512m -Xmx512m\\\" \\\\\\n  -v /home/elasticsearch/config/elasticsearch.yml:/usr/share/elasticsearch/config/elasticsearch.yml \\\\\\n  -v /home/elasticsearch/data:/usr/share/elasticsearch/data \\\\\\n  -v /home/elasticsearch/plugins:/usr/share/elasticsearch/plugins \\\\\\n  elasticsearch:7.17.12\\n```\\n\\n#### 3.6.3 安装 IK 分词器\\n```bash\\n# 进入容器\\ndocker exec -it elasticsearch /bin/bash\\n\\n# 安装 IK 分词器（版本必须匹配）\\n./bin/elasticsearch-plugin install https://github.com/medcl/elasticsearch-analysis-ik/releases/download/v7.17.12/elasticsearch-analysis-ik-7.17.12.zip\\n\\n# 退出并重启容器\\nexit\\ndocker restart elasticsearch\\n```\\n\\n#### 3.6.4 验证安装\\n1. 访问 `http://服务器IP:9200`，应看到版本信息\\n2. 测试分词功能：\\n   ```bash\\n   curl -X POST \\\"http://服务器IP:9200/_analyze\\\" -H \'Content-Type: application/json\' -d\'\\n   {\\n     \\\"tokenizer\\\": \\\"ik_smart\\\",\\n     \\\"text\\\": \\\"我爱技术\\\"\\n   }\'\\n   ```\\n\\n### 3.7 Maxwell 部署\\n```bash\\ndocker pull zendesk/maxwell\\ndocker run --name maxwell --restart=always -d zendesk/maxwell \\\\\\n  bin/maxwell \\\\\\n  --user=\'root\' \\\\\\n  --password=\'你的密码\' \\\\\\n  --host=\'你的IP\' \\\\\\n  --producer=rabbitmq \\\\\\n  --rabbitmq_user=\'guest\' \\\\\\n  --rabbitmq_pass=\'guest\' \\\\\\n  --rabbitmq_host=\'你的IP\' \\\\\\n  --rabbitmq_port=\'5672\' \\\\\\n  --rabbitmq_exchange=\'maxwell_exchange\' \\\\\\n  --rabbitmq_exchange_type=\'fanout\' \\\\\\n  --rabbitmq_exchange_durable=\'true\' \\\\\\n  --filter=\'exclude: *.*, include: aurora.t_article.article_title = *, include: aurora.t_article.article_content = *, include: aurora.t_article.is_delete = *, include: aurora.t_article.status = *\'\\n```\\n\\n> **注意**：`aurora` 为数据库名称，请根据实际情况修改。\\n\\n### 3.8 MinIO 对象存储部署\\n\\n#### 3.8.1 安装 MinIO\\n```bash\\ndocker run -d \\\\\\n  --name minio \\\\\\n  --restart=always \\\\\\n  -p 9000:9000 \\\\\\n  -p 9001:9001 \\\\\\n  -e \\\"MINIO_ROOT_USER=你的用户名\\\" \\\\\\n  -e \\\"MINIO_ROOT_PASSWORD=你的密码\\\" \\\\\\n  -v /minio/data:/data \\\\\\n  -v /minio/config:/root/.minio \\\\\\n  minio/minio \\\\\\n  server /data --console-address \\\":9001\\\"\\n```\\n\\n#### 3.8.2 Nginx 配置（MinIO 代理）\\n```nginx\\n# MinIO API 代理 (HTTPS)\\nserver {\\n    listen  443 ssl;\\n    server_name ws.你的域名;\\n\\n    ssl on;\\n    ssl_certificate /etc/nginx/cert/ws.你的域名_bundle.pem;\\n    ssl_certificate_key /etc/nginx/cert/ws.你的域名.key;\\n    ssl_session_timeout 5m;\\n    ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n    ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n    ssl_prefer_server_ciphers on;\\n\\n    location / {\\n        proxy_pass http://你的IP:9000/aurora/;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n    }\\n}\\n\\n# HTTP 重定向到 HTTPS\\nserver {\\n    listen 80;\\n    server_name ws.你的域名;\\n    rewrite ^(.*)$ https://$host$1 permanent;\\n}\\n\\n# MinIO 直接访问（HTTP）\\nserver {\\n    listen 80;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/aurora/;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n    }\\n}\\n\\n# MinIO 控制台访问（可选）\\nserver {\\n    listen 9000;\\n    server_name ws.你的域名;\\n    location / {\\n        proxy_pass http://你的IP:9000/;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n    }\\n}\\n```\\n\\n---\\n\\n## 四、应用部署\\n\\n### 4.1 后端 Spring Boot 应用部署\\n\\n#### 4.1.1 项目打包\\n在 IDEA 中使用 Maven 执行 `package` 命令，生成 `aurora-springboot-0.0.1.jar`。\\n\\n#### 4.1.2 服务器准备\\n```bash\\nmkdir -p /usr/local/docker\\n# 将 jar 包上传到该目录\\n```\\n\\n#### 4.1.3 创建 Dockerfile\\n```dockerfile\\nFROM openjdk:17-jdk-slim-buster\\nVOLUME /tmp\\nADD aurora-springboot-0.0.1.jar blog.jar\\nENTRYPOINT [\\\"java\\\",\\\"-Djava.security.egd=file:/dev/./urandom\\\",\\\"-jar\\\",\\\"/blog.jar\\\"]\\n```\\n\\n#### 4.1.4 创建部署脚本\\n创建 `aurora-start.sh`：\\n```bash\\n#!/bin/bash\\nSOURCE_PATH=/usr/local/docker\\nSERVER_NAME=aurora-springboot-0.0.1.jar\\nTAG=latest\\nSERVER_PORT=8080\\n\\n# 停止并删除旧容器\\nCID=$(docker ps | grep \\\"$SERVER_NAME\\\" | awk \'{print $1}\')\\nif [ -n \\\"$CID\\\" ]; then\\n  echo \\\"存在容器 $SERVER_NAME, CID-$CID\\\"\\n  docker stop $CID\\n  echo \\\"成功停止容器 $SERVER_NAME, CID-$CID\\\"\\n  docker rm $CID\\n  echo \\\"成功删除容器 $SERVER_NAME, CID-$CID\\\"\\nfi\\n\\n# 删除旧镜像\\nIID=$(docker images | grep \\\"$SERVER_NAME\\\" | awk \'{print $3}\')\\nif [ -n \\\"$IID\\\" ]; then\\n  echo \\\"存在镜像 $SERVER_NAME:$TAG, IID=$IID\\\"\\n  docker rmi $IID\\n  echo \\\"成功删除镜像 $SERVER_NAME:$TAG, IID=$IID\\\"\\nfi\\n\\n# 构建新镜像\\necho \\\"开始构建镜像 $SERVER_NAME:$TAG\\\"\\ncd $SOURCE_PATH\\ndocker build -t $SERVER_NAME:$TAG .\\necho \\\"成功构建镜像 $SERVER_NAME:$TAG\\\"\\n\\n# 运行新容器\\ndocker run --restart=always --name aurora-springboot-0.0.1.jar -d -p 8080:8080 aurora-springboot-0.0.1.jar:latest\\necho \\\"成功创建并运行容器 $SERVER_NAME\\\"\\n```\\n\\n> **重要**：使用 Notepad++ 将脚本转换为 Unix 格式：编辑 → 文档格式转换 → 转为 Unix。\\n\\n#### 4.1.5 执行部署\\n```bash\\ncd /usr/local/docker\\nchmod +x aurora-start.sh\\n./aurora-start.sh\\n```\\n\\n#### 4.1.6 验证\\n访问 `http://服务器IP:8080`，确认应用正常运行。\\n\\n### 4.2 前端 Vue 项目部署\\n\\n#### 4.2.1 修改配置文件\\n1. **修改 `src/config/config.ts`**：\\n   ```typescript\\n   captcha: {\\n     TENCENT_CAPTCHA: \'你自己的天御验证码\'\\n   },\\n   qqLogin: {\\n     QQ_APP_ID: \'你自己的APP_ID\',\\n     QQ_REDIRECT_URI: \'https://你的前台域名/oauth/login/qq\'\\n   },\\n   ```\\n\\n2. **修改 `public/index.html`**：\\n   ```html\\n   <script src=\\\"http://connect.qq.com/qc_jssdk.js\\\"\\n           data-appid=\\\"你自己的APP_ID\\\"\\n           data-redirecturi=\\\"https://你的前台域名/oauth/login/qq\\\"></script>\\n   ```\\n\\n3. **如不使用 HTTPS**，注释以下代码：\\n   ```html\\n   <!-- <meta http-equiv=\\\"Content-Security-Policy\\\" content=\\\"upgrade-insecure-requests\\\" /> -->\\n   ```\\n\\n#### 4.2.2 构建项目\\n```bash\\n# 分别在前台和后台项目目录执行\\nnpm install\\nnpm run build\\n```\\n\\n> 参考版本：npm 8.3.1，vue-cli 5.0.6\\n\\n#### 4.2.3 上传至服务器\\n```bash\\nmkdir -p /usr/local/vue\\n# 将构建后的文件上传：\\n# - aurora-blog/dist 重命名为 blog\\n# - aurora-admin/dist 重命名为 admin\\n# 上传到 /usr/local/vue/\\n```\\n\\n### 4.3 Nginx 配置与部署\\n\\n#### 4.3.1 HTTP 配置\\n```nginx\\nevents {\\n    worker_connections 1024;\\n}\\n\\nhttp {\\n    include       mime.types;\\n    default_type  application/octet-stream;\\n    sendfile      on;\\n    keepalive_timeout 65;\\n\\n    client_max_body_size 50m;\\n    client_body_buffer_size 10m;\\n    client_header_timeout 1m;\\n    client_body_timeout 1m;\\n\\n    # 启用Gzip压缩\\n    gzip on;\\n    gzip_min_length 1k;\\n    gzip_buffers 4 16k;\\n    gzip_comp_level 4;\\n    gzip_types text/plain application/javascript application/x-javascript text/css application/xml text/javascript application/x-httpd-php image/jpeg image/gif image/png;\\n    gzip_vary on;\\n\\n    # 前台网站配置\\n    server {\\n        listen 80;\\n        server_name 前台域名;\\n\\n        location / {\\n            root /usr/local/vue/blog;\\n            index index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\n        location ^~ /api/ {\\n            proxy_pass http://服务器IP:8080/;\\n            proxy_set_header Host $host;\\n            proxy_set_header X-Real-IP $remote_addr;\\n            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        }\\n    }\\n\\n    # 后台管理配置\\n    server {\\n        listen 80;\\n        server_name 后台子域名;\\n\\n        location / {\\n            root /usr/local/vue/admin;\\n            index index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\n        location ^~ /api/ {\\n            proxy_pass http://服务器IP:8080/;\\n            proxy_set_header Host $host;\\n            proxy_set_header X-Real-IP $remote_addr;\\n            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        }\\n    }\\n}\\n```\\n\\n#### 4.3.2 HTTPS 配置（全站 HTTPS + MinIO）\\n```nginx\\nevents {\\n    worker_connections 1024;\\n}\\n\\nhttp {\\n    include       mime.types;\\n    default_type  application/octet-stream;\\n    sendfile      on;\\n    keepalive_timeout 65;\\n\\n    client_max_body_size 50m;\\n    client_body_buffer_size 10m;\\n    client_header_timeout 1m;\\n    client_body_timeout 1m;\\n\\n    gzip on;\\n    gzip_min_length 1k;\\n    gzip_buffers 4 16k;\\n    gzip_comp_level 4;\\n    gzip_types text/plain application/javascript application/x-javascript text/css application/xml text/javascript application/x-httpd-php image/jpeg image/gif image/png;\\n    gzip_vary on;\\n\\n    # 前台网站 - HTTPS\\n    server {\\n        listen 443 ssl;\\n        server_name 你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/你的域名_bundle.pem;\\n        ssl_certificate_key /etc/nginx/cert/你的域名.key;\\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n        location / {\\n            root /usr/local/vue/blog;\\n            index index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\n        location ^~ /api/ {\\n            proxy_pass http://你的IP:8080/;\\n            proxy_set_header Host $host;\\n            proxy_set_header X-Real-IP $remote_addr;\\n            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        }\\n    }\\n\\n    # 后台管理 - HTTPS\\n    server {\\n        listen 443 ssl;\\n        server_name admin.你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/admin.你的域名_bundle.pem;\\n        ssl_certificate_key /etc/nginx/cert/admin.你的域名.key;\\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n        location / {\\n            root /usr/local/vue/admin;\\n            index index.html index.htm;\\n            try_files $uri $uri/ /index.html;\\n        }\\n\\n        location ^~ /api/ {\\n            proxy_pass http://你的IP:8080/;\\n            proxy_set_header Host $host;\\n            proxy_set_header X-Real-IP $remote_addr;\\n            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        }\\n    }\\n\\n    # MinIO 代理 - HTTPS\\n    server {\\n        listen 443 ssl;\\n        server_name ws.你的域名;\\n\\n        ssl on;\\n        ssl_certificate /etc/nginx/cert/ws.你的域名_bundle.pem;\\n        ssl_certificate_key /etc/nginx/cert/ws.你的域名.key;\\n        ssl_session_timeout 5m;\\n        ssl_ciphers ECDHE-RSA-AES128-GCM-SHA256:ECDHE:ECDH:AES:HIGH:!NULL:!aNULL:!MD5:!ADH:!RC4;\\n        ssl_protocols TLSv1 TLSv1.1 TLSv1.2;\\n        ssl_prefer_server_ciphers on;\\n\\n        location / {\\n            proxy_pass http://你的IP:9000/aurora/;\\n            proxy_set_header Host $host;\\n            proxy_set_header X-Real-IP $remote_addr;\\n            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        }\\n    }\\n\\n    # HTTP 重定向到 HTTPS\\n    server {\\n        listen 80;\\n        server_name 你的域名;\\n        rewrite ^(.*)$ https://$host$1 permanent;\\n    }\\n\\n    server {\\n        listen 80;\\n        server_name admin.你的域名;\\n        rewrite ^(.*)$ https://$host$1 permanent;\\n    }\\n\\n    server {\\n        listen 80;\\n        server_name ws.你的域名;\\n        rewrite ^(.*)$ https://$host$1 permanent;\\n    }\\n}\\n```\\n\\n#### 4.3.3 启动 Nginx\\n```bash\\n# 拉取镜像\\ndocker pull nginx\\n\\n# 启动容器（HTTPS 配置）\\ndocker run -d \\\\\\n  --name nginx \\\\\\n  --restart=always \\\\\\n  -p 80:80 \\\\\\n  -p 443:443 \\\\\\n  -v /usr/local/nginx/nginx.conf:/etc/nginx/nginx.conf \\\\\\n  -v /usr/local/nginx/cert:/etc/nginx/cert \\\\\\n  -v /usr/local/vue:/usr/local/vue \\\\\\n  --privileged=true \\\\\\n  nginx:latest\\n```\\n\\n---\\n\\n## 五、配置与验证\\n\\n### 5.1 应用配置文件\\n在 `aurora-springboot` 项目的 `application.yml` 中配置以下内容：\\n\\n1. **数据库连接**：MySQL 的连接信息\\n2. **Redis 配置**：Redis 的连接信息\\n3. **Elasticsearch 配置**：ES 的连接信息\\n4. **RabbitMQ 配置**：MQ 的连接信息\\n5. **MinIO 配置**：MinIO 的连接信息\\n6. **第三方服务**：OSS、QQ互联等配置\\n\\n### 5.2 服务验证清单\\n部署完成后，请按以下顺序验证各服务：\\n\\n| 服务 | 验证方法 | 预期结果 |\\n|------|----------|----------|\\n| **MySQL** | `docker logs mysql` | 无错误日志，连接正常 |\\n| **Redis** | `docker exec redis redis-cli ping` | 返回 `PONG` |\\n| **RabbitMQ** | 访问 `http://IP:15672` | 可登录管理界面 |\\n| **Elasticsearch** | 访问 `http://IP:9200` | 返回版本信息JSON |\\n| **MinIO** | 访问 `http://IP:9001` | 可登录管理界面 |\\n| **后端应用** | `docker logs aurora-springboot` | 无启动错误，应用正常 |\\n| **Nginx** | 访问配置的域名 | 正常显示网站内容 |\\n\\n### 5.3 常见问题排查\\n\\n#### Q1: Elasticsearch 启动失败，提示权限问题？\\nA: 确保 `/home/elasticsearch/` 目录权限正确：\\n```bash\\nchmod -R 777 /home/elasticsearch/\\n```\\n\\n#### Q2: 前端访问白屏？\\nA: 检查以下配置：\\n1. Nginx 配置中 `root` 路径是否正确\\n2. `try_files` 指令是否配置正确\\n3. 浏览器控制台是否有资源加载错误\\n\\n#### Q3: 后端连接数据库超时？\\nA: 检查：\\n1. `application.yml` 中的连接IP是否正确\\n2. 防火墙是否开放对应端口\\n3. 数据库容器是否正常运行\\n\\n#### Q4: MinIO 上传文件失败？\\nA: 确认：\\n1. MinIO 服务正常运行\\n2. Nginx 代理配置正确\\n3. 后端配置的 endpoint 与代理地址一致\\n\\n---\\n\\n## 附录\\n\\n### A. 版本兼容性矩阵\\n\\n| 组件 | 推荐版本 | 最低要求 | 备注 |\\n|------|----------|----------|------|\\n| JDK | 17 | 11+ | 推荐 LTS 版本 |\\n| Spring Boot | 2.7.18 | 2.5+ | 长期支持版本 |\\n| Elasticsearch | 7.17.12 | 7.10+ | 与客户端版本匹配 |\\n| MySQL | 8.0+ | 5.7+ | 推荐 8.0+ |\\n| Redis | 7.0+ | 6.0+ | 推荐最新稳定版 |\\n| MinIO | 最新版 | - | 对象存储服务 |\\n\\n### B. 命令速查表\\n\\n```bash\\n# 查看容器状态\\ndocker ps -a\\n\\n# 查看容器日志\\ndocker logs [容器名]\\n\\n# 进入容器\\ndocker exec -it [容器名] /bin/bash\\n\\n# 重启容器\\ndocker restart [容器名]\\n\\n# 停止并删除容器\\ndocker stop [容器名] && docker rm [容器名]\\n\\n# 删除镜像\\ndocker rmi [镜像ID]\\n```\\n\\n### C. 配置文件位置\\n- Nginx 配置：`/usr/local/nginx/nginx.conf`\\n- 前端文件：`/usr/local/vue/`\\n- 后端应用：`/usr/local/docker/`\\n- 证书文件：`/usr/local/nginx/cert/`\\n\\n---\\n\\n**文档更新记录**：\\n- 2022-08-01：初始版本，记录 JDK11 升级问题\\n- 2023-05-05：补充 MinIO 部署与全站 HTTPS 配置\\n- 2024-02-02：记录 Spring Boot2.7.18 JDK17 升级问题\\n通过以上步骤，您应该能够顺利完成 Aurora 博客系统的全面升级与部署。如果在部署过程中遇到问题，请参考对应章节的故障排查部分，或查阅相关服务的官方文档。\",\"articleCover\":\"http://ws.aqi125.cn/articles/854cb4178a8fa828a3bc7d1e694d37de.jpg\",\"articleTitle\":\"AuroraJDK17版本\",\"categoryName\":\"blog部署\",\"id\":142,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[\"JDK\\t17\",\"Spring Boot\\t2.7.18\"],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.127.50', '中国|河南省|南阳市|移动', '2025-12-13 12:27:46', NULL);
