INSERT INTO `t_operation_log` VALUES (2110, '文章模块', '上传', '/admin/articles/images', 'com.aurora.controller.ArticleController.saveArticleImages', '上传文章图片', 'file', 'POST', '{\"code\":20000,\"data\":\"https://ws.aqi125.cn/articles/346065b80634d00d58791014ab0c0cb8.jpg\",\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '219.154.19.110', '中国|河南省|新乡市|联通', '2026-01-03 14:53:04', NULL);
