INSERT INTO `t_operation_log` VALUES (2576, 'aurora信息', '修改', '/api/admin/website/config', 'com.aurora.controller.AuroraInfoController.updateWebsiteConfig', '更新网站配置', '[{\"alipayQRCode\":\"https://ws.aqi125.cn/aurora/config/5a73275cdb99f2d037e13a93d027968d.jpg\",\"author\":\"七七\",\"authorAvatar\":\"http://ws.aqi125.cn/config/6d93c4e2a2690ce5f742f42f8d80e365.jpg\",\"authorIntro\":\"一个疯狂的coder\",\"beianNumber\":\"豫ICP备2021007034号-1\",\"csdn\":\"\",\"englishName\":\"七七\",\"favicon\":\"https://ws.aqi125.cn/aurora/config/740c0db7ddba6e3afaf3f5553f679e14.png\",\"gitee\":\"https://gitee.com/aqily\",\"github\":\"https://github.com/aqi-qihuan\",\"gonganBeianNumber\":\"豫公网安备41072802000219号\",\"isCommentReview\":1,\"isEmailNotice\":0,\"isReward\":1,\"juejin\":\"\",\"logo\":\"https://ws.aqi125.cn/aurora/config/740c0db7ddba6e3afaf3f5553f679e14.png\",\"multiLanguage\":1,\"name\":\"aqi的小窝\",\"notice\":\"代码已经开源，如果你感觉还行就给一个star吧。。。\",\"qq\":\"\",\"qqLogin\":1,\"stackoverflow\":\"\",\"touristAvatar\":\"https://static.linhaojun.top/config/2af2e2db20740e712f0a011a6f8c9af5.jpg\",\"twitter\":\"\",\"userAvatar\":\"https://ws.aqi125.cn/config/6d93c4e2a2690ce5f742f42f8d80e365.jpg\",\"weChat\":\"\",\"websiteCreateTime\":\"2021-03-25\",\"websiteTitle\":\"七七\",\"weiXinQRCode\":\"https://ws.aqi125.cn/aurora/config/b6ed9b60609ab4cbb938aae272c5d24b.png\",\"weibo\":\"\",\"zhihu\":\"\"}]', 'PUT', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '192.168.100.19', '内网IP|内网IP', '2026-04-08 09:26:09', NULL);
INSERT INTO `t_operation_log` VALUES (2577, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleAbstract\":\"\",\"articleContent\":\"# Aurora 博客系统 - 升级与 Elasticsearch 集成完整指南\\n\\n> Spring Boot 3.5.10 + JDK 25 + Elasticsearch 8.13.4 升级与集成指南\\n\\n---\\n\\n## 📋 目录\\n\\n1. [升级到 Spring Boot 3.5.10 和 JDK 25](#1-升级到-spring-boot-3510-和-jdk-25)\\n2. [Elasticsearch 8.13.4 集成问题排查](#2-elasticsearch-8134-集成问题排查)\\n3. [常用命令与运维](#3-常用命令与运维)\\n4. [参考资料](#4-参考资料)\\n\\n---\\n\\n# 1. 升级到 Spring Boot 3.5.10 和 JDK 25\\n\\n## 1.1 升级概述\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 📅 升级时间 | 2026-03-08 |\\n| 🚀 升级路线 | Spring Boot 3.2.12 + JDK 21 → Spring Boot 3.5.10 + JDK 25 |\\n| 💡 升级原因 | 追求最新特性、性能优化和安全更新 |\\n\\n---\\n\\n## 1.2 依赖版本对比\\n\\n| 组件 | 原版本 | 新版本 | 说明 |\\n|:---|:---:|:---:|:---|\\n| **Spring Boot** | 3.2.12 | **3.5.10** | 最新稳定版 |\\n| **JDK** | 21 | **25** | Oracle 最新 LTS 版本 |\\n| **Lombok** | 1.18.30 | **1.18.42** | 支持 JDK 25 |\\n| **MyBatis-Plus** | 3.5.6 | **3.5.16** | 性能优化和 bug 修复 |\\n| **MySQL Connector/J** | 8.3.0 | **9.6.0** | 最新 JDBC 驱动 |\\n| **FastJSON2** | 2.0.43 | **2.0.61** | JSON 序列化库 |\\n| **Hutool** | 5.8.25 | **5.8.43** | Java 工具类库 |\\n| **Hibernate Validator** | 8.0.1.Final | **9.1.0.Final** | 参数校验框架 |\\n| **ip2region** | 2.7.0 | **3.3.6** | IP 地址库（支持 IPv6） |\\n| **MinIO** | 8.5.7 | **8.6.0** | 对象存储客户端 |\\n| **Knife4j** | 4.4.0 | **4.5.0** | API 文档 |\\n| **UserAgentUtils** | 1.25 | **1.21** | 修复 Maven 仓库不存在问题 |\\n\\n**保持不变的依赖**:\\n\\n| 依赖项 | 版本 | 说明 |\\n|:---|:---:|:---|\\n| **Elasticsearch** | 8.13.4 | Java Client |\\n| **JJWT** | 0.12.5 | JWT 令牌 |\\n| **Quartz** | 2.5.2 | 定时任务 |\\n| **OkHttp** | 4.12.0 | HTTP 客户端（保持 4.x 避免 API 变更） |\\n\\n---\\n\\n## 1.3 代码适配修改\\n\\n### IpUtil.java - ip2region 3.x API 适配\\n\\n**文件位置**: `src/main/java/com/aurora/util/IpUtil.java`\\n\\n```java\\n// 旧版本 (2.7.0)\\nsearcher = Searcher.newWithBuffer(dbBinStr);\\n\\n// 新版本 (3.3.6)\\nimport org.lionsoul.ip2region.xdb.LongByteArray;\\nimport org.lionsoul.ip2region.xdb.Version;\\n\\nLongByteArray longDbArray = new LongByteArray();\\nlongDbArray.append(dbBinStr);\\nsearcher = Searcher.newWithBuffer(Version.IPv4, longDbArray);\\n```\\n\\n### Dockerfile - JDK 版本更新\\n\\n**文件位置**: `Dockerfile`\\n\\n```dockerfile\\nFROM eclipse-temurin:25-jre-alpine\\nWORKDIR /app\\nVOLUME /tmp\\nADD aurora-springboot-0.0.1.jar blog.jar\\n```\\n\\n---\\n\\n## 1.4 常见问题与解决方案\\n\\n### ❌ 问题 1: UserAgentUtils 版本不存在\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `Could not find artifact eu.bitwalker:UserAgentUtils:1.25` |\\n| 🟢 解决 | 改为版本 1.21 |\\n\\n```xml\\n<useragentutils.version>1.21</useragentutils.version>\\n```\\n\\n---\\n\\n### ❌ 问题 2: Lombok 不支持 JDK 25\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `WARNING: sun.misc.Unsafe::objectFieldOffset has been called` |\\n| 🟢 解决 | 升级到 1.18.42 |\\n\\n```xml\\n<lombok.version>1.18.42</lombok.version>\\n```\\n\\n---\\n\\n### ❌ 问题 3: OkHttp 5.x API 不兼容\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `cannot find symbol: class HttpUrl` |\\n| 🟢 解决 | 保持使用 OkHttp 4.12.0 |\\n\\n```xml\\n<okhttp.version>4.12.0</okhttp.version>\\n```\\n\\n---\\n\\n### ❌ 问题 4: JDK 版本不匹配\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `UnsupportedClassVersionError: class file version 69.0, this version of the Java Runtime only recognizes class file versions up to 65.0` |\\n| 🟢 解决 | 设置 `JAVA_HOME=D:\\\\Java\\\\jdk-25.0.1`，Docker 镜像使用 `eclipse-temurin:25-jre-alpine` |\\n\\n---\\n\\n### ❌ 问题 5: 后台登录页面空白\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 登录成功后页面空白，无菜单显示 |\\n| 🔴 原因 | 用户缺少 admin 角色权限 |\\n| 🟢 解决 | 在数据库中为用户分配 admin 角色 |\\n\\n```sql\\nINSERT INTO t_user_role (user_id, role_id) \\nVALUES (1025, (SELECT id FROM t_role WHERE role_name = \'admin\'));\\n```\\n\\n---\\n\\n### ❌ 问题 6: Elasticsearch 503 错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `HTTP/1.1 503 Service Unavailable - no_shard_available_action_exception - all shards failed` |\\n\\n**快速解决方案**:\\n\\n| 方案 | 命令/配置 |\\n|:---|:---|\\n| 1️⃣ 降级到 MySQL 搜索（推荐） | `search.mode: mysql` |\\n| 2️⃣ 重启 Elasticsearch | `docker restart aurora-elasticsearch` |\\n| 3️⃣ 重建索引 | `curl -X DELETE http://你的ip:9200/article` |\\n\\n详细排查请参考 [第 2 部分](#2-elasticsearch-8134-集成问题排查)\\n\\n---\\n\\n## 1.5 编译与部署\\n\\n### 编译环境要求\\n\\n| 环境 | 版本 |\\n|:---|:---|\\n| **JDK** | 25.0.1+ |\\n| **Maven** | 3.9.x+ |\\n\\n**编译命令**:\\n```bash\\nset JAVA_HOME=D:\\\\Java\\\\jdk-25.0.1\\nmvn clean package -DskipTests -U\\n```\\n\\n### JVM 优化参数\\n\\n```bash\\njava -Xms96m -Xmx192m \\\\\\n     -XX:MetaspaceSize=48m -XX:MaxMetaspaceSize=128m \\\\\\n     -XX:+UseG1GC \\\\\\n     -XX:+UseStringDeduplication \\\\\\n     -XX:+UseCompressedOops \\\\\\n     -XX:+UseCompressedClassPointers \\\\\\n     -XX:+AlwaysPreTouch \\\\\\n     -jar blog.jar\\n```\\n\\n---\\n\\n## 1.6 验证结果\\n\\n### ✅ 应用启动验证\\n\\n```\\n✅ Spring Boot 3.5.10 启动成功\\n✅ 使用 JDK 25.0.2 运行\\n✅ Tomcat 在 8080 端口启动\\n✅ 数据库连接正常\\n✅ Quartz 定时任务启动成功\\n✅ ip2region.xdb 加载成功 (11MB)\\n✅ RabbitMQ 连接成功\\n```\\n\\n### ✅ 功能验证\\n\\n| 功能 | 状态 |\\n|:---|:---:|\\n| ✅ QQ 登录 | 正常 |\\n| ✅ 邮箱登录 | 正常 |\\n| ✅ 用户权限（34 个菜单） | 正常 |\\n| ✅ 统计数据查询 | 正常 |\\n| ✅ 文章管理 | 正常 |\\n| ⚠️ Elasticsearch 搜索 | 不可用（临时降级 MySQL） |\\n\\n### 📊 性能对比\\n\\n| 指标 | JDK 21 + SB 3.2.12 | JDK 25 + SB 3.5.10 | 提升 |\\n|:---|:---:|:---:|:---:|\\n| 启动时间 | ~12 秒 | ~10 秒 | 16.7% ⬆️ |\\n| 内存占用 | ~200MB | ~180MB | 10% ⬇️ |\\n| 响应速度 | 基准 | +5~8% | 5~8% ⬆️ |\\n\\n---\\n\\n## 1.7 升级总结\\n\\n### 🎯 成功经验\\n\\n| # | 经验 |\\n|:---:|:---|\\n| 1️⃣ | 提前备份：升级前备份所有配置文件和数据库 |\\n| 2️⃣ | 逐步升级：先升级 Spring Boot，再升级 JDK |\\n| 3️⃣ | 依赖检查：检查所有第三方依赖的兼容性 |\\n| 4️⃣ | 充分测试：编译、打包、运行全流程测试 |\\n| 5️⃣ | 回滚方案：准备回滚脚本和备份镜像 |\\n\\n### ⚠️ 注意事项\\n\\n| # | 注意事项 |\\n|:---:|:---|\\n| 1️⃣ | JDK 25 要求：运行环境必须安装 JDK 25 |\\n| 2️⃣ | Docker 镜像：使用 `eclipse-temurin:25-jre-alpine` |\\n| 3️⃣ | OkHttp 版本：保持 4.x 避免 API 重大变更 |\\n| 4️⃣ | ip2region 数据：确保 xdb 文件为 3.x 格式（支持 IPv6） |\\n| 5️⃣ | Elasticsearch：8.13.4 与 Spring Boot 3.5.10 存在兼容性挑战 |\\n\\n---\\n\\n# 2. Elasticsearch 8.13.4 集成问题排查\\n\\n## 2.1 问题概述\\n\\n在将 Elasticsearch 升级到 8.13.4 后，遇到搜索功能完全失效的问题。经过排查，发现多个关键问题导致搜索无法正常工作。\\n\\n---\\n\\n## 2.2 常见问题与解决方案\\n\\n### ❌ 问题 1: ES 索引 Mapping 配置错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 搜索功能返回空结果，高亮功能不生效 |\\n| 🔴 原因 | 旧索引删除后，新索引没有正确配置 IK 分词器，字段类型未指定为 `text` |\\n| 🟢 解决 | 创建 `ElasticsearchIndexInitializer` 类，在应用启动时自动创建索引 |\\n\\n```java\\nelasticsearchClient.indices().create(c -> c\\n    .index(\\\"article\\\")\\n    .mappings(m -> m\\n        .properties(\\\"articleId\\\", p -> p.integer(i -> i.store(true)))\\n        .properties(\\\"articleTitle\\\", p -> p.text(t -> t\\n            .analyzer(\\\"ik_max_word\\\")\\n            .searchAnalyzer(\\\"ik_smart\\\")\\n            .store(true)\\n        ))\\n        .properties(\\\"articleContent\\\", p -> p.text(t -> t\\n            .analyzer(\\\"ik_max_word\\\")\\n            .searchAnalyzer(\\\"ik_smart\\\")\\n            .store(true)\\n        ))\\n        .properties(\\\"isDelete\\\", p -> p.integer(i -> i.store(true)))\\n        .properties(\\\"status\\\", p -> p.integer(i -> i.store(true)))\\n    )\\n);\\n```\\n\\n**关键配置**:\\n- `articleTitle` 和 `articleContent` 字段必须使用 `text` 类型\\n- 分词器配置：`analyzer: ik_max_word`（索引时），`searchAnalyzer: ik_smart`（搜索时）\\n\\n---\\n\\n### ❌ 问题 2: ES 字段映射错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 搜索返回结果，但文章 ID 为 null |\\n\\n**错误代码**:\\n```java\\n// ❌ 错误：ES 中的字段名是 id，不是 articleId\\narticle.setId(jsonObj.getInteger(\\\"articleId\\\"));\\n```\\n\\n**正确代码**:\\n```java\\n// ✅ 正确：ES 中的字段名是 id\\narticle.setId(jsonObj.getInteger(\\\"id\\\"));\\n```\\n\\n> 💡 **教训**: ES 索引中的字段名是 `id`，不是 `articleId`\\n\\n---\\n\\n### ❌ 问题 3: JsonData.toJson() 类型转换错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 编译错误 `不兼容的类型。实际为 jakarta.json.JsonValue\'，需要 \'java.lang.String\'` |\\n\\n**错误代码**:\\n```java\\n// ❌ 错误：toJson() 返回的是 JsonValue 对象\\nString rawJson = sourceData.toJson();\\n```\\n\\n**正确代码**:\\n```java\\n// ✅ 正确：需要调用 toString() 转换为字符串\\nString rawJson = sourceData.toJson().toString();\\n```\\n\\n> 💡 **原因**: ES 8.x 的 `JsonData.toJson()` 返回的是 `JsonValue` 对象\\n\\n---\\n\\n### ❌ 问题 4: ES 索引中没有数据\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 索引存在且配置正确，搜索返回空数组 |\\n| 🔴 原因 | 删除索引后，新索引创建成功但没有文章数据，MaxWell 只同步增量变更 |\\n| 🟢 解决 | 在 `ElasticsearchIndexInitializer` 中添加数据同步方法 |\\n\\n**同步结果**:\\n```\\n========== 文章数据同步完成 ==========\\n应同步文章数：23\\n实际同步成功：23\\n======================================\\n```\\n\\n---\\n\\n### ❌ 问题 5: 搜索查询未使用 IK 分词器\\n\\n| 项目 | content |\\n|:---|:---|\\n| 🔴 现象 | 中文搜索不准确，分词效果差 |\\n| 🟢 解决 | 在 `buildQuery` 方法中明确指定 analyzer |\\n\\n```java\\nBoolQuery boolQuery = BoolQuery.of(b -> b\\n    .must(m -> m.bool(bb -> bb\\n        .should(s -> s.match(t -> t\\n            .field(\\\"articleTitle\\\")\\n            .query(keywords)\\n            .analyzer(\\\"ik_max_word\\\")  // ✅ 明确指定分词器\\n        ))\\n        .should(s -> s.match(t -> t\\n            .field(\\\"articleContent\\\")\\n            .query(keywords)\\n            .analyzer(\\\"ik_max_word\\\")  // ✅ 明确指定分词器\\n        ))\\n    ))\\n    .must(m -> m.term(t -> t.field(\\\"isDelete\\\").value(FALSE)))\\n    .must(m -> m.term(t -> t.field(\\\"status\\\").value(PUBLIC.getStatus())))\\n);\\n```\\n\\n---\\n\\n### ❌ 问题 6: 高亮配置不生效\\n\\n| 项目 | content |\\n|:---|:---|\\n| 🔴 现象 | 搜索结果有高亮字段，但值为空 |\\n| 🔴 原因 | `preTags` 和 `postTags` 没有在全局设置 |\\n| 🟢 解决 | 全局设置高亮标签 |\\n\\n```java\\nHighlight highlight = Highlight.of(h -> h\\n    .preTags(PRE_TAG)  // ✅ 全局设置前置标签\\n    .postTags(POST_TAG) // ✅ 全局设置后置标签\\n    .fields(\\\"articleTitle\\\", HighlightField.of(hf -> hf\\n        .fragmentSize(0)\\n    ))\\n    .fields(\\\"articleContent\\\", HighlightField.of(hf -> hf\\n        .fragmentSize(50)\\n        .numberOfFragments(3)\\n    ))\\n);\\n```\\n\\n---\\n\\n### ❌ 问题 7: 测试环境缺少 ES 配置\\n\\n| 项目 | content |\\n|:---|:---|\\n| 🔴 现象 | 应用启动失败，错误 `No qualifying bean of type \'ElasticsearchClient\' available` |\\n| 🟢 解决 | 恢复 `ElasticsearchConfig` 配置类，添加 `@Profile(\\\"!test\\\")` |\\n\\n---\\n\\n## 2.3 关键配置文件\\n\\n### application-prod.yml\\n\\n```yaml\\nelasticsearch:\\n  rest:\\n    uris: http://你的ip:9200\\n    username: 用户名\\n    password: 密码\\n\\nsearch:\\n  mode: elasticsearch\\n```\\n\\n### 核心代码文件\\n\\n| 文件 | 说明 |\\n|:---|:---|\\n| 1️⃣ `ElasticsearchConfig.java` | ES 客户端配置 |\\n| 2️⃣ `ElasticsearchIndexInitializer.java` | 索引初始化与数据同步 |\\n| 3️⃣ `EsSearchStrategyImpl.java` | ES 搜索策略实现 |\\n| 4️⃣ `ArticleController.java` | 搜索 API 接口 |\\n\\n---\\n\\n## 2.4 经验总结\\n\\n| # | 经验 |\\n|:---:|:---|\\n| 1️⃣ | 字段映射必须匹配实际存储：ES 中的字段名必须与索引时的字段名一致 |\\n| 2️⃣ | 数据同步机制：MaxWell 只同步增量变更，删除索引后需要手动全量同步历史数据 |\\n| 3️⃣ | 分词器配置：索引时使用 `ik_max_word`，搜索时使用 `ik_smart`，查询时必须明确指定 analyzer |\\n| 4️⃣ | 高亮配置：全局设置 `preTags` 和 `postTags`，字段级别可以单独配置 `fragmentSize` 和 `numberOfFragments` |\\n| 5️⃣ | 测试注意事项：ES 搜索测试需要真实环境，避免对\\\"不存在的关键词\\\"做强断言 |\\n\\n---\\n\\n# 3. 常用命令与运维\\n\\n## 3.1 ES 常用命令\\n\\n```bash\\n# 📊 检查集群健康\\ncurl -u 用户名:密码 http://你的ip:9200/_cluster/health?pretty\\n\\n# 📋 检查索引列表\\ncurl -u 用户名:密码 http://你的ip:9200/_cat/indices?v\\n\\n# 🔍 检查分片状态\\ncurl -u 用户名:密码 http://你的ip:9200/_cat/shards/article?v\\n\\n# 🗑️ 删除索引\\ncurl -X DELETE -u 用户名:密码 http://你的ip:9200/article\\n\\n# 📄 查看索引映射\\ncurl -u 用户名:密码 http://your-ip:9200/article/_mapping?pretty\\n\\n# 🔎 测试搜索\\ncurl -X POST -u 用户名:密码 \\\\\\n  http://你的ip:9200/article/_search?pretty \\\\\\n  -H \'Content-Type: application/json\' \\\\\\n  -d \'{\\\"query\\\":{\\\"match_all\\\":{}}, \\\"size\\\":1}\'\\n\\n# 📜 查看 ES 日志\\ndocker logs aurora-elasticsearch --tail 100 -f\\n\\n# 🔄 重启 ES 服务\\ndocker restart aurora-elasticsearch\\n\\n# 💾 查看 ES 资源使用\\ndocker stats aurora-elasticsearch --no-stream\\n```\\n\\n---\\n\\n## 3.2 搜索模式切换\\n\\n| 模式 | 配置 |\\n|:---|:---|\\n| 🔵 MySQL 搜索 | `search.mode: mysql` |\\n| 🟢 Elasticsearch | `search.mode: elasticsearch` |\\n\\n**重启应用**:\\n```bash\\ndocker restart aurora-springboot\\n```\\n\\n---\\n\\n## 3.3 应用重启流程\\n\\n| 步骤 | 命令 |\\n|:---|:---|\\n| 1️⃣ 停止应用 | `docker stop aurora-springboot` |\\n| 2️⃣ 更新配置 | 修改 `application-prod.yml`，上传新的 jar 包到 `/opt/aurora/app/` |\\n| 3️⃣ 启动应用 | `docker start aurora-springboot` |\\n| 4️⃣ 检查日志 | `docker logs aurora-springboot -f` |\\n| 5️⃣ 验证健康 | `curl http://localhost:8080/api/articles/topAndFeatured` |\\n\\n---\\n\\n## 3.4 常见问题快速解决\\n\\n### ❌ factoryBeanObjectType 错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | `Invalid value type for attribute \'factoryBeanObjectType\': java.lang.String` |\\n| 🟢 解决 | 使用 `mybatis-plus-spring-boot3-starter` 替代 `mybatis-plus-boot-starter` |\\n\\n---\\n\\n### ❌ 端口被占用\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | `Port 8080 was already in use` |\\n| 🟢 解决 | 查看端口占用并释放，或修改端口为 8081 |\\n\\n```powershell\\n# Windows\\nnetstat -ano | findstr :8080\\npowershell -Command \\\"Stop-Process -Id <PID> -Force\\\"\\n```\\n\\n---\\n\\n# 4. 参考资料\\n\\n## 4.1 官方文档\\n\\n| 文档 | 链接 |\\n|:---|:---|\\n| 📘 Spring Boot 3.5 Release Notes | [查看](https://spring.io/blog/spring-boot-3-5-0-available-now) |\\n| ☕ JDK 25 Release Notes | [查看](https://openjdk.org/projects/jdk/25/) |\\n| 🗂️ MyBatis-Plus 3.5.x Documentation | [查看](https://baomidou.com/) |\\n| 🌍 ip2region 3.x GitHub | [查看](https://github.com/lionsoul2014/ip2region) |\\n| 📦 Lombok 1.18.42 Release | [查看](https://projectlombok.org/changelog) |\\n| 🔍 Elasticsearch 8.x 官方文档 | [查看](https://www.elastic.co/guide/en/elasticsearch/reference/current/index.html) |\\n| 📝 IK 分词器文档 | [查看](https://github.com/medcl/elasticsearch-analysis-ik) |\\n\\n## 4.2 迁移指南\\n\\n| 指南 | 链接 |\\n|:---|:---|\\n| 🚀 Spring Boot 3.0 Migration Guide | [查看](https://github.com/spring-projects/spring-boot/wiki/Spring-Boot-3.0-Migration-Guide) |\\n| 🏛️ Jakarta EE 9+ Migration Guide | [查看](https://jakarta.ee/blogs/jakarta-ee-9-migration-guide/) |\\n| ☕ Elasticsearch 8.x Java Client | [查看](https://www.elastic.co/guide/en/elasticsearch/client/java-api-client/current/index.html) |\\n\\n---\\n\\n## 📝 文档修订历史\\n\\n| 版本 | 日期 | 修改内容 | 作者 |\\n|:---|:---:|:---|:---|\\n| v1.0 | 2026-03-09 | 合并《升级到SpringBoot3.5.10 和 JDK25 历程》和《Elasticsearch8 集成问题排查记录》 | Aurora Team |\\n| v1.1 | 2026-03-09 | 优化结构，去除重复内容，简化 FAQ 章节 | Aurora Team |\\n\\n---\\n\\n<div align=\\\"center\\\">\\n\\n**文档版本**: v1.1 (优化版)  \\n**最后更新**: 2026-03-09  \\n**维护者**: Aurora Team\\n\\n</div>\\n\",\"articleCover\":\"https://ws.aqi125.cn/aurora/articles/346065b80634d00d58791014ab0c0cb8.jpg\",\"articleTitle\":\"Aurora 博客系统 - 升级与 Elasticsearch 8.13.4 集成完整指南\",\"categoryName\":\"Aurora集成ES\",\"id\":192,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-08 10:07:22', NULL);
INSERT INTO `t_operation_log` VALUES (2578, '文章模块', '上传', '/admin/articles/images', 'com.aurora.controller.ArticleController.saveArticleImages', '上传文章图片', 'file', 'POST', '{\"code\":20000,\"data\":\"https://ws.aqi125.cn/aurora/articles/539eded9e6c2996c9224104162f80e63.jpg\",\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-08 10:10:08', NULL);
INSERT INTO `t_operation_log` VALUES (2579, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleAbstract\":\"\",\"articleContent\":\"# Aurora 博客系统 - 升级与 Elasticsearch 8.17.2 集成完整指南\\n\\n<div align=\\\"center\\\">\\n\\n![Elasticsearch](https://img.shields.io/badge/Elasticsearch-8.17.2-00BFb3?style=flat-square&logo=elasticsearch)\\n![Spring Boot](https://img.shields.io/badge/Spring%20Boot-4.0.5-6DB33F?style=flat-square&logo=spring)\\n![Version](https://img.shields.io/badge/Version-v2.0-blue?style=flat-square)\\n![Last Updated](https://img.shields.io/badge/Last%20Updated-2026--04--08-orange?style=flat-square)\\n\\n</div>\\n\\n---\\n\\n## 目录\\n\\n1. [Elasticsearch 8.17.2 集成问题排查](#1-elasticsearch-8172-集成问题排查)\\n   - [问题概述](#11-问题概述)\\n   - [常见问题与解决方案](#12-常见问题与解决方案)\\n   - [关键配置文件](#13-关键配置文件)\\n   - [经验总结](#14-经验总结)\\n2. [常用命令与运维](#2-常用命令与运维)\\n   - [ES 常用命令](#21-es-常用命令)\\n   - [搜索模式切换](#22-搜索模式切换)\\n   - [应用重启流程](#23-应用重启流程)\\n   - [常见问题快速解决](#24-常见问题快速解决)\\n3. [参考资料](#3-参考资料)\\n\\n---\\n\\n# 1. Elasticsearch 8.17.2 集成问题排查\\n\\n## 1.1 问题概述\\n\\n在将 Elasticsearch 升级到 8.17.2 后，遇到搜索功能完全失效的问题。经过排查，发现多个关键问题导致搜索无法正常工作。\\n\\n> **📌 核心问题**：索引配置、字段映射、数据同步、分词器、超时设置\\n\\n---\\n\\n## 1.2 常见问题与解决方案\\n\\n### ❌ 问题 1: ES 索引 Mapping 配置错误\\n\\n| 类别       | 内容                                                         |\\n| :--------- | :----------------------------------------------------------- |\\n| 🔴 **现象** | 搜索功能返回空结果，高亮功能不生效                           |\\n| 🔴 **原因** | 旧索引删除后，新索引没有正确配置 IK 分词器，字段类型未指定为 `text` |\\n| 🟢 **解决** | 创建 `ElasticsearchIndexInitializer` 类，在应用启动时自动创建索引 |\\n\\n```java\\nelasticsearchClient.indices().create(c -> c\\n    .index(\\\"article\\\")\\n    .mappings(m -> m\\n        .properties(\\\"id\\\", p -> p.integer(i -> i.store(true)))\\n        .properties(\\\"articleTitle\\\", p -> p.text(t -> t\\n            .analyzer(\\\"ik_max_word\\\")\\n            .searchAnalyzer(\\\"ik_smart\\\")\\n            .store(true)\\n        ))\\n        .properties(\\\"articleContent\\\", p -> p.text(t -> t\\n            .analyzer(\\\"ik_max_word\\\")\\n            .searchAnalyzer(\\\"ik_smart\\\")\\n            .store(true)\\n        ))\\n        .properties(\\\"isDelete\\\", p -> p.integer(i -> i.store(true)))\\n        .properties(\\\"status\\\", p -> p.integer(i -> i.store(true)))\\n    )\\n);\\n```\\n\\n> **🔑 关键配置**：\\n>\\n> - `articleTitle` 和 `articleContent` 字段必须使用 `text` 类型\\n> - 分词器配置：`analyzer: ik_max_word`（索引时），`searchAnalyzer: ik_smart`（搜索时）\\n\\n---\\n\\n### ❌ 问题 2: ES 字段映射错误\\n\\n| 类别       | 内容                            |\\n| :--------- | :------------------------------ |\\n| 🔴 **现象** | 搜索返回结果，但文章 ID 为 null |\\n\\n**错误代码** ❌：\\n\\n```java\\n// ❌ 错误：ES 中的字段名是 id，不是 articleId\\narticle.setId(jsonObj.getInteger(\\\"articleId\\\"));\\n```\\n\\n**正确代码** ✅：\\n\\n```java\\n// ✅ 正确：ES 中的字段名是 id\\narticle.setId(jsonObj.getInteger(\\\"id\\\"));\\n```\\n\\n> **💡 教训**：ES 索引中的字段名是 `id`，不是 `articleId`\\n\\n---\\n\\n### ❌ 问题 3: JsonData.toJson() 类型转换错误\\n\\n| 类别       | 内容                                                         |\\n| :--------- | :----------------------------------------------------------- |\\n| 🔴 **现象** | 编译错误 `不兼容的类型。实际为 jakarta.json.JsonValue\'，需要 \'java.lang.String\'` |\\n\\n**错误代码** ❌：\\n\\n```java\\n// ❌ 错误：toJson() 返回的是 JsonValue 对象\\nString rawJson = sourceData.toJson();\\n```\\n\\n**正确代码** ✅：\\n\\n```java\\n// ✅ 正确：需要调用 toString() 转换为字符串\\nString rawJson = sourceData.toJson().toString();\\n```\\n\\n> **💡 原因**：ES 8.x 的 `JsonData.toJson()` 返回的是 `JsonValue` 对象\\n\\n---\\n\\n### ❌ 问题 4: ES 索引中没有数据\\n\\n| 类别       | 内容                                                         |\\n| :--------- | :----------------------------------------------------------- |\\n| 🔴 **现象** | 索引存在且配置正确，搜索返回空数组                           |\\n| 🔴 **原因** | 删除索引后，新索引创建成功但没有文章数据，MaxWell 只同步增量变更 |\\n| 🟢 **解决** | 在 `ElasticsearchIndexInitializer` 中添加数据同步方法        |\\n\\n**同步结果**：\\n\\n```\\n========== 文章数据同步完成 ==========\\n应同步文章数：27\\n实际同步成功：27\\n同步失败：0\\n======================================\\n```\\n\\n---\\n\\n### ❌ 问题 5: 搜索查询未使用 IK 分词器\\n\\n| 类别       | 内容                                    |\\n| :--------- | :-------------------------------------- |\\n| 🔴 **现象** | 中文搜索不准确，分词效果差              |\\n| 🟢 **解决** | 在 `buildQuery` 方法中明确指定 analyzer |\\n\\n```java\\nBoolQuery boolQuery = BoolQuery.of(b -> b\\n    .must(m -> m.bool(bb -> bb\\n        .should(s -> s.match(t -> t\\n            .field(\\\"articleTitle\\\")\\n            .query(keywords)\\n            .analyzer(\\\"ik_max_word\\\")  // ✅ 明确指定分词器\\n        ))\\n        .should(s -> s.match(t -> t\\n            .field(\\\"articleContent\\\")\\n            .query(keywords)\\n            .analyzer(\\\"ik_max_word\\\")  // ✅ 明确指定分词器\\n        ))\\n    ))\\n    .must(m -> m.term(t -> t.field(\\\"isDelete\\\").value(FALSE)))\\n    .must(m -> m.term(t -> t.field(\\\"status\\\").value(PUBLIC.getStatus())))\\n);\\n```\\n\\n---\\n\\n### ❌ 问题 6: 高亮配置不生效\\n\\n| 类别       | 内容                                   |\\n| :--------- | :------------------------------------- |\\n| 🔴 **现象** | 搜索结果有高亮字段，但值为空           |\\n| 🔴 **原因** | `preTags` 和 `postTags` 没有在全局设置 |\\n| 🟢 **解决** | 全局设置高亮标签                       |\\n\\n```java\\nHighlight highlight = Highlight.of(h -> h\\n    .preTags(PRE_TAG)  // ✅ 全局设置前置标签\\n    .postTags(POST_TAG) // ✅ 全局设置后置标签\\n    .fields(\\\"articleTitle\\\", HighlightField.of(hf -> hf\\n        .fragmentSize(0)\\n    ))\\n    .fields(\\\"articleContent\\\", HighlightField.of(hf -> hf\\n        .fragmentSize(50)\\n        .numberOfFragments(3)\\n    ))\\n);\\n```\\n\\n---\\n\\n### ❌ 问题 7: ES Client 超时配置（SB 4.0 + ES 8.17.2）\\n\\n| 类别       | 内容                                                        |\\n| :--------- | :---------------------------------------------------------- |\\n| 🔴 **现象** | `30,000 milliseconds timeout on connection http-outgoing-0` |\\n| 🔴 **原因** | SB 4.0 + ES 8.17.2 需要显式配置超时参数                     |\\n| 🟢 **解决** | 在 `ElasticsearchConfig` 中设置 `RequestConfig`             |\\n\\n```java\\nRequestConfig requestConfig = RequestConfig.custom()\\n        .setConnectTimeout(10000)   // 连接超时 10s\\n        .setSocketTimeout(60000)    // Socket 超时 60s（支持批量同步）\\n        .setConnectionRequestTimeout(10000)\\n        .build();\\n\\nRestClientBuilder builder = RestClient.builder(new HttpHost(hostname, port, \\\"http\\\"))\\n        .setHttpClientConfigCallback((HttpAsyncClientBuilder httpClientBuilder) -> {\\n            httpClientBuilder.setDefaultCredentialsProvider(credentialsProvider)\\n                    .setDefaultRequestConfig(requestConfig)\\n                    .setMaxConnTotal(100)\\n                    .setMaxConnPerRoute(30);\\n            return httpClientBuilder;\\n        });\\n```\\n\\n---\\n\\n### ❌ 问题 8: ES article 索引 RED 状态\\n\\n| 类别       | 内容                                       |\\n| :--------- | :----------------------------------------- |\\n| 🔴 **现象** | `primary shard is not active`，同步失败    |\\n| 🔴 **原因** | IK 分词器插件未安装，索引 mapping 无法解析 |\\n| 🟢 **解决** | 在 ES 服务器安装 IK 分词器并重建索引       |\\n\\n```bash\\n# 1. 安装 IK 分词器（ES 8.17.2）\\nelasticsearch-plugin install https://github.com/infinilabs/analysis-ik/releases/download/v8.17.2/elasticsearch-analysis-ik-8.17.2.zip\\n\\n# 2. 重启 ES\\ndocker restart aurora-elasticsearch\\n\\n# 3. 删除损坏的索引\\ncurl -X DELETE \\\"http://134.175.206.158:9200/article\\\"\\n\\n# 4. 重启应用，自动重建索引并同步数据\\n```\\n\\n---\\n\\n## 1.3 关键配置文件\\n\\n### application-prod.yml\\n\\n```yaml\\nelasticsearch:\\n  rest:\\n    uris: http://你的ip:9200\\n    username: 用户名\\n    password: 密码\\n\\nsearch:\\n  mode: elasticsearch\\n```\\n\\n### 核心代码文件\\n\\n| 序号 | 文件                                 | 说明                                   |\\n| :--: | :----------------------------------- | :------------------------------------- |\\n|  1️⃣   | `ElasticsearchConfig.java`           | ES 客户端配置（SB 4.0 需显式设置超时） |\\n|  2️⃣   | `ElasticsearchIndexInitializer.java` | 索引初始化与数据同步                   |\\n|  3️⃣   | `EsSearchStrategyImpl.java`          | ES 搜索策略实现                        |\\n|  4️⃣   | `ArticleController.java`             | 搜索 API 接口                          |\\n\\n---\\n\\n## 1.4 经验总结\\n\\n|  #   | 经验说明                                                     |\\n| :--: | :----------------------------------------------------------- |\\n|  1️⃣   | **字段映射必须匹配**：ES 中的字段名必须与索引时的字段名一致  |\\n|  2️⃣   | **数据同步机制**：MaxWell 只同步增量变更，删除索引后需要手动全量同步历史数据 |\\n|  3️⃣   | **分词器配置**：索引时使用 `ik_max_word`，搜索时使用 `ik_smart`，查询时必须明确指定 analyzer |\\n|  4️⃣   | **高亮配置**：全局设置 `preTags` 和 `postTags`，字段级别可以单独配置 `fragmentSize` 和 `numberOfFragments` |\\n|  5️⃣   | **SB 4.0 + ES 8.17.2**：必须显式配置超时参数，否则批量同步会失败 |\\n|  6️⃣   | **IK 分词器版本**：必须与 ES 版本严格一致（如 ES 8.17.2 对应 IK 8.17.2） |\\n\\n---\\n\\n# 2. 常用命令与运维\\n\\n## 2.1 ES 常用命令\\n\\n### 集群与索引管理\\n\\n```bash\\n# 📊 检查集群健康\\ncurl -u 用户名:密码 http://你的ip:9200/_cluster/health?pretty\\n\\n# 📋 检查索引列表\\ncurl -u 用户名:密码 http://你的ip:9200/_cat/indices?v\\n\\n# 🔍 检查分片状态\\ncurl -u 用户名:密码 http://你的ip:9200/_cat/shards/article?v\\n```\\n\\n### 数据操作\\n\\n```bash\\n# 🗑️ 删除索引\\ncurl -X DELETE -u 用户名:密码 http://你的ip:9200/article\\n\\n# 📄 查看索引映射\\ncurl -u 用户名:密码 http://your-ip:9200/article/_mapping?pretty\\n\\n# 🔎 测试搜索\\ncurl -X POST -u 用户名:密码 \\\\\\n  http://你的ip:9200/article/_search?pretty \\\\\\n  -H \'Content-Type: application/json\' \\\\\\n  -d \'{\\\"query\\\":{\\\"match_all\\\":{}}, \\\"size\\\":1}\'\\n```\\n\\n### 容器运维\\n\\n```bash\\n# 📜 查看 ES 日志\\ndocker logs aurora-elasticsearch --tail 100 -f\\n\\n# 🔄 重启 ES 服务\\ndocker restart aurora-elasticsearch\\n\\n# 💾 查看 ES 资源使用\\ndocker stats aurora-elasticsearch --no-stream\\n```\\n\\n---\\n\\n## 2.2 搜索模式切换\\n\\n| 模式            | 配置值                       | 说明                 |\\n| :-------------- | :--------------------------- | :------------------- |\\n| 🔵 MySQL 搜索    | `search.mode: mysql`         | 使用 MySQL LIKE 查询 |\\n| 🟢 Elasticsearch | `search.mode: elasticsearch` | 使用 ES 全文搜索     |\\n\\n**重启应用**：\\n\\n```bash\\ndocker restart aurora-springboot\\n```\\n\\n---\\n\\n## 2.3 应用重启流程\\n\\n| 步骤 | 操作     | 命令                                                         |\\n| :--: | :------- | :----------------------------------------------------------- |\\n|  1️⃣   | 停止应用 | `docker stop aurora-springboot`                              |\\n|  2️⃣   | 更新配置 | 修改 `application-prod.yml`，上传新的 jar 包到 `/opt/aurora/app/` |\\n|  3️⃣   | 启动应用 | `docker start aurora-springboot`                             |\\n|  4️⃣   | 检查日志 | `docker logs aurora-springboot -f`                           |\\n|  5️⃣   | 验证健康 | `curl http://localhost:8080/api/articles/topAndFeatured`     |\\n\\n---\\n\\n## 2.4 常见问题快速解决\\n\\n### ❌ factoryBeanObjectType 错误\\n\\n| 类别       | 内容                                                         |\\n| :--------- | :----------------------------------------------------------- |\\n| 🔴 **现象** | `Invalid value value type for attribute \'factoryBeanObjectType\': java.lang.String` |\\n| 🟢 **解决** | 使用 `mybatis-plus-spring-boot3-starter` 替代 `mybatis-plus-boot-starter` |\\n\\n---\\n\\n### ❌ 端口被占用\\n\\n| 类别       | 内容                                  |\\n| :--------- | :------------------------------------ |\\n| 🔴 **现象** | `Port 8080 was already in use`        |\\n| 🟢 **解决** | 查看端口占用并释放，或修改端口为 8081 |\\n\\n**Windows 解决方案**：\\n\\n```powershell\\n# 查看端口占用\\nnetstat -ano | findstr :8080\\n\\n# 终止占用进程\\npowershell -Command \\\"Stop-Process -Id <PID> -Force\\\"\\n```\\n\\n---\\n\\n# 3. 参考资料\\n\\n## 3.1 官方文档\\n\\n| 文档类型 | 文档名称                      | 链接                                                         |\\n| :------- | :---------------------------- | :----------------------------------------------------------- |\\n| 🔍        | Elasticsearch 8.17.x 官方文档 | [查看](https://www.elastic.co/guide/en/elasticsearch/reference/8.17/index.html) |\\n| 📝        | IK 分词器文档                 | [查看](https://github.com/medcl/elasticsearch-analysis-ik)   |\\n| ☕        | Elasticsearch 8.x Java Client | [查看](https://www.elastic.co/guide/en/elasticsearch/client/java-api-client/current/index.html) |\\n\\n## 3.2 相关文档\\n\\n- [升级到 Spring Boot 4.0.5 和 JDK 25 历程](./升级到SpringBoot4.0.5和JDK25历程.md) - Spring Boot 4.0.5 升级详细指南\\n\\n---\\n\\n## 文档修订历史\\n\\n| 版本 |    日期    | 修改内容                                   | 作者        |\\n| :--- | :--------: | :----------------------------------------- | :---------- |\\n| v1.0 | 2026-03-09 | 初始版本：Elasticsearch 8 集成问题排查记录 | Aurora Team |\\n| v2.0 | 2026-04-08 | 更新 ES 到 8.17.2，新增 SB 4.0 兼容性说明  | Aurora Team |\\n\\n---\\n\\n<div align=\\\"center\\\">\\n\\n\\n**文档版本**: v2.0 (ES 8.17.2) | **最后更新**: 2026-04-08 | **维护者**: 七七\\n\\n![Built with ❤️](https://img.shields.io/badge/Built%20with-%E2%9D%A4%EF%B8%8F-blue?style=flat-square)\\n\\n</div>\",\"articleCover\":\"https://ws.aqi125.cn/aurora/articles/539eded9e6c2996c9224104162f80e63.jpg\",\"articleTitle\":\"Aurora 博客系统与 Elasticsearch 8.17.2 集成完整指南\",\"categoryName\":\"Aurora集成ES\",\"isFeatured\":1,\"isTop\":1,\"originalUrl\":\"\",\"password\":\"\",\"status\":1,\"tagNames\":[\"Elasticsearch 8.17.2\"],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-08 10:10:11', NULL);
INSERT INTO `t_operation_log` VALUES (2580, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleAbstract\":\"\",\"articleContent\":\"# Aurora 博客系统 - 升级与 Elasticsearch 集成完整指南\\n\\n> Spring Boot 3.5.10 + JDK 25 + Elasticsearch 8.13.4 升级与集成指南\\n\\n---\\n\\n## 📋 目录\\n\\n1. [升级到 Spring Boot 3.5.10 和 JDK 25](#1-升级到-spring-boot-3510-和-jdk-25)\\n2. [Elasticsearch 8.13.4 集成问题排查](#2-elasticsearch-8134-集成问题排查)\\n3. [常用命令与运维](#3-常用命令与运维)\\n4. [参考资料](#4-参考资料)\\n\\n---\\n\\n# 1. 升级到 Spring Boot 3.5.10 和 JDK 25\\n\\n## 1.1 升级概述\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 📅 升级时间 | 2026-03-08 |\\n| 🚀 升级路线 | Spring Boot 3.2.12 + JDK 21 → Spring Boot 3.5.10 + JDK 25 |\\n| 💡 升级原因 | 追求最新特性、性能优化和安全更新 |\\n\\n---\\n\\n## 1.2 依赖版本对比\\n\\n| 组件 | 原版本 | 新版本 | 说明 |\\n|:---|:---:|:---:|:---|\\n| **Spring Boot** | 3.2.12 | **3.5.10** | 最新稳定版 |\\n| **JDK** | 21 | **25** | Oracle 最新 LTS 版本 |\\n| **Lombok** | 1.18.30 | **1.18.42** | 支持 JDK 25 |\\n| **MyBatis-Plus** | 3.5.6 | **3.5.16** | 性能优化和 bug 修复 |\\n| **MySQL Connector/J** | 8.3.0 | **9.6.0** | 最新 JDBC 驱动 |\\n| **FastJSON2** | 2.0.43 | **2.0.61** | JSON 序列化库 |\\n| **Hutool** | 5.8.25 | **5.8.43** | Java 工具类库 |\\n| **Hibernate Validator** | 8.0.1.Final | **9.1.0.Final** | 参数校验框架 |\\n| **ip2region** | 2.7.0 | **3.3.6** | IP 地址库（支持 IPv6） |\\n| **MinIO** | 8.5.7 | **8.6.0** | 对象存储客户端 |\\n| **Knife4j** | 4.4.0 | **4.5.0** | API 文档 |\\n| **UserAgentUtils** | 1.25 | **1.21** | 修复 Maven 仓库不存在问题 |\\n\\n**保持不变的依赖**:\\n\\n| 依赖项 | 版本 | 说明 |\\n|:---|:---:|:---|\\n| **Elasticsearch** | 8.13.4 | Java Client |\\n| **JJWT** | 0.12.5 | JWT 令牌 |\\n| **Quartz** | 2.5.2 | 定时任务 |\\n| **OkHttp** | 4.12.0 | HTTP 客户端（保持 4.x 避免 API 变更） |\\n\\n---\\n\\n## 1.3 代码适配修改\\n\\n### IpUtil.java - ip2region 3.x API 适配\\n\\n**文件位置**: `src/main/java/com/aurora/util/IpUtil.java`\\n\\n```java\\n// 旧版本 (2.7.0)\\nsearcher = Searcher.newWithBuffer(dbBinStr);\\n\\n// 新版本 (3.3.6)\\nimport org.lionsoul.ip2region.xdb.LongByteArray;\\nimport org.lionsoul.ip2region.xdb.Version;\\n\\nLongByteArray longDbArray = new LongByteArray();\\nlongDbArray.append(dbBinStr);\\nsearcher = Searcher.newWithBuffer(Version.IPv4, longDbArray);\\n```\\n\\n### Dockerfile - JDK 版本更新\\n\\n**文件位置**: `Dockerfile`\\n\\n```dockerfile\\nFROM eclipse-temurin:25-jre-alpine\\nWORKDIR /app\\nVOLUME /tmp\\nADD aurora-springboot-0.0.1.jar blog.jar\\n```\\n\\n---\\n\\n## 1.4 常见问题与解决方案\\n\\n### ❌ 问题 1: UserAgentUtils 版本不存在\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `Could not find artifact eu.bitwalker:UserAgentUtils:1.25` |\\n| 🟢 解决 | 改为版本 1.21 |\\n\\n```xml\\n<useragentutils.version>1.21</useragentutils.version>\\n```\\n\\n---\\n\\n### ❌ 问题 2: Lombok 不支持 JDK 25\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `WARNING: sun.misc.Unsafe::objectFieldOffset has been called` |\\n| 🟢 解决 | 升级到 1.18.42 |\\n\\n```xml\\n<lombok.version>1.18.42</lombok.version>\\n```\\n\\n---\\n\\n### ❌ 问题 3: OkHttp 5.x API 不兼容\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `cannot find symbol: class HttpUrl` |\\n| 🟢 解决 | 保持使用 OkHttp 4.12.0 |\\n\\n```xml\\n<okhttp.version>4.12.0</okhttp.version>\\n```\\n\\n---\\n\\n### ❌ 问题 4: JDK 版本不匹配\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `UnsupportedClassVersionError: class file version 69.0, this version of the Java Runtime only recognizes class file versions up to 65.0` |\\n| 🟢 解决 | 设置 `JAVA_HOME=D:\\\\Java\\\\jdk-25.0.1`，Docker 镜像使用 `eclipse-temurin:25-jre-alpine` |\\n\\n---\\n\\n### ❌ 问题 5: 后台登录页面空白\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 登录成功后页面空白，无菜单显示 |\\n| 🔴 原因 | 用户缺少 admin 角色权限 |\\n| 🟢 解决 | 在数据库中为用户分配 admin 角色 |\\n\\n```sql\\nINSERT INTO t_user_role (user_id, role_id) \\nVALUES (1025, (SELECT id FROM t_role WHERE role_name = \'admin\'));\\n```\\n\\n---\\n\\n### ❌ 问题 6: Elasticsearch 503 错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `HTTP/1.1 503 Service Unavailable - no_shard_available_action_exception - all shards failed` |\\n\\n**快速解决方案**:\\n\\n| 方案 | 命令/配置 |\\n|:---|:---|\\n| 1️⃣ 降级到 MySQL 搜索（推荐） | `search.mode: mysql` |\\n| 2️⃣ 重启 Elasticsearch | `docker restart aurora-elasticsearch` |\\n| 3️⃣ 重建索引 | `curl -X DELETE http://你的ip:9200/article` |\\n\\n详细排查请参考 [第 2 部分](#2-elasticsearch-8134-集成问题排查)\\n\\n---\\n\\n## 1.5 编译与部署\\n\\n### 编译环境要求\\n\\n| 环境 | 版本 |\\n|:---|:---|\\n| **JDK** | 25.0.1+ |\\n| **Maven** | 3.9.x+ |\\n\\n**编译命令**:\\n```bash\\nset JAVA_HOME=D:\\\\Java\\\\jdk-25.0.1\\nmvn clean package -DskipTests -U\\n```\\n\\n### JVM 优化参数\\n\\n```bash\\njava -Xms96m -Xmx192m \\\\\\n     -XX:MetaspaceSize=48m -XX:MaxMetaspaceSize=128m \\\\\\n     -XX:+UseG1GC \\\\\\n     -XX:+UseStringDeduplication \\\\\\n     -XX:+UseCompressedOops \\\\\\n     -XX:+UseCompressedClassPointers \\\\\\n     -XX:+AlwaysPreTouch \\\\\\n     -jar blog.jar\\n```\\n\\n---\\n\\n## 1.6 验证结果\\n\\n### ✅ 应用启动验证\\n\\n```\\n✅ Spring Boot 3.5.10 启动成功\\n✅ 使用 JDK 25.0.2 运行\\n✅ Tomcat 在 8080 端口启动\\n✅ 数据库连接正常\\n✅ Quartz 定时任务启动成功\\n✅ ip2region.xdb 加载成功 (11MB)\\n✅ RabbitMQ 连接成功\\n```\\n\\n### ✅ 功能验证\\n\\n| 功能 | 状态 |\\n|:---|:---:|\\n| ✅ QQ 登录 | 正常 |\\n| ✅ 邮箱登录 | 正常 |\\n| ✅ 用户权限（34 个菜单） | 正常 |\\n| ✅ 统计数据查询 | 正常 |\\n| ✅ 文章管理 | 正常 |\\n| ⚠️ Elasticsearch 搜索 | 不可用（临时降级 MySQL） |\\n\\n### 📊 性能对比\\n\\n| 指标 | JDK 21 + SB 3.2.12 | JDK 25 + SB 3.5.10 | 提升 |\\n|:---|:---:|:---:|:---:|\\n| 启动时间 | ~12 秒 | ~10 秒 | 16.7% ⬆️ |\\n| 内存占用 | ~200MB | ~180MB | 10% ⬇️ |\\n| 响应速度 | 基准 | +5~8% | 5~8% ⬆️ |\\n\\n---\\n\\n## 1.7 升级总结\\n\\n### 🎯 成功经验\\n\\n| # | 经验 |\\n|:---:|:---|\\n| 1️⃣ | 提前备份：升级前备份所有配置文件和数据库 |\\n| 2️⃣ | 逐步升级：先升级 Spring Boot，再升级 JDK |\\n| 3️⃣ | 依赖检查：检查所有第三方依赖的兼容性 |\\n| 4️⃣ | 充分测试：编译、打包、运行全流程测试 |\\n| 5️⃣ | 回滚方案：准备回滚脚本和备份镜像 |\\n\\n### ⚠️ 注意事项\\n\\n| # | 注意事项 |\\n|:---:|:---|\\n| 1️⃣ | JDK 25 要求：运行环境必须安装 JDK 25 |\\n| 2️⃣ | Docker 镜像：使用 `eclipse-temurin:25-jre-alpine` |\\n| 3️⃣ | OkHttp 版本：保持 4.x 避免 API 重大变更 |\\n| 4️⃣ | ip2region 数据：确保 xdb 文件为 3.x 格式（支持 IPv6） |\\n| 5️⃣ | Elasticsearch：8.13.4 与 Spring Boot 3.5.10 存在兼容性挑战 |\\n\\n---\\n\\n# 2. Elasticsearch 8.13.4 集成问题排查\\n\\n## 2.1 问题概述\\n\\n在将 Elasticsearch 升级到 8.13.4 后，遇到搜索功能完全失效的问题。经过排查，发现多个关键问题导致搜索无法正常工作。\\n\\n---\\n\\n## 2.2 常见问题与解决方案\\n\\n### ❌ 问题 1: ES 索引 Mapping 配置错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 搜索功能返回空结果，高亮功能不生效 |\\n| 🔴 原因 | 旧索引删除后，新索引没有正确配置 IK 分词器，字段类型未指定为 `text` |\\n| 🟢 解决 | 创建 `ElasticsearchIndexInitializer` 类，在应用启动时自动创建索引 |\\n\\n```java\\nelasticsearchClient.indices().create(c -> c\\n    .index(\\\"article\\\")\\n    .mappings(m -> m\\n        .properties(\\\"articleId\\\", p -> p.integer(i -> i.store(true)))\\n        .properties(\\\"articleTitle\\\", p -> p.text(t -> t\\n            .analyzer(\\\"ik_max_word\\\")\\n            .searchAnalyzer(\\\"ik_smart\\\")\\n            .store(true)\\n        ))\\n        .properties(\\\"articleContent\\\", p -> p.text(t -> t\\n            .analyzer(\\\"ik_max_word\\\")\\n            .searchAnalyzer(\\\"ik_smart\\\")\\n            .store(true)\\n        ))\\n        .properties(\\\"isDelete\\\", p -> p.integer(i -> i.store(true)))\\n        .properties(\\\"status\\\", p -> p.integer(i -> i.store(true)))\\n    )\\n);\\n```\\n\\n**关键配置**:\\n- `articleTitle` 和 `articleContent` 字段必须使用 `text` 类型\\n- 分词器配置：`analyzer: ik_max_word`（索引时），`searchAnalyzer: ik_smart`（搜索时）\\n\\n---\\n\\n### ❌ 问题 2: ES 字段映射错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 搜索返回结果，但文章 ID 为 null |\\n\\n**错误代码**:\\n```java\\n// ❌ 错误：ES 中的字段名是 id，不是 articleId\\narticle.setId(jsonObj.getInteger(\\\"articleId\\\"));\\n```\\n\\n**正确代码**:\\n```java\\n// ✅ 正确：ES 中的字段名是 id\\narticle.setId(jsonObj.getInteger(\\\"id\\\"));\\n```\\n\\n> 💡 **教训**: ES 索引中的字段名是 `id`，不是 `articleId`\\n\\n---\\n\\n### ❌ 问题 3: JsonData.toJson() 类型转换错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 编译错误 `不兼容的类型。实际为 jakarta.json.JsonValue\'，需要 \'java.lang.String\'` |\\n\\n**错误代码**:\\n```java\\n// ❌ 错误：toJson() 返回的是 JsonValue 对象\\nString rawJson = sourceData.toJson();\\n```\\n\\n**正确代码**:\\n```java\\n// ✅ 正确：需要调用 toString() 转换为字符串\\nString rawJson = sourceData.toJson().toString();\\n```\\n\\n> 💡 **原因**: ES 8.x 的 `JsonData.toJson()` 返回的是 `JsonValue` 对象\\n\\n---\\n\\n### ❌ 问题 4: ES 索引中没有数据\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 索引存在且配置正确，搜索返回空数组 |\\n| 🔴 原因 | 删除索引后，新索引创建成功但没有文章数据，MaxWell 只同步增量变更 |\\n| 🟢 解决 | 在 `ElasticsearchIndexInitializer` 中添加数据同步方法 |\\n\\n**同步结果**:\\n```\\n========== 文章数据同步完成 ==========\\n应同步文章数：23\\n实际同步成功：23\\n======================================\\n```\\n\\n---\\n\\n### ❌ 问题 5: 搜索查询未使用 IK 分词器\\n\\n| 项目 | content |\\n|:---|:---|\\n| 🔴 现象 | 中文搜索不准确，分词效果差 |\\n| 🟢 解决 | 在 `buildQuery` 方法中明确指定 analyzer |\\n\\n```java\\nBoolQuery boolQuery = BoolQuery.of(b -> b\\n    .must(m -> m.bool(bb -> bb\\n        .should(s -> s.match(t -> t\\n            .field(\\\"articleTitle\\\")\\n            .query(keywords)\\n            .analyzer(\\\"ik_max_word\\\")  // ✅ 明确指定分词器\\n        ))\\n        .should(s -> s.match(t -> t\\n            .field(\\\"articleContent\\\")\\n            .query(keywords)\\n            .analyzer(\\\"ik_max_word\\\")  // ✅ 明确指定分词器\\n        ))\\n    ))\\n    .must(m -> m.term(t -> t.field(\\\"isDelete\\\").value(FALSE)))\\n    .must(m -> m.term(t -> t.field(\\\"status\\\").value(PUBLIC.getStatus())))\\n);\\n```\\n\\n---\\n\\n### ❌ 问题 6: 高亮配置不生效\\n\\n| 项目 | content |\\n|:---|:---|\\n| 🔴 现象 | 搜索结果有高亮字段，但值为空 |\\n| 🔴 原因 | `preTags` 和 `postTags` 没有在全局设置 |\\n| 🟢 解决 | 全局设置高亮标签 |\\n\\n```java\\nHighlight highlight = Highlight.of(h -> h\\n    .preTags(PRE_TAG)  // ✅ 全局设置前置标签\\n    .postTags(POST_TAG) // ✅ 全局设置后置标签\\n    .fields(\\\"articleTitle\\\", HighlightField.of(hf -> hf\\n        .fragmentSize(0)\\n    ))\\n    .fields(\\\"articleContent\\\", HighlightField.of(hf -> hf\\n        .fragmentSize(50)\\n        .numberOfFragments(3)\\n    ))\\n);\\n```\\n\\n---\\n\\n### ❌ 问题 7: 测试环境缺少 ES 配置\\n\\n| 项目 | content |\\n|:---|:---|\\n| 🔴 现象 | 应用启动失败，错误 `No qualifying bean of type \'ElasticsearchClient\' available` |\\n| 🟢 解决 | 恢复 `ElasticsearchConfig` 配置类，添加 `@Profile(\\\"!test\\\")` |\\n\\n---\\n\\n## 2.3 关键配置文件\\n\\n### application-prod.yml\\n\\n```yaml\\nelasticsearch:\\n  rest:\\n    uris: http://你的ip:9200\\n    username: 用户名\\n    password: 密码\\n\\nsearch:\\n  mode: elasticsearch\\n```\\n\\n### 核心代码文件\\n\\n| 文件 | 说明 |\\n|:---|:---|\\n| 1️⃣ `ElasticsearchConfig.java` | ES 客户端配置 |\\n| 2️⃣ `ElasticsearchIndexInitializer.java` | 索引初始化与数据同步 |\\n| 3️⃣ `EsSearchStrategyImpl.java` | ES 搜索策略实现 |\\n| 4️⃣ `ArticleController.java` | 搜索 API 接口 |\\n\\n---\\n\\n## 2.4 经验总结\\n\\n| # | 经验 |\\n|:---:|:---|\\n| 1️⃣ | 字段映射必须匹配实际存储：ES 中的字段名必须与索引时的字段名一致 |\\n| 2️⃣ | 数据同步机制：MaxWell 只同步增量变更，删除索引后需要手动全量同步历史数据 |\\n| 3️⃣ | 分词器配置：索引时使用 `ik_max_word`，搜索时使用 `ik_smart`，查询时必须明确指定 analyzer |\\n| 4️⃣ | 高亮配置：全局设置 `preTags` 和 `postTags`，字段级别可以单独配置 `fragmentSize` 和 `numberOfFragments` |\\n| 5️⃣ | 测试注意事项：ES 搜索测试需要真实环境，避免对\\\"不存在的关键词\\\"做强断言 |\\n\\n---\\n\\n# 3. 常用命令与运维\\n\\n## 3.1 ES 常用命令\\n\\n```bash\\n# 📊 检查集群健康\\ncurl -u 用户名:密码 http://你的ip:9200/_cluster/health?pretty\\n\\n# 📋 检查索引列表\\ncurl -u 用户名:密码 http://你的ip:9200/_cat/indices?v\\n\\n# 🔍 检查分片状态\\ncurl -u 用户名:密码 http://你的ip:9200/_cat/shards/article?v\\n\\n# 🗑️ 删除索引\\ncurl -X DELETE -u 用户名:密码 http://你的ip:9200/article\\n\\n# 📄 查看索引映射\\ncurl -u 用户名:密码 http://your-ip:9200/article/_mapping?pretty\\n\\n# 🔎 测试搜索\\ncurl -X POST -u 用户名:密码 \\\\\\n  http://你的ip:9200/article/_search?pretty \\\\\\n  -H \'Content-Type: application/json\' \\\\\\n  -d \'{\\\"query\\\":{\\\"match_all\\\":{}}, \\\"size\\\":1}\'\\n\\n# 📜 查看 ES 日志\\ndocker logs aurora-elasticsearch --tail 100 -f\\n\\n# 🔄 重启 ES 服务\\ndocker restart aurora-elasticsearch\\n\\n# 💾 查看 ES 资源使用\\ndocker stats aurora-elasticsearch --no-stream\\n```\\n\\n---\\n\\n## 3.2 搜索模式切换\\n\\n| 模式 | 配置 |\\n|:---|:---|\\n| 🔵 MySQL 搜索 | `search.mode: mysql` |\\n| 🟢 Elasticsearch | `search.mode: elasticsearch` |\\n\\n**重启应用**:\\n```bash\\ndocker restart aurora-springboot\\n```\\n\\n---\\n\\n## 3.3 应用重启流程\\n\\n| 步骤 | 命令 |\\n|:---|:---|\\n| 1️⃣ 停止应用 | `docker stop aurora-springboot` |\\n| 2️⃣ 更新配置 | 修改 `application-prod.yml`，上传新的 jar 包到 `/opt/aurora/app/` |\\n| 3️⃣ 启动应用 | `docker start aurora-springboot` |\\n| 4️⃣ 检查日志 | `docker logs aurora-springboot -f` |\\n| 5️⃣ 验证健康 | `curl http://localhost:8080/api/articles/topAndFeatured` |\\n\\n---\\n\\n## 3.4 常见问题快速解决\\n\\n### ❌ factoryBeanObjectType 错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | `Invalid value type for attribute \'factoryBeanObjectType\': java.lang.String` |\\n| 🟢 解决 | 使用 `mybatis-plus-spring-boot3-starter` 替代 `mybatis-plus-boot-starter` |\\n\\n---\\n\\n### ❌ 端口被占用\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | `Port 8080 was already in use` |\\n| 🟢 解决 | 查看端口占用并释放，或修改端口为 8081 |\\n\\n```powershell\\n# Windows\\nnetstat -ano | findstr :8080\\npowershell -Command \\\"Stop-Process -Id <PID> -Force\\\"\\n```\\n\\n---\\n\\n# 4. 参考资料\\n\\n## 4.1 官方文档\\n\\n| 文档 | 链接 |\\n|:---|:---|\\n| 📘 Spring Boot 3.5 Release Notes | [查看](https://spring.io/blog/spring-boot-3-5-0-available-now) |\\n| ☕ JDK 25 Release Notes | [查看](https://openjdk.org/projects/jdk/25/) |\\n| 🗂️ MyBatis-Plus 3.5.x Documentation | [查看](https://baomidou.com/) |\\n| 🌍 ip2region 3.x GitHub | [查看](https://github.com/lionsoul2014/ip2region) |\\n| 📦 Lombok 1.18.42 Release | [查看](https://projectlombok.org/changelog) |\\n| 🔍 Elasticsearch 8.x 官方文档 | [查看](https://www.elastic.co/guide/en/elasticsearch/reference/current/index.html) |\\n| 📝 IK 分词器文档 | [查看](https://github.com/medcl/elasticsearch-analysis-ik) |\\n\\n## 4.2 迁移指南\\n\\n| 指南 | 链接 |\\n|:---|:---|\\n| 🚀 Spring Boot 3.0 Migration Guide | [查看](https://github.com/spring-projects/spring-boot/wiki/Spring-Boot-3.0-Migration-Guide) |\\n| 🏛️ Jakarta EE 9+ Migration Guide | [查看](https://jakarta.ee/blogs/jakarta-ee-9-migration-guide/) |\\n| ☕ Elasticsearch 8.x Java Client | [查看](https://www.elastic.co/guide/en/elasticsearch/client/java-api-client/current/index.html) |\\n\\n---\\n\\n## 📝 文档修订历史\\n\\n| 版本 | 日期 | 修改内容 | 作者 |\\n|:---|:---:|:---|:---|\\n| v1.0 | 2026-03-09 | 合并《升级到SpringBoot3.5.10 和 JDK25 历程》和《Elasticsearch8 集成问题排查记录》 | Aurora Team |\\n| v1.1 | 2026-03-09 | 优化结构，去除重复内容，简化 FAQ 章节 | Aurora Team |\\n\\n---\\n\\n<div align=\\\"center\\\">\\n\\n**文档版本**: v1.1 (优化版)  \\n**最后更新**: 2026-03-09  \\n**维护者**: 七七\\n\\n</div>\\n\",\"articleCover\":\"https://ws.aqi125.cn/aurora/articles/346065b80634d00d58791014ab0c0cb8.jpg\",\"articleTitle\":\"Aurora 博客系统 - 升级与 Elasticsearch 8.13.4 集成完整指南\",\"categoryName\":\"Aurora集成ES\",\"id\":192,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-08 10:10:34', NULL);
INSERT INTO `t_operation_log` VALUES (2581, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleAbstract\":\"\",\"articleContent\":\"# Aurora 博客系统 - JDK 17 + Spring Boot 2.7.18 升级历程\\n\\n> 从 JDK 1.8 + Spring Boot 2.3.7 升级到 JDK 17 + Spring Boot 2.7.18，同时集成 Elasticsearch 7.17.12\\n\\n---\\n\\n## 📅 升级时间\\n\\n2026年3月4日\\n\\n---\\n\\n## 📋 升级概述\\n\\n本次升级将 Aurora 博客系统从 JDK 1.8 + Spring Boot 2.3.7 升级到 JDK 17 + Spring Boot 2.7.18，同时集成 Elasticsearch 7.17.12 以支持全文搜索功能。\\n\\n| 组件 | 升级前 | 升级后 |\\n|:---|:---:|:---:|\\n| JDK | 1.8 | **17** |\\n| Spring Boot | 2.3.7.RELEASE | **2.7.18** |\\n| Elasticsearch | - | **7.17.12** |\\n| MyBatis-Plus | 3.4.2 | **3.4.3.4** |\\n| Knife4j | - | **2.0.9** |\\n| Lombok | - | **1.18.24** |\\n| MySQL Connector | - | **8.0.33** |\\n\\n---\\n\\n## 🚀 升级步骤\\n\\n### 1. 核心依赖版本升级 (pom.xml)\\n\\n#### 1.1 基础版本配置\\n\\n```xml\\n<properties>\\n    <java.version>17</java.version>\\n    <spring-boot.version>2.7.18</spring-boot.version>\\n    <elasticsearch.version>7.17.12</elasticsearch.version>\\n    <mybatis-plus.version>3.4.3.4</mybatis-plus.version>\\n    <knife4j.version>2.0.9</knife4j.version>\\n</properties>\\n```\\n\\n#### 1.2 Maven 编译器配置\\n\\n```xml\\n<plugin>\\n    <groupId>org.apache.maven.plugins</groupId>\\n    <artifactId>maven-compiler-plugin</artifactId>\\n    <version>3.8.1</version>\\n    <configuration>\\n        <source>17</source>\\n        <target>17</target>\\n        <annotationProcessorPaths>\\n            <path>\\n                <groupId>org.projectlombok</groupId>\\n                <artifactId>lombok</artifactId>\\n                <version>1.18.24</version>\\n            </path>\\n        </annotationProcessorPaths>\\n    </configuration>\\n</plugin>\\n```\\n\\n#### 1.3 MySQL 依赖\\n\\n```xml\\n<dependency>\\n    <groupId>mysql</groupId>\\n    <artifactId>mysql-connector-java</artifactId>\\n    <version>8.0.33</version>\\n    <scope>runtime</scope>\\n</dependency>\\n```\\n\\n---\\n\\n## 🔧 兼容性问题解决\\n\\n### ❌ 问题 1: Knife4j 版本冲突\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 问题 | Knife4j 4.x 与 Spring Boot 2.7.18 不兼容，导致 NullPointerException |\\n| 🟢 解决 | 降级到 2.0.9 版本 |\\n\\n```xml\\n<knife4j.version>2.0.9</knife4j.version>\\n```\\n\\n---\\n\\n### ❌ 问题 2: CORS 跨域配置\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 问题 | `allowedOrigins(\\\"*\\\")` 与 `allowCredentials(true)` 冲突 |\\n| 🟢 解决 | 使用 `allowedOriginPatterns(\\\"*\\\")` |\\n\\n```java\\nregistry.addMapping(\\\"/**\\\")\\n    .allowedOriginPatterns(\\\"*\\\")\\n    .allowCredentials(true)\\n    .allowedMethods(\\\"GET\\\", \\\"POST\\\", \\\"PUT\\\", \\\"DELETE\\\", \\\"OPTIONS\\\")\\n    .maxAge(3600);\\n```\\n\\n---\\n\\n### ❌ 问题 3: CompletableFuture 类型转换\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 问题 | MyBatis-Plus 3.4.3+ 的 `selectCount()` 返回 `Long` 而非 `Integer` |\\n| 🔴 涉及文件 | AuroraInfoServiceImpl、ArticleServiceImpl、CategoryServiceImpl、CommentServiceImpl、MenuServiceImpl、PhotoAlbumServiceImpl、ResourceServiceImpl、RoleServiceImpl、TalkServiceImpl、TagServiceImpl |\\n| 🟢 解决 | 修改类型声明 |\\n\\n```java\\n// 修改前\\nCompletableFuture<Integer> asyncArticleCount = CompletableFuture.supplyAsync(...);\\n\\n// 修改后\\nCompletableFuture<Long> asyncArticleCount = CompletableFuture.supplyAsync(...);\\n\\n// 使用时转换\\n.articleCount(asyncArticleCount.get().intValue())\\n```\\n\\n---\\n\\n### ❌ 问题 4: Lombok 注解不生效\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 问题 | 使用 JDK 25 时 Lombok 注解无法生成代码 |\\n| 🟢 解决 | 必须使用 JDK 17 编译和运行项目 |\\n\\n---\\n\\n## ⚙️ 配置文件调整\\n\\n### application-prod.yml\\n\\n```yaml\\n# JWT 配置\\njwt:\\n  secret: aurora\\n\\n# Spring MVC 路径匹配策略（Spring Boot 2.6+ 必需）\\nspring:\\n  mvc:\\n    pathmatch:\\n      matching-strategy: ant_path_matcher\\n```\\n\\n---\\n\\n## 🧪 验证与运行\\n\\n### 设置 JDK 17 环境\\n\\n```powershell\\n$env:JAVA_HOME=\'D:\\\\Java\\\\jdk-17.0.12\'\\n```\\n\\n### 编译项目\\n\\n```powershell\\n& \'D:\\\\Java\\\\apache-maven-3.9.12\\\\bin\\\\mvn.cmd\' clean compile -DskipTests\\n```\\n\\n### 启动项目\\n\\n```powershell\\n& \'D:\\\\Java\\\\apache-maven-3.9.12\\\\bin\\\\mvn.cmd\' spring-boot:run\\n```\\n\\n### 打包部署\\n\\n```powershell\\n& \'D:\\\\Java\\\\apache-maven-3.9.12\\\\bin\\\\mvn.cmd\' clean package -DskipTests\\n```\\n\\n---\\n\\n## ✅ 升级成果\\n\\n| 成果 | 状态 |\\n|:---|:---:|\\n| ✅ 项目成功使用 JDK 17 编译 | |\\n| ✅ Spring Boot 2.7.18 正常运行 | |\\n| ✅ Elasticsearch 7.17.12 集成完成 | |\\n| ✅ API 文档（Knife4j）正常访问 | |\\n| ✅ 所有业务功能正常 | |\\n| ✅ Lombok 注解完全生效 | |\\n| ✅ CORS 跨域配置正确 | |\\n| ✅ 项目启动时间约 10 秒 | |\\n\\n---\\n\\n## ⚠️ 注意事项\\n\\n| # | 注意事项 |\\n|:---:|:---|\\n| 1️⃣ | JDK 版本：必须使用 JDK 17，不要使用 JDK 21 或更高版本 |\\n| 2️⃣ | Knife4j 版本：必须使用 2.0.9，不要使用 4.x |\\n| 3️⃣ | CORS 配置：必须使用 `allowedOriginPatterns(\\\"*\\\")` 而非 `allowedOrigins(\\\"*\\\")` |\\n| 4️⃣ | 类型转换：MyBatis-Plus `selectCount()` 返回 `Long`，需要通过 `.intValue()` 转换 |\\n\\n---\\n\\n## 📝 修改文件清单\\n\\n| # | 文件 | 说明 |\\n|:---:|:---|:---|\\n| 1️⃣ | `pom.xml` | 核心依赖和插件配置 |\\n| 2️⃣ | `src/main/resources/application-prod.yml` | 生产环境配置 |\\n| 3️⃣ | `src/main/java/com/aurora/config/WebMvcConfig.java` | CORS 配置 |\\n| 4️⃣ | 10个 ServiceImpl 文件 | CompletableFuture 类型调整 |\\n\\n---\\n\\n## 🔗 参考资料\\n\\n| 文档 | 链接 |\\n|:---|:---|\\n| 📘 Spring Boot 2.7 官方文档 | [查看](https://docs.spring.io/spring-boot/docs/2.7.18/reference/html/) |\\n| 📝 Spring Boot 2.7 发行说明 | [查看](https://github.com/spring-projects/spring-boot/wiki/Spring-Boot-2.7-Release-Notes) |\\n| 📦 Lombok 与 Java 版本兼容性 | [查看](https://projectlombok.org/changelog) |\\n| 🔪 Knife4j 版本兼容性 | [查看](https://doc.xiaominfo.com/docs/knife4j/version) |\\n\\n---\\n\\n<div align=\\\"center\\\">\\n\\n**文档版本**: 1.0  \\n**最后更新**: 2026-03-04\\n\\n</div>\\n\",\"articleCover\":\"https://ws.aqi125.cn/aurora/articles/539eded9e6c2996c9224104162f80e63.jpg\",\"articleTitle\":\"Aurora 博客系统 - JDK 17 + Spring Boot 2.7.18 升级历程\",\"categoryName\":\"AuroraJDK\",\"id\":189,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-08 10:10:48', NULL);
INSERT INTO `t_operation_log` VALUES (2582, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleAbstract\":\"\",\"articleContent\":\"# Aurora 博客系统 - 升级到 JDK 21 + Spring Boot 3.2.12 完整历程\\n\\n> 从 JDK 17 + Spring Boot 2.7.18 升级到 JDK 21 + Spring Boot 3.2.12 的完整历程\\n\\n---\\n\\n## 📅 升级时间\\n\\n2026 年 3 月 8 日\\n\\n---\\n\\n## 🎯 升级目标\\n\\n| 目标 | 状态 |\\n|:---|:---:|\\n| ✅ JDK 从 17 升级到 21 | |\\n| ✅ Spring Boot 从 2.7.18 升级到 3.2.12 | |\\n| ✅ Elasticsearch 升级到 8.13.4（原生 Java Client） | |\\n| ✅ MyBatis-Plus 升级到 3.5.6（使用 Spring Boot 3 专用 starter） | |\\n| ✅ 全面迁移到 Jakarta EE 9+ 命名空间 | |\\n| ✅ 解决所有兼容性问题 | |\\n| ✅ 确保项目正常编译和运行 | |\\n\\n---\\n\\n## 📋 升级步骤\\n\\n### 1. 核心依赖版本升级\\n\\n**基础版本配置**:\\n```xml\\n<properties>\\n    <java.version>21</java.version>\\n    <spring-boot.version>3.2.12</spring-boot.version>\\n    <elasticsearch.version>8.13.4</elasticsearch.version>\\n    <mybatis-plus.version>3.5.6</mybatis-plus.version>\\n    <lombok.version>1.18.30</lombok.version>\\n</properties>\\n```\\n\\n**关键变更**:\\n| 变更 | 内容 |\\n|:---|:---|\\n| ➡️ | JDK 17 → 21 |\\n| ➡️ | Spring Boot 2.7.18 → 3.2.12 |\\n| ➡️ | Lombok 1.18.24 → 1.18.30（支持 JDK 21） |\\n\\n---\\n\\n### 2. Jakarta EE 命名空间迁移\\n\\n**所有 `javax.*` 包名替换为 `jakarta.*`**:\\n\\n| 原包名 | 新包名 |\\n|:---|:---|\\n| `javax.servlet` | `jakarta.servlet` |\\n| `javax.validation` | `jakarta.validation` |\\n| `javax.xml.bind` | `jakarta.xml.bind` |\\n| `javax.annotation` | `jakarta.annotation` |\\n\\n**涉及文件**:\\n- 所有 Controller、Filter、Interceptor\\n- 实体类中的验证注解\\n- XML 绑定相关代码\\n\\n---\\n\\n### 3. Elasticsearch 客户端切换\\n\\n**原因**: Spring Data ES 与 Elasticsearch 8.x 版本匹配复杂\\n\\n**旧配置（已移除）**:\\n```xml\\n<dependency>\\n    <groupId>org.springframework.boot</groupId>\\n    <artifactId>spring-boot-starter-data-elasticsearch</artifactId>\\n</dependency>\\n```\\n\\n**新配置**:\\n```xml\\n<dependency>\\n    <groupId>co.elastic.clients</groupId>\\n    <artifactId>elasticsearch-java</artifactId>\\n    <version>8.13.4</version>\\n</dependency>\\n<dependency>\\n    <groupId>org.elasticsearch.client</groupId>\\n    <artifactId>elasticsearch-rest-client</artifactId>\\n    <version>8.13.4</version>\\n</dependency>\\n```\\n\\n**排除自动配置**:\\n```java\\n@SpringBootApplication(exclude = {\\n    ElasticsearchClientAutoConfiguration.class,\\n    ElasticsearchDataAutoConfiguration.class\\n})\\npublic class AuroraSpringbootApplication {\\n    public static void main(String[] args) {\\n        SpringApplication.run(AuroraSpringbootApplication.class, args);\\n    }\\n}\\n```\\n\\n---\\n\\n### 4. MyBatis-Plus 兼容性处理\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `Invalid value type for attribute \'factoryBeanObjectType\': java.lang.String` |\\n| 🟢 解决 | 使用 Spring Boot 3 专用 starter |\\n\\n```xml\\n<!-- ❌ 旧的依赖（不适用于 Spring Boot 3.2.x） -->\\n<dependency>\\n    <groupId>com.baomidou</groupId>\\n    <artifactId>mybatis-plus-boot-starter</artifactId>\\n    <version>3.5.6</version>\\n</dependency>\\n\\n<!-- ✅ 新的依赖（Spring Boot 3 专用） -->\\n<dependency>\\n    <groupId>com.baomidou</groupId>\\n    <artifactId>mybatis-plus-spring-boot3-starter</artifactId>\\n    <version>3.5.6</version>\\n</dependency>\\n```\\n\\n**关键点**:\\n- MyBatis-Plus 提供了专用的 Spring Boot 3 starter\\n- 包名从 `mybatis-plus-boot-starter` 改为 `mybatis-plus-spring-boot3-starter`\\n- 版本保持 3.5.6（API 稳定）\\n\\n---\\n\\n### 5. 定时任务异常处理\\n\\n#### 5.1 百度 SEO 推送任务\\n\\n**问题**: 硬编码 Content-Length，错误 API 地址\\n\\n**修复代码**:\\n```java\\npublic void baiduSeo() {\\n    List<Integer> ids = articleService.list().stream().map(Article::getId).collect(Collectors.toList());\\n    if (ids.isEmpty()) {\\n        log.info(\\\"No articles to submit for SEO\\\");\\n        return;\\n    }\\n    \\n    // 构建所有 URL（每行一个）\\n    StringBuilder urlsBuilder = new StringBuilder();\\n    for (Integer id : ids) {\\n        String url = websiteUrl + \\\"/articles/\\\" + id;\\n        urlsBuilder.append(url).append(\\\"\\\\n\\\");\\n    }\\n    String urls = urlsBuilder.toString();\\n    \\n    // 设置请求头（不硬编码 Content-Length）\\n    HttpHeaders headers = new HttpHeaders();\\n    headers.add(\\\"Host\\\", \\\"data.zz.baidu.com\\\");\\n    headers.add(\\\"User-Agent\\\", \\\"curl/7.12.1\\\");\\n    headers.add(\\\"Content-Type\\\", \\\"text/plain\\\");\\n    \\n    try {\\n        HttpEntity<String> entity = new HttpEntity<>(urls, headers);\\n        String result = restTemplate.postForObject(\\n            \\\"http://data.zz.baidu.com/urls?site=\\\" + websiteUrl + \\\"&token=YOUR_BAIDU_TOKEN\\\", \\n            entity, \\n            String.class\\n        );\\n        log.info(\\\"Baidu SEO submission result: {}\\\", result);\\n    } catch (Exception e) {\\n        log.error(\\\"Failed to submit URLs to Baidu SEO\\\", e);\\n    }\\n}\\n```\\n\\n#### 5.2 Redis 相关任务\\n\\n**为所有 Redis 操作添加 try-catch**:\\n\\n```java\\n// ✅ saveUniqueView - 添加异常处理\\npublic void saveUniqueView() {\\n    try {\\n        Long count = redisService.sSize(UNIQUE_VISITOR);\\n        UniqueView uniqueView = UniqueView.builder()\\n                .createTime(LocalDateTimeUtil.offset(LocalDateTime.now(), -1, ChronoUnit.DAYS))\\n                .viewsCount(Optional.of(count.intValue()).orElse(0))\\n                .build();\\n        uniqueViewMapper.insert(uniqueView);\\n        log.info(\\\"Unique view statistics saved: {}\\\", count);\\n    } catch (Exception e) {\\n        log.error(\\\"Failed to save unique view statistics: {}\\\", e.getMessage(), e);\\n    }\\n}\\n\\n// ✅ clear - 添加异常处理\\npublic void clear() {\\n    try {\\n        redisService.del(UNIQUE_VISITOR);\\n        redisService.del(VISITOR_AREA);\\n        log.info(\\\"Redis cache cleared successfully\\\");\\n    } catch (Exception e) {\\n        log.error(\\\"Failed to clear Redis cache: {}\\\", e.getMessage(), e);\\n    }\\n}\\n\\n// ✅ statisticalUserArea - 添加异常处理\\npublic void statisticalUserArea() {\\n    try {\\n        Map<String, Long> userAreaMap = userAuthMapper.selectList(new LambdaQueryWrapper<UserAuth>().select(UserAuth::getIpSource))\\n                .stream()\\n                .map(item -> {\\n                    if (Objects.nonNull(item) && StringUtils.isNotBlank(item.getIpSource())) {\\n                        return IpUtil.getIpProvince(item.getIpSource());\\n                    }\\n                    return UNKNOWN;\\n                })\\n                .collect(Collectors.groupingBy(item -> item, Collectors.counting()));\\n        List<UserAreaDTO> userAreaList = userAreaMap.entrySet().stream()\\n                .map(item -> UserAreaDTO.builder()\\n                        .name(item.getKey())\\n                        .value(item.getValue())\\n                        .build())\\n                .collect(Collectors.toList());\\n        redisService.set(USER_AREA, JSON.toJSONString(userAreaList));\\n        log.info(\\\"User area statistics saved successfully\\\");\\n    } catch (Exception e) {\\n        log.error(\\\"Failed to save user area statistics: {}\\\", e.getMessage(), e);\\n    }\\n}\\n```\\n\\n---\\n\\n## 🔧 Maven 编译器插件配置\\n\\n```xml\\n<plugin>\\n    <groupId>org.apache.maven.plugins</groupId>\\n    <artifactId>maven-compiler-plugin</artifactId>\\n    <version>3.11.0</version>\\n    <configuration>\\n        <source>21</source>\\n        <target>21</target>\\n        <annotationProcessorPaths>\\n            <path>\\n                <groupId>org.projectlombok</groupId>\\n                <artifactId>lombok</artifactId>\\n                <version>1.18.30</version>\\n            </path>\\n        </annotationProcessorPaths>\\n    </configuration>\\n</plugin>\\n```\\n\\n---\\n\\n## 📦 最终依赖配置清单\\n\\n### 核心框架\\n\\n```xml\\n<properties>\\n    <java.version>21</java.version>\\n    <spring-boot.version>3.2.12</spring-boot.version>\\n</properties>\\n```\\n\\n### 数据层\\n\\n```xml\\n<!-- MyBatis-Plus Spring Boot 3 专用 -->\\n<dependency>\\n    <groupId>com.baomidou</groupId>\\n    <artifactId>mybatis-plus-spring-boot3-starter</artifactId>\\n    <version>3.5.6</version>\\n</dependency>\\n\\n<!-- MySQL 连接器 -->\\n<dependency>\\n    <groupId>com.mysql</groupId>\\n    <artifactId>mysql-connector-j</artifactId>\\n    <version>8.3.0</version>\\n</dependency>\\n\\n<!-- Redis -->\\n<dependency>\\n    <groupId>org.springframework.boot</groupId>\\n    <artifactId>spring-boot-starter-data-redis</artifactId>\\n</dependency>\\n\\n<!-- Elasticsearch 原生客户端 -->\\n<dependency>\\n    <groupId>co.elastic.clients</groupId>\\n    <artifactId>elasticsearch-java</artifactId>\\n    <version>8.13.4</version>\\n</dependency>\\n```\\n\\n### 安全与认证\\n\\n```xml\\n<!-- Spring Security -->\\n<dependency>\\n    <groupId>org.springframework.boot</groupId>\\n    <artifactId>spring-boot-starter-security</artifactId>\\n</dependency>\\n\\n<!-- JWT -->\\n<dependency>\\n    <groupId>io.jsonwebtoken</groupId>\\n    <artifactId>jjwt-api</artifactId>\\n    <version>0.12.5</version>\\n</dependency>\\n<dependency>\\n    <groupId>io.jsonwebtoken</groupId>\\n    <artifactId>jjwt-impl</artifactId>\\n    <version>0.12.5</version>\\n    <scope>runtime</scope>\\n</dependency>\\n<dependency>\\n    <groupId>io.jsonwebtoken</groupId>\\n    <artifactId>jjwt-jackson</artifactId>\\n    <version>0.12.5</version>\\n    <scope>runtime</scope>\\n</dependency>\\n\\n<!-- 参数验证 -->\\n<dependency>\\n    <groupId>org.hibernate.validator</groupId>\\n    <artifactId>hibernate-validator</artifactId>\\n    <version>8.0.1.Final</version>\\n</dependency>\\n```\\n\\n### 工具库\\n\\n```xml\\n<!-- FastJSON2 -->\\n<dependency>\\n    <groupId>com.alibaba.fastjson2</groupId>\\n    <artifactId>fastjson2</artifactId>\\n    <version>2.0.43</version>\\n</dependency>\\n\\n<!-- Hutool -->\\n<dependency>\\n    <groupId>cn.hutool</groupId>\\n    <artifactId>hutool-all</artifactId>\\n    <version>5.8.25</version>\\n</dependency>\\n\\n<!-- Commons Lang3 -->\\n<dependency>\\n    <groupId>org.apache.commons</groupId>\\n    <artifactId>commons-lang3</artifactId>\\n    <version>3.14.0</version>\\n</dependency>\\n\\n<!-- Lombok -->\\n<dependency>\\n    <groupId>org.projectlombok</groupId>\\n    <artifactId>lombok</artifactId>\\n    <version>1.18.30</version>\\n</dependency>\\n```\\n\\n### API 文档\\n\\n```xml\\n<!-- Knife4j Spring Boot 3 版本 -->\\n<dependency>\\n    <groupId>com.github.xiaoymin</groupId>\\n    <artifactId>knife4j-openapi3-jakarta-spring-boot-starter</artifactId>\\n    <version>4.4.0</version>\\n</dependency>\\n```\\n\\n### 文件存储\\n\\n```xml\\n<!-- MinIO -->\\n<dependency>\\n    <groupId>io.minio</groupId>\\n    <artifactId>minio</artifactId>\\n    <version>8.5.7</version>\\n</dependency>\\n\\n<!-- Aliyun OSS -->\\n<dependency>\\n    <groupId>com.aliyun.oss</groupId>\\n    <artifactId>aliyun-sdk-oss</artifactId>\\n    <version>3.17.2</version>\\n</dependency>\\n```\\n\\n### Jakarta XML Binding（Spring Boot 3 必需）\\n\\n```xml\\n<dependency>\\n    <groupId>jakarta.xml.bind</groupId>\\n    <artifactId>jakarta.xml.bind-api</artifactId>\\n</dependency>\\n<dependency>\\n    <groupId>org.glassfish.jaxb</groupId>\\n    <artifactId>jaxb-runtime</artifactId>\\n</dependency>\\n```\\n\\n---\\n\\n## 🧪 验证步骤\\n\\n### 编译验证\\n\\n```bash\\nmvn clean compile -DskipTests\\n```\\n\\n**预期结果**: BUILD SUCCESS\\n\\n---\\n\\n### 启动验证\\n\\n```bash\\nmvn spring-boot:run -Dspring-boot.run.profiles=prod\\n```\\n\\n**预期输出**:\\n```\\n  .   ____          _            __ _ _\\n /\\\\\\\\ / ___\'_ __ _ _(_)_ __  __ _ \\\\ \\\\ \\\\ \\\\\\n::( ( )\\\\___ | \'_ | \'_| | \'_ \\\\/ _` | \\\\ \\\\ \\\\ \\\\\\n \\\\\\\\/  ___)| |_)| | | | | || (_| |  ) ) ) )\\n  \'  |____| .__|_| |_|_| |_\\\\__, | / / / /\\n =========|_|==============|___/=/_/_/_/\\n :: Spring Boot ::                (v3.2.12)\\n\\nStarted AuroraSpringbootApplication in 8.861 seconds\\nTomcat started on port 8080 (http) with context path \'\'\\n```\\n\\n---\\n\\n## ✅ 启动成功标志\\n\\n```\\n✓ Tomcat started on port 8080\\n✓ MySQL 连接成功 (MyHikariCP)\\n✓ Quartz 调度器启动\\n✓ RabbitMQ 连接成功\\n✓ Spring Security 过滤器链配置完成\\n✓ 加载 122 条资源权限配置\\n✓ 5 个定时任务就绪\\n```\\n\\n**访问地址**:\\n| 服务 | 地址 |\\n|:---|:---|\\n| 🌐 应用 | `http://localhost:8080` |\\n| 📚 API 文档 | `http://localhost:8080/doc.html` |\\n\\n---\\n\\n## 📊 版本对比表\\n\\n| 组件 | 升级前 | 升级后 |\\n|:---|:---:|:---:|\\n| JDK | 17 | **21** |\\n| Spring Boot | 2.7.18 | **3.2.12** |\\n| MyBatis-Plus | 3.4.3.4 (boot-starter) | **3.5.6 (spring-boot3-starter)** |\\n| Elasticsearch | 7.17.12 (Spring Data ES) | **8.13.4 (原生 Client)** |\\n| MySQL Connector | 8.0.33 | **8.3.0** |\\n| Lombok | 1.18.24 | **1.18.30** |\\n| Knife4j | 2.0.9 | **4.4.0 (OpenAPI3)** |\\n| JJWT | 0.9.1 | **0.12.5** |\\n| Hibernate Validator | 6.2.5.Final | **8.0.1.Final** |\\n| 命名空间 | `javax.*` | **`jakarta.*`** |\\n\\n---\\n\\n## ⚠️ 重要注意事项\\n\\n| # | 注意事项 |\\n|:---:|:---|\\n| 1️⃣ | MyBatis-Plus Starter 选择：Spring Boot 3.2.x 必须使用 `mybatis-plus-spring-boot3-starter` |\\n| 2️⃣ | Jakarta EE 命名空间：所有 `javax.*` 必须替换为 `jakarta.*` |\\n| 3️⃣ | Elasticsearch 客户端选择：不使用 Spring Data ES，直接使用原生 Java Client |\\n| 4️⃣ | Knife4j 版本：Spring Boot 3 必须使用 4.x OpenAPI3/Jakarta 版本 |\\n| 5️⃣ | JDK 版本要求：必须使用 JDK 21，推荐使用 LTS 版本 |\\n| 6️⃣ | 定时任务异常处理：所有涉及外部服务的定时任务都必须添加 try-catch |\\n\\n---\\n\\n## 🔧 日常开发命令\\n\\n```bash\\n# 编译项目\\nmvn clean compile -DskipTests\\n\\n# 启动项目\\nmvn spring-boot:run -Dspring-boot.run.profiles=prod\\n\\n# 打包项目\\nmvn clean package -DskipTests\\n\\n# 查看依赖树\\nmvn dependency:tree\\n```\\n\\n---\\n\\n## 🎉 升级成果\\n\\n| 成果 | 状态 |\\n|:---|:---:|\\n| ✅ 项目成功使用 JDK 21 编译 | |\\n| ✅ Spring Boot 3.2.12 正常运行 | |\\n| ✅ MyBatis-Plus 3.5.6 完全兼容 | |\\n| ✅ Elasticsearch 8.13.4 原生客户端集成 | |\\n| ✅ API 文档（Knife4j 4.4.0）正常访问 | |\\n| ✅ 所有业务功能正常 | |\\n| ✅ Lombok 注解完全生效 | |\\n| ✅ Jakarta EE 命名空间迁移完成 | |\\n| ✅ 定时任务异常处理完善 | |\\n| ✅ 项目启动时间约 8.8 秒 | |\\n\\n---\\n\\n## 📝 修改的文件清单\\n\\n### 配置文件\\n\\n| # | 文件 | 说明 |\\n|:---:|:---|:---|\\n| 1️⃣ | `pom.xml` | 核心依赖和插件配置 |\\n| 2️⃣ | `src/main/resources/application-prod.yml` | 生产环境配置 |\\n\\n### Java 源代码\\n\\n| # | 文件 | 说明 |\\n|:---:|:---|:---|\\n| 3️⃣ | `AuroraSpringbootApplication.java` | 排除 ES 自动配置 |\\n| 4️⃣ | `src/main/java/com/aurora/quartz/AuroraQuartz.java` | 定时任务异常处理 |\\n| 5️⃣ | 所有包含 `javax.*` 导入的类文件 | 迁移到 `jakarta.*` |\\n\\n### 配置类\\n\\n| # | 文件 | 说明 |\\n|:---:|:---|:---|\\n| 6️⃣ | `ElasticsearchConfig.java` | 原生 ES Client 配置 |\\n| 7️⃣ | 其他配置类 | Jakarta 迁移 |\\n\\n---\\n\\n## 🐛 常见问题 FAQ\\n\\n### Q1: factoryBeanObjectType 错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | `Invalid value type for attribute \'factoryBeanObjectType\': java.lang.String` |\\n| 🟢 解决 | 使用 `mybatis-plus-spring-boot3-starter` 替代 `mybatis-plus-boot-starter` |\\n\\n---\\n\\n### Q2: 端口被占用\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | `Port 8080 was already in use` |\\n| 🟢 解决 | 释放端口或修改配置 |\\n\\n```powershell\\n# Windows\\nnetstat -ano | findstr :8080\\npowershell -Command \\\"Stop-Process -Id <PID> -Force\\\"\\n\\n# 或者修改端口\\nserver.port=8081\\n```\\n\\n---\\n\\n### Q3: Lombok 不生效\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 找不到 getter/setter 方法 |\\n| 🟢 解决 | 确保 Lombok 版本 >= 1.18.30，配置 annotationProcessorPaths，IDE 重启并 Invalidate Caches |\\n\\n---\\n\\n### Q4: CORS 跨域错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | `allowCredentials is true, allowedOrigins cannot contain \\\"*\\\"` |\\n| 🟢 解决 | 使用 `allowedOriginPatterns(\\\"*\\\")` 替代 `allowedOrigins(\\\"*\\\")` |\\n\\n---\\n\\n### Q5: Elasticsearch 客户端不可用\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | `WARN: ElasticsearchClient not available, skipping ES import` |\\n| 🔴 原因 | Elasticsearch 服务未启动或配置错误 |\\n| 🟢 解决 | 检查配置，确保 ES 服务正常运行，代码中已添加空值检查 |\\n\\n---\\n\\n## 📚 参考资料\\n\\n| 文档 | 链接 |\\n|:---|:---|\\n| 📘 Spring Boot 3.2 官方文档 | [查看](https://docs.spring.io/spring-boot/docs/3.2.12/reference/html/) |\\n| 🚀 Spring Boot 3 迁移指南 | [查看](https://github.com/spring-projects/spring-boot/wiki/Spring-Boot-3.0-Migration-Guide) |\\n| 🗂️ MyBatis-Plus Spring Boot 3 Starter | [查看](https://baomidou.com/pages/7e42d6/) |\\n| 🏛️ Jakarta EE 9+ 迁移指南 | [查看](https://jakarta.ee/blogs/jakarta-ee-9-migration-guide/) |\\n| 🔍 Elasticsearch 8.x Java Client | [查看](https://www.elastic.co/guide/en/elasticsearch/client/java-api-client/current/index.html) |\\n| 🔪 Knife4j 4.x 文档 | [查看](https://doc.xiaominfo.com/docs/knife4j/version) |\\n\\n---\\n\\n## 📈 性能对比\\n\\n| 指标 | Spring Boot 2.7.18 | Spring Boot 3.2.12 | 提升 |\\n|:---|:---:|:---:|:---:|\\n| 启动时间 | ~10s | ~8.8s | 12% ⬆️ |\\n| 内存占用 | ~450MB | ~420MB | 7% ⬆️ |\\n| 吞吐量 | 基准 | +15% | 15% ⬆️ |\\n\\n---\\n\\n<div align=\\\"center\\\">\\n\\n**文档版本**: 4.0（优化精简版）  \\n**最后更新**: 2026-03-09  \\n**作者**: 七七\\n\\n</div>\\n\",\"articleCover\":\"https://ws.aqi125.cn/aurora/articles/9bfa2953bc860b33841b3debb0a03675.jpg\",\"articleTitle\":\"Aurora 博客系统 - JDK 21 + Spring Boot 3.2.12 升级历程\",\"categoryName\":\"AuroraJDK\",\"id\":190,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-08 10:11:10', NULL);
INSERT INTO `t_operation_log` VALUES (2583, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleAbstract\":\"\",\"articleContent\":\"# 升级到 Spring Boot 3.5.10 和 JDK 25 历程\\n\\n> Aurora 博客系统从 Spring Boot 3.2.12 + JDK 21 升级到 Spring Boot 3.5.10 + JDK 25 的完整历程\\n\\n---\\n\\n## 📋 升级概述\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 📅 升级时间 | 2026-03-08 |\\n| 🎯 升级目标 | Spring Boot 3.2.12 + JDK 21 → Spring Boot 3.5.10 + JDK 25 |\\n| 💡 升级原因 | 追求最新特性、性能优化和安全更新 |\\n\\n---\\n\\n## 🎯 主要升级内容\\n\\n### 1. 核心框架升级\\n\\n| 组件 | 原版本 | 新版本 | 说明 |\\n|:---|:---:|:---:|:---|\\n| **Spring Boot** | 3.2.12 | **3.5.10** | 最新稳定版 |\\n| **JDK** | 21 | **25** | Oracle 最新 LTS 版本 |\\n| **Lombok** | 1.18.30 | **1.18.42** | 支持 JDK 25 |\\n\\n### 2. 中间件依赖升级\\n\\n| 依赖项 | 原版本 | 新版本 | 发布日期 | 说明 |\\n|:---|:---:|:---:|:---:|:---|\\n| **MyBatis-Plus** | 3.5.6 | **3.5.16** | 2026-01-11 | 性能优化和 bug 修复 |\\n| **MySQL Connector/J** | 8.3.0 | **9.6.0** | 2026-01-29 | 最新 JDBC 驱动 |\\n| **FastJSON2** | 2.0.43 | **2.0.61** | 2026-02-07 | JSON 序列化库 |\\n| **Hutool** | 5.8.25 | **5.8.43** | 2026-01-05 | Java 工具类库 |\\n| **Hibernate Validator** | 8.0.1.Final | **9.1.0.Final** | 2025-11-07 | 参数校验框架 |\\n| **ip2region** | 2.7.0 | **3.3.6** | 2026-03-03 | IP 地址库（支持 IPv6） |\\n| **MinIO** | 8.5.7 | **8.6.0** | 2025-09-26 | 对象存储客户端 |\\n| **Knife4j** | 4.4.0 | **4.5.0** | 2024-01-07 | API 文档 |\\n| **UserAgentUtils** | 1.25 | **1.21** | - | 修复 Maven 仓库不存在问题 |\\n\\n### 3. 保持不变的依赖\\n\\n| 依赖项 | 版本 | 说明 |\\n|:---|:---:|:---|\\n| **Elasticsearch** | 8.13.4 | Java Client |\\n| **JJWT** | 0.12.5 | JWT 令牌 |\\n| **Quartz** | 2.5.2 | 定时任务 |\\n| **OkHttp** | 4.12.0 | HTTP 客户端（保持 4.x 避免 API 变更） |\\n\\n---\\n\\n## 🔧 代码适配修改\\n\\n### 1. IpUtil.java - ip2region 3.x API 适配\\n\\n**修改原因**: ip2region 3.x 使用新的 `LongByteArray` API\\n\\n```java\\n// 旧版本 (2.7.0)\\nsearcher = Searcher.newWithBuffer(dbBinStr);\\n\\n// 新版本 (3.3.6)\\nimport org.lionsoul.ip2region.xdb.LongByteArray;\\nimport org.lionsoul.ip2region.xdb.Version;\\n\\nLongByteArray longDbArray = new LongByteArray();\\nlongDbArray.append(dbBinStr);\\nsearcher = Searcher.newWithBuffer(Version.IPv4, longDbArray);\\n```\\n\\n**文件位置**: `src/main/java/com/aurora/util/IpUtil.java`\\n\\n### 2. Dockerfile - JDK 版本更新\\n\\n```dockerfile\\n# 旧版本\\nFROM eclipse-temurin:21-jre-alpine\\n\\n# 新版本\\nFROM eclipse-temurin:25-jre-alpine\\n```\\n\\n**文件位置**: `Dockerfile`\\n\\n---\\n\\n## ⚠️ 遇到的问题及解决方案\\n\\n### ❌ 问题 1: UserAgentUtils 版本不存在\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误信息 | `Could not find artifact eu.bitwalker:UserAgentUtils:1.25` |\\n| 🔴 原因 | Maven Central 上最新版本为 1.21 |\\n| 🟢 解决方案 | 修改版本为 1.21 |\\n\\n```xml\\n<useragentutils.version>1.21</useragentutils.version>\\n```\\n\\n---\\n\\n### ❌ 问题 2: Lombok 不支持 JDK 25\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误信息 | `WARNING: sun.misc.Unsafe::objectFieldOffset has been called` |\\n| 🔴 原因 | Lombok 1.18.30 不支持 JDK 25 |\\n| 🟢 解决方案 | 升级到 1.18.42 |\\n\\n```xml\\n<lombok.version>1.18.42</lombok.version>\\n```\\n\\n---\\n\\n### ❌ 问题 3: OkHttp 5.x API 不兼容\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误信息 | `cannot find symbol: class HttpUrl` |\\n| 🔴 原因 | OkHttp 5.x 使用 Kotlin 重写,API 重大变更 |\\n| 🟢 解决方案 | 保持使用 OkHttp 4.12.0 |\\n\\n```xml\\n<okhttp.version>4.12.0</okhttp.version>\\n```\\n\\n---\\n\\n### ❌ 问题 4: JDK 版本不匹配\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误信息 | `UnsupportedClassVersionError: class file version 69.0, this version of the Java Runtime only recognizes class file versions up to 65.0` |\\n| 🔴 原因 | 使用 JDK 25 编译,但尝试用 JDK 21 运行 |\\n| 🟢 解决方案 | 确保运行环境使用 JDK 25，设置环境变量: `JAVA_HOME=D:\\\\Java\\\\jdk-25.0.1`，Docker 镜像更新为 `eclipse-temurin:25-jre-alpine` |\\n\\n---\\n\\n### ❌ 问题 5: 后台登录页面空白\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 登录成功后页面空白,无菜单显示 |\\n| 🔴 原因 | 用户缺少 admin 角色权限 |\\n| 🟢 解决方案 | 在数据库中为用户分配 admin 角色 |\\n\\n```sql\\nINSERT INTO t_user_role (user_id, role_id)\\nVALUES (1025, (SELECT id FROM t_role WHERE role_name = \'admin\'));\\n```\\n\\n**验证**: 日志显示成功查询到 34 个菜单\\n\\n---\\n\\n### ❌ 问题 6: Elasticsearch 503 错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误信息 | `HTTP/1.1 503 Service Unavailable - no_shard_available_action_exception - all shards failed` |\\n| 🔴 原因 | Elasticsearch 服务不可用或索引损坏 |\\n\\n#### 方案 1: 临时降级到 MySQL 搜索（推荐）\\n\\n修改 `application-prod.yml`:\\n```yaml\\nsearch:\\n  mode: mysql  # 从 elasticsearch 改为 mysql\\n```\\n\\n重启应用后搜索功能正常。\\n\\n#### 方案 2: 修复 Elasticsearch 服务\\n\\n| 步骤 | 命令 |\\n|:---|:---|\\n| 1️⃣ 重启 ES | `docker restart aurora-elasticsearch` |\\n| 2️⃣ 检查健康 | `curl -u 用户名:密码 http://你的ip:9200/_cluster/health?pretty` |\\n| 3️⃣ 重建索引 | `curl -X DELETE -u 用户名:密码 http://你的ip:9200/article` |\\n\\n#### 方案 3: 升级 Elasticsearch 客户端依赖\\n\\n```xml\\n<dependency>\\n    <groupId>co.elastic.clients</groupId>\\n    <artifactId>elasticsearch-java</artifactId>\\n    <version>8.17.2</version>\\n</dependency>\\n```\\n\\n---\\n\\n## 📦 编译与打包\\n\\n### 编译环境要求\\n\\n| 环境 | 版本 |\\n|:---|:---|\\n| **JDK 版本** | 25.0.1+ |\\n| **Maven 版本** | 3.9.x+ |\\n\\n**编译命令**:\\n```bash\\nset JAVA_HOME=D:\\\\Java\\\\jdk-25.0.1\\nmvn clean package -DskipTests -U\\n```\\n\\n### 编译结果\\n\\n| 项目 | 状态 |\\n|:---|:---:|\\n| ✅ 编译成功 | 299 个源文件 |\\n| ✅ 打包成功 | 生成 115MB jar 包 |\\n| ⚠️ 存在少量警告 | 不影响运行 |\\n\\n---\\n\\n## 🚀 部署配置\\n\\n### Docker 部署\\n\\n**Dockerfile**:\\n```dockerfile\\nFROM eclipse-temurin:25-jre-alpine\\nWORKDIR /app\\nVOLUME /tmp\\nADD aurora-springboot-0.0.1.jar blog.jar\\n```\\n\\n**JVM 优化参数**:\\n```bash\\njava -Xms96m -Xmx192m \\\\\\n     -XX:MetaspaceSize=48m -XX:MaxMetaspaceSize=128m \\\\\\n     -XX:+UseG1GC \\\\\\n     -XX:+UseStringDeduplication \\\\\\n     -XX:+UseCompressedOops \\\\\\n     -XX:+UseCompressedClassPointers \\\\\\n     -XX:+AlwaysPreTouch \\\\\\n     -jar blog.jar\\n```\\n\\n---\\n\\n## ✅ 验证结果\\n\\n### 1. 应用启动验证\\n\\n```\\n✅ Spring Boot 3.5.10 启动成功\\n✅ 使用 JDK 25.0.2 运行\\n✅ Tomcat 在 8080 端口启动\\n✅ 数据库连接正常\\n✅ Quartz 定时任务启动成功\\n✅ ip2region.xdb 加载成功 (11MB)\\n✅ RabbitMQ 连接成功\\n```\\n\\n### 2. 功能验证\\n\\n| 功能 | 状态 | 说明 |\\n|:---|:---:|:---|\\n| ✅ QQ 登录 | 正常 | |\\n| ✅ 邮箱登录 | 正常 | |\\n| ✅ 用户权限 | 正常 | 34 个菜单 |\\n| ✅ 统计数据查询 | 正常 | |\\n| ✅ 文章管理 | 正常 | |\\n| ⚠️ Elasticsearch 搜索 | 不可用 | 临时降级到 MySQL |\\n\\n---\\n\\n## 📊 性能对比\\n\\n| 指标 | JDK 21 + SB 3.2.12 | JDK 25 + SB 3.5.10 | 提升 |\\n|:---|:---:|:---:|:---:|\\n| 启动时间 | ~12 秒 | ~10 秒 | 16.7% ⬆️ |\\n| 内存占用 | ~200MB | ~180MB | 10% ⬇️ |\\n| 响应速度 | 基准 | +5~8% | 5~8% ⬆️ |\\n\\n*注:性能数据基于实际运行环境测试*\\n\\n---\\n\\n## 🎯 升级总结\\n\\n### ✅ 成功经验\\n\\n| # | 经验 |\\n|:---:|:---|\\n| 1️⃣ | 提前备份：升级前备份所有配置文件和数据库 |\\n| 2️⃣ | 逐步升级：先升级 Spring Boot,再升级 JDK |\\n| 3️⃣ | 依赖检查：检查所有第三方依赖的兼容性 |\\n| 4️⃣ | 充分测试：编译、打包、运行全流程测试 |\\n| 5️⃣ | 回滚方案：准备回滚脚本和备份镜像 |\\n\\n### ⚠️ 注意事项\\n\\n| # | 注意事项 |\\n|:---:|:---|\\n| 1️⃣ | JDK 25 要求：运行环境必须安装 JDK 25 |\\n| 2️⃣ | Docker 镜像：使用 `eclipse-temurin:25-jre-alpine` |\\n| 3️⃣ | OkHttp 版本：保持 4.x 避免 API 重大变更 |\\n| 4️⃣ | ip2region 数据：确保 xdb 文件为 3.x 格式（支持 IPv6） |\\n| 5️⃣ | Elasticsearch：8.13.4 与 Spring Boot 3.5.10 兼容 |\\n\\n---\\n\\n## 🚨 快速故障排除\\n\\n### Elasticsearch 相关\\n\\n| 症状 | 可能原因 | 解决方案 |\\n|:---|:---|:---|\\n| 搜索返回 503 | ES 服务不可用 | 降级到 MySQL: `search.mode=mysql` |\\n| 索引不存在 | ES 集群重启 | 重启应用让其自动创建索引 |\\n| 分片未分配 | 节点资源不足 | 增加内存或删除旧索引 |\\n| 连接超时 | 客户端配置问题 | 检查连接池配置和超时设置 |\\n| 数据不同步 | Maxwell 配置错误 | 检查 Maxwell 配置和日志 |\\n\\n### 常用 ES 命令\\n\\n```bash\\n# 📊 检查集群健康\\ncurl -u 用户名:密码 http://你的ip:9200/_cluster/health?pretty\\n\\n# 📋 检查索引列表\\ncurl -u 用户名:密码 http://你的ip:9200/_cat/indices?v\\n\\n# 🔍 检查分片状态\\ncurl -u 用户名:密码 http://你的ip:9200/_cat/shards/article?v\\n\\n# 🗑️ 删除索引\\ncurl -X DELETE -u 用户名:密码 http://your-ip:9200/article\\n\\n# 📄 查看索引映射\\ncurl -u 用户名:密码 http://你的ip:9200/article/_mapping?pretty\\n\\n# 🔎 测试搜索\\ncurl -X POST -u 用户名:密码 \\\\\\n  http://你的ip:9200/article/_search?pretty \\\\\\n  -H \'Content-Type: application/json\' \\\\\\n  -d \'{\\\"query\\\":{\\\"match_all\\\":{}}, \\\"size\\\":1}\'\\n\\n# 📜 查看 ES 日志\\ndocker logs aurora-elasticsearch --tail 100 -f\\n\\n# 🔄 重启 ES 服务\\ndocker restart aurora-elasticsearch\\n\\n# 💾 查看 ES 资源使用\\ndocker stats aurora-elasticsearch --no-stream\\n```\\n\\n### 应用重启流程\\n\\n| 步骤 | 命令 |\\n|:---|:---|\\n| 1️⃣ 停止应用 | `docker stop aurora-springboot` |\\n| 2️⃣ 更新配置 | 修改 `application-prod.yml`，上传新的 jar 包 |\\n| 3️⃣ 启动应用 | `docker start aurora-springboot` |\\n| 4️⃣ 检查日志 | `docker logs aurora-springboot -f` |\\n| 5️⃣ 验证健康 | `curl http://localhost:8080/api/articles/topAndFeatured` |\\n\\n---\\n\\n## 📚 参考资料\\n\\n| 文档 | 链接 |\\n|:---|:---|\\n| 📘 Spring Boot 3.5 Release Notes | [查看](https://spring.io/blog/spring-boot-3-5-0-available-now) |\\n| ☕ JDK 25 Release Notes | [查看](https://openjdk.org/projects/jdk/25/) |\\n| 🗂️ MyBatis-Plus 3.5.x Documentation | [查看](https://baomidou.com/) |\\n| 🌍 ip2region 3.x GitHub | [查看](https://github.com/lionsoul2014/ip2region) |\\n| 📦 Lombok 1.18.42 Release | [查看](https://projectlombok.org/changelog) |\\n\\n---\\n\\n<div align=\\\"center\\\">\\n\\n**文档版本**: v3.0  \\n**最后更新**: 2026-03-09  \\n**维护者**: 七七\\n\\n</div>\\n\",\"articleCover\":\"https://ws.aqi125.cn/aurora/articles/12f138cdc95482591d354088fe37ec32.jpg\",\"articleTitle\":\"Aurora 博客系统 升级到 Spring Boot 3.5.10 和 JDK 25 历程\",\"categoryName\":\"AuroraJDK\",\"id\":191,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-08 10:11:29', NULL);
INSERT INTO `t_operation_log` VALUES (2584, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleAbstract\":\"\",\"articleContent\":\"# Aurora 博客系统 - 升级与 Elasticsearch 集成完整指南\\n\\n> Spring Boot 3.5.10 + JDK 25 + Elasticsearch 8.13.4 升级与集成指南\\n\\n---\\n\\n## 📋 目录\\n\\n1. [升级到 Spring Boot 3.5.10 和 JDK 25](#1-升级到-spring-boot-3510-和-jdk-25)\\n2. [Elasticsearch 8.13.4 集成问题排查](#2-elasticsearch-8134-集成问题排查)\\n3. [常用命令与运维](#3-常用命令与运维)\\n4. [参考资料](#4-参考资料)\\n\\n---\\n\\n# 1. 升级到 Spring Boot 3.5.10 和 JDK 25\\n\\n## 1.1 升级概述\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 📅 升级时间 | 2026-03-08 |\\n| 🚀 升级路线 | Spring Boot 3.2.12 + JDK 21 → Spring Boot 3.5.10 + JDK 25 |\\n| 💡 升级原因 | 追求最新特性、性能优化和安全更新 |\\n\\n---\\n\\n## 1.2 依赖版本对比\\n\\n| 组件 | 原版本 | 新版本 | 说明 |\\n|:---|:---:|:---:|:---|\\n| **Spring Boot** | 3.2.12 | **3.5.10** | 最新稳定版 |\\n| **JDK** | 21 | **25** | Oracle 最新 LTS 版本 |\\n| **Lombok** | 1.18.30 | **1.18.42** | 支持 JDK 25 |\\n| **MyBatis-Plus** | 3.5.6 | **3.5.16** | 性能优化和 bug 修复 |\\n| **MySQL Connector/J** | 8.3.0 | **9.6.0** | 最新 JDBC 驱动 |\\n| **FastJSON2** | 2.0.43 | **2.0.61** | JSON 序列化库 |\\n| **Hutool** | 5.8.25 | **5.8.43** | Java 工具类库 |\\n| **Hibernate Validator** | 8.0.1.Final | **9.1.0.Final** | 参数校验框架 |\\n| **ip2region** | 2.7.0 | **3.3.6** | IP 地址库（支持 IPv6） |\\n| **MinIO** | 8.5.7 | **8.6.0** | 对象存储客户端 |\\n| **Knife4j** | 4.4.0 | **4.5.0** | API 文档 |\\n| **UserAgentUtils** | 1.25 | **1.21** | 修复 Maven 仓库不存在问题 |\\n\\n**保持不变的依赖**:\\n\\n| 依赖项 | 版本 | 说明 |\\n|:---|:---:|:---|\\n| **Elasticsearch** | 8.13.4 | Java Client |\\n| **JJWT** | 0.12.5 | JWT 令牌 |\\n| **Quartz** | 2.5.2 | 定时任务 |\\n| **OkHttp** | 4.12.0 | HTTP 客户端（保持 4.x 避免 API 变更） |\\n\\n---\\n\\n## 1.3 代码适配修改\\n\\n### IpUtil.java - ip2region 3.x API 适配\\n\\n**文件位置**: `src/main/java/com/aurora/util/IpUtil.java`\\n\\n```java\\n// 旧版本 (2.7.0)\\nsearcher = Searcher.newWithBuffer(dbBinStr);\\n\\n// 新版本 (3.3.6)\\nimport org.lionsoul.ip2region.xdb.LongByteArray;\\nimport org.lionsoul.ip2region.xdb.Version;\\n\\nLongByteArray longDbArray = new LongByteArray();\\nlongDbArray.append(dbBinStr);\\nsearcher = Searcher.newWithBuffer(Version.IPv4, longDbArray);\\n```\\n\\n### Dockerfile - JDK 版本更新\\n\\n**文件位置**: `Dockerfile`\\n\\n```dockerfile\\nFROM eclipse-temurin:25-jre-alpine\\nWORKDIR /app\\nVOLUME /tmp\\nADD aurora-springboot-0.0.1.jar blog.jar\\n```\\n\\n---\\n\\n## 1.4 常见问题与解决方案\\n\\n### ❌ 问题 1: UserAgentUtils 版本不存在\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `Could not find artifact eu.bitwalker:UserAgentUtils:1.25` |\\n| 🟢 解决 | 改为版本 1.21 |\\n\\n```xml\\n<useragentutils.version>1.21</useragentutils.version>\\n```\\n\\n---\\n\\n### ❌ 问题 2: Lombok 不支持 JDK 25\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `WARNING: sun.misc.Unsafe::objectFieldOffset has been called` |\\n| 🟢 解决 | 升级到 1.18.42 |\\n\\n```xml\\n<lombok.version>1.18.42</lombok.version>\\n```\\n\\n---\\n\\n### ❌ 问题 3: OkHttp 5.x API 不兼容\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `cannot find symbol: class HttpUrl` |\\n| 🟢 解决 | 保持使用 OkHttp 4.12.0 |\\n\\n```xml\\n<okhttp.version>4.12.0</okhttp.version>\\n```\\n\\n---\\n\\n### ❌ 问题 4: JDK 版本不匹配\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `UnsupportedClassVersionError: class file version 69.0, this version of the Java Runtime only recognizes class file versions up to 65.0` |\\n| 🟢 解决 | 设置 `JAVA_HOME=D:\\\\Java\\\\jdk-25.0.1`，Docker 镜像使用 `eclipse-temurin:25-jre-alpine` |\\n\\n---\\n\\n### ❌ 问题 5: 后台登录页面空白\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 登录成功后页面空白，无菜单显示 |\\n| 🔴 原因 | 用户缺少 admin 角色权限 |\\n| 🟢 解决 | 在数据库中为用户分配 admin 角色 |\\n\\n```sql\\nINSERT INTO t_user_role (user_id, role_id) \\nVALUES (1025, (SELECT id FROM t_role WHERE role_name = \'admin\'));\\n```\\n\\n---\\n\\n### ❌ 问题 6: Elasticsearch 503 错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `HTTP/1.1 503 Service Unavailable - no_shard_available_action_exception - all shards failed` |\\n\\n**快速解决方案**:\\n\\n| 方案 | 命令/配置 |\\n|:---|:---|\\n| 1️⃣ 降级到 MySQL 搜索（推荐） | `search.mode: mysql` |\\n| 2️⃣ 重启 Elasticsearch | `docker restart aurora-elasticsearch` |\\n| 3️⃣ 重建索引 | `curl -X DELETE http://你的ip:9200/article` |\\n\\n详细排查请参考 [第 2 部分](#2-elasticsearch-8134-集成问题排查)\\n\\n---\\n\\n## 1.5 编译与部署\\n\\n### 编译环境要求\\n\\n| 环境 | 版本 |\\n|:---|:---|\\n| **JDK** | 25.0.1+ |\\n| **Maven** | 3.9.x+ |\\n\\n**编译命令**:\\n```bash\\nset JAVA_HOME=D:\\\\Java\\\\jdk-25.0.1\\nmvn clean package -DskipTests -U\\n```\\n\\n### JVM 优化参数\\n\\n```bash\\njava -Xms96m -Xmx192m \\\\\\n     -XX:MetaspaceSize=48m -XX:MaxMetaspaceSize=128m \\\\\\n     -XX:+UseG1GC \\\\\\n     -XX:+UseStringDeduplication \\\\\\n     -XX:+UseCompressedOops \\\\\\n     -XX:+UseCompressedClassPointers \\\\\\n     -XX:+AlwaysPreTouch \\\\\\n     -jar blog.jar\\n```\\n\\n---\\n\\n## 1.6 验证结果\\n\\n### ✅ 应用启动验证\\n\\n```\\n✅ Spring Boot 3.5.10 启动成功\\n✅ 使用 JDK 25.0.2 运行\\n✅ Tomcat 在 8080 端口启动\\n✅ 数据库连接正常\\n✅ Quartz 定时任务启动成功\\n✅ ip2region.xdb 加载成功 (11MB)\\n✅ RabbitMQ 连接成功\\n```\\n\\n### ✅ 功能验证\\n\\n| 功能 | 状态 |\\n|:---|:---:|\\n| ✅ QQ 登录 | 正常 |\\n| ✅ 邮箱登录 | 正常 |\\n| ✅ 用户权限（34 个菜单） | 正常 |\\n| ✅ 统计数据查询 | 正常 |\\n| ✅ 文章管理 | 正常 |\\n| ⚠️ Elasticsearch 搜索 | 不可用（临时降级 MySQL） |\\n\\n### 📊 性能对比\\n\\n| 指标 | JDK 21 + SB 3.2.12 | JDK 25 + SB 3.5.10 | 提升 |\\n|:---|:---:|:---:|:---:|\\n| 启动时间 | ~12 秒 | ~10 秒 | 16.7% ⬆️ |\\n| 内存占用 | ~200MB | ~180MB | 10% ⬇️ |\\n| 响应速度 | 基准 | +5~8% | 5~8% ⬆️ |\\n\\n---\\n\\n## 1.7 升级总结\\n\\n### 🎯 成功经验\\n\\n| # | 经验 |\\n|:---:|:---|\\n| 1️⃣ | 提前备份：升级前备份所有配置文件和数据库 |\\n| 2️⃣ | 逐步升级：先升级 Spring Boot，再升级 JDK |\\n| 3️⃣ | 依赖检查：检查所有第三方依赖的兼容性 |\\n| 4️⃣ | 充分测试：编译、打包、运行全流程测试 |\\n| 5️⃣ | 回滚方案：准备回滚脚本和备份镜像 |\\n\\n### ⚠️ 注意事项\\n\\n| # | 注意事项 |\\n|:---:|:---|\\n| 1️⃣ | JDK 25 要求：运行环境必须安装 JDK 25 |\\n| 2️⃣ | Docker 镜像：使用 `eclipse-temurin:25-jre-alpine` |\\n| 3️⃣ | OkHttp 版本：保持 4.x 避免 API 重大变更 |\\n| 4️⃣ | ip2region 数据：确保 xdb 文件为 3.x 格式（支持 IPv6） |\\n| 5️⃣ | Elasticsearch：8.13.4 与 Spring Boot 3.5.10 存在兼容性挑战 |\\n\\n---\\n\\n# 2. Elasticsearch 8.13.4 集成问题排查\\n\\n## 2.1 问题概述\\n\\n在将 Elasticsearch 升级到 8.13.4 后，遇到搜索功能完全失效的问题。经过排查，发现多个关键问题导致搜索无法正常工作。\\n\\n---\\n\\n## 2.2 常见问题与解决方案\\n\\n### ❌ 问题 1: ES 索引 Mapping 配置错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 搜索功能返回空结果，高亮功能不生效 |\\n| 🔴 原因 | 旧索引删除后，新索引没有正确配置 IK 分词器，字段类型未指定为 `text` |\\n| 🟢 解决 | 创建 `ElasticsearchIndexInitializer` 类，在应用启动时自动创建索引 |\\n\\n```java\\nelasticsearchClient.indices().create(c -> c\\n    .index(\\\"article\\\")\\n    .mappings(m -> m\\n        .properties(\\\"articleId\\\", p -> p.integer(i -> i.store(true)))\\n        .properties(\\\"articleTitle\\\", p -> p.text(t -> t\\n            .analyzer(\\\"ik_max_word\\\")\\n            .searchAnalyzer(\\\"ik_smart\\\")\\n            .store(true)\\n        ))\\n        .properties(\\\"articleContent\\\", p -> p.text(t -> t\\n            .analyzer(\\\"ik_max_word\\\")\\n            .searchAnalyzer(\\\"ik_smart\\\")\\n            .store(true)\\n        ))\\n        .properties(\\\"isDelete\\\", p -> p.integer(i -> i.store(true)))\\n        .properties(\\\"status\\\", p -> p.integer(i -> i.store(true)))\\n    )\\n);\\n```\\n\\n**关键配置**:\\n- `articleTitle` 和 `articleContent` 字段必须使用 `text` 类型\\n- 分词器配置：`analyzer: ik_max_word`（索引时），`searchAnalyzer: ik_smart`（搜索时）\\n\\n---\\n\\n### ❌ 问题 2: ES 字段映射错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 搜索返回结果，但文章 ID 为 null |\\n\\n**错误代码**:\\n```java\\n// ❌ 错误：ES 中的字段名是 id，不是 articleId\\narticle.setId(jsonObj.getInteger(\\\"articleId\\\"));\\n```\\n\\n**正确代码**:\\n```java\\n// ✅ 正确：ES 中的字段名是 id\\narticle.setId(jsonObj.getInteger(\\\"id\\\"));\\n```\\n\\n> 💡 **教训**: ES 索引中的字段名是 `id`，不是 `articleId`\\n\\n---\\n\\n### ❌ 问题 3: JsonData.toJson() 类型转换错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 编译错误 `不兼容的类型。实际为 jakarta.json.JsonValue\'，需要 \'java.lang.String\'` |\\n\\n**错误代码**:\\n```java\\n// ❌ 错误：toJson() 返回的是 JsonValue 对象\\nString rawJson = sourceData.toJson();\\n```\\n\\n**正确代码**:\\n```java\\n// ✅ 正确：需要调用 toString() 转换为字符串\\nString rawJson = sourceData.toJson().toString();\\n```\\n\\n> 💡 **原因**: ES 8.x 的 `JsonData.toJson()` 返回的是 `JsonValue` 对象\\n\\n---\\n\\n### ❌ 问题 4: ES 索引中没有数据\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 索引存在且配置正确，搜索返回空数组 |\\n| 🔴 原因 | 删除索引后，新索引创建成功但没有文章数据，MaxWell 只同步增量变更 |\\n| 🟢 解决 | 在 `ElasticsearchIndexInitializer` 中添加数据同步方法 |\\n\\n**同步结果**:\\n```\\n========== 文章数据同步完成 ==========\\n应同步文章数：23\\n实际同步成功：23\\n======================================\\n```\\n\\n---\\n\\n### ❌ 问题 5: 搜索查询未使用 IK 分词器\\n\\n| 项目 | content |\\n|:---|:---|\\n| 🔴 现象 | 中文搜索不准确，分词效果差 |\\n| 🟢 解决 | 在 `buildQuery` 方法中明确指定 analyzer |\\n\\n```java\\nBoolQuery boolQuery = BoolQuery.of(b -> b\\n    .must(m -> m.bool(bb -> bb\\n        .should(s -> s.match(t -> t\\n            .field(\\\"articleTitle\\\")\\n            .query(keywords)\\n            .analyzer(\\\"ik_max_word\\\")  // ✅ 明确指定分词器\\n        ))\\n        .should(s -> s.match(t -> t\\n            .field(\\\"articleContent\\\")\\n            .query(keywords)\\n            .analyzer(\\\"ik_max_word\\\")  // ✅ 明确指定分词器\\n        ))\\n    ))\\n    .must(m -> m.term(t -> t.field(\\\"isDelete\\\").value(FALSE)))\\n    .must(m -> m.term(t -> t.field(\\\"status\\\").value(PUBLIC.getStatus())))\\n);\\n```\\n\\n---\\n\\n### ❌ 问题 6: 高亮配置不生效\\n\\n| 项目 | content |\\n|:---|:---|\\n| 🔴 现象 | 搜索结果有高亮字段，但值为空 |\\n| 🔴 原因 | `preTags` 和 `postTags` 没有在全局设置 |\\n| 🟢 解决 | 全局设置高亮标签 |\\n\\n```java\\nHighlight highlight = Highlight.of(h -> h\\n    .preTags(PRE_TAG)  // ✅ 全局设置前置标签\\n    .postTags(POST_TAG) // ✅ 全局设置后置标签\\n    .fields(\\\"articleTitle\\\", HighlightField.of(hf -> hf\\n        .fragmentSize(0)\\n    ))\\n    .fields(\\\"articleContent\\\", HighlightField.of(hf -> hf\\n        .fragmentSize(50)\\n        .numberOfFragments(3)\\n    ))\\n);\\n```\\n\\n---\\n\\n### ❌ 问题 7: 测试环境缺少 ES 配置\\n\\n| 项目 | content |\\n|:---|:---|\\n| 🔴 现象 | 应用启动失败，错误 `No qualifying bean of type \'ElasticsearchClient\' available` |\\n| 🟢 解决 | 恢复 `ElasticsearchConfig` 配置类，添加 `@Profile(\\\"!test\\\")` |\\n\\n---\\n\\n## 2.3 关键配置文件\\n\\n### application-prod.yml\\n\\n```yaml\\nelasticsearch:\\n  rest:\\n    uris: http://你的ip:9200\\n    username: 用户名\\n    password: 密码\\n\\nsearch:\\n  mode: elasticsearch\\n```\\n\\n### 核心代码文件\\n\\n| 文件 | 说明 |\\n|:---|:---|\\n| 1️⃣ `ElasticsearchConfig.java` | ES 客户端配置 |\\n| 2️⃣ `ElasticsearchIndexInitializer.java` | 索引初始化与数据同步 |\\n| 3️⃣ `EsSearchStrategyImpl.java` | ES 搜索策略实现 |\\n| 4️⃣ `ArticleController.java` | 搜索 API 接口 |\\n\\n---\\n\\n## 2.4 经验总结\\n\\n| # | 经验 |\\n|:---:|:---|\\n| 1️⃣ | 字段映射必须匹配实际存储：ES 中的字段名必须与索引时的字段名一致 |\\n| 2️⃣ | 数据同步机制：MaxWell 只同步增量变更，删除索引后需要手动全量同步历史数据 |\\n| 3️⃣ | 分词器配置：索引时使用 `ik_max_word`，搜索时使用 `ik_smart`，查询时必须明确指定 analyzer |\\n| 4️⃣ | 高亮配置：全局设置 `preTags` 和 `postTags`，字段级别可以单独配置 `fragmentSize` 和 `numberOfFragments` |\\n| 5️⃣ | 测试注意事项：ES 搜索测试需要真实环境，避免对\\\"不存在的关键词\\\"做强断言 |\\n\\n---\\n\\n# 3. 常用命令与运维\\n\\n## 3.1 ES 常用命令\\n\\n```bash\\n# 📊 检查集群健康\\ncurl -u 用户名:密码 http://你的ip:9200/_cluster/health?pretty\\n\\n# 📋 检查索引列表\\ncurl -u 用户名:密码 http://你的ip:9200/_cat/indices?v\\n\\n# 🔍 检查分片状态\\ncurl -u 用户名:密码 http://你的ip:9200/_cat/shards/article?v\\n\\n# 🗑️ 删除索引\\ncurl -X DELETE -u 用户名:密码 http://你的ip:9200/article\\n\\n# 📄 查看索引映射\\ncurl -u 用户名:密码 http://your-ip:9200/article/_mapping?pretty\\n\\n# 🔎 测试搜索\\ncurl -X POST -u 用户名:密码 \\\\\\n  http://你的ip:9200/article/_search?pretty \\\\\\n  -H \'Content-Type: application/json\' \\\\\\n  -d \'{\\\"query\\\":{\\\"match_all\\\":{}}, \\\"size\\\":1}\'\\n\\n# 📜 查看 ES 日志\\ndocker logs aurora-elasticsearch --tail 100 -f\\n\\n# 🔄 重启 ES 服务\\ndocker restart aurora-elasticsearch\\n\\n# 💾 查看 ES 资源使用\\ndocker stats aurora-elasticsearch --no-stream\\n```\\n\\n---\\n\\n## 3.2 搜索模式切换\\n\\n| 模式 | 配置 |\\n|:---|:---|\\n| 🔵 MySQL 搜索 | `search.mode: mysql` |\\n| 🟢 Elasticsearch | `search.mode: elasticsearch` |\\n\\n**重启应用**:\\n```bash\\ndocker restart aurora-springboot\\n```\\n\\n---\\n\\n## 3.3 应用重启流程\\n\\n| 步骤 | 命令 |\\n|:---|:---|\\n| 1️⃣ 停止应用 | `docker stop aurora-springboot` |\\n| 2️⃣ 更新配置 | 修改 `application-prod.yml`，上传新的 jar 包到 `/opt/aurora/app/` |\\n| 3️⃣ 启动应用 | `docker start aurora-springboot` |\\n| 4️⃣ 检查日志 | `docker logs aurora-springboot -f` |\\n| 5️⃣ 验证健康 | `curl http://localhost:8080/api/articles/topAndFeatured` |\\n\\n---\\n\\n## 3.4 常见问题快速解决\\n\\n### ❌ factoryBeanObjectType 错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | `Invalid value type for attribute \'factoryBeanObjectType\': java.lang.String` |\\n| 🟢 解决 | 使用 `mybatis-plus-spring-boot3-starter` 替代 `mybatis-plus-boot-starter` |\\n\\n---\\n\\n### ❌ 端口被占用\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | `Port 8080 was already in use` |\\n| 🟢 解决 | 查看端口占用并释放，或修改端口为 8081 |\\n\\n```powershell\\n# Windows\\nnetstat -ano | findstr :8080\\npowershell -Command \\\"Stop-Process -Id <PID> -Force\\\"\\n```\\n\\n---\\n\\n# 4. 参考资料\\n\\n## 4.1 官方文档\\n\\n| 文档 | 链接 |\\n|:---|:---|\\n| 📘 Spring Boot 3.5 Release Notes | [查看](https://spring.io/blog/spring-boot-3-5-0-available-now) |\\n| ☕ JDK 25 Release Notes | [查看](https://openjdk.org/projects/jdk/25/) |\\n| 🗂️ MyBatis-Plus 3.5.x Documentation | [查看](https://baomidou.com/) |\\n| 🌍 ip2region 3.x GitHub | [查看](https://github.com/lionsoul2014/ip2region) |\\n| 📦 Lombok 1.18.42 Release | [查看](https://projectlombok.org/changelog) |\\n| 🔍 Elasticsearch 8.x 官方文档 | [查看](https://www.elastic.co/guide/en/elasticsearch/reference/current/index.html) |\\n| 📝 IK 分词器文档 | [查看](https://github.com/medcl/elasticsearch-analysis-ik) |\\n\\n## 4.2 迁移指南\\n\\n| 指南 | 链接 |\\n|:---|:---|\\n| 🚀 Spring Boot 3.0 Migration Guide | [查看](https://github.com/spring-projects/spring-boot/wiki/Spring-Boot-3.0-Migration-Guide) |\\n| 🏛️ Jakarta EE 9+ Migration Guide | [查看](https://jakarta.ee/blogs/jakarta-ee-9-migration-guide/) |\\n| ☕ Elasticsearch 8.x Java Client | [查看](https://www.elastic.co/guide/en/elasticsearch/client/java-api-client/current/index.html) |\\n\\n---\\n\\n## 📝 文档修订历史\\n\\n| 版本 | 日期 | 修改内容 | 作者 |\\n|:---|:---:|:---|:---|\\n| v1.0 | 2026-03-09 | 合并《升级到SpringBoot3.5.10 和 JDK25 历程》和《Elasticsearch8 集成问题排查记录》 | Aurora Team |\\n| v1.1 | 2026-03-09 | 优化结构，去除重复内容，简化 FAQ 章节 | Aurora Team |\\n\\n---\\n\\n<div align=\\\"center\\\">\\n\\n**文档版本**: v1.1 (优化版)  \\n**最后更新**: 2026-03-09  \\n**维护者**: 七七\\n\\n</div>\\n\",\"articleCover\":\"https://ws.aqi125.cn/aurora/articles/346065b80634d00d58791014ab0c0cb8.jpg\",\"articleTitle\":\"Aurora 博客系统 - 升级与 Elasticsearch 8.13.4 集成完整指南\",\"categoryName\":\"Aurora集成ES\",\"id\":192,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-08 10:11:43', NULL);
INSERT INTO `t_operation_log` VALUES (2585, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleAbstract\":\"\",\"articleContent\":\"# Aurora 博客系统 - 升级与 Elasticsearch 集成完整指南\\n\\n> Spring Boot 3.5.10 + JDK 25 + Elasticsearch 8.13.4 升级与集成指南\\n\\n---\\n\\n## 📋 目录\\n\\n1. [升级到 Spring Boot 3.5.10 和 JDK 25](#1-升级到-spring-boot-3510-和-jdk-25)\\n2. [Elasticsearch 8.13.4 集成问题排查](#2-elasticsearch-8134-集成问题排查)\\n3. [常用命令与运维](#3-常用命令与运维)\\n4. [参考资料](#4-参考资料)\\n\\n---\\n\\n# 1. 升级到 Spring Boot 3.5.10 和 JDK 25\\n\\n## 1.1 升级概述\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 📅 升级时间 | 2026-03-08 |\\n| 🚀 升级路线 | Spring Boot 3.2.12 + JDK 21 → Spring Boot 3.5.10 + JDK 25 |\\n| 💡 升级原因 | 追求最新特性、性能优化和安全更新 |\\n\\n---\\n\\n## 1.2 依赖版本对比\\n\\n| 组件 | 原版本 | 新版本 | 说明 |\\n|:---|:---:|:---:|:---|\\n| **Spring Boot** | 3.2.12 | **3.5.10** | 最新稳定版 |\\n| **JDK** | 21 | **25** | Oracle 最新 LTS 版本 |\\n| **Lombok** | 1.18.30 | **1.18.42** | 支持 JDK 25 |\\n| **MyBatis-Plus** | 3.5.6 | **3.5.16** | 性能优化和 bug 修复 |\\n| **MySQL Connector/J** | 8.3.0 | **9.6.0** | 最新 JDBC 驱动 |\\n| **FastJSON2** | 2.0.43 | **2.0.61** | JSON 序列化库 |\\n| **Hutool** | 5.8.25 | **5.8.43** | Java 工具类库 |\\n| **Hibernate Validator** | 8.0.1.Final | **9.1.0.Final** | 参数校验框架 |\\n| **ip2region** | 2.7.0 | **3.3.6** | IP 地址库（支持 IPv6） |\\n| **MinIO** | 8.5.7 | **8.6.0** | 对象存储客户端 |\\n| **Knife4j** | 4.4.0 | **4.5.0** | API 文档 |\\n| **UserAgentUtils** | 1.25 | **1.21** | 修复 Maven 仓库不存在问题 |\\n\\n**保持不变的依赖**:\\n\\n| 依赖项 | 版本 | 说明 |\\n|:---|:---:|:---|\\n| **Elasticsearch** | 8.13.4 | Java Client |\\n| **JJWT** | 0.12.5 | JWT 令牌 |\\n| **Quartz** | 2.5.2 | 定时任务 |\\n| **OkHttp** | 4.12.0 | HTTP 客户端（保持 4.x 避免 API 变更） |\\n\\n---\\n\\n## 1.3 代码适配修改\\n\\n### IpUtil.java - ip2region 3.x API 适配\\n\\n**文件位置**: `src/main/java/com/aurora/util/IpUtil.java`\\n\\n```java\\n// 旧版本 (2.7.0)\\nsearcher = Searcher.newWithBuffer(dbBinStr);\\n\\n// 新版本 (3.3.6)\\nimport org.lionsoul.ip2region.xdb.LongByteArray;\\nimport org.lionsoul.ip2region.xdb.Version;\\n\\nLongByteArray longDbArray = new LongByteArray();\\nlongDbArray.append(dbBinStr);\\nsearcher = Searcher.newWithBuffer(Version.IPv4, longDbArray);\\n```\\n\\n### Dockerfile - JDK 版本更新\\n\\n**文件位置**: `Dockerfile`\\n\\n```dockerfile\\nFROM eclipse-temurin:25-jre-alpine\\nWORKDIR /app\\nVOLUME /tmp\\nADD aurora-springboot-0.0.1.jar blog.jar\\n```\\n\\n---\\n\\n## 1.4 常见问题与解决方案\\n\\n### ❌ 问题 1: UserAgentUtils 版本不存在\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `Could not find artifact eu.bitwalker:UserAgentUtils:1.25` |\\n| 🟢 解决 | 改为版本 1.21 |\\n\\n```xml\\n<useragentutils.version>1.21</useragentutils.version>\\n```\\n\\n---\\n\\n### ❌ 问题 2: Lombok 不支持 JDK 25\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `WARNING: sun.misc.Unsafe::objectFieldOffset has been called` |\\n| 🟢 解决 | 升级到 1.18.42 |\\n\\n```xml\\n<lombok.version>1.18.42</lombok.version>\\n```\\n\\n---\\n\\n### ❌ 问题 3: OkHttp 5.x API 不兼容\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `cannot find symbol: class HttpUrl` |\\n| 🟢 解决 | 保持使用 OkHttp 4.12.0 |\\n\\n```xml\\n<okhttp.version>4.12.0</okhttp.version>\\n```\\n\\n---\\n\\n### ❌ 问题 4: JDK 版本不匹配\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `UnsupportedClassVersionError: class file version 69.0, this version of the Java Runtime only recognizes class file versions up to 65.0` |\\n| 🟢 解决 | 设置 `JAVA_HOME=D:\\\\Java\\\\jdk-25.0.1`，Docker 镜像使用 `eclipse-temurin:25-jre-alpine` |\\n\\n---\\n\\n### ❌ 问题 5: 后台登录页面空白\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 登录成功后页面空白，无菜单显示 |\\n| 🔴 原因 | 用户缺少 admin 角色权限 |\\n| 🟢 解决 | 在数据库中为用户分配 admin 角色 |\\n\\n```sql\\nINSERT INTO t_user_role (user_id, role_id) \\nVALUES (1025, (SELECT id FROM t_role WHERE role_name = \'admin\'));\\n```\\n\\n---\\n\\n### ❌ 问题 6: Elasticsearch 503 错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `HTTP/1.1 503 Service Unavailable - no_shard_available_action_exception - all shards failed` |\\n\\n**快速解决方案**:\\n\\n| 方案 | 命令/配置 |\\n|:---|:---|\\n| 1️⃣ 降级到 MySQL 搜索（推荐） | `search.mode: mysql` |\\n| 2️⃣ 重启 Elasticsearch | `docker restart aurora-elasticsearch` |\\n| 3️⃣ 重建索引 | `curl -X DELETE http://你的ip:9200/article` |\\n\\n详细排查请参考 [第 2 部分](#2-elasticsearch-8134-集成问题排查)\\n\\n---\\n\\n## 1.5 编译与部署\\n\\n### 编译环境要求\\n\\n| 环境 | 版本 |\\n|:---|:---|\\n| **JDK** | 25.0.1+ |\\n| **Maven** | 3.9.x+ |\\n\\n**编译命令**:\\n```bash\\nset JAVA_HOME=D:\\\\Java\\\\jdk-25.0.1\\nmvn clean package -DskipTests -U\\n```\\n\\n### JVM 优化参数\\n\\n```bash\\njava -Xms96m -Xmx192m \\\\\\n     -XX:MetaspaceSize=48m -XX:MaxMetaspaceSize=128m \\\\\\n     -XX:+UseG1GC \\\\\\n     -XX:+UseStringDeduplication \\\\\\n     -XX:+UseCompressedOops \\\\\\n     -XX:+UseCompressedClassPointers \\\\\\n     -XX:+AlwaysPreTouch \\\\\\n     -jar blog.jar\\n```\\n\\n---\\n\\n## 1.6 验证结果\\n\\n### ✅ 应用启动验证\\n\\n```\\n✅ Spring Boot 3.5.10 启动成功\\n✅ 使用 JDK 25.0.2 运行\\n✅ Tomcat 在 8080 端口启动\\n✅ 数据库连接正常\\n✅ Quartz 定时任务启动成功\\n✅ ip2region.xdb 加载成功 (11MB)\\n✅ RabbitMQ 连接成功\\n```\\n\\n### ✅ 功能验证\\n\\n| 功能 | 状态 |\\n|:---|:---:|\\n| ✅ QQ 登录 | 正常 |\\n| ✅ 邮箱登录 | 正常 |\\n| ✅ 用户权限（34 个菜单） | 正常 |\\n| ✅ 统计数据查询 | 正常 |\\n| ✅ 文章管理 | 正常 |\\n| ⚠️ Elasticsearch 搜索 | 不可用（临时降级 MySQL） |\\n\\n### 📊 性能对比\\n\\n| 指标 | JDK 21 + SB 3.2.12 | JDK 25 + SB 3.5.10 | 提升 |\\n|:---|:---:|:---:|:---:|\\n| 启动时间 | ~12 秒 | ~10 秒 | 16.7% ⬆️ |\\n| 内存占用 | ~200MB | ~180MB | 10% ⬇️ |\\n| 响应速度 | 基准 | +5~8% | 5~8% ⬆️ |\\n\\n---\\n\\n## 1.7 升级总结\\n\\n### 🎯 成功经验\\n\\n| # | 经验 |\\n|:---:|:---|\\n| 1️⃣ | 提前备份：升级前备份所有配置文件和数据库 |\\n| 2️⃣ | 逐步升级：先升级 Spring Boot，再升级 JDK |\\n| 3️⃣ | 依赖检查：检查所有第三方依赖的兼容性 |\\n| 4️⃣ | 充分测试：编译、打包、运行全流程测试 |\\n| 5️⃣ | 回滚方案：准备回滚脚本和备份镜像 |\\n\\n### ⚠️ 注意事项\\n\\n| # | 注意事项 |\\n|:---:|:---|\\n| 1️⃣ | JDK 25 要求：运行环境必须安装 JDK 25 |\\n| 2️⃣ | Docker 镜像：使用 `eclipse-temurin:25-jre-alpine` |\\n| 3️⃣ | OkHttp 版本：保持 4.x 避免 API 重大变更 |\\n| 4️⃣ | ip2region 数据：确保 xdb 文件为 3.x 格式（支持 IPv6） |\\n| 5️⃣ | Elasticsearch：8.13.4 与 Spring Boot 3.5.10 存在兼容性挑战 |\\n\\n---\\n\\n# 2. Elasticsearch 8.13.4 集成问题排查\\n\\n## 2.1 问题概述\\n\\n在将 Elasticsearch 升级到 8.13.4 后，遇到搜索功能完全失效的问题。经过排查，发现多个关键问题导致搜索无法正常工作。\\n\\n---\\n\\n## 2.2 常见问题与解决方案\\n\\n### ❌ 问题 1: ES 索引 Mapping 配置错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 搜索功能返回空结果，高亮功能不生效 |\\n| 🔴 原因 | 旧索引删除后，新索引没有正确配置 IK 分词器，字段类型未指定为 `text` |\\n| 🟢 解决 | 创建 `ElasticsearchIndexInitializer` 类，在应用启动时自动创建索引 |\\n\\n```java\\nelasticsearchClient.indices().create(c -> c\\n    .index(\\\"article\\\")\\n    .mappings(m -> m\\n        .properties(\\\"articleId\\\", p -> p.integer(i -> i.store(true)))\\n        .properties(\\\"articleTitle\\\", p -> p.text(t -> t\\n            .analyzer(\\\"ik_max_word\\\")\\n            .searchAnalyzer(\\\"ik_smart\\\")\\n            .store(true)\\n        ))\\n        .properties(\\\"articleContent\\\", p -> p.text(t -> t\\n            .analyzer(\\\"ik_max_word\\\")\\n            .searchAnalyzer(\\\"ik_smart\\\")\\n            .store(true)\\n        ))\\n        .properties(\\\"isDelete\\\", p -> p.integer(i -> i.store(true)))\\n        .properties(\\\"status\\\", p -> p.integer(i -> i.store(true)))\\n    )\\n);\\n```\\n\\n**关键配置**:\\n- `articleTitle` 和 `articleContent` 字段必须使用 `text` 类型\\n- 分词器配置：`analyzer: ik_max_word`（索引时），`searchAnalyzer: ik_smart`（搜索时）\\n\\n---\\n\\n### ❌ 问题 2: ES 字段映射错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 搜索返回结果，但文章 ID 为 null |\\n\\n**错误代码**:\\n```java\\n// ❌ 错误：ES 中的字段名是 id，不是 articleId\\narticle.setId(jsonObj.getInteger(\\\"articleId\\\"));\\n```\\n\\n**正确代码**:\\n```java\\n// ✅ 正确：ES 中的字段名是 id\\narticle.setId(jsonObj.getInteger(\\\"id\\\"));\\n```\\n\\n> 💡 **教训**: ES 索引中的字段名是 `id`，不是 `articleId`\\n\\n---\\n\\n### ❌ 问题 3: JsonData.toJson() 类型转换错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 编译错误 `不兼容的类型。实际为 jakarta.json.JsonValue\'，需要 \'java.lang.String\'` |\\n\\n**错误代码**:\\n```java\\n// ❌ 错误：toJson() 返回的是 JsonValue 对象\\nString rawJson = sourceData.toJson();\\n```\\n\\n**正确代码**:\\n```java\\n// ✅ 正确：需要调用 toString() 转换为字符串\\nString rawJson = sourceData.toJson().toString();\\n```\\n\\n> 💡 **原因**: ES 8.x 的 `JsonData.toJson()` 返回的是 `JsonValue` 对象\\n\\n---\\n\\n### ❌ 问题 4: ES 索引中没有数据\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 索引存在且配置正确，搜索返回空数组 |\\n| 🔴 原因 | 删除索引后，新索引创建成功但没有文章数据，MaxWell 只同步增量变更 |\\n| 🟢 解决 | 在 `ElasticsearchIndexInitializer` 中添加数据同步方法 |\\n\\n**同步结果**:\\n```\\n========== 文章数据同步完成 ==========\\n应同步文章数：23\\n实际同步成功：23\\n======================================\\n```\\n\\n---\\n\\n### ❌ 问题 5: 搜索查询未使用 IK 分词器\\n\\n| 项目 | content |\\n|:---|:---|\\n| 🔴 现象 | 中文搜索不准确，分词效果差 |\\n| 🟢 解决 | 在 `buildQuery` 方法中明确指定 analyzer |\\n\\n```java\\nBoolQuery boolQuery = BoolQuery.of(b -> b\\n    .must(m -> m.bool(bb -> bb\\n        .should(s -> s.match(t -> t\\n            .field(\\\"articleTitle\\\")\\n            .query(keywords)\\n            .analyzer(\\\"ik_max_word\\\")  // ✅ 明确指定分词器\\n        ))\\n        .should(s -> s.match(t -> t\\n            .field(\\\"articleContent\\\")\\n            .query(keywords)\\n            .analyzer(\\\"ik_max_word\\\")  // ✅ 明确指定分词器\\n        ))\\n    ))\\n    .must(m -> m.term(t -> t.field(\\\"isDelete\\\").value(FALSE)))\\n    .must(m -> m.term(t -> t.field(\\\"status\\\").value(PUBLIC.getStatus())))\\n);\\n```\\n\\n---\\n\\n### ❌ 问题 6: 高亮配置不生效\\n\\n| 项目 | content |\\n|:---|:---|\\n| 🔴 现象 | 搜索结果有高亮字段，但值为空 |\\n| 🔴 原因 | `preTags` 和 `postTags` 没有在全局设置 |\\n| 🟢 解决 | 全局设置高亮标签 |\\n\\n```java\\nHighlight highlight = Highlight.of(h -> h\\n    .preTags(PRE_TAG)  // ✅ 全局设置前置标签\\n    .postTags(POST_TAG) // ✅ 全局设置后置标签\\n    .fields(\\\"articleTitle\\\", HighlightField.of(hf -> hf\\n        .fragmentSize(0)\\n    ))\\n    .fields(\\\"articleContent\\\", HighlightField.of(hf -> hf\\n        .fragmentSize(50)\\n        .numberOfFragments(3)\\n    ))\\n);\\n```\\n\\n---\\n\\n### ❌ 问题 7: 测试环境缺少 ES 配置\\n\\n| 项目 | content |\\n|:---|:---|\\n| 🔴 现象 | 应用启动失败，错误 `No qualifying bean of type \'ElasticsearchClient\' available` |\\n| 🟢 解决 | 恢复 `ElasticsearchConfig` 配置类，添加 `@Profile(\\\"!test\\\")` |\\n\\n---\\n\\n## 2.3 关键配置文件\\n\\n### application-prod.yml\\n\\n```yaml\\nelasticsearch:\\n  rest:\\n    uris: http://你的ip:9200\\n    username: 用户名\\n    password: 密码\\n\\nsearch:\\n  mode: elasticsearch\\n```\\n\\n### 核心代码文件\\n\\n| 文件 | 说明 |\\n|:---|:---|\\n| 1️⃣ `ElasticsearchConfig.java` | ES 客户端配置 |\\n| 2️⃣ `ElasticsearchIndexInitializer.java` | 索引初始化与数据同步 |\\n| 3️⃣ `EsSearchStrategyImpl.java` | ES 搜索策略实现 |\\n| 4️⃣ `ArticleController.java` | 搜索 API 接口 |\\n\\n---\\n\\n## 2.4 经验总结\\n\\n| # | 经验 |\\n|:---:|:---|\\n| 1️⃣ | 字段映射必须匹配实际存储：ES 中的字段名必须与索引时的字段名一致 |\\n| 2️⃣ | 数据同步机制：MaxWell 只同步增量变更，删除索引后需要手动全量同步历史数据 |\\n| 3️⃣ | 分词器配置：索引时使用 `ik_max_word`，搜索时使用 `ik_smart`，查询时必须明确指定 analyzer |\\n| 4️⃣ | 高亮配置：全局设置 `preTags` 和 `postTags`，字段级别可以单独配置 `fragmentSize` 和 `numberOfFragments` |\\n| 5️⃣ | 测试注意事项：ES 搜索测试需要真实环境，避免对\\\"不存在的关键词\\\"做强断言 |\\n\\n---\\n\\n# 3. 常用命令与运维\\n\\n## 3.1 ES 常用命令\\n\\n```bash\\n# 📊 检查集群健康\\ncurl -u 用户名:密码 http://你的ip:9200/_cluster/health?pretty\\n\\n# 📋 检查索引列表\\ncurl -u 用户名:密码 http://你的ip:9200/_cat/indices?v\\n\\n# 🔍 检查分片状态\\ncurl -u 用户名:密码 http://你的ip:9200/_cat/shards/article?v\\n\\n# 🗑️ 删除索引\\ncurl -X DELETE -u 用户名:密码 http://你的ip:9200/article\\n\\n# 📄 查看索引映射\\ncurl -u 用户名:密码 http://your-ip:9200/article/_mapping?pretty\\n\\n# 🔎 测试搜索\\ncurl -X POST -u 用户名:密码 \\\\\\n  http://你的ip:9200/article/_search?pretty \\\\\\n  -H \'Content-Type: application/json\' \\\\\\n  -d \'{\\\"query\\\":{\\\"match_all\\\":{}}, \\\"size\\\":1}\'\\n\\n# 📜 查看 ES 日志\\ndocker logs aurora-elasticsearch --tail 100 -f\\n\\n# 🔄 重启 ES 服务\\ndocker restart aurora-elasticsearch\\n\\n# 💾 查看 ES 资源使用\\ndocker stats aurora-elasticsearch --no-stream\\n```\\n\\n---\\n\\n## 3.2 搜索模式切换\\n\\n| 模式 | 配置 |\\n|:---|:---|\\n| 🔵 MySQL 搜索 | `search.mode: mysql` |\\n| 🟢 Elasticsearch | `search.mode: elasticsearch` |\\n\\n**重启应用**:\\n```bash\\ndocker restart aurora-springboot\\n```\\n\\n---\\n\\n## 3.3 应用重启流程\\n\\n| 步骤 | 命令 |\\n|:---|:---|\\n| 1️⃣ 停止应用 | `docker stop aurora-springboot` |\\n| 2️⃣ 更新配置 | 修改 `application-prod.yml`，上传新的 jar 包到 `/opt/aurora/app/` |\\n| 3️⃣ 启动应用 | `docker start aurora-springboot` |\\n| 4️⃣ 检查日志 | `docker logs aurora-springboot -f` |\\n| 5️⃣ 验证健康 | `curl http://localhost:8080/api/articles/topAndFeatured` |\\n\\n---\\n\\n## 3.4 常见问题快速解决\\n\\n### ❌ factoryBeanObjectType 错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | `Invalid value type for attribute \'factoryBeanObjectType\': java.lang.String` |\\n| 🟢 解决 | 使用 `mybatis-plus-spring-boot3-starter` 替代 `mybatis-plus-boot-starter` |\\n\\n---\\n\\n### ❌ 端口被占用\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | `Port 8080 was already in use` |\\n| 🟢 解决 | 查看端口占用并释放，或修改端口为 8081 |\\n\\n```powershell\\n# Windows\\nnetstat -ano | findstr :8080\\npowershell -Command \\\"Stop-Process -Id <PID> -Force\\\"\\n```\\n\\n---\\n\\n# 4. 参考资料\\n\\n## 4.1 官方文档\\n\\n| 文档 | 链接 |\\n|:---|:---|\\n| 📘 Spring Boot 3.5 Release Notes | [查看](https://spring.io/blog/spring-boot-3-5-0-available-now) |\\n| ☕ JDK 25 Release Notes | [查看](https://openjdk.org/projects/jdk/25/) |\\n| 🗂️ MyBatis-Plus 3.5.x Documentation | [查看](https://baomidou.com/) |\\n| 🌍 ip2region 3.x GitHub | [查看](https://github.com/lionsoul2014/ip2region) |\\n| 📦 Lombok 1.18.42 Release | [查看](https://projectlombok.org/changelog) |\\n| 🔍 Elasticsearch 8.x 官方文档 | [查看](https://www.elastic.co/guide/en/elasticsearch/reference/current/index.html) |\\n| 📝 IK 分词器文档 | [查看](https://github.com/medcl/elasticsearch-analysis-ik) |\\n\\n## 4.2 迁移指南\\n\\n| 指南 | 链接 |\\n|:---|:---|\\n| 🚀 Spring Boot 3.0 Migration Guide | [查看](https://github.com/spring-projects/spring-boot/wiki/Spring-Boot-3.0-Migration-Guide) |\\n| 🏛️ Jakarta EE 9+ Migration Guide | [查看](https://jakarta.ee/blogs/jakarta-ee-9-migration-guide/) |\\n| ☕ Elasticsearch 8.x Java Client | [查看](https://www.elastic.co/guide/en/elasticsearch/client/java-api-client/current/index.html) |\\n\\n---\\n\\n## 📝 文档修订历史\\n\\n| 版本 | 日期 | 修改内容 | 作者 |\\n|:---|:---:|:---|:---|\\n| v1.0 | 2026-03-09 | 合并《升级到SpringBoot3.5.10 和 JDK25 历程》和《Elasticsearch8 集成问题排查记录》 | Aurora Team |\\n| v1.1 | 2026-03-09 | 优化结构，去除重复内容，简化 FAQ 章节 | Aurora Team |\\n\\n---\\n\\n<div align=\\\"center\\\">\\n\\n**文档版本**: v1.1 (优化版)  \\n**最后更新**: 2026-03-09  \\n**维护者**: 七七\\n\\n</div>\\n\",\"articleCover\":\"https://ws.aqi125.cn/aurora/articles/346065b80634d00d58791014ab0c0cb8.jpg\",\"articleTitle\":\"Aurora 博客系统 - 升级与 Elasticsearch 8.13.4 集成完整指南\",\"categoryName\":\"Aurora集成ES\",\"id\":192,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-08 10:11:58', NULL);
INSERT INTO `t_operation_log` VALUES (2586, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleAbstract\":\"\",\"articleContent\":\"# Aurora 博客系统 - 升级到 JDK 21 + Spring Boot 3.2.12 完整历程\\n\\n> 从 JDK 17 + Spring Boot 2.7.18 升级到 JDK 21 + Spring Boot 3.2.12 的完整历程\\n\\n---\\n\\n## 📅 升级时间\\n\\n2026 年 3 月 8 日\\n\\n---\\n\\n## 🎯 升级目标\\n\\n| 目标 | 状态 |\\n|:---|:---:|\\n| ✅ JDK 从 17 升级到 21 | |\\n| ✅ Spring Boot 从 2.7.18 升级到 3.2.12 | |\\n| ✅ Elasticsearch 升级到 8.13.4（原生 Java Client） | |\\n| ✅ MyBatis-Plus 升级到 3.5.6（使用 Spring Boot 3 专用 starter） | |\\n| ✅ 全面迁移到 Jakarta EE 9+ 命名空间 | |\\n| ✅ 解决所有兼容性问题 | |\\n| ✅ 确保项目正常编译和运行 | |\\n\\n---\\n\\n## 📋 升级步骤\\n\\n### 1. 核心依赖版本升级\\n\\n**基础版本配置**:\\n```xml\\n<properties>\\n    <java.version>21</java.version>\\n    <spring-boot.version>3.2.12</spring-boot.version>\\n    <elasticsearch.version>8.13.4</elasticsearch.version>\\n    <mybatis-plus.version>3.5.6</mybatis-plus.version>\\n    <lombok.version>1.18.30</lombok.version>\\n</properties>\\n```\\n\\n**关键变更**:\\n| 变更 | 内容 |\\n|:---|:---|\\n| ➡️ | JDK 17 → 21 |\\n| ➡️ | Spring Boot 2.7.18 → 3.2.12 |\\n| ➡️ | Lombok 1.18.24 → 1.18.30（支持 JDK 21） |\\n\\n---\\n\\n### 2. Jakarta EE 命名空间迁移\\n\\n**所有 `javax.*` 包名替换为 `jakarta.*`**:\\n\\n| 原包名 | 新包名 |\\n|:---|:---|\\n| `javax.servlet` | `jakarta.servlet` |\\n| `javax.validation` | `jakarta.validation` |\\n| `javax.xml.bind` | `jakarta.xml.bind` |\\n| `javax.annotation` | `jakarta.annotation` |\\n\\n**涉及文件**:\\n- 所有 Controller、Filter、Interceptor\\n- 实体类中的验证注解\\n- XML 绑定相关代码\\n\\n---\\n\\n### 3. Elasticsearch 客户端切换\\n\\n**原因**: Spring Data ES 与 Elasticsearch 8.x 版本匹配复杂\\n\\n**旧配置（已移除）**:\\n```xml\\n<dependency>\\n    <groupId>org.springframework.boot</groupId>\\n    <artifactId>spring-boot-starter-data-elasticsearch</artifactId>\\n</dependency>\\n```\\n\\n**新配置**:\\n```xml\\n<dependency>\\n    <groupId>co.elastic.clients</groupId>\\n    <artifactId>elasticsearch-java</artifactId>\\n    <version>8.13.4</version>\\n</dependency>\\n<dependency>\\n    <groupId>org.elasticsearch.client</groupId>\\n    <artifactId>elasticsearch-rest-client</artifactId>\\n    <version>8.13.4</version>\\n</dependency>\\n```\\n\\n**排除自动配置**:\\n```java\\n@SpringBootApplication(exclude = {\\n    ElasticsearchClientAutoConfiguration.class,\\n    ElasticsearchDataAutoConfiguration.class\\n})\\npublic class AuroraSpringbootApplication {\\n    public static void main(String[] args) {\\n        SpringApplication.run(AuroraSpringbootApplication.class, args);\\n    }\\n}\\n```\\n\\n---\\n\\n### 4. MyBatis-Plus 兼容性处理\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误 | `Invalid value type for attribute \'factoryBeanObjectType\': java.lang.String` |\\n| 🟢 解决 | 使用 Spring Boot 3 专用 starter |\\n\\n```xml\\n<!-- ❌ 旧的依赖（不适用于 Spring Boot 3.2.x） -->\\n<dependency>\\n    <groupId>com.baomidou</groupId>\\n    <artifactId>mybatis-plus-boot-starter</artifactId>\\n    <version>3.5.6</version>\\n</dependency>\\n\\n<!-- ✅ 新的依赖（Spring Boot 3 专用） -->\\n<dependency>\\n    <groupId>com.baomidou</groupId>\\n    <artifactId>mybatis-plus-spring-boot3-starter</artifactId>\\n    <version>3.5.6</version>\\n</dependency>\\n```\\n\\n**关键点**:\\n- MyBatis-Plus 提供了专用的 Spring Boot 3 starter\\n- 包名从 `mybatis-plus-boot-starter` 改为 `mybatis-plus-spring-boot3-starter`\\n- 版本保持 3.5.6（API 稳定）\\n\\n---\\n\\n### 5. 定时任务异常处理\\n\\n#### 5.1 百度 SEO 推送任务\\n\\n**问题**: 硬编码 Content-Length，错误 API 地址\\n\\n**修复代码**:\\n```java\\npublic void baiduSeo() {\\n    List<Integer> ids = articleService.list().stream().map(Article::getId).collect(Collectors.toList());\\n    if (ids.isEmpty()) {\\n        log.info(\\\"No articles to submit for SEO\\\");\\n        return;\\n    }\\n    \\n    // 构建所有 URL（每行一个）\\n    StringBuilder urlsBuilder = new StringBuilder();\\n    for (Integer id : ids) {\\n        String url = websiteUrl + \\\"/articles/\\\" + id;\\n        urlsBuilder.append(url).append(\\\"\\\\n\\\");\\n    }\\n    String urls = urlsBuilder.toString();\\n    \\n    // 设置请求头（不硬编码 Content-Length）\\n    HttpHeaders headers = new HttpHeaders();\\n    headers.add(\\\"Host\\\", \\\"data.zz.baidu.com\\\");\\n    headers.add(\\\"User-Agent\\\", \\\"curl/7.12.1\\\");\\n    headers.add(\\\"Content-Type\\\", \\\"text/plain\\\");\\n    \\n    try {\\n        HttpEntity<String> entity = new HttpEntity<>(urls, headers);\\n        String result = restTemplate.postForObject(\\n            \\\"http://data.zz.baidu.com/urls?site=\\\" + websiteUrl + \\\"&token=YOUR_BAIDU_TOKEN\\\", \\n            entity, \\n            String.class\\n        );\\n        log.info(\\\"Baidu SEO submission result: {}\\\", result);\\n    } catch (Exception e) {\\n        log.error(\\\"Failed to submit URLs to Baidu SEO\\\", e);\\n    }\\n}\\n```\\n\\n#### 5.2 Redis 相关任务\\n\\n**为所有 Redis 操作添加 try-catch**:\\n\\n```java\\n// ✅ saveUniqueView - 添加异常处理\\npublic void saveUniqueView() {\\n    try {\\n        Long count = redisService.sSize(UNIQUE_VISITOR);\\n        UniqueView uniqueView = UniqueView.builder()\\n                .createTime(LocalDateTimeUtil.offset(LocalDateTime.now(), -1, ChronoUnit.DAYS))\\n                .viewsCount(Optional.of(count.intValue()).orElse(0))\\n                .build();\\n        uniqueViewMapper.insert(uniqueView);\\n        log.info(\\\"Unique view statistics saved: {}\\\", count);\\n    } catch (Exception e) {\\n        log.error(\\\"Failed to save unique view statistics: {}\\\", e.getMessage(), e);\\n    }\\n}\\n\\n// ✅ clear - 添加异常处理\\npublic void clear() {\\n    try {\\n        redisService.del(UNIQUE_VISITOR);\\n        redisService.del(VISITOR_AREA);\\n        log.info(\\\"Redis cache cleared successfully\\\");\\n    } catch (Exception e) {\\n        log.error(\\\"Failed to clear Redis cache: {}\\\", e.getMessage(), e);\\n    }\\n}\\n\\n// ✅ statisticalUserArea - 添加异常处理\\npublic void statisticalUserArea() {\\n    try {\\n        Map<String, Long> userAreaMap = userAuthMapper.selectList(new LambdaQueryWrapper<UserAuth>().select(UserAuth::getIpSource))\\n                .stream()\\n                .map(item -> {\\n                    if (Objects.nonNull(item) && StringUtils.isNotBlank(item.getIpSource())) {\\n                        return IpUtil.getIpProvince(item.getIpSource());\\n                    }\\n                    return UNKNOWN;\\n                })\\n                .collect(Collectors.groupingBy(item -> item, Collectors.counting()));\\n        List<UserAreaDTO> userAreaList = userAreaMap.entrySet().stream()\\n                .map(item -> UserAreaDTO.builder()\\n                        .name(item.getKey())\\n                        .value(item.getValue())\\n                        .build())\\n                .collect(Collectors.toList());\\n        redisService.set(USER_AREA, JSON.toJSONString(userAreaList));\\n        log.info(\\\"User area statistics saved successfully\\\");\\n    } catch (Exception e) {\\n        log.error(\\\"Failed to save user area statistics: {}\\\", e.getMessage(), e);\\n    }\\n}\\n```\\n\\n---\\n\\n## 🔧 Maven 编译器插件配置\\n\\n```xml\\n<plugin>\\n    <groupId>org.apache.maven.plugins</groupId>\\n    <artifactId>maven-compiler-plugin</artifactId>\\n    <version>3.11.0</version>\\n    <configuration>\\n        <source>21</source>\\n        <target>21</target>\\n        <annotationProcessorPaths>\\n            <path>\\n                <groupId>org.projectlombok</groupId>\\n                <artifactId>lombok</artifactId>\\n                <version>1.18.30</version>\\n            </path>\\n        </annotationProcessorPaths>\\n    </configuration>\\n</plugin>\\n```\\n\\n---\\n\\n## 📦 最终依赖配置清单\\n\\n### 核心框架\\n\\n```xml\\n<properties>\\n    <java.version>21</java.version>\\n    <spring-boot.version>3.2.12</spring-boot.version>\\n</properties>\\n```\\n\\n### 数据层\\n\\n```xml\\n<!-- MyBatis-Plus Spring Boot 3 专用 -->\\n<dependency>\\n    <groupId>com.baomidou</groupId>\\n    <artifactId>mybatis-plus-spring-boot3-starter</artifactId>\\n    <version>3.5.6</version>\\n</dependency>\\n\\n<!-- MySQL 连接器 -->\\n<dependency>\\n    <groupId>com.mysql</groupId>\\n    <artifactId>mysql-connector-j</artifactId>\\n    <version>8.3.0</version>\\n</dependency>\\n\\n<!-- Redis -->\\n<dependency>\\n    <groupId>org.springframework.boot</groupId>\\n    <artifactId>spring-boot-starter-data-redis</artifactId>\\n</dependency>\\n\\n<!-- Elasticsearch 原生客户端 -->\\n<dependency>\\n    <groupId>co.elastic.clients</groupId>\\n    <artifactId>elasticsearch-java</artifactId>\\n    <version>8.13.4</version>\\n</dependency>\\n```\\n\\n### 安全与认证\\n\\n```xml\\n<!-- Spring Security -->\\n<dependency>\\n    <groupId>org.springframework.boot</groupId>\\n    <artifactId>spring-boot-starter-security</artifactId>\\n</dependency>\\n\\n<!-- JWT -->\\n<dependency>\\n    <groupId>io.jsonwebtoken</groupId>\\n    <artifactId>jjwt-api</artifactId>\\n    <version>0.12.5</version>\\n</dependency>\\n<dependency>\\n    <groupId>io.jsonwebtoken</groupId>\\n    <artifactId>jjwt-impl</artifactId>\\n    <version>0.12.5</version>\\n    <scope>runtime</scope>\\n</dependency>\\n<dependency>\\n    <groupId>io.jsonwebtoken</groupId>\\n    <artifactId>jjwt-jackson</artifactId>\\n    <version>0.12.5</version>\\n    <scope>runtime</scope>\\n</dependency>\\n\\n<!-- 参数验证 -->\\n<dependency>\\n    <groupId>org.hibernate.validator</groupId>\\n    <artifactId>hibernate-validator</artifactId>\\n    <version>8.0.1.Final</version>\\n</dependency>\\n```\\n\\n### 工具库\\n\\n```xml\\n<!-- FastJSON2 -->\\n<dependency>\\n    <groupId>com.alibaba.fastjson2</groupId>\\n    <artifactId>fastjson2</artifactId>\\n    <version>2.0.43</version>\\n</dependency>\\n\\n<!-- Hutool -->\\n<dependency>\\n    <groupId>cn.hutool</groupId>\\n    <artifactId>hutool-all</artifactId>\\n    <version>5.8.25</version>\\n</dependency>\\n\\n<!-- Commons Lang3 -->\\n<dependency>\\n    <groupId>org.apache.commons</groupId>\\n    <artifactId>commons-lang3</artifactId>\\n    <version>3.14.0</version>\\n</dependency>\\n\\n<!-- Lombok -->\\n<dependency>\\n    <groupId>org.projectlombok</groupId>\\n    <artifactId>lombok</artifactId>\\n    <version>1.18.30</version>\\n</dependency>\\n```\\n\\n### API 文档\\n\\n```xml\\n<!-- Knife4j Spring Boot 3 版本 -->\\n<dependency>\\n    <groupId>com.github.xiaoymin</groupId>\\n    <artifactId>knife4j-openapi3-jakarta-spring-boot-starter</artifactId>\\n    <version>4.4.0</version>\\n</dependency>\\n```\\n\\n### 文件存储\\n\\n```xml\\n<!-- MinIO -->\\n<dependency>\\n    <groupId>io.minio</groupId>\\n    <artifactId>minio</artifactId>\\n    <version>8.5.7</version>\\n</dependency>\\n\\n<!-- Aliyun OSS -->\\n<dependency>\\n    <groupId>com.aliyun.oss</groupId>\\n    <artifactId>aliyun-sdk-oss</artifactId>\\n    <version>3.17.2</version>\\n</dependency>\\n```\\n\\n### Jakarta XML Binding（Spring Boot 3 必需）\\n\\n```xml\\n<dependency>\\n    <groupId>jakarta.xml.bind</groupId>\\n    <artifactId>jakarta.xml.bind-api</artifactId>\\n</dependency>\\n<dependency>\\n    <groupId>org.glassfish.jaxb</groupId>\\n    <artifactId>jaxb-runtime</artifactId>\\n</dependency>\\n```\\n\\n---\\n\\n## 🧪 验证步骤\\n\\n### 编译验证\\n\\n```bash\\nmvn clean compile -DskipTests\\n```\\n\\n**预期结果**: BUILD SUCCESS\\n\\n---\\n\\n### 启动验证\\n\\n```bash\\nmvn spring-boot:run -Dspring-boot.run.profiles=prod\\n```\\n\\n**预期输出**:\\n```\\n  .   ____          _            __ _ _\\n /\\\\\\\\ / ___\'_ __ _ _(_)_ __  __ _ \\\\ \\\\ \\\\ \\\\\\n::( ( )\\\\___ | \'_ | \'_| | \'_ \\\\/ _` | \\\\ \\\\ \\\\ \\\\\\n \\\\\\\\/  ___)| |_)| | | | | || (_| |  ) ) ) )\\n  \'  |____| .__|_| |_|_| |_\\\\__, | / / / /\\n =========|_|==============|___/=/_/_/_/\\n :: Spring Boot ::                (v3.2.12)\\n\\nStarted AuroraSpringbootApplication in 8.861 seconds\\nTomcat started on port 8080 (http) with context path \'\'\\n```\\n\\n---\\n\\n## ✅ 启动成功标志\\n\\n```\\n✓ Tomcat started on port 8080\\n✓ MySQL 连接成功 (MyHikariCP)\\n✓ Quartz 调度器启动\\n✓ RabbitMQ 连接成功\\n✓ Spring Security 过滤器链配置完成\\n✓ 加载 122 条资源权限配置\\n✓ 5 个定时任务就绪\\n```\\n\\n**访问地址**:\\n| 服务 | 地址 |\\n|:---|:---|\\n| 🌐 应用 | `http://localhost:8080` |\\n| 📚 API 文档 | `http://localhost:8080/doc.html` |\\n\\n---\\n\\n## 📊 版本对比表\\n\\n| 组件 | 升级前 | 升级后 |\\n|:---|:---:|:---:|\\n| JDK | 17 | **21** |\\n| Spring Boot | 2.7.18 | **3.2.12** |\\n| MyBatis-Plus | 3.4.3.4 (boot-starter) | **3.5.6 (spring-boot3-starter)** |\\n| Elasticsearch | 7.17.12 (Spring Data ES) | **8.13.4 (原生 Client)** |\\n| MySQL Connector | 8.0.33 | **8.3.0** |\\n| Lombok | 1.18.24 | **1.18.30** |\\n| Knife4j | 2.0.9 | **4.4.0 (OpenAPI3)** |\\n| JJWT | 0.9.1 | **0.12.5** |\\n| Hibernate Validator | 6.2.5.Final | **8.0.1.Final** |\\n| 命名空间 | `javax.*` | **`jakarta.*`** |\\n\\n---\\n\\n## ⚠️ 重要注意事项\\n\\n| # | 注意事项 |\\n|:---:|:---|\\n| 1️⃣ | MyBatis-Plus Starter 选择：Spring Boot 3.2.x 必须使用 `mybatis-plus-spring-boot3-starter` |\\n| 2️⃣ | Jakarta EE 命名空间：所有 `javax.*` 必须替换为 `jakarta.*` |\\n| 3️⃣ | Elasticsearch 客户端选择：不使用 Spring Data ES，直接使用原生 Java Client |\\n| 4️⃣ | Knife4j 版本：Spring Boot 3 必须使用 4.x OpenAPI3/Jakarta 版本 |\\n| 5️⃣ | JDK 版本要求：必须使用 JDK 21，推荐使用 LTS 版本 |\\n| 6️⃣ | 定时任务异常处理：所有涉及外部服务的定时任务都必须添加 try-catch |\\n\\n---\\n\\n## 🔧 日常开发命令\\n\\n```bash\\n# 编译项目\\nmvn clean compile -DskipTests\\n\\n# 启动项目\\nmvn spring-boot:run -Dspring-boot.run.profiles=prod\\n\\n# 打包项目\\nmvn clean package -DskipTests\\n\\n# 查看依赖树\\nmvn dependency:tree\\n```\\n\\n---\\n\\n## 🎉 升级成果\\n\\n| 成果 | 状态 |\\n|:---|:---:|\\n| ✅ 项目成功使用 JDK 21 编译 | |\\n| ✅ Spring Boot 3.2.12 正常运行 | |\\n| ✅ MyBatis-Plus 3.5.6 完全兼容 | |\\n| ✅ Elasticsearch 8.13.4 原生客户端集成 | |\\n| ✅ API 文档（Knife4j 4.4.0）正常访问 | |\\n| ✅ 所有业务功能正常 | |\\n| ✅ Lombok 注解完全生效 | |\\n| ✅ Jakarta EE 命名空间迁移完成 | |\\n| ✅ 定时任务异常处理完善 | |\\n| ✅ 项目启动时间约 8.8 秒 | |\\n\\n---\\n\\n## 📝 修改的文件清单\\n\\n### 配置文件\\n\\n| # | 文件 | 说明 |\\n|:---:|:---|:---|\\n| 1️⃣ | `pom.xml` | 核心依赖和插件配置 |\\n| 2️⃣ | `src/main/resources/application-prod.yml` | 生产环境配置 |\\n\\n### Java 源代码\\n\\n| # | 文件 | 说明 |\\n|:---:|:---|:---|\\n| 3️⃣ | `AuroraSpringbootApplication.java` | 排除 ES 自动配置 |\\n| 4️⃣ | `src/main/java/com/aurora/quartz/AuroraQuartz.java` | 定时任务异常处理 |\\n| 5️⃣ | 所有包含 `javax.*` 导入的类文件 | 迁移到 `jakarta.*` |\\n\\n### 配置类\\n\\n| # | 文件 | 说明 |\\n|:---:|:---|:---|\\n| 6️⃣ | `ElasticsearchConfig.java` | 原生 ES Client 配置 |\\n| 7️⃣ | 其他配置类 | Jakarta 迁移 |\\n\\n---\\n\\n## 🐛 常见问题 FAQ\\n\\n### Q1: factoryBeanObjectType 错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | `Invalid value type for attribute \'factoryBeanObjectType\': java.lang.String` |\\n| 🟢 解决 | 使用 `mybatis-plus-spring-boot3-starter` 替代 `mybatis-plus-boot-starter` |\\n\\n---\\n\\n### Q2: 端口被占用\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | `Port 8080 was already in use` |\\n| 🟢 解决 | 释放端口或修改配置 |\\n\\n```powershell\\n# Windows\\nnetstat -ano | findstr :8080\\npowershell -Command \\\"Stop-Process -Id <PID> -Force\\\"\\n\\n# 或者修改端口\\nserver.port=8081\\n```\\n\\n---\\n\\n### Q3: Lombok 不生效\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 找不到 getter/setter 方法 |\\n| 🟢 解决 | 确保 Lombok 版本 >= 1.18.30，配置 annotationProcessorPaths，IDE 重启并 Invalidate Caches |\\n\\n---\\n\\n### Q4: CORS 跨域错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | `allowCredentials is true, allowedOrigins cannot contain \\\"*\\\"` |\\n| 🟢 解决 | 使用 `allowedOriginPatterns(\\\"*\\\")` 替代 `allowedOrigins(\\\"*\\\")` |\\n\\n---\\n\\n### Q5: Elasticsearch 客户端不可用\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | `WARN: ElasticsearchClient not available, skipping ES import` |\\n| 🔴 原因 | Elasticsearch 服务未启动或配置错误 |\\n| 🟢 解决 | 检查配置，确保 ES 服务正常运行，代码中已添加空值检查 |\\n\\n---\\n\\n## 📚 参考资料\\n\\n| 文档 | 链接 |\\n|:---|:---|\\n| 📘 Spring Boot 3.2 官方文档 | [查看](https://docs.spring.io/spring-boot/docs/3.2.12/reference/html/) |\\n| 🚀 Spring Boot 3 迁移指南 | [查看](https://github.com/spring-projects/spring-boot/wiki/Spring-Boot-3.0-Migration-Guide) |\\n| 🗂️ MyBatis-Plus Spring Boot 3 Starter | [查看](https://baomidou.com/pages/7e42d6/) |\\n| 🏛️ Jakarta EE 9+ 迁移指南 | [查看](https://jakarta.ee/blogs/jakarta-ee-9-migration-guide/) |\\n| 🔍 Elasticsearch 8.x Java Client | [查看](https://www.elastic.co/guide/en/elasticsearch/client/java-api-client/current/index.html) |\\n| 🔪 Knife4j 4.x 文档 | [查看](https://doc.xiaominfo.com/docs/knife4j/version) |\\n\\n---\\n\\n## 📈 性能对比\\n\\n| 指标 | Spring Boot 2.7.18 | Spring Boot 3.2.12 | 提升 |\\n|:---|:---:|:---:|:---:|\\n| 启动时间 | ~10s | ~8.8s | 12% ⬆️ |\\n| 内存占用 | ~450MB | ~420MB | 7% ⬆️ |\\n| 吞吐量 | 基准 | +15% | 15% ⬆️ |\\n\\n---\\n\\n<div align=\\\"center\\\">\\n\\n**文档版本**: 4.0（优化精简版）  \\n**最后更新**: 2026-03-09  \\n**作者**: 七七\\n\\n</div>\\n\",\"articleCover\":\"https://ws.aqi125.cn/aurora/articles/9bfa2953bc860b33841b3debb0a03675.jpg\",\"articleTitle\":\"Aurora 博客系统 - JDK 21 + Spring Boot 3.2.12 升级历程\",\"categoryName\":\"AuroraJDK\",\"id\":190,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-08 10:12:07', NULL);
INSERT INTO `t_operation_log` VALUES (2587, '文章模块', '新增或修改', '/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleAbstract\":\"\",\"articleContent\":\"# 升级到 Spring Boot 3.5.10 和 JDK 25 历程\\n\\n> Aurora 博客系统从 Spring Boot 3.2.12 + JDK 21 升级到 Spring Boot 3.5.10 + JDK 25 的完整历程\\n\\n---\\n\\n## 📋 升级概述\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 📅 升级时间 | 2026-03-08 |\\n| 🎯 升级目标 | Spring Boot 3.2.12 + JDK 21 → Spring Boot 3.5.10 + JDK 25 |\\n| 💡 升级原因 | 追求最新特性、性能优化和安全更新 |\\n\\n---\\n\\n## 🎯 主要升级内容\\n\\n### 1. 核心框架升级\\n\\n| 组件 | 原版本 | 新版本 | 说明 |\\n|:---|:---:|:---:|:---|\\n| **Spring Boot** | 3.2.12 | **3.5.10** | 最新稳定版 |\\n| **JDK** | 21 | **25** | Oracle 最新 LTS 版本 |\\n| **Lombok** | 1.18.30 | **1.18.42** | 支持 JDK 25 |\\n\\n### 2. 中间件依赖升级\\n\\n| 依赖项 | 原版本 | 新版本 | 发布日期 | 说明 |\\n|:---|:---:|:---:|:---:|:---|\\n| **MyBatis-Plus** | 3.5.6 | **3.5.16** | 2026-01-11 | 性能优化和 bug 修复 |\\n| **MySQL Connector/J** | 8.3.0 | **9.6.0** | 2026-01-29 | 最新 JDBC 驱动 |\\n| **FastJSON2** | 2.0.43 | **2.0.61** | 2026-02-07 | JSON 序列化库 |\\n| **Hutool** | 5.8.25 | **5.8.43** | 2026-01-05 | Java 工具类库 |\\n| **Hibernate Validator** | 8.0.1.Final | **9.1.0.Final** | 2025-11-07 | 参数校验框架 |\\n| **ip2region** | 2.7.0 | **3.3.6** | 2026-03-03 | IP 地址库（支持 IPv6） |\\n| **MinIO** | 8.5.7 | **8.6.0** | 2025-09-26 | 对象存储客户端 |\\n| **Knife4j** | 4.4.0 | **4.5.0** | 2024-01-07 | API 文档 |\\n| **UserAgentUtils** | 1.25 | **1.21** | - | 修复 Maven 仓库不存在问题 |\\n\\n### 3. 保持不变的依赖\\n\\n| 依赖项 | 版本 | 说明 |\\n|:---|:---:|:---|\\n| **Elasticsearch** | 8.13.4 | Java Client |\\n| **JJWT** | 0.12.5 | JWT 令牌 |\\n| **Quartz** | 2.5.2 | 定时任务 |\\n| **OkHttp** | 4.12.0 | HTTP 客户端（保持 4.x 避免 API 变更） |\\n\\n---\\n\\n## 🔧 代码适配修改\\n\\n### 1. IpUtil.java - ip2region 3.x API 适配\\n\\n**修改原因**: ip2region 3.x 使用新的 `LongByteArray` API\\n\\n```java\\n// 旧版本 (2.7.0)\\nsearcher = Searcher.newWithBuffer(dbBinStr);\\n\\n// 新版本 (3.3.6)\\nimport org.lionsoul.ip2region.xdb.LongByteArray;\\nimport org.lionsoul.ip2region.xdb.Version;\\n\\nLongByteArray longDbArray = new LongByteArray();\\nlongDbArray.append(dbBinStr);\\nsearcher = Searcher.newWithBuffer(Version.IPv4, longDbArray);\\n```\\n\\n**文件位置**: `src/main/java/com/aurora/util/IpUtil.java`\\n\\n### 2. Dockerfile - JDK 版本更新\\n\\n```dockerfile\\n# 旧版本\\nFROM eclipse-temurin:21-jre-alpine\\n\\n# 新版本\\nFROM eclipse-temurin:25-jre-alpine\\n```\\n\\n**文件位置**: `Dockerfile`\\n\\n---\\n\\n## ⚠️ 遇到的问题及解决方案\\n\\n### ❌ 问题 1: UserAgentUtils 版本不存在\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误信息 | `Could not find artifact eu.bitwalker:UserAgentUtils:1.25` |\\n| 🔴 原因 | Maven Central 上最新版本为 1.21 |\\n| 🟢 解决方案 | 修改版本为 1.21 |\\n\\n```xml\\n<useragentutils.version>1.21</useragentutils.version>\\n```\\n\\n---\\n\\n### ❌ 问题 2: Lombok 不支持 JDK 25\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误信息 | `WARNING: sun.misc.Unsafe::objectFieldOffset has been called` |\\n| 🔴 原因 | Lombok 1.18.30 不支持 JDK 25 |\\n| 🟢 解决方案 | 升级到 1.18.42 |\\n\\n```xml\\n<lombok.version>1.18.42</lombok.version>\\n```\\n\\n---\\n\\n### ❌ 问题 3: OkHttp 5.x API 不兼容\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误信息 | `cannot find symbol: class HttpUrl` |\\n| 🔴 原因 | OkHttp 5.x 使用 Kotlin 重写,API 重大变更 |\\n| 🟢 解决方案 | 保持使用 OkHttp 4.12.0 |\\n\\n```xml\\n<okhttp.version>4.12.0</okhttp.version>\\n```\\n\\n---\\n\\n### ❌ 问题 4: JDK 版本不匹配\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误信息 | `UnsupportedClassVersionError: class file version 69.0, this version of the Java Runtime only recognizes class file versions up to 65.0` |\\n| 🔴 原因 | 使用 JDK 25 编译,但尝试用 JDK 21 运行 |\\n| 🟢 解决方案 | 确保运行环境使用 JDK 25，设置环境变量: `JAVA_HOME=D:\\\\Java\\\\jdk-25.0.1`，Docker 镜像更新为 `eclipse-temurin:25-jre-alpine` |\\n\\n---\\n\\n### ❌ 问题 5: 后台登录页面空白\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 现象 | 登录成功后页面空白,无菜单显示 |\\n| 🔴 原因 | 用户缺少 admin 角色权限 |\\n| 🟢 解决方案 | 在数据库中为用户分配 admin 角色 |\\n\\n```sql\\nINSERT INTO t_user_role (user_id, role_id)\\nVALUES (1025, (SELECT id FROM t_role WHERE role_name = \'admin\'));\\n```\\n\\n**验证**: 日志显示成功查询到 34 个菜单\\n\\n---\\n\\n### ❌ 问题 6: Elasticsearch 503 错误\\n\\n| 项目 | 内容 |\\n|:---|:---|\\n| 🔴 错误信息 | `HTTP/1.1 503 Service Unavailable - no_shard_available_action_exception - all shards failed` |\\n| 🔴 原因 | Elasticsearch 服务不可用或索引损坏 |\\n\\n#### 方案 1: 临时降级到 MySQL 搜索（推荐）\\n\\n修改 `application-prod.yml`:\\n```yaml\\nsearch:\\n  mode: mysql  # 从 elasticsearch 改为 mysql\\n```\\n\\n重启应用后搜索功能正常。\\n\\n#### 方案 2: 修复 Elasticsearch 服务\\n\\n| 步骤 | 命令 |\\n|:---|:---|\\n| 1️⃣ 重启 ES | `docker restart aurora-elasticsearch` |\\n| 2️⃣ 检查健康 | `curl -u 用户名:密码 http://你的ip:9200/_cluster/health?pretty` |\\n| 3️⃣ 重建索引 | `curl -X DELETE -u 用户名:密码 http://你的ip:9200/article` |\\n\\n#### 方案 3: 升级 Elasticsearch 客户端依赖\\n\\n```xml\\n<dependency>\\n    <groupId>co.elastic.clients</groupId>\\n    <artifactId>elasticsearch-java</artifactId>\\n    <version>8.17.2</version>\\n</dependency>\\n```\\n\\n---\\n\\n## 📦 编译与打包\\n\\n### 编译环境要求\\n\\n| 环境 | 版本 |\\n|:---|:---|\\n| **JDK 版本** | 25.0.1+ |\\n| **Maven 版本** | 3.9.x+ |\\n\\n**编译命令**:\\n```bash\\nset JAVA_HOME=D:\\\\Java\\\\jdk-25.0.1\\nmvn clean package -DskipTests -U\\n```\\n\\n### 编译结果\\n\\n| 项目 | 状态 |\\n|:---|:---:|\\n| ✅ 编译成功 | 299 个源文件 |\\n| ✅ 打包成功 | 生成 115MB jar 包 |\\n| ⚠️ 存在少量警告 | 不影响运行 |\\n\\n---\\n\\n## 🚀 部署配置\\n\\n### Docker 部署\\n\\n**Dockerfile**:\\n```dockerfile\\nFROM eclipse-temurin:25-jre-alpine\\nWORKDIR /app\\nVOLUME /tmp\\nADD aurora-springboot-0.0.1.jar blog.jar\\n```\\n\\n**JVM 优化参数**:\\n```bash\\njava -Xms96m -Xmx192m \\\\\\n     -XX:MetaspaceSize=48m -XX:MaxMetaspaceSize=128m \\\\\\n     -XX:+UseG1GC \\\\\\n     -XX:+UseStringDeduplication \\\\\\n     -XX:+UseCompressedOops \\\\\\n     -XX:+UseCompressedClassPointers \\\\\\n     -XX:+AlwaysPreTouch \\\\\\n     -jar blog.jar\\n```\\n\\n---\\n\\n## ✅ 验证结果\\n\\n### 1. 应用启动验证\\n\\n```\\n✅ Spring Boot 3.5.10 启动成功\\n✅ 使用 JDK 25.0.2 运行\\n✅ Tomcat 在 8080 端口启动\\n✅ 数据库连接正常\\n✅ Quartz 定时任务启动成功\\n✅ ip2region.xdb 加载成功 (11MB)\\n✅ RabbitMQ 连接成功\\n```\\n\\n### 2. 功能验证\\n\\n| 功能 | 状态 | 说明 |\\n|:---|:---:|:---|\\n| ✅ QQ 登录 | 正常 | |\\n| ✅ 邮箱登录 | 正常 | |\\n| ✅ 用户权限 | 正常 | 34 个菜单 |\\n| ✅ 统计数据查询 | 正常 | |\\n| ✅ 文章管理 | 正常 | |\\n| ⚠️ Elasticsearch 搜索 | 不可用 | 临时降级到 MySQL |\\n\\n---\\n\\n## 📊 性能对比\\n\\n| 指标 | JDK 21 + SB 3.2.12 | JDK 25 + SB 3.5.10 | 提升 |\\n|:---|:---:|:---:|:---:|\\n| 启动时间 | ~12 秒 | ~10 秒 | 16.7% ⬆️ |\\n| 内存占用 | ~200MB | ~180MB | 10% ⬇️ |\\n| 响应速度 | 基准 | +5~8% | 5~8% ⬆️ |\\n\\n*注:性能数据基于实际运行环境测试*\\n\\n---\\n\\n## 🎯 升级总结\\n\\n### ✅ 成功经验\\n\\n| # | 经验 |\\n|:---:|:---|\\n| 1️⃣ | 提前备份：升级前备份所有配置文件和数据库 |\\n| 2️⃣ | 逐步升级：先升级 Spring Boot,再升级 JDK |\\n| 3️⃣ | 依赖检查：检查所有第三方依赖的兼容性 |\\n| 4️⃣ | 充分测试：编译、打包、运行全流程测试 |\\n| 5️⃣ | 回滚方案：准备回滚脚本和备份镜像 |\\n\\n### ⚠️ 注意事项\\n\\n| # | 注意事项 |\\n|:---:|:---|\\n| 1️⃣ | JDK 25 要求：运行环境必须安装 JDK 25 |\\n| 2️⃣ | Docker 镜像：使用 `eclipse-temurin:25-jre-alpine` |\\n| 3️⃣ | OkHttp 版本：保持 4.x 避免 API 重大变更 |\\n| 4️⃣ | ip2region 数据：确保 xdb 文件为 3.x 格式（支持 IPv6） |\\n| 5️⃣ | Elasticsearch：8.13.4 与 Spring Boot 3.5.10 兼容 |\\n\\n---\\n\\n## 🚨 快速故障排除\\n\\n### Elasticsearch 相关\\n\\n| 症状 | 可能原因 | 解决方案 |\\n|:---|:---|:---|\\n| 搜索返回 503 | ES 服务不可用 | 降级到 MySQL: `search.mode=mysql` |\\n| 索引不存在 | ES 集群重启 | 重启应用让其自动创建索引 |\\n| 分片未分配 | 节点资源不足 | 增加内存或删除旧索引 |\\n| 连接超时 | 客户端配置问题 | 检查连接池配置和超时设置 |\\n| 数据不同步 | Maxwell 配置错误 | 检查 Maxwell 配置和日志 |\\n\\n### 常用 ES 命令\\n\\n```bash\\n# 📊 检查集群健康\\ncurl -u 用户名:密码 http://你的ip:9200/_cluster/health?pretty\\n\\n# 📋 检查索引列表\\ncurl -u 用户名:密码 http://你的ip:9200/_cat/indices?v\\n\\n# 🔍 检查分片状态\\ncurl -u 用户名:密码 http://你的ip:9200/_cat/shards/article?v\\n\\n# 🗑️ 删除索引\\ncurl -X DELETE -u 用户名:密码 http://your-ip:9200/article\\n\\n# 📄 查看索引映射\\ncurl -u 用户名:密码 http://你的ip:9200/article/_mapping?pretty\\n\\n# 🔎 测试搜索\\ncurl -X POST -u 用户名:密码 \\\\\\n  http://你的ip:9200/article/_search?pretty \\\\\\n  -H \'Content-Type: application/json\' \\\\\\n  -d \'{\\\"query\\\":{\\\"match_all\\\":{}}, \\\"size\\\":1}\'\\n\\n# 📜 查看 ES 日志\\ndocker logs aurora-elasticsearch --tail 100 -f\\n\\n# 🔄 重启 ES 服务\\ndocker restart aurora-elasticsearch\\n\\n# 💾 查看 ES 资源使用\\ndocker stats aurora-elasticsearch --no-stream\\n```\\n\\n### 应用重启流程\\n\\n| 步骤 | 命令 |\\n|:---|:---|\\n| 1️⃣ 停止应用 | `docker stop aurora-springboot` |\\n| 2️⃣ 更新配置 | 修改 `application-prod.yml`，上传新的 jar 包 |\\n| 3️⃣ 启动应用 | `docker start aurora-springboot` |\\n| 4️⃣ 检查日志 | `docker logs aurora-springboot -f` |\\n| 5️⃣ 验证健康 | `curl http://localhost:8080/api/articles/topAndFeatured` |\\n\\n---\\n\\n## 📚 参考资料\\n\\n| 文档 | 链接 |\\n|:---|:---|\\n| 📘 Spring Boot 3.5 Release Notes | [查看](https://spring.io/blog/spring-boot-3-5-0-available-now) |\\n| ☕ JDK 25 Release Notes | [查看](https://openjdk.org/projects/jdk/25/) |\\n| 🗂️ MyBatis-Plus 3.5.x Documentation | [查看](https://baomidou.com/) |\\n| 🌍 ip2region 3.x GitHub | [查看](https://github.com/lionsoul2014/ip2region) |\\n| 📦 Lombok 1.18.42 Release | [查看](https://projectlombok.org/changelog) |\\n\\n---\\n\\n<div align=\\\"center\\\">\\n\\n**文档版本**: v3.0  \\n**最后更新**: 2026-03-09  \\n**维护者**: 七七\\n\\n</div>\\n\",\"articleCover\":\"https://ws.aqi125.cn/aurora/articles/12f138cdc95482591d354088fe37ec32.jpg\",\"articleTitle\":\"Aurora 博客系统 升级到 Spring Boot 3.5.10 和 JDK 25 历程\",\"categoryName\":\"AuroraJDK\",\"id\":191,\"isFeatured\":1,\"isTop\":1,\"status\":1,\"tagNames\":[],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-08 10:12:13', NULL);
INSERT INTO `t_operation_log` VALUES (2588, 'aurora信息', '修改', '/api/admin/about', 'com.aurora.controller.AuroraInfoController.updateAbout', '修改关于我信息', '[{\"content\":\"是七七啊！\"}]', 'PUT', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-09 02:36:57', NULL);
INSERT INTO `t_operation_log` VALUES (2589, 'aurora信息', '修改', '/api/admin/about', 'com.aurora.controller.AuroraInfoController.updateAbout', '修改关于我信息', '[{\"content\":\"是七七啊！\"}]', 'PUT', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-09 02:37:13', NULL);
INSERT INTO `t_operation_log` VALUES (2590, 'aurora信息', '修改', '/api/admin/website/config', 'com.aurora.controller.AuroraInfoController.updateWebsiteConfig', '更新网站配置', '[{\"alipayQRCode\":\"https://ws.aqi125.cn/aurora/config/5a73275cdb99f2d037e13a93d027968d.jpg\",\"author\":\"七七\",\"authorAvatar\":\"http://ws.aqi125.cn/config/6d93c4e2a2690ce5f742f42f8d80e365.jpg\",\"authorIntro\":\"一个疯狂的coder\",\"beianNumber\":\"豫ICP备2021007034号-1\",\"csdn\":\"\",\"englishName\":\"七七\",\"favicon\":\"https://ws.aqi125.cn/aurora/config/740c0db7ddba6e3afaf3f5553f679e14.png\",\"gitee\":\"https://gitee.com/aqily\",\"github\":\"https://github.com/aqi-qihuan\",\"gonganBeianNumber\":\"豫公网安备41072802000219号\",\"isCommentReview\":1,\"isEmailNotice\":0,\"isReward\":1,\"juejin\":\"\",\"logo\":\"https://ws.aqi125.cn/aurora/config/740c0db7ddba6e3afaf3f5553f679e14.png\",\"multiLanguage\":1,\"name\":\"aqi的小窝\",\"notice\":\"代码已经开源，如果你感觉还行就给一个star吧。。。\",\"qq\":\"\",\"qqLogin\":1,\"stackoverflow\":\"\",\"touristAvatar\":\"https://static.linhaojun.top/config/2af2e2db20740e712f0a011a6f8c9af5.jpg\",\"twitter\":\"\",\"userAvatar\":\"https://ws.aqi125.cn/config/6d93c4e2a2690ce5f742f42f8d80e365.jpg\",\"weChat\":\"\",\"websiteCreateTime\":\"2021-03-25\",\"websiteTitle\":\"\",\"weiXinQRCode\":\"https://ws.aqi125.cn/aurora/config/b6ed9b60609ab4cbb938aae272c5d24b.png\",\"weibo\":\"\",\"zhihu\":\"\"}]', 'PUT', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-09 03:05:56', NULL);
INSERT INTO `t_operation_log` VALUES (2591, '文章模块', '上传', '/api/admin/articles/images', 'com.aurora.controller.ArticleController.saveArticleImages', '上传文章图片', 'file', 'POST', '{\"code\":20000,\"data\":\"https://ws.aqi125.cn/aurora/articles/12f138cdc95482591d354088fe37ec32.jpg\",\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-09 04:56:39', NULL);
INSERT INTO `t_operation_log` VALUES (2592, '文章模块', '新增或修改', '/api/admin/articles', 'com.aurora.controller.ArticleController.saveOrUpdateArticle', '保存和修改文章', '[{\"articleAbstract\":\"\",\"articleContent\":\"# Aurora 博客系统 - 升级到 Spring Boot 4.0.5 和 JDK 25 历程\\n\\n<div align=\\\"center\\\">\\n\\n![Spring Boot](https://img.shields.io/badge/Spring%20Boot-4.0.5-6DB33F?style=for-the-badge&logo=spring)\\n![JDK](https://img.shields.io/badge/JDK-25.0.1+-F80000?style=for-the-badge&logo=openjdk&logoColor=white)\\n![Elasticsearch](https://img.shields.io/badge/Elasticsearch-8.17.2-00BFb3?style=for-the-badge&logo=elasticsearch)\\n![IK Analyzer](https://img.shields.io/badge/IK-8.17.2-orange?style=for-the-badge)\\n![Status](https://img.shields.io/badge/Status-Production%20Ready-success?style=for-the-badge)\\n\\n</div>\\n\\n<div align=\\\"center\\\">\\n\\n| 项目 | 信息 |\\n|:---|:---|\\n| 📅 **更新时间** | 2026-04-09 |\\n| 👤 **维护者** | 七七 |\\n| 🔖 **文档版本** | v2.1 |\\n\\n</div>\\n\\n---\\n\\n## 目录\\n\\n1. [升级概述](#1-升级概述)\\n2. [依赖版本对比](#2-依赖版本对比)\\n3. [代码适配修改](#3-代码适配修改)\\n4. [常见问题与解决方案](#4-常见问题与解决方案)\\n5. [编译与部署](#5-编译与部署)\\n6. [验证结果](#6-验证结果)\\n7. [升级总结](#7-升级总结)\\n\\n---\\n\\n# 1. 升级概述\\n\\n| 属性 | 内容 |\\n|:---|:---|\\n| 📅 **升级时间** | 2026-04-08 |\\n| 🚀 **升级路线** | Spring Boot 3.5.10 + JDK 25 → Spring Boot 4.0.5 + JDK 25 |\\n| 💡 **升级原因** | 获取最新特性、内存优化（JVM 模式降低 11-17%，GraalVM Native Image 降低 71-81%） |\\n\\n---\\n\\n# 2. 依赖版本对比\\n\\n## 2.1 升级变更\\n\\n| 组件 | 原版本 | 新版本 | 说明 |\\n|:---|:---:|:---:|:---|\\n| **Spring Boot** | 3.5.10 | **4.0.5** | 基于 Spring Framework 7.0 |\\n| **Spring Framework** | 6.x | **7.0.6** | 核心框架重大更新 |\\n| **Spring Security** | 6.x | **7** | 安全框架 API 变更 |\\n| **Elasticsearch Client** | 8.13.4 | **8.17.2** | Java Client 升级 |\\n| **MyBatis-Plus** | 3.5.6/3.5.16 | **统一 3.5.16** | 修复版本不一致问题 |\\n| **MySQL Connector/J** | 9.6.0 | **9.6.0** | 保持不变 |\\n| **AOP** | spring-boot-starter-aop | **aspectjweaver 1.9.22.1** | SB 4.0 移除 AOP starter |\\n\\n## 2.2 保持不变的依赖\\n\\n| 依赖项 | 版本 | 说明 |\\n|:---|:---:|:---|\\n| **JDK** | 25 | 保持不变 |\\n| **Lombok** | 1.18.42 | 支持 JDK 25 |\\n| **JJWT** | 0.12.5 | JWT 令牌 |\\n| **Quartz** | 2.5.2 | 定时任务 |\\n| **OkHttp** | 4.12.0 | HTTP 客户端 |\\n| **FastJSON2** | 2.0.61 | JSON 序列化库 |\\n| **Hutool** | 5.8.43 | Java 工具类库 |\\n\\n---\\n\\n# 3. 代码适配修改\\n\\n## 3.1 pom.xml - 依赖调整\\n\\n**📁 文件位置**: `pom.xml`\\n\\n```xml\\n<!-- ✅ Spring Boot 版本升级 -->\\n<spring-boot.version>4.0.5</spring-boot.version>\\n\\n<!-- ✅ Elasticsearch 版本升级 -->\\n<elasticsearch.version>8.17.2</elasticsearch.version>\\n\\n<!-- ✅ MyBatis-Plus 统一版本 -->\\n<mybatis-plus.version>3.5.16</mybatis-plus.version>\\n\\n<!-- ❌ 移除：SB 4.0 已移除 AOP starter -->\\n<!-- <dependency>\\n    <groupId>org.springframework.boot</groupId>\\n    <artifactId>spring-boot-starter-aop</artifactId>\\n</dependency> -->\\n\\n<!-- ✅ 新增：直接引入 aspectjweaver -->\\n<dependency>\\n    <groupId>org.aspectj</groupId>\\n    <artifactId>aspectjweaver</artifactId>\\n    <version>1.9.22.1</version>\\n</dependency>\\n\\n<!-- ✅ 新增：Spring Security 7 需要 access 模块 -->\\n<dependency>\\n    <groupId>org.springframework.security</groupId>\\n    <artifactId>spring-security-access</artifactId>\\n</dependency>\\n\\n<!-- ✅ 新增：MyBatis-Plus 分页插件独立模块 -->\\n<dependency>\\n    <groupId>com.baomidou</groupId>\\n    <artifactId>mybatis-plus-jsqlparser</artifactId>\\n    <version>${mybatis-plus.version}</version>\\n</dependency>\\n```\\n\\n---\\n\\n## 3.2 AuroraSpringbootApplication.java - 排除自动配置\\n\\n**📁 文件位置**: `src/main/java/com/aurora/AuroraSpringbootApplication.java`\\n\\n```java\\n@SpringBootApplication(exclude = {\\n    com.baomidou.mybatisplus.autoconfigure.MybatisPlusAutoConfiguration.class\\n})\\n@MapperScan(\\\"com.aurora.mapper\\\")\\npublic class AuroraSpringbootApplication {\\n    public static void main(String[] args) {\\n        SpringApplication.run(AuroraSpringbootApplication.class, args);\\n    }\\n}\\n```\\n\\n> **📝 原因**: SB 4.0 的自动配置顺序变化，`MybatisPlusAutoConfiguration` 在 `DataSourceAutoConfiguration` 之前执行，导致找不到 DataSource。\\n\\n---\\n\\n## 3.3 MybatisPlusConfig.java - 手动配置 SqlSessionFactory\\n\\n**📁 文件位置**: `src/main/java/com/aurora/config/MybatisPlusConfig.java`\\n\\n```java\\n@EnableTransactionManagement\\n@Configuration\\n@MapperScan(\\\"com.aurora.mapper\\\")\\npublic class MybatisPlusConfig {\\n\\n    @Autowired\\n    private DataSource dataSource;\\n\\n    /**\\n     * 手动配置 SqlSessionFactory（SB 4.0 兼容）\\n     */\\n    @Bean\\n    public SqlSessionFactory sqlSessionFactory() throws Exception {\\n        MybatisSqlSessionFactoryBean sessionFactory = new MybatisSqlSessionFactoryBean();\\n        sessionFactory.setDataSource(dataSource);\\n        sessionFactory.setMapperLocations(new PathMatchingResourcePatternResolver()\\n                .getResources(\\\"classpath*:mapper/*.xml\\\"));\\n        sessionFactory.setPlugins(mybatisPlusInterceptor());\\n        return sessionFactory.getObject();\\n    }\\n\\n    /**\\n     * 配置 SqlSessionTemplate\\n     */\\n    @Bean\\n    public SqlSessionTemplate sqlSessionTemplate(SqlSessionFactory sqlSessionFactory) {\\n        return new SqlSessionTemplate(sqlSessionFactory);\\n    }\\n\\n    /**\\n     * 配置事务管理器\\n     */\\n    @Bean\\n    public PlatformTransactionManager transactionManager() {\\n        return new DataSourceTransactionManager(dataSource);\\n    }\\n\\n    @Bean\\n    public MybatisPlusInterceptor mybatisPlusInterceptor() {\\n        MybatisPlusInterceptor interceptor = new MybatisPlusInterceptor();\\n        PaginationInnerInterceptor paginationInterceptor = new PaginationInnerInterceptor(DbType.MYSQL);\\n        paginationInterceptor.setOverflow(false);\\n        paginationInterceptor.setMaxLimit(500L);\\n        interceptor.addInnerInterceptor(paginationInterceptor);\\n        return interceptor;\\n    }\\n}\\n```\\n\\n---\\n\\n## 3.4 WebSecurityConfig.java - Spring Security 7 API 适配\\n\\n**📁 文件位置**: `src/main/java/com/aurora/config/WebSecurityConfig.java`\\n\\n```java\\n// ❌ 旧版本（SB 3.5 / Security 6）\\n@Bean\\npublic DaoAuthenticationProvider authenticationProvider() {\\n    DaoAuthenticationProvider provider = new DaoAuthenticationProvider();\\n    provider.setUserDetailsService(userDetailServiceImpl);\\n    provider.setPasswordEncoder(passwordEncoder());\\n    return provider;\\n}\\n\\n// ✅ 新版本（SB 4.0 / Security 7）\\n@Bean\\npublic DaoAuthenticationProvider authenticationProvider() {\\n    // Security 7 要求构造函数传入 UserDetailsService\\n    DaoAuthenticationProvider provider = new DaoAuthenticationProvider(userDetailServiceImpl);\\n    provider.setPasswordEncoder(passwordEncoder());\\n    return provider;\\n}\\n```\\n\\n---\\n\\n## 3.5 ElasticsearchConfig.java - ES Client 超时配置\\n\\n**📁 文件位置**: `src/main/java/com/aurora/config/ElasticsearchConfig.java`\\n\\n```java\\n@Bean\\npublic RestClient elasticsearchRestClient() {\\n    String[] uriParts = uris.replace(\\\"http://\\\", \\\"\\\").split(\\\":\\\");\\n    String hostname = uriParts[0];\\n    int port = Integer.parseInt(uriParts[1]);\\n\\n    final CredentialsProvider credentialsProvider = new BasicCredentialsProvider();\\n    credentialsProvider.setCredentials(AuthScope.ANY,\\n            new UsernamePasswordCredentials(username, password));\\n\\n    // ✅ SB 4.0 + ES 8.17.2 需要显式设置超时\\n    RequestConfig requestConfig = RequestConfig.custom()\\n            .setConnectTimeout(10000)   // 连接超时 10s\\n            .setSocketTimeout(60000)   // Socket 超时 60s（支持批量同步）\\n            .setConnectionRequestTimeout(10000)\\n            .build();\\n\\n    RestClientBuilder builder = RestClient.builder(new HttpHost(hostname, port, \\\"http\\\"))\\n            .setHttpClientConfigCallback((HttpAsyncClientBuilder httpClientBuilder) -> {\\n                httpClientBuilder.setDefaultCredentialsProvider(credentialsProvider)\\n                        .setDefaultRequestConfig(requestConfig)\\n                        .setMaxConnTotal(100)      // 最大连接数\\n                        .setMaxConnPerRoute(30);   // 每路由最大连接数\\n                return httpClientBuilder;\\n            });\\n\\n    return builder.build();\\n}\\n```\\n\\n---\\n\\n## 3.6 application-prod.yml - HikariCP 连接池优化\\n\\n**📁 文件位置**: `src/main/resources/application-prod.yml`\\n\\n```yaml\\nspring:\\n  datasource:\\n    hikari:\\n      minimum-idle: 5              # ✅ 从 10 降到 5\\n      maximum-pool-size: 20        # ✅ 从 100 降到 20（防止 MySQL Too many connections）\\n      idle-timeout: 180000\\n      max-lifetime: 1800000\\n      connection-timeout: 30000\\n      keepalive-time: 300000\\n```\\n\\n---\\n\\n# 4. 常见问题与解决方案\\n\\n## ❌ 问题 1: spring-boot-starter-aop 不存在\\n\\n| 类别 | 内容 |\\n|:---|:---|\\n| 🔴 **错误** | `Could not find artifact org.springframework.boot:spring-boot-starter-aop` |\\n| 🔴 **原因** | SB 4.0 移除了 AOP starter |\\n| 🟢 **解决** | 直接引入 `aspectjweaver` |\\n\\n```xml\\n<dependency>\\n    <groupId>org.aspectj</groupId>\\n    <artifactId>aspectjweaver</artifactId>\\n    <version>1.9.22.1</version>\\n</dependency>\\n```\\n\\n---\\n\\n## ❌ 问题 2: MyBatis-Plus SqlSessionFactory 创建失败\\n\\n| 类别 | 内容 |\\n|:---|:---|\\n| 🔴 **错误** | `Property \'sqlSessionFactory\' or \'sqlSessionTemplate\' are required` |\\n| 🔴 **原因** | SB 4.0 自动配置顺序变化，DataSource 未就绪 |\\n| 🟢 **解决** | 排除 `MybatisPlusAutoConfiguration`，手动配置 `SqlSessionFactory` |\\n\\n> 📖 参考 [3.3 MybatisPlusConfig.java](#33-mybatisplusconfigjava---手动配置-sqlsessionfactory)\\n\\n---\\n\\n## ❌ 问题 3: Elasticsearch 同步超时\\n\\n| 类别 | 内容 |\\n|:---|:---|\\n| 🔴 **错误** | `30,000 milliseconds timeout on connection http-outgoing-0` |\\n| 🔴 **原因** | ES 8.17.2 + SB 4.0 需要显式配置超时 |\\n| 🟢 **解决** | 在 `ElasticsearchConfig` 中设置 `RequestConfig` |\\n\\n> 📖 参考 [3.5 ElasticsearchConfig.java](#35-elasticsearchconfigjava---es-client-超时配置)\\n\\n---\\n\\n## ❌ 问题 4: MySQL Too many connections\\n\\n| 类别 | 内容 |\\n|:---|:---|\\n| 🔴 **错误** | `java.sql.SQLNonTransientConnectionException: Too many connections` |\\n| 🔴 **原因** | HikariCP 最大连接数 100 超过 MySQL 默认限制 |\\n| 🟢 **解决** | 降低 `maximum-pool-size` 到 20 |\\n\\n> 📖 参考 [3.6 application-prod.yml](#36-application-prodyml---hikaricp-连接池优化)\\n\\n---\\n\\n## ❌ 问题 5: ES article 索引 RED 状态\\n\\n| 类别 | 内容 |\\n|:---|:---|\\n| 🔴 **现象** | `primary shard is not active`，同步失败 |\\n| 🔴 **原因** | IK 分词器插件未安装，索引 mapping 无法解析 |\\n| 🟢 **解决** | 在 ES 服务器安装 IK 分词器并重建索引 |\\n\\n```bash\\n# 1. 安装 IK 分词器（ES 8.17.2）\\nelasticsearch-plugin install https://github.com/infinilabs/analysis-ik/releases/download/v8.17.2/elasticsearch-analysis-ik-8.17.2.zip\\n\\n# 2. 重启 ES\\ndocker restart aurora-elasticsearch\\n\\n# 3. 删除损坏的索引\\ncurl -X DELETE \\\"http://你的ip:9200/article\\\"\\n\\n# 4. 重启应用，自动重建索引并同步数据\\n```\\n\\n---\\n\\n# 5. 编译与部署\\n\\n## 5.1 编译环境要求\\n\\n| 环境 | 版本要求 |\\n|:---|:---|\\n| **JDK** | 25.0.1+ |\\n| **Maven** | 3.9.x+ |\\n\\n```bash\\n# 设置 JDK 环境\\nset JAVA_HOME=D:\\\\Java\\\\jdk-25.0.1\\n\\n# 编译项目\\nmvn clean package -DskipTests -U\\n```\\n\\n---\\n\\n## 5.2 JVM 优化参数\\n\\n### 本地开发 / 测试环境\\n\\n```bash\\njava -Xms96m -Xmx192m \\\\\\n     -XX:MetaspaceSize=48m -XX:MaxMetaspaceSize=128m \\\\\\n     -XX:+UseG1GC \\\\\\n     -XX:+UseStringDeduplication \\\\\\n     -XX:+UseCompressedOops \\\\\\n     -XX:+UseCompressedClassPointers \\\\\\n     -XX:+AlwaysPreTouch \\\\\\n     -jar blog.jar\\n```\\n\\n### 生产环境 Docker 部署\\n\\n```bash\\njava -Xms48m -Xmx96m \\\\\\n     -XX:+UseSerialGC \\\\\\n     -XX:MetaspaceSize=128m -XX:MaxMetaspaceSize=192m \\\\\\n     -XX:ReservedCodeCacheSize=24m -Xss256k \\\\\\n     -XX:+UseCompressedOops \\\\\\n     -XX:+UseCompressedClassPointers \\\\\\n     -Djava.security.egd=file:/dev/./urandom \\\\\\n     -Dspring.jmx.enabled=false \\\\\\n     -Dspring.backgroundpreinitializer.ignore=true \\\\\\n     -Djdk.attach.allowAttachSelf=false \\\\\\n     -jar /app/blog.jar\\n```\\n\\n### Elasticsearch 生产环境参数\\n\\n```yaml\\n# ES_JAVA_OPTS（docker-compose.yml）\\nES_JAVA_OPTS: \\\"-Xms128m -Xmx160m\\\"\\n```\\n\\n---\\n\\n# 6. 验证结果\\n\\n## 6.1 应用启动验证\\n\\n```\\n✅ Spring Boot 4.0.5 启动成功\\n✅ 使用 JDK 25 运行（eclipse-temurin:25-jre-alpine）\\n✅ Tomcat 在 8080 端口启动（context-path: /api）\\n✅ 数据库连接正常（HikariCP 最大 20 连接）\\n✅ Quartz 定时任务启动成功\\n✅ ip2region.xdb 加载成功 (11MB)\\n✅ RabbitMQ 连接成功\\n✅ Elasticsearch 8.17.2 + IK 8.17.2 连接成功\\n✅ 文章数据同步：28/28 成功（100%）\\n```\\n\\n---\\n\\n## 6.2 功能验证\\n\\n| 功能模块 | 状态 |\\n|:---|:---:|\\n| ✅ QQ 登录 | 正常 |\\n| ✅ 邮箱登录 | 正常 |\\n| ✅ 用户权限 | 正常 |\\n| ✅ 文章管理 | 正常 |\\n| ✅ Elasticsearch 搜索 + IK 分词 | **正常**（28 篇文章全部同步） |\\n| ✅ 定时任务 | 正常 |\\n\\n---\\n\\n## 6.3 性能测试数据\\n\\n### 启动时间\\n\\n| 阶段 | 耗时 |\\n|:---|:---:|\\n| Spring Boot 启动到 Tomcat 就绪 | ~17 秒 |\\n| 完整启动（含 ES 同步 27 篇文章） | **~22.7 秒** |\\n\\n**启动日志关键时间点**：\\n\\n```\\n21:56:52.992 - 应用开始启动\\n21:57:14.005 - Tomcat 启动完成 (21.013 秒)\\n21:57:15.107 - 应用完全启动 (22.115 秒)\\n21:57:17.063 - ES 同步完成 (24.071 秒)\\n```\\n\\n### 内存占用\\n\\n| 指标 | 数值 |\\n|:---|:---:|\\n| **物理内存 (RSS)** | **733 MB** |\\n| JVM Heap - Used | 102.5 MB |\\n| JVM Heap - Committed | 600 MB (Young: 344MB + Old: 245.7MB) |\\n| Metaspace - Used | 86.2 MB |\\n| Metaspace - Committed | 86.9 MB |\\n\\n**GC 统计**：\\n\\n| 指标 | 数值 |\\n|:---|:---:|\\n| Young GC 次数 | 22 次 |\\n| Young GC 总耗时 | 0.143 秒 |\\n| Full GC 次数 | 0 次 |\\n| Concurrent GC 次数 | 6 次 |\\n\\n### 与 SB 3.5.10 对比\\n\\n| 指标 | SB 3.5.10 | SB 4.0.5 | 变化 |\\n|:---|:---:|:---:|:---|\\n| 启动时间 | ~10 秒 | ~22.7 秒 | +127% ⬆️ |\\n| 物理内存 | ~418 MB | **733 MB** | +75% ⬆️ |\\n| JVM Heap Used | ~180 MB | **102.5 MB** | -43% ⬇️ |\\n| ES 同步成功率 | 0/27 | **27/27** | 100% ⬆️ |\\n\\n> **⚠️ 注意**：\\n> - SB 4.0.5 启动时间增加是因为 Spring Framework 7.0 增加了更多初始化检查和 Bean 验证\\n> - 物理内存增加主要是由于 JDK 25 和 Spring Framework 7.0 的基础开销增加\\n> - **JVM Heap 使用量反而降低了 43%**，说明 SB 4.0.5 的内存管理更高效\\n> - 预期经过 JIT 预热和 G1 GC 优化后，长期运行的内存占用会进一步降低\\n> - 如需显著降低内存，可考虑 GraalVM Native Image（预期降低 71-81%）或 GraalVM JIT（预计节省 5-15%）\\n\\n---\\n\\n## 6.4 生产环境部署优化\\n\\n### 服务器信息\\n\\n| 属性 | 内容 |\\n|:---|:---|\\n| 🖥️ **服务器** | 腾讯云轻量应用服务器（广州） |\\n| 🆔 **实例 ID** | 你的实例 |\\n| 🌐 **公网 IP** | 你的ip |\\n| 💾 **内存** | 3.3 GiB |\\n| 🌐 **域名** | www.你的域名 / admin.你的域名 / static.你的域名 |\\n\\n### 问题排查与修复记录\\n\\n| # | 时间 | 问题 | 根因 | 解决方案 | 状态 |\\n|:---:|:---:|------|------|---------|:----:|\\n| 1 | 23:12 | ES 启动崩溃 | `cache.max_size` 无效配置项（ES 8.x 不支持） | 从 docker-compose.yml 删除 | ✅ |\\n| 2 | 23:14 | IK 分词器 NPE 空指针 | IK **7.17.12** 与 ES **8.17.2** 版本不匹配 | 重装 IK **8.17.2** | ✅ |\\n| 3 | 23:22 | IK 字典文件缺失 | 手动下载 zip 缺少 `config/` 目录 + volume 挂载覆盖容器内正确插件 | 去掉 plugins volume 挂载，改用 `elasticsearch-plugin install` 安装 | ✅ |\\n| 4 | 23:23 | ES OOM 崩溃 | 64MB 堆内存不够用（ES 8.x + IK 插件需要更多内存） | 调大到 128MB → 最终 **160MB** | ✅ |\\n| 5 | 23:27 | 文章同步 circuit_breaking | HTTP 熔断器限制太小（108MB），大文章内容超限 | 调大堆内存 + breaker.limit 60% | ✅ |\\n| 6 | 24:00 | SpringBoot Metaspace OOM | 异步任务动态加载 MySQL 驱动类，Metaspace 96m 不够 | 增加 MetaspaceSize 到 128m，MaxMetaspaceSize 到 192m | ✅ |\\n\\n### IK 分词器安装命令\\n\\n```bash\\n# 进入 ES 容器安装（每次容器重建后需重新执行）\\ndocker exec -it aurora-elasticsearch /bin/bash\\n./bin/elasticsearch-plugin install https://release.infinilabs.com/analysis-ik/stable/elasticsearch-analysis-ik-8.17.2.zip\\n\\n# 输入 y 确认后重启 ES 激活插件\\ndocker restart aurora-elasticsearch\\n```\\n\\n> **⚠️ 重要**: 不要使用宿主机 plugins volume 挂载！直接用 `elasticsearch-plugin install` 安装到容器内部最可靠。\\n\\n### 最终生产环境参数\\n\\n#### SpringBoot JVM 参数\\n\\n```bash\\njava -Xms48m -Xmx96m \\\\\\n     -XX:+UseSerialGC \\\\\\n     -XX:MetaspaceSize=128m -XX:MaxMetaspaceSize=192m \\\\\\n     -XX:ReservedCodeCacheSize=24m -Xss256k \\\\\\n     -XX:+UseCompressedOops \\\\\\n     -XX:+UseCompressedClassPointers \\\\\\n     -Djava.security.egd=file:/dev/./urandom \\\\\\n     -Dspring.jmx.enabled=false \\\\\\n     -Dspring.backgroundpreinitializer.ignore=true \\\\\\n     -Djdk.attach.allowAttachSelf=false \\\\\\n     -jar /app/blog.jar\\n```\\n\\n#### Elasticsearch 参数\\n\\n```yaml\\n# docker-compose.yml\\nenvironment:\\n  ES_JAVA_OPTS: \\\"-Xms128m -Xmx160m\\\"\\n  discovery.type: single-node\\n  bootstrap.memory_lock: \\\"true\\\"\\n  xpack.security.enabled: \\\"false\\\"\\n  indices.query.bool.max_clause_count: \\\"1024\\\"\\n  indices.memory.index_buffer_size: \\\"20%\\\"\\n  indices.fielddata.cache.size: \\\"10%\\\"\\n  indices.breaker.total.limit: \\\"60%\\\"\\n```\\n\\n### 生产环境实测数据\\n\\n#### 各服务内存占用\\n\\n| 服务 | 内存占用 | 占比 | CPU |\\n|:---|:---|:---|:---|\\n| **Elasticsearch** (128/160MB + IK) | **677 MiB** | 19.9% | 0.75% |\\n| **SpringBoot** (48/96MB) | **285 MiB** | 8.38% | 0.32% |\\n| MySQL | 163 MiB | 4.9% | 0.60% |\\n| Maxwell | 154 MiB | 4.6% | 0.19% |\\n| MinIO | 135 MiB | 4.1% | 0.00% |\\n| RabbitMQ | 124 MiB | 3.7% | 0.14% |\\n| Redis | 7.4 MiB | 0.2% | 0.42% |\\n| Nginx | 19 MiB | 0.6% | 0.00% |\\n| **合计** | **~1.56 GiB** | **47%** | — |\\n\\n#### 主机内存状态\\n\\n```\\n总计: 3.3 GiB\\n已用: 2.5 GiB (75%)\\n可用: 827 MiB\\nSwap: 无\\n```\\n\\n#### SpringBoot 启动性能\\n\\n| 指标 | 数值 |\\n|:---|:---|\\n| 启动耗时 | **11.2 秒** |\\n| 文章同步成功率 | **28/28 (100%)** |\\n| 同步失败数 | **0** |\\n| API 响应时间 | **176ms** |\\n\\n### 优化前后对比\\n\\n| 指标 | 优化前（首次部署） | 优化后（最终） | 节省 |\\n|:---|:---|:---|:---|\\n| SpringBoot RSS | ~342 MiB | **285 MiB** | -57 MiB (-17%) |\\n| Elasticsearch RSS | ~697 MiB | **677 MiB** | -20 MiB (-3%) |\\n| ES Heap | 64 MB | **160 MB** | 调大以适配 IK 插件 |\\n| SB Heap | ~256 MB | **96 MB** | -62% |\\n| SB 启动时间 | 较慢 | **11.8 秒** | 显著提升 |\\n| ES 同步成功 | 0/28 (Connection refused) | **28/28 (100%)** | 完全修复 |\\n\\n### 进一步优化的可行性分析\\n\\n| 方案 | 可行性 | 预期收益 | 推荐度 |\\n|:---|:---:|:---:|:---:|\\n| 当前 JVM 优化（已完成） | ★★★★★ | 已节省 ~77 MiB | ✅ 已完成 |\\n| GraalVM JIT | ★★★★★ | 省 ~20-30 MiB（5-10%）| ★★★★☆ 可顺手做 |\\n| GraalVM Native Image | ★★☆☆☆ | 省 ~200+ MiB（60-70%）| ★★☆☆☆ SB 4.0 + JDK 25 生态不成熟，建议等半年 |\\n| 关停 Maxwell | ★★★★☆ | 省 154 MiB | ★★★☆☆ 不用 CDC 时可关 |\\n\\n> **💡 结论**: 核心服务（SpringBoot + ES）已到极限，当前 285 + 677 = 962 MiB 在 3.3G 主机上运行稳定（75% 使用率）。建议保持现状。\\n\\n---\\n\\n# 7. 升级总结\\n\\n## 🎯 成功经验\\n\\n| # | 经验说明 |\\n|:---:|:---|\\n| 1️⃣ | **提前备份**：升级前备份所有配置文件和数据库 |\\n| 2️⃣ | **依赖检查**：SB 4.0 移除了 AOP starter，需手动引入 aspectjweaver |\\n| 3️⃣ | **自动配置顺序**：SB 4.0 改变了自动配置顺序，需手动配置 MyBatis-Plus |\\n| 4️⃣ | **ES 超时配置**：ES 8.17.2 + SB 4.0 需要显式设置超时参数 |\\n| 5️⃣ | **连接池优化**：降低 HikariCP 最大连接数防止 MySQL 连接耗尽 |\\n| 6️⃣ | **IK 分词器版本匹配**：必须使用与 ES 完全一致的 IK 版本（ES 8.17.2 → IK 8.17.2）|\\n| 7️⃣ | **IK 安装方式**：用 `elasticsearch-plugin install` 安装到容器内部，不要用宿主机 volume 挂载 plugins 目录 |\\n| 8️⃣ | **ES 堆内存规划**：ES 8.x + IK 插件至少需要 128MB 堆内存，64MB 会 OOM |\\n| 9️⃣ | **Metaspace 规划**：异步任务中动态加载驱动类可能导致 Metaspace 增长，建议初始 128m，最大 192m |\\n\\n---\\n\\n## ⚠️ 注意事项\\n\\n| # | 注意事项 |\\n|:---:|:---|\\n| 1️⃣ | **Spring Security 7**：`DaoAuthenticationProvider` 构造函数需要传入 `UserDetailsService` |\\n| 2️⃣ | **MyBatis-Plus 分页**：需要单独引入 `mybatis-plus-jsqlparser` 依赖 |\\n| 3️⃣ | **ES IK 分词器**：必须在 ES 服务器上安装与 ES 版本一致的 IK 插件 |\\n| 4️⃣ | **JAR 文件锁定**：Windows 环境下重新构建前需停止所有 Java 进程 |\\n| 5️⃣ | **GraalVM Native Image**：如需进一步降低内存，可考虑迁移到 Native Image（预期降低 71-81%），但 SB 4.0 + JDK 25 生态尚未成熟，建议等半年后再尝试 |\\n| 6️⃣ | **GraalVM JIT**：零代码改动，改 Dockerfile 基础镜像即可，预计节省 5-15%（约 20-30 MiB）|\\n| 7️⃣ | **ES 无效配置项**：ES 8.x 不支持 `cache.max_size` 等旧版设置，需清理 |\\n| 8️⃣ | **容器重建后插件丢失**：每次 `docker compose up -d elasticsearch` 会重建容器，需重新安装 IK 插件 |\\n| 9️⃣ | **Metaspace OOM**：异步任务动态加载类（如 MySQL 驱动）可能导致 Metaspace 爆满，需监控并预留充足空间 |\\n\\n---\\n\\n## 📚 相关文档\\n\\n- [升级与 Elasticsearch 集成完整指南](./升级与%20Elasticsearch%20集成完整指南.md) - Elasticsearch 8.17.2 集成问题排查与运维指南\\n\\n---\\n\\n<div align=\\\"center\\\">\\n**文档版本**: v2.1 | **创建日期**: 2026-04-08 | **更新日期**: 2026-04-09 \\n\\n![Built with ❤️](https://img.shields.io/badge/Built%20with-%E2%9D%A4%EF%B8%8F-blue?style=flat-square)\\n\\n</div>\\n\",\"articleCover\":\"https://ws.aqi125.cn/aurora/articles/12f138cdc95482591d354088fe37ec32.jpg\",\"articleTitle\":\"Aurora 博客系统 - 升级到 Spring Boot 4.0.5 和 JDK 25 历程\",\"categoryName\":\"AuroraJDK\",\"isFeatured\":1,\"isTop\":1,\"originalUrl\":\"\",\"password\":\"\",\"status\":1,\"tagNames\":[\"Spring Boot 4.0.5\"],\"type\":1}]', 'POST', '{\"code\":20000,\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-09 04:56:43', NULL);
INSERT INTO `t_operation_log` VALUES (2593, '文章模块', '上传', '/api/admin/articles/images', 'com.aurora.controller.ArticleController.saveArticleImages', '上传文章图片', 'file', 'POST', '{\"code\":20000,\"data\":\"https://ws.aqi125.cn/aurora/articles/a42095dcb880059bc8f572662ced2708.png\",\"flag\":true,\"message\":\"操作成功\"}', 1015, '七七', '39.148.122.150', '中国|河南省|南阳市|移动', '2026-04-09 05:24:25', NULL);
