INSERT INTO `t_talk` VALUES (69, 1025, 'JVM终于搞完了。', '[\"http://ws.aqi125.cn/talks/e75cf23711926f7aac4a34650b916b27.jpg\",\"http://ws.aqi125.cn/talks/7e6eb110e91d6223468f1ac096421d64.jpg\"]', 0, 1, '2023-05-23 17:37:02', NULL);
INSERT INTO `t_talk` VALUES (70, 1025, '一站式DevOps打通了，耗时一个星期。真难啊，写个文档记录一下踩的坑。\n先写个ubuntu开发环境基本初始化吧。\n\n', '', 0, 1, '2023-08-06 14:49:59', '2023-08-06 15:21:12');
INSERT INTO `t_talk` VALUES (71, 1025, '旧腾讯云服务器到期替换了下服务器，做了下nginx优化，这个流程文档记录一下，\n使用 Docker 搭建一个网页版 Firefox，这个也搞定了，等下一起发出来。\n', '[\"https://ws.aqi125.cn/talks/21d0c818a08722630541bd2b49fb410e.jpg\"]', 1, 1, '2024-11-07 23:24:42', '2024-11-08 00:23:49');
